import { useState, useEffect } from 'react';
import { RefreshCw, Sparkles, Copy, Check, TrendingUp, AlertTriangle, Zap, Send } from 'lucide-react';
import toast from 'react-hot-toast';
import { useCRM } from '../contexts/CRMContext';
import { SendDraftModal } from './SendDraftModal';
import type { AILeadInsight } from '@mpbhealth/crm-core';

interface AIInsightsPanelProps {
  leadId: string;
  leadEmail?: string;
}

export function AIInsightsPanel({ leadId, leadEmail }: AIInsightsPanelProps) {
  const { insightsService } = useCRM();
  const [insights, setInsights] = useState<AILeadInsight | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [draftLoading, setDraftLoading] = useState<'email' | 'sms' | null>(null);
  const [draft, setDraft] = useState<{ type: string; subject?: string; body: string } | null>(null);
  const [copied, setCopied] = useState(false);
  const [showSendModal, setShowSendModal] = useState(false);

  useEffect(() => {
    loadInsights();
  }, [leadId]);

  const loadInsights = async () => {
    setLoading(true);
    const data = await insightsService.getInsights(leadId);
    setInsights(data);
    setLoading(false);
  };

  const handleRefresh = async () => {
    setRefreshing(true);
    const result = await insightsService.refreshInsights(leadId);
    if (result.success) {
      await loadInsights();
      toast.success('Insights refreshed');
    } else {
      toast.error(result.error || 'Failed to refresh');
    }
    setRefreshing(false);
  };

  const handleGenerateDraft = async (type: 'email' | 'sms') => {
    setDraftLoading(type);
    const result = await insightsService.generateDraft(leadId, type);
    if (result.success && result.draft) {
      setDraft({ type, subject: result.draft.subject, body: result.draft.body });
    } else {
      toast.error(result.error || 'Failed to generate draft');
    }
    setDraftLoading(null);
  };

  const handleCopy = () => {
    if (!draft) return;
    const text = draft.subject ? `Subject: ${draft.subject}\n\n${draft.body}` : draft.body;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const urgencyColors = {
    low: 'bg-green-100 text-green-700',
    medium: 'bg-yellow-100 text-yellow-700',
    high: 'bg-orange-100 text-orange-700',
    critical: 'bg-red-100 text-red-700',
  };

  if (loading) {
    return (
      <div className="bg-surface-primary rounded-xl border border-th-border p-6">
        <div className="flex items-center space-x-2 mb-4">
          <Sparkles className="w-5 h-5 text-blue-500" />
          <h2 className="text-lg font-semibold text-th-text-primary">AI Insights</h2>
        </div>
        <div className="flex items-center justify-center h-24">
          <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-500" />
        </div>
      </div>
    );
  }

  if (!insights) {
    return (
      <div className="bg-surface-primary rounded-xl border border-th-border p-6">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center space-x-2">
            <Sparkles className="w-5 h-5 text-blue-500" />
            <h2 className="text-lg font-semibold text-th-text-primary">AI Insights</h2>
          </div>
          <button
            onClick={handleRefresh}
            disabled={refreshing}
            className="text-sm text-blue-600 hover:text-blue-700 flex items-center gap-1"
          >
            <RefreshCw className={`w-4 h-4 ${refreshing ? 'animate-spin' : ''}`} />
            Generate
          </button>
        </div>
        <p className="text-sm text-th-text-tertiary text-center py-4">
          No AI insights yet. Click Generate to analyze this lead.
        </p>
      </div>
    );
  }

  return (
    <div className="bg-surface-primary rounded-xl border border-th-border p-6 space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-2">
          <Sparkles className="w-5 h-5 text-blue-500" />
          <h2 className="text-lg font-semibold text-th-text-primary">AI Insights</h2>
        </div>
        <button
          onClick={handleRefresh}
          disabled={refreshing}
          className="text-sm text-blue-600 hover:text-blue-700 flex items-center gap-1"
        >
          <RefreshCw className={`w-4 h-4 ${refreshing ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>

      {/* Score ring + conversion */}
      <div className="flex items-center gap-4">
        <div className="relative w-16 h-16">
          <svg className="w-16 h-16 -rotate-90" viewBox="0 0 64 64">
            <circle cx="32" cy="32" r="28" fill="none" stroke="#e5e7eb" strokeWidth="4" />
            <circle
              cx="32" cy="32" r="28" fill="none"
              stroke={insights.ai_score >= 70 ? '#22c55e' : insights.ai_score >= 40 ? '#f59e0b' : '#ef4444'}
              strokeWidth="4"
              strokeDasharray={`${(insights.ai_score / 100) * 175.9} 175.9`}
              strokeLinecap="round"
            />
          </svg>
          <span className="absolute inset-0 flex items-center justify-center text-sm font-bold text-th-text-primary">
            {insights.ai_score}
          </span>
        </div>
        <div>
          <p className="text-sm font-medium text-th-text-primary">AI Score</p>
          <p className="text-xs text-th-text-tertiary">
            {Math.round(insights.conversion_probability * 100)}% conversion probability
          </p>
          <span className={`inline-flex items-center px-2 py-0.5 mt-1 rounded-full text-xs font-medium ${urgencyColors[insights.urgency]}`}>
            {insights.urgency} urgency
          </span>
        </div>
      </div>

      {/* Score factors */}
      {insights.score_factors && insights.score_factors.length > 0 && (
        <div>
          <p className="text-xs font-medium text-th-text-tertiary uppercase tracking-wider mb-2">Score Factors</p>
          <div className="space-y-1.5">
            {insights.score_factors.slice(0, 4).map((factor, i) => (
              <div key={i} className="flex items-center gap-2 text-xs">
                {factor.impact === 'positive' ? (
                  <TrendingUp className="w-3.5 h-3.5 text-green-500 flex-shrink-0" />
                ) : factor.impact === 'negative' ? (
                  <AlertTriangle className="w-3.5 h-3.5 text-red-500 flex-shrink-0" />
                ) : (
                  <Zap className="w-3.5 h-3.5 text-th-text-tertiary flex-shrink-0" />
                )}
                <span className="text-th-text-secondary">{factor.description}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Recommended action */}
      <div className="bg-blue-50 rounded-lg p-3">
        <p className="text-xs font-medium text-blue-700 mb-1">Recommended Action</p>
        <p className="text-sm text-blue-900">{insights.recommended_action}</p>
        <p className="text-xs text-blue-600 mt-1">via {insights.recommended_channel}</p>
      </div>

      {/* Conversation summary */}
      {insights.conversation_summary && (
        <div>
          <p className="text-xs font-medium text-th-text-tertiary uppercase tracking-wider mb-1">Summary</p>
          <p className="text-sm text-th-text-secondary">{insights.conversation_summary}</p>
        </div>
      )}

      {/* Draft generation */}
      <div>
        <p className="text-xs font-medium text-th-text-tertiary uppercase tracking-wider mb-2">Generate Draft</p>
        <div className="flex gap-2">
          <button
            onClick={() => handleGenerateDraft('email')}
            disabled={draftLoading !== null}
            className="flex-1 px-3 py-1.5 text-xs font-medium bg-surface-primary border border-th-border rounded-lg hover:bg-surface-secondary disabled:opacity-50"
          >
            {draftLoading === 'email' ? 'Generating...' : 'Email Draft'}
          </button>
          <button
            onClick={() => handleGenerateDraft('sms')}
            disabled={draftLoading !== null}
            className="flex-1 px-3 py-1.5 text-xs font-medium bg-surface-primary border border-th-border rounded-lg hover:bg-surface-secondary disabled:opacity-50"
          >
            {draftLoading === 'sms' ? 'Generating...' : 'SMS Draft'}
          </button>
        </div>
      </div>

      {/* Generated draft */}
      {draft && (
        <div className="bg-surface-secondary rounded-lg p-3 relative">
          <div className="flex items-center justify-between mb-1">
            <p className="text-xs font-medium text-th-text-tertiary">{draft.type.toUpperCase()} Draft</p>
            <div className="flex items-center gap-1">
              {leadEmail && (
                <button
                  onClick={() => setShowSendModal(true)}
                  className="text-blue-500 hover:text-blue-700 p-0.5"
                  title="Send"
                >
                  <Send className="w-4 h-4" />
                </button>
              )}
              <button onClick={handleCopy} className="text-th-text-tertiary hover:text-th-text-secondary p-0.5">
                {copied ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
              </button>
            </div>
          </div>
          {draft.subject && (
            <p className="text-xs text-th-text-tertiary mb-1">Subject: {draft.subject}</p>
          )}
          <p className="text-sm text-th-text-secondary whitespace-pre-wrap">{draft.body}</p>
        </div>
      )}

      {/* Send draft modal */}
      {draft && leadEmail && (
        <SendDraftModal
          open={showSendModal}
          onClose={() => setShowSendModal(false)}
          leadId={leadId}
          leadEmail={leadEmail}
          subject={draft.subject}
          body={draft.body}
          draftType={draft.type as 'email' | 'sms'}
        />
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { InputField, SelectField, TextareaField, SubmitButton } from './FormField';
import { useForm } from '../hooks/useForm';
import { useOrg } from '../contexts/OrgContext';
import { logAuditEvent } from '@mpbhealth/auth';
import {
  createAccountService,
  type AccountWithRelations,
  type AccountCreateInput,
} from '@mpbhealth/crm-core';
import { supabase } from '../lib/supabase';

interface AddAccountModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess?: (accountId: string) => void;
  account?: AccountWithRelations | null; // For edit mode
}

interface AccountFormValues {
  name: string;
  industry: string;
  website: string;
  phone: string;
  fax: string;
  account_type: string;
  rating: string;
  description: string;
  annual_revenue: string;
  employee_count: string;
  // Address fields
  street: string;
  city: string;
  state: string;
  zip: string;
  country: string;
  // Social
  linkedin_url: string;
  twitter_handle: string;
  // Tags
  tags: string;
  // Owner
  owner_id: string;
}

const ACCOUNT_TYPE_OPTIONS = [
  { value: 'prospect', label: 'Prospect' },
  { value: 'customer', label: 'Customer' },
  { value: 'partner', label: 'Partner' },
  { value: 'vendor', label: 'Vendor' },
  { value: 'other', label: 'Other' },
];

const RATING_OPTIONS = [
  { value: '', label: 'Select Rating...' },
  { value: 'hot', label: 'Hot' },
  { value: 'warm', label: 'Warm' },
  { value: 'cold', label: 'Cold' },
];

const INDUSTRY_OPTIONS = [
  { value: '', label: 'Select Industry...' },
  { value: 'Healthcare', label: 'Healthcare' },
  { value: 'Insurance', label: 'Insurance' },
  { value: 'Technology', label: 'Technology' },
  { value: 'Finance', label: 'Finance' },
  { value: 'Retail', label: 'Retail' },
  { value: 'Manufacturing', label: 'Manufacturing' },
  { value: 'Education', label: 'Education' },
  { value: 'Government', label: 'Government' },
  { value: 'Non-Profit', label: 'Non-Profit' },
  { value: 'Real Estate', label: 'Real Estate' },
  { value: 'Legal', label: 'Legal' },
  { value: 'Media', label: 'Media' },
  { value: 'Transportation', label: 'Transportation' },
  { value: 'Energy', label: 'Energy' },
  { value: 'Agriculture', label: 'Agriculture' },
  { value: 'Construction', label: 'Construction' },
  { value: 'Hospitality', label: 'Hospitality' },
  { value: 'Other', label: 'Other' },
];

const defaultValues: AccountFormValues = {
  name: '',
  industry: '',
  website: '',
  phone: '',
  fax: '',
  account_type: 'prospect',
  rating: '',
  description: '',
  annual_revenue: '',
  employee_count: '',
  street: '',
  city: '',
  state: '',
  zip: '',
  country: '',
  linkedin_url: '',
  twitter_handle: '',
  tags: '',
  owner_id: '',
};

export function AddAccountModal({ open, onClose, onSuccess, account }: AddAccountModalProps) {
  const { activeOrgId } = useOrg();
  const [accountService] = useState(() => createAccountService(supabase));
  const [teamMembers, setTeamMembers] = useState<{ id: string; email: string; full_name: string | null }[]>([]);

  const isEdit = !!account;

  // Load team members for owner selector
  useEffect(() => {
    async function loadTeamMembers() {
      try {
        // Step 1: Get org membership user IDs
        const { data: memberships, error: memError } = await supabase
          .from('org_memberships')
          .select('user_id')
          .eq('org_id', activeOrgId)
          .eq('status', 'active');

        if (memError || !memberships || memberships.length === 0) {
          return;
        }

        // Step 2: Fetch profiles for those users (auth.users not exposed via PostgREST)
        const userIds = memberships.map((m: any) => m.user_id);
        const { data: profiles, error: profError } = await supabase
          .from('profiles')
          .select('id, email, full_name')
          .in('id', userIds);

        if (!profError && profiles) {
          const members = profiles.map((p: any) => ({
            id: p.id,
            email: p.email || '',
            full_name: p.full_name || null,
          }));
          setTeamMembers(members);
        }
      } catch (err) {
        console.error('Failed to load team members:', err);
      }
    }

    if (open && activeOrgId) {
      loadTeamMembers();
    }
  }, [open, activeOrgId]);

  // Get initial values from account for edit mode
  const getInitialValues = (): AccountFormValues => {
    if (!account) return defaultValues;

    return {
      name: account.name || '',
      industry: account.industry || '',
      website: account.website || '',
      phone: account.phone || '',
      fax: account.fax || '',
      account_type: account.account_type || 'prospect',
      rating: account.rating || '',
      description: account.description || '',
      annual_revenue: account.annual_revenue?.toString() || '',
      employee_count: account.employee_count?.toString() || '',
      street: account.address?.street || '',
      city: account.address?.city || '',
      state: account.address?.state || '',
      zip: account.address?.zip || '',
      country: account.address?.country || '',
      linkedin_url: account.linkedin_url || '',
      twitter_handle: account.twitter_handle || '',
      tags: account.tags?.join(', ') || '',
      owner_id: account.owner_id || '',
    };
  };

  const handleSubmit = async (values: AccountFormValues) => {
    // Parse tags
    const tags = values.tags
      ? values.tags.split(',').map((t) => t.trim()).filter(Boolean)
      : [];

    // Build address object
    const address: Record<string, string> = {};
    if (values.street) address.street = values.street;
    if (values.city) address.city = values.city;
    if (values.state) address.state = values.state;
    if (values.zip) address.zip = values.zip;
    if (values.country) address.country = values.country;

    const accountData: AccountCreateInput = {
      name: values.name,
      industry: values.industry || undefined,
      website: values.website || undefined,
      phone: values.phone || undefined,
      fax: values.fax || undefined,
      account_type: values.account_type as AccountCreateInput['account_type'],
      rating: values.rating ? (values.rating as AccountCreateInput['rating']) : undefined,
      description: values.description || undefined,
      annual_revenue: values.annual_revenue ? Number(values.annual_revenue) : undefined,
      employee_count: values.employee_count ? Number(values.employee_count) : undefined,
      address: Object.keys(address).length > 0 ? address : undefined,
      linkedin_url: values.linkedin_url || undefined,
      twitter_handle: values.twitter_handle || undefined,
      tags: tags.length > 0 ? tags : undefined,
      owner_id: values.owner_id || undefined,
    };

    if (isEdit && account) {
      // Update existing account
      const result = await accountService.updateAccount(account.id, accountData);
      if (!result.success) {
        toast.error(result.error || 'Failed to update account');
        return;
      }

      toast.success('Account updated');
      logAuditEvent({
        orgId: activeOrgId || '',
        action: 'account.updated',
        entityType: 'account',
        entityId: account.id,
        before: { name: account.name },
        after: { name: values.name },
      }).catch(console.error);

      onSuccess?.(account.id);
      onClose();
    } else {
      // Create new account
      const result = await accountService.createAccount(accountData);
      if (!result.success) {
        toast.error(result.error || 'Failed to create account');
        return;
      }

      toast.success('Account created');
      logAuditEvent({
        orgId: activeOrgId || '',
        action: 'account.created',
        entityType: 'account',
        entityId: result.accountId,
        after: { name: values.name },
      }).catch(console.error);

      onSuccess?.(result.accountId!);
      onClose();
    }
  };

  const { values, errors, loading, handleChange, handleSubmit: onFormSubmit, reset } = useForm<AccountFormValues>({
    initialValues: getInitialValues(),
    validate: (vals) => {
      const errs: Partial<Record<keyof AccountFormValues, string>> = {};
      if (!vals.name.trim()) errs.name = 'Account name is required';
      if (vals.website && !/^(https?:\/\/)?[\w.-]+\.[a-z]{2,}(\/.*)?$/i.test(vals.website)) {
        errs.website = 'Invalid website URL';
      }
      if (vals.annual_revenue && isNaN(Number(vals.annual_revenue))) {
        errs.annual_revenue = 'Must be a number';
      }
      if (vals.employee_count && isNaN(Number(vals.employee_count))) {
        errs.employee_count = 'Must be a number';
      }
      return errs;
    },
    onSubmit: handleSubmit,
  });

  // Reset form when modal opens/closes or account changes
  useEffect(() => {
    if (open) {
      reset();
    }
  }, [open, account]);

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={isEdit ? 'Edit Account' : 'New Account'}
      description={isEdit ? 'Update account details' : 'Enter account details'}
      variant="slideOver"
      size="lg"
    >
      <form onSubmit={onFormSubmit} className="space-y-6">
        {/* Basic Information */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-th-text-primary uppercase tracking-wider">
            Basic Information
          </h3>
          <InputField
            label="Account Name"
            name="name"
            value={values.name}
            onChange={handleChange}
            error={errors.name}
            required
            placeholder="Acme Corporation"
          />
          <div className="grid grid-cols-2 gap-4">
            <SelectField
              label="Account Type"
              name="account_type"
              value={values.account_type}
              onChange={handleChange}
              options={ACCOUNT_TYPE_OPTIONS}
              required
            />
            <SelectField
              label="Rating"
              name="rating"
              value={values.rating}
              onChange={handleChange}
              options={RATING_OPTIONS}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <SelectField
              label="Industry"
              name="industry"
              value={values.industry}
              onChange={handleChange}
              options={INDUSTRY_OPTIONS}
            />
            <SelectField
              label="Owner"
              name="owner_id"
              value={values.owner_id}
              onChange={handleChange}
              options={[
                { value: '', label: 'Select Owner...' },
                ...teamMembers.map((m) => ({
                  value: m.id,
                  label: m.full_name || m.email,
                })),
              ]}
            />
          </div>
        </div>

        {/* Contact Information */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-th-text-primary uppercase tracking-wider">
            Contact Information
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <InputField
              label="Phone"
              name="phone"
              type="tel"
              value={values.phone}
              onChange={handleChange}
              placeholder="(555) 123-4567"
            />
            <InputField
              label="Fax"
              name="fax"
              type="tel"
              value={values.fax}
              onChange={handleChange}
              placeholder="(555) 123-4568"
            />
          </div>
          <InputField
            label="Website"
            name="website"
            value={values.website}
            onChange={handleChange}
            error={errors.website}
            placeholder="https://www.example.com"
          />
        </div>

        {/* Address */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-th-text-primary uppercase tracking-wider">
            Address
          </h3>
          <InputField
            label="Street"
            name="street"
            value={values.street}
            onChange={handleChange}
            placeholder="123 Main Street"
          />
          <div className="grid grid-cols-2 gap-4">
            <InputField
              label="City"
              name="city"
              value={values.city}
              onChange={handleChange}
              placeholder="New York"
            />
            <InputField
              label="State/Province"
              name="state"
              value={values.state}
              onChange={handleChange}
              placeholder="NY"
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <InputField
              label="ZIP/Postal Code"
              name="zip"
              value={values.zip}
              onChange={handleChange}
              placeholder="10001"
            />
            <InputField
              label="Country"
              name="country"
              value={values.country}
              onChange={handleChange}
              placeholder="USA"
            />
          </div>
        </div>

        {/* Company Details */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-th-text-primary uppercase tracking-wider">
            Company Details
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <InputField
              label="Annual Revenue"
              name="annual_revenue"
              type="number"
              value={values.annual_revenue}
              onChange={handleChange}
              error={errors.annual_revenue}
              placeholder="1000000"
            />
            <InputField
              label="Number of Employees"
              name="employee_count"
              type="number"
              value={values.employee_count}
              onChange={handleChange}
              error={errors.employee_count}
              placeholder="50"
            />
          </div>
          <TextareaField
            label="Description"
            name="description"
            value={values.description}
            onChange={handleChange}
            rows={3}
            placeholder="Enter a description of this account..."
          />
        </div>

        {/* Social & Tags */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-th-text-primary uppercase tracking-wider">
            Social & Tags
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <InputField
              label="LinkedIn URL"
              name="linkedin_url"
              value={values.linkedin_url}
              onChange={handleChange}
              placeholder="https://linkedin.com/company/..."
            />
            <InputField
              label="Twitter Handle"
              name="twitter_handle"
              value={values.twitter_handle}
              onChange={handleChange}
              placeholder="@company"
            />
          </div>
          <InputField
            label="Tags"
            name="tags"
            value={values.tags}
            onChange={handleChange}
            placeholder="Comma-separated tags, e.g. enterprise, healthcare"
          />
        </div>

        {/* Actions */}
        <div className="flex items-center gap-3 pt-4 border-t border-th-border">
          <SubmitButton
            loading={loading}
            label={isEdit ? 'Update Account' : 'Create Account'}
            loadingLabel={isEdit ? 'Updating...' : 'Creating...'}
          />
          <button
            type="button"
            onClick={onClose}
            className="flex-1 px-4 py-2.5 text-sm font-medium text-th-text-secondary bg-surface-primary border border-th-border rounded-lg hover:bg-surface-secondary transition-colors"
          >
            Cancel
          </button>
        </div>
      </form>
    </Modal>
  );
}

import { useState, useEffect } from 'react';
import { Search, Users, UserPlus, Check } from 'lucide-react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { useCRM } from '../contexts/CRMContext';
import type { Lead, ContactWithRelations } from '@mpbhealth/crm-core';

interface AddCampaignMembersModalProps {
  open: boolean;
  onClose: () => void;
  campaignId: string;
  onSuccess?: () => void;
}

type MemberType = 'leads' | 'contacts';

export function AddCampaignMembersModal({
  open,
  onClose,
  campaignId,
  onSuccess,
}: AddCampaignMembersModalProps) {
  const { campaignService, leadService, contactService } = useCRM();

  const [loading, setLoading] = useState(false);
  const [adding, setAdding] = useState(false);
  const [memberType, setMemberType] = useState<MemberType>('leads');
  const [search, setSearch] = useState('');
  const [leads, setLeads] = useState<Lead[]>([]);
  const [contacts, setContacts] = useState<ContactWithRelations[]>([]);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Load leads or contacts based on selected type
  useEffect(() => {
    if (!open) return;

    const loadMembers = async () => {
      setLoading(true);
      setSelectedIds(new Set());

      if (memberType === 'leads') {
        const { leads } = await leadService.getLeads(
          { search: search || undefined },
          50,
          0
        );
        setLeads(leads);
      } else {
        const { contacts } = await contactService.getContacts(
          { search: search || undefined },
          50,
          0
        );
        setContacts(contacts);
      }

      setLoading(false);
    };

    loadMembers();
  }, [open, memberType, search, leadService, contactService]);

  // Reset when modal closes
  useEffect(() => {
    if (!open) {
      setSearch('');
      setSelectedIds(new Set());
      setMemberType('leads');
    }
  }, [open]);

  const toggleSelection = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const toggleSelectAll = () => {
    const items = memberType === 'leads' ? leads : contacts;
    if (selectedIds.size === items.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(items.map((item) => item.id)));
    }
  };

  const handleAddMembers = async () => {
    if (selectedIds.size === 0) {
      toast.error('Please select at least one member to add');
      return;
    }

    setAdding(true);

    let result;
    const ids = Array.from(selectedIds);

    if (memberType === 'leads') {
      result = await campaignService.addLeadsToCampaign(campaignId, ids);
    } else {
      result = await campaignService.addContactsToCampaign(campaignId, ids);
    }

    setAdding(false);

    if (result.success) {
      toast.success(`Added ${result.addedCount} member(s) to campaign`);
      onSuccess?.();
      onClose();
    } else {
      toast.error(result.error || 'Failed to add members');
    }
  };

  const items = memberType === 'leads' ? leads : contacts;

  return (
    <Modal
      open={open}
      onClose={onClose}
      title="Add Campaign Members"
      description="Select leads or contacts to add to this campaign"
      variant="slideOver"
      size="lg"
    >
      <div className="space-y-4">
        {/* Member Type Toggle */}
        <div className="flex bg-surface-tertiary rounded-lg p-1">
          <button
            onClick={() => setMemberType('leads')}
            className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-colors ${
              memberType === 'leads'
                ? 'bg-surface-primary text-th-text-primary shadow-sm'
                : 'text-th-text-tertiary hover:text-th-text-secondary'
            }`}
          >
            <Users className="w-4 h-4" />
            Leads
          </button>
          <button
            onClick={() => setMemberType('contacts')}
            className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-colors ${
              memberType === 'contacts'
                ? 'bg-surface-primary text-th-text-primary shadow-sm'
                : 'text-th-text-tertiary hover:text-th-text-secondary'
            }`}
          >
            <UserPlus className="w-4 h-4" />
            Contacts
          </button>
        </div>

        {/* Search */}
        <div className="flex items-center bg-surface-tertiary rounded-lg px-3 py-2">
          <Search className="w-4 h-4 text-th-text-tertiary mr-2" />
          <input
            type="text"
            placeholder={`Search ${memberType}...`}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="bg-transparent border-none outline-none text-sm w-full text-th-text-secondary placeholder-th-text-tertiary"
          />
        </div>

        {/* Selection header */}
        <div className="flex items-center justify-between px-2">
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              checked={items.length > 0 && selectedIds.size === items.length}
              onChange={toggleSelectAll}
              className="w-4 h-4 rounded border-th-border"
            />
            <span className="text-sm text-th-text-secondary">Select all</span>
          </label>
          {selectedIds.size > 0 && (
            <span className="text-sm text-th-accent-600">{selectedIds.size} selected</span>
          )}
        </div>

        {/* Members list */}
        <div className="border border-th-border rounded-lg overflow-hidden max-h-[400px] overflow-y-auto">
          {loading ? (
            <div className="flex items-center justify-center py-12">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-th-accent-600" />
            </div>
          ) : items.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-th-text-tertiary">
              <Users className="w-10 h-10 mb-2 opacity-50" />
              <p className="text-sm">No {memberType} found</p>
              {search && (
                <p className="text-xs mt-1">Try a different search term</p>
              )}
            </div>
          ) : (
            <div className="divide-y divide-th-border">
              {memberType === 'leads'
                ? leads.map((lead) => (
                    <MemberRow
                      key={lead.id}
                      id={lead.id}
                      name={`${lead.first_name} ${lead.last_name}`}
                      email={lead.email}
                      subtitle={lead.current_insurance || lead.zip_code || undefined}
                      selected={selectedIds.has(lead.id)}
                      onToggle={() => toggleSelection(lead.id)}
                    />
                  ))
                : contacts.map((contact) => (
                    <MemberRow
                      key={contact.id}
                      id={contact.id}
                      name={`${contact.first_name} ${contact.last_name}`}
                      email={contact.email || undefined}
                      subtitle={contact.account?.name}
                      selected={selectedIds.has(contact.id)}
                      onToggle={() => toggleSelection(contact.id)}
                    />
                  ))}
            </div>
          )}
        </div>

        {/* Actions */}
        <div className="flex justify-end gap-3 pt-4 border-t border-th-border">
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-th-text-secondary hover:bg-surface-secondary rounded-lg"
          >
            Cancel
          </button>
          <button
            onClick={handleAddMembers}
            disabled={adding || selectedIds.size === 0}
            className="px-4 py-2 text-sm font-medium text-white bg-th-accent-600 hover:bg-th-accent-700 rounded-lg disabled:opacity-50"
          >
            {adding ? 'Adding...' : `Add ${selectedIds.size} Member${selectedIds.size !== 1 ? 's' : ''}`}
          </button>
        </div>
      </div>
    </Modal>
  );
}

// Helper component for member rows
function MemberRow({
  id,
  name,
  email,
  subtitle,
  selected,
  onToggle,
}: {
  id: string;
  name: string;
  email?: string;
  subtitle?: string;
  selected: boolean;
  onToggle: () => void;
}) {
  return (
    <div
      onClick={onToggle}
      className={`flex items-center gap-3 px-4 py-3 cursor-pointer transition-colors ${
        selected ? 'bg-th-accent-50' : 'hover:bg-surface-secondary'
      }`}
    >
      <div
        className={`w-5 h-5 rounded border flex items-center justify-center ${
          selected
            ? 'bg-th-accent-600 border-th-accent-600'
            : 'border-th-border bg-surface-primary'
        }`}
      >
        {selected && <Check className="w-3 h-3 text-white" />}
      </div>
      <div className="w-8 h-8 bg-th-accent-100 rounded-full flex items-center justify-center">
        <span className="text-th-accent-700 font-medium text-sm">
          {name.charAt(0).toUpperCase()}
        </span>
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-sm font-medium text-th-text-primary truncate">{name}</p>
        {email && (
          <p className="text-xs text-th-text-tertiary truncate">{email}</p>
        )}
      </div>
      {subtitle && (
        <span className="text-xs text-th-text-tertiary bg-surface-tertiary px-2 py-0.5 rounded">
          {subtitle}
        </span>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import { logAuditEvent, AUDIT_ACTIONS } from '@mpbhealth/auth';
import type {
  CampaignWithRelations,
  CampaignCreateInput,
  CampaignType,
  CampaignStatus,
} from '@mpbhealth/crm-core';

interface AddCampaignModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess?: (campaignId: string) => void;
  campaign?: CampaignWithRelations | null;
}

export function AddCampaignModal({
  open,
  onClose,
  onSuccess,
  campaign,
}: AddCampaignModalProps) {
  const { campaignService } = useCRM();
  const { activeOrgId } = useOrg();

  const [loading, setLoading] = useState(false);

  // Form state
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [campaignType, setCampaignType] = useState<CampaignType>('email');
  const [status, setStatus] = useState<CampaignStatus>('draft');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [budget, setBudget] = useState('');
  const [actualCost, setActualCost] = useState('');
  const [expectedRevenue, setExpectedRevenue] = useState('');
  const [actualRevenue, setActualRevenue] = useState('');
  const [expectedResponse, setExpectedResponse] = useState('');
  const [tags, setTags] = useState('');

  // Initialize form when campaign prop changes or modal opens
  useEffect(() => {
    if (open) {
      if (campaign) {
        setName(campaign.name);
        setDescription(campaign.description || '');
        setCampaignType(campaign.campaign_type);
        setStatus(campaign.status);
        setStartDate(campaign.start_date?.split('T')[0] || '');
        setEndDate(campaign.end_date?.split('T')[0] || '');
        setBudget(campaign.budget?.toString() || '');
        setActualCost(campaign.actual_cost?.toString() || '');
        setExpectedRevenue(campaign.expected_revenue?.toString() || '');
        setActualRevenue(campaign.actual_revenue?.toString() || '');
        setExpectedResponse(campaign.expected_response?.toString() || '');
        setTags(campaign.tags?.join(', ') || '');
      } else {
        // Reset form for new campaign
        setName('');
        setDescription('');
        setCampaignType('email');
        setStatus('draft');
        setStartDate('');
        setEndDate('');
        setBudget('');
        setActualCost('');
        setExpectedRevenue('');
        setActualRevenue('');
        setExpectedResponse('');
        setTags('');
      }
    }
  }, [open, campaign]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!name.trim()) {
      toast.error('Campaign name is required');
      return;
    }

    setLoading(true);

    const tagsArray = tags
      .split(',')
      .map((t) => t.trim())
      .filter(Boolean);

    const input: CampaignCreateInput = {
      name: name.trim(),
      description: description || undefined,
      campaign_type: campaignType,
      status,
      start_date: startDate || undefined,
      end_date: endDate || undefined,
      budget: budget ? parseFloat(budget) : undefined,
      expected_revenue: expectedRevenue ? parseFloat(expectedRevenue) : undefined,
      expected_response: expectedResponse ? parseFloat(expectedResponse) : undefined,
      tags: tagsArray.length > 0 ? tagsArray : undefined,
    };

    let result;

    if (campaign) {
      // Update existing campaign
      result = await campaignService.updateCampaign(campaign.id, {
        ...input,
        actual_cost: actualCost ? parseFloat(actualCost) : undefined,
        actual_revenue: actualRevenue ? parseFloat(actualRevenue) : undefined,
      });
      if (result.success) {
        toast.success('Campaign updated');
        logAuditEvent({
          orgId: activeOrgId || '',
          action: 'campaign.updated',
          entityType: 'campaign',
          entityId: campaign.id,
          before: { name: campaign.name },
          after: { name: input.name },
        }).catch(console.error);
        onSuccess?.(campaign.id);
        onClose();
      } else {
        toast.error(result.error || 'Failed to update campaign');
      }
    } else {
      // Create new campaign
      result = await campaignService.createCampaign(input);
      if (result.success && result.campaignId) {
        toast.success('Campaign created');
        logAuditEvent({
          orgId: activeOrgId || '',
          action: 'campaign.created',
          entityType: 'campaign',
          entityId: result.campaignId,
          after: { name: input.name },
        }).catch(console.error);
        onSuccess?.(result.campaignId);
        onClose();
      } else {
        toast.error(result.error || 'Failed to create campaign');
      }
    }

    setLoading(false);
  };

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={campaign ? 'Edit Campaign' : 'New Campaign'}
      description={campaign ? 'Update campaign details' : 'Create a new marketing campaign'}
      variant="slideOver"
      size="lg"
    >
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Campaign Name */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Campaign Name <span className="text-red-500">*</span>
          </label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Enter campaign name"
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            required
          />
        </div>

        {/* Type & Status */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-th-text-secondary mb-1">
              Campaign Type
            </label>
            <select
              value={campaignType}
              onChange={(e) => setCampaignType(e.target.value as CampaignType)}
              className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              <option value="email">Email</option>
              <option value="social">Social Media</option>
              <option value="event">Event</option>
              <option value="webinar">Webinar</option>
              <option value="advertisement">Advertisement</option>
              <option value="referral">Referral</option>
              <option value="other">Other</option>
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-th-text-secondary mb-1">
              Status
            </label>
            <select
              value={status}
              onChange={(e) => setStatus(e.target.value as CampaignStatus)}
              className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              <option value="draft">Draft</option>
              <option value="scheduled">Scheduled</option>
              <option value="active">Active</option>
              <option value="paused">Paused</option>
              <option value="completed">Completed</option>
              <option value="cancelled">Cancelled</option>
            </select>
          </div>
        </div>

        {/* Description */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Description
          </label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Describe the campaign objectives and strategy..."
            rows={3}
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          />
        </div>

        {/* Dates */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-th-text-secondary mb-1">
              Start Date
            </label>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-th-text-secondary mb-1">
              End Date
            </label>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            />
          </div>
        </div>

        {/* Budget Section */}
        <div className="border-t border-th-border pt-4">
          <h3 className="text-sm font-semibold text-th-text-primary mb-3">Budget & Revenue</h3>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Budget
              </label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-th-text-tertiary">$</span>
                <input
                  type="number"
                  value={budget}
                  onChange={(e) => setBudget(e.target.value)}
                  placeholder="0.00"
                  min="0"
                  step="0.01"
                  className="w-full border border-th-border rounded-lg pl-7 pr-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Actual Cost
              </label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-th-text-tertiary">$</span>
                <input
                  type="number"
                  value={actualCost}
                  onChange={(e) => setActualCost(e.target.value)}
                  placeholder="0.00"
                  min="0"
                  step="0.01"
                  className="w-full border border-th-border rounded-lg pl-7 pr-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Expected Revenue
              </label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-th-text-tertiary">$</span>
                <input
                  type="number"
                  value={expectedRevenue}
                  onChange={(e) => setExpectedRevenue(e.target.value)}
                  placeholder="0.00"
                  min="0"
                  step="0.01"
                  className="w-full border border-th-border rounded-lg pl-7 pr-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Actual Revenue
              </label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-th-text-tertiary">$</span>
                <input
                  type="number"
                  value={actualRevenue}
                  onChange={(e) => setActualRevenue(e.target.value)}
                  placeholder="0.00"
                  min="0"
                  step="0.01"
                  className="w-full border border-th-border rounded-lg pl-7 pr-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
            </div>
          </div>
        </div>

        {/* Expected Response */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Expected Response (%)
          </label>
          <input
            type="number"
            value={expectedResponse}
            onChange={(e) => setExpectedResponse(e.target.value)}
            placeholder="0"
            min="0"
            max="100"
            step="0.1"
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          />
          <p className="mt-1 text-xs text-th-text-tertiary">Percentage of members expected to respond</p>
        </div>

        {/* Tags */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Tags
          </label>
          <input
            type="text"
            value={tags}
            onChange={(e) => setTags(e.target.value)}
            placeholder="product-launch, q1-2026, email"
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          />
          <p className="mt-1 text-xs text-th-text-tertiary">Separate tags with commas</p>
        </div>

        {/* Actions */}
        <div className="flex justify-end gap-3 pt-4 border-t border-th-border">
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-th-text-secondary hover:bg-surface-secondary rounded-lg"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="px-4 py-2 text-sm font-medium text-white bg-th-accent-600 hover:bg-th-accent-700 rounded-lg disabled:opacity-50"
          >
            {loading ? 'Saving...' : campaign ? 'Update Campaign' : 'Create Campaign'}
          </button>
        </div>
      </form>
    </Modal>
  );
}

import { useState, useEffect } from 'react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import { logAuditEvent, AUDIT_ACTIONS } from '@mpbhealth/auth';
import type {
  DealWithRelations,
  DealCreateInput,
  AccountWithRelations,
  ContactWithRelations,
} from '@mpbhealth/crm-core';

interface AddDealModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess?: (dealId: string) => void;
  deal?: DealWithRelations | null;
  defaultStageId?: string;
  defaultAccountId?: string;
}

export function AddDealModal({
  open,
  onClose,
  onSuccess,
  deal,
  defaultStageId,
  defaultAccountId,
}: AddDealModalProps) {
  const { dealService, accountService, contactService, dealStages, refreshDashboard } = useCRM();
  const { activeOrgId } = useOrg();

  const [loading, setLoading] = useState(false);
  const [accounts, setAccounts] = useState<AccountWithRelations[]>([]);
  const [contacts, setContacts] = useState<ContactWithRelations[]>([]);
  const [loadingAccounts, setLoadingAccounts] = useState(false);
  const [loadingContacts, setLoadingContacts] = useState(false);

  // Form state
  const [name, setName] = useState('');
  const [amount, setAmount] = useState('');
  const [stageId, setStageId] = useState('');
  const [accountId, setAccountId] = useState('');
  const [contactId, setContactId] = useState('');
  const [expectedCloseDate, setExpectedCloseDate] = useState('');
  const [dealType, setDealType] = useState<'new_business' | 'existing_business' | 'renewal'>('new_business');
  const [leadSource, setLeadSource] = useState('');
  const [nextStep, setNextStep] = useState('');
  const [tags, setTags] = useState('');
  const [description, setDescription] = useState('');

  // Load accounts
  useEffect(() => {
    if (!open) return;

    const loadAccounts = async () => {
      setLoadingAccounts(true);
      const { accounts } = await accountService.getAccounts({}, 100, 0);
      setAccounts(accounts);
      setLoadingAccounts(false);
    };

    loadAccounts();
  }, [open, accountService]);

  // Load contacts when account changes
  useEffect(() => {
    if (!accountId) {
      setContacts([]);
      return;
    }

    const loadContacts = async () => {
      setLoadingContacts(true);
      const { contacts } = await contactService.getContacts({ account_id: accountId }, 100, 0);
      setContacts(contacts);
      setLoadingContacts(false);
    };

    loadContacts();
  }, [accountId, contactService]);

  // Initialize form when deal prop changes or modal opens
  useEffect(() => {
    if (open) {
      if (deal) {
        setName(deal.name);
        setAmount(deal.amount?.toString() || '');
        setStageId(deal.stage_id);
        setAccountId(deal.account_id || '');
        setContactId(deal.contact_id || '');
        setExpectedCloseDate(deal.expected_close_date?.split('T')[0] || '');
        setDealType(deal.deal_type || 'new_business');
        setLeadSource(deal.lead_source || '');
        setNextStep(deal.next_step || '');
        setTags(deal.tags?.join(', ') || '');
        setDescription(deal.description || '');
      } else {
        // Reset form for new deal
        setName('');
        setAmount('');
        setStageId(defaultStageId || (dealStages[0]?.id || ''));
        setAccountId(defaultAccountId || '');
        setContactId('');
        setExpectedCloseDate('');
        setDealType('new_business');
        setLeadSource('');
        setNextStep('');
        setTags('');
        setDescription('');
      }
    }
  }, [open, deal, defaultStageId, defaultAccountId, dealStages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!name.trim()) {
      toast.error('Deal name is required');
      return;
    }
    if (!stageId) {
      toast.error('Please select a stage');
      return;
    }

    setLoading(true);

    const tagsArray = tags
      .split(',')
      .map((t) => t.trim())
      .filter(Boolean);

    const input: DealCreateInput = {
      name: name.trim(),
      amount: amount ? parseFloat(amount) : undefined,
      stage_id: stageId,
      account_id: accountId || undefined,
      contact_id: contactId || undefined,
      expected_close_date: expectedCloseDate || undefined,
      deal_type: dealType,
      lead_source: leadSource || undefined,
      next_step: nextStep || undefined,
      tags: tagsArray.length > 0 ? tagsArray : undefined,
      description: description || undefined,
    };

    let result;

    if (deal) {
      // Update existing deal
      result = await dealService.updateDeal(deal.id, input);
      if (result.success) {
        toast.success('Deal updated');
        logAuditEvent({
          orgId: activeOrgId || '',
          action: AUDIT_ACTIONS.DEAL_UPDATED || 'deal.updated',
          entityType: 'deal',
          entityId: deal.id,
          before: { name: deal.name, amount: deal.amount },
          after: { name: input.name, amount: input.amount },
        }).catch(console.error);
        refreshDashboard();
        onSuccess?.(deal.id);
        onClose();
      } else {
        toast.error(result.error || 'Failed to update deal');
      }
    } else {
      // Create new deal
      result = await dealService.createDeal(input);
      if (result.success && result.dealId) {
        toast.success('Deal created');
        logAuditEvent({
          orgId: activeOrgId || '',
          action: AUDIT_ACTIONS.DEAL_CREATED || 'deal.created',
          entityType: 'deal',
          entityId: result.dealId,
          after: { name: input.name, amount: input.amount },
        }).catch(console.error);
        refreshDashboard();
        onSuccess?.(result.dealId);
        onClose();
      } else {
        toast.error(result.error || 'Failed to create deal');
      }
    }

    setLoading(false);
  };

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={deal ? 'Edit Deal' : 'New Deal'}
      description={deal ? 'Update deal details' : 'Create a new deal'}
      variant="slideOver"
      size="lg"
    >
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Deal Name */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Deal Name <span className="text-red-500">*</span>
          </label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Enter deal name"
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            required
          />
        </div>

        {/* Amount */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Amount
          </label>
          <div className="relative">
            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-th-text-tertiary">$</span>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              placeholder="0.00"
              min="0"
              step="0.01"
              className="w-full border border-th-border rounded-lg pl-7 pr-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            />
          </div>
        </div>

        {/* Stage */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Stage <span className="text-red-500">*</span>
          </label>
          <select
            value={stageId}
            onChange={(e) => setStageId(e.target.value)}
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            required
          >
            <option value="">Select a stage</option>
            {dealStages.map((stage) => (
              <option key={stage.id} value={stage.id}>
                {stage.display_name} ({stage.probability}%)
              </option>
            ))}
          </select>
        </div>

        {/* Account */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Account
          </label>
          <select
            value={accountId}
            onChange={(e) => {
              setAccountId(e.target.value);
              setContactId(''); // Reset contact when account changes
            }}
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            disabled={loadingAccounts}
          >
            <option value="">Select an account</option>
            {accounts.map((account) => (
              <option key={account.id} value={account.id}>
                {account.name}
              </option>
            ))}
          </select>
        </div>

        {/* Contact */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Primary Contact
          </label>
          <select
            value={contactId}
            onChange={(e) => setContactId(e.target.value)}
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            disabled={!accountId || loadingContacts}
          >
            <option value="">{accountId ? 'Select a contact' : 'Select an account first'}</option>
            {contacts.map((contact) => (
              <option key={contact.id} value={contact.id}>
                {contact.first_name} {contact.last_name}
                {contact.email ? ` (${contact.email})` : ''}
              </option>
            ))}
          </select>
        </div>

        {/* Expected Close Date */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Expected Close Date
          </label>
          <input
            type="date"
            value={expectedCloseDate}
            onChange={(e) => setExpectedCloseDate(e.target.value)}
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          />
        </div>

        {/* Deal Type */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Deal Type
          </label>
          <select
            value={dealType}
            onChange={(e) => setDealType(e.target.value as any)}
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          >
            <option value="new_business">New Business</option>
            <option value="existing_business">Existing Business</option>
            <option value="renewal">Renewal</option>
          </select>
        </div>

        {/* Lead Source */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Lead Source
          </label>
          <input
            type="text"
            value={leadSource}
            onChange={(e) => setLeadSource(e.target.value)}
            placeholder="e.g., Website, Referral, Cold Call"
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          />
        </div>

        {/* Next Step */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Next Step
          </label>
          <input
            type="text"
            value={nextStep}
            onChange={(e) => setNextStep(e.target.value)}
            placeholder="Describe the next action"
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          />
        </div>

        {/* Tags */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Tags
          </label>
          <input
            type="text"
            value={tags}
            onChange={(e) => setTags(e.target.value)}
            placeholder="Comma-separated tags"
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          />
          <p className="mt-1 text-xs text-th-text-tertiary">Separate tags with commas</p>
        </div>

        {/* Description */}
        <div>
          <label className="block text-sm font-medium text-th-text-secondary mb-1">
            Description
          </label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Add any additional details..."
            rows={3}
            className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
          />
        </div>

        {/* Actions */}
        <div className="flex justify-end gap-3 pt-4 border-t border-th-border">
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-th-text-secondary hover:bg-surface-secondary rounded-lg"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="px-4 py-2 text-sm font-medium text-white bg-th-accent-600 hover:bg-th-accent-700 rounded-lg disabled:opacity-50"
          >
            {loading ? 'Saving...' : deal ? 'Update Deal' : 'Create Deal'}
          </button>
        </div>
      </form>
    </Modal>
  );
}

import { useState, useEffect, useCallback } from 'react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { InputField, SelectField, TextareaField, SubmitButton } from './FormField';
import { useForm } from '../hooks/useForm';
import { useCRM } from '../contexts/CRMContext';
import type { Lead } from '@mpbhealth/crm-core';

interface EditableEvent {
  id: string;
  title: string;
  event_type: string;
  start_time: string;
  end_time: string;
  all_day?: boolean;
  location?: string;
  meeting_link?: string;
  lead_id?: string;
  reminder_minutes?: number;
  description?: string;
}

interface AddEventModalProps {
  open: boolean;
  onClose: () => void;
  defaultDate?: string; // YYYY-MM-DD
  leadId?: string;
  editEvent?: EditableEvent | null;
  onSuccess?: () => void;
}

interface EventFormValues {
  title: string;
  event_type: string;
  start_date: string;
  start_time: string;
  end_date: string;
  end_time: string;
  all_day: string;
  location: string;
  meeting_link: string;
  lead_id: string;
  reminder_minutes: string;
  description: string;
}

const EVENT_TYPE_OPTIONS = [
  { value: 'meeting', label: 'Meeting' },
  { value: 'call', label: 'Call' },
  { value: 'follow_up', label: 'Follow Up' },
  { value: 'deadline', label: 'Deadline' },
  { value: 'reminder', label: 'Reminder' },
  { value: 'other', label: 'Other' },
];

const REMINDER_OPTIONS = [
  { value: '', label: 'No Reminder' },
  { value: '5', label: '5 minutes before' },
  { value: '15', label: '15 minutes before' },
  { value: '30', label: '30 minutes before' },
  { value: '60', label: '1 hour before' },
  { value: '1440', label: '1 day before' },
];

export function AddEventModal({ open, onClose, defaultDate, leadId, editEvent, onSuccess }: AddEventModalProps) {
  const { calendarService, leadService } = useCRM();
  const [leadSearch, setLeadSearch] = useState('');
  const [leadResults, setLeadResults] = useState<Lead[]>([]);
  const [showLeadDropdown, setShowLeadDropdown] = useState(false);

  const isEditing = !!editEvent;
  const today = defaultDate || new Date().toISOString().split('T')[0];

  function getInitialValues(): EventFormValues {
    if (editEvent) {
      const start = new Date(editEvent.start_time);
      const end = new Date(editEvent.end_time);
      const startDate = start.toISOString().split('T')[0];
      const endDate = end.toISOString().split('T')[0];
      const startTime = `${String(start.getHours()).padStart(2, '0')}:${String(start.getMinutes()).padStart(2, '0')}`;
      const endTime = `${String(end.getHours()).padStart(2, '0')}:${String(end.getMinutes()).padStart(2, '0')}`;

      return {
        title: editEvent.title || '',
        event_type: editEvent.event_type || 'meeting',
        start_date: startDate,
        start_time: startTime,
        end_date: endDate,
        end_time: endTime,
        all_day: editEvent.all_day ? 'true' : 'false',
        location: editEvent.location || '',
        meeting_link: editEvent.meeting_link || '',
        lead_id: editEvent.lead_id || leadId || '',
        reminder_minutes: editEvent.reminder_minutes?.toString() || '15',
        description: editEvent.description || '',
      };
    }
    return {
      title: '',
      event_type: 'meeting',
      start_date: today,
      start_time: '09:00',
      end_date: today,
      end_time: '10:00',
      all_day: 'false',
      location: '',
      meeting_link: '',
      lead_id: leadId || '',
      reminder_minutes: '15',
      description: '',
    };
  }

  const { values, errors, loading, handleChange, handleSubmit, setFieldValue, reset } = useForm<EventFormValues>({
    initialValues: getInitialValues(),
    validate: (vals) => {
      const errs: Partial<Record<keyof EventFormValues, string>> = {};
      if (!vals.title.trim()) errs.title = 'Title is required';
      if (!vals.start_date) errs.start_date = 'Start date is required';
      if (!vals.end_date) errs.end_date = 'End date is required';
      if (vals.all_day !== 'true') {
        if (!vals.start_time) errs.start_time = 'Start time is required';
        if (!vals.end_time) errs.end_time = 'End time is required';
      }
      return errs;
    },
    onSubmit: async (vals) => {
      const isAllDay = vals.all_day === 'true';
      const startTime = isAllDay
        ? `${vals.start_date}T00:00:00`
        : `${vals.start_date}T${vals.start_time}`;
      const endTime = isAllDay
        ? `${vals.end_date}T23:59:59`
        : `${vals.end_date}T${vals.end_time}`;

      const eventData = {
        title: vals.title,
        event_type: vals.event_type as any,
        start_time: startTime,
        end_time: endTime,
        all_day: isAllDay,
        location: vals.location || undefined,
        meeting_link: vals.meeting_link || undefined,
        lead_id: vals.lead_id || undefined,
        reminder_minutes: vals.reminder_minutes ? Number(vals.reminder_minutes) : undefined,
        description: vals.description || undefined,
      };

      const result = isEditing
        ? await calendarService.updateEvent(editEvent!.id, eventData)
        : await calendarService.createEvent(eventData);

      if (!result.success) {
        toast.error(result.error || `Failed to ${isEditing ? 'update' : 'create'} event`);
        return;
      }

      toast.success(isEditing ? 'Event updated' : 'Event created');
      onSuccess?.();
      onClose();
    },
  });

  // Reset form when editEvent changes
  useEffect(() => {
    if (open) {
      reset(getInitialValues());
    }
  }, [editEvent, open]);

  // Lead search with debounce
  const searchLeads = useCallback(async (query: string) => {
    if (query.length < 2) {
      setLeadResults([]);
      return;
    }
    const { leads } = await leadService.getLeads({ search: query }, 5, 0);
    setLeadResults(leads);
    setShowLeadDropdown(true);
  }, [leadService]);

  useEffect(() => {
    const timer = setTimeout(() => searchLeads(leadSearch), 300);
    return () => clearTimeout(timer);
  }, [leadSearch, searchLeads]);

  const selectLead = (lead: Lead) => {
    setFieldValue('lead_id', lead.id);
    setLeadSearch(`${lead.first_name} ${lead.last_name}`);
    setShowLeadDropdown(false);
  };

  const isAllDay = values.all_day === 'true';

  return (
    <Modal open={open} onClose={onClose} title={isEditing ? 'Edit Event' : 'Add Event'} size="lg">
      <form onSubmit={handleSubmit} className="space-y-4">
        <InputField
          label="Title"
          name="title"
          value={values.title}
          onChange={handleChange}
          error={errors.title}
          required
          placeholder="e.g. Benefits review meeting"
        />

        <div className="grid grid-cols-2 gap-4">
          <SelectField
            label="Event Type"
            name="event_type"
            value={values.event_type}
            onChange={handleChange}
            options={EVENT_TYPE_OPTIONS}
          />
          <SelectField
            label="Reminder"
            name="reminder_minutes"
            value={values.reminder_minutes}
            onChange={handleChange}
            options={REMINDER_OPTIONS}
          />
        </div>

        {/* All-day toggle */}
        <label className="flex items-center gap-2 text-sm">
          <input
            type="checkbox"
            checked={isAllDay}
            onChange={(e) => setFieldValue('all_day', e.target.checked ? 'true' : 'false')}
            className="w-4 h-4 rounded border-th-border"
          />
          <span className="text-th-text-secondary">All day event</span>
        </label>

        {/* Start */}
        <div className="grid grid-cols-2 gap-4">
          <InputField
            label="Start Date"
            name="start_date"
            type="date"
            value={values.start_date}
            onChange={handleChange}
            error={errors.start_date}
            required
          />
          {!isAllDay && (
            <InputField
              label="Start Time"
              name="start_time"
              type="time"
              value={values.start_time}
              onChange={handleChange}
              error={errors.start_time}
              required
            />
          )}
        </div>

        {/* End */}
        <div className="grid grid-cols-2 gap-4">
          <InputField
            label="End Date"
            name="end_date"
            type="date"
            value={values.end_date}
            onChange={handleChange}
            error={errors.end_date}
            required
          />
          {!isAllDay && (
            <InputField
              label="End Time"
              name="end_time"
              type="time"
              value={values.end_time}
              onChange={handleChange}
              error={errors.end_time}
              required
            />
          )}
        </div>

        <div className="grid grid-cols-2 gap-4">
          <InputField
            label="Location"
            name="location"
            value={values.location}
            onChange={handleChange}
            placeholder="e.g. Office / Zoom"
          />
          <InputField
            label="Meeting Link"
            name="meeting_link"
            value={values.meeting_link}
            onChange={handleChange}
            placeholder="https://..."
          />
        </div>

        {/* Lead selector */}
        {!leadId && (
          <div className="relative">
            <InputField
              label="Link to Lead (optional)"
              name="lead_search"
              value={leadSearch}
              onChange={(e) => {
                setLeadSearch(e.target.value);
                if (!e.target.value) {
                  setFieldValue('lead_id', '');
                }
              }}
              placeholder="Search for a lead..."
            />
            {showLeadDropdown && leadResults.length > 0 && (
              <div className="absolute z-10 w-full mt-1 bg-surface-primary border border-th-border rounded-lg shadow-lg max-h-40 overflow-y-auto">
                {leadResults.map((lead) => (
                  <button
                    key={lead.id}
                    type="button"
                    onClick={() => selectLead(lead)}
                    className="w-full text-left px-3 py-2 text-sm hover:bg-surface-secondary"
                  >
                    <span className="font-medium">{lead.first_name} {lead.last_name}</span>
                    <span className="text-th-text-tertiary ml-2">{lead.email}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        )}

        <TextareaField
          label="Description"
          name="description"
          value={values.description}
          onChange={handleChange}
          placeholder="Event details..."
          rows={2}
        />

        <div className="flex items-center gap-3 pt-2">
          <SubmitButton loading={loading} label={isEditing ? 'Update Event' : 'Create Event'} />
          <button
            type="button"
            onClick={onClose}
            className="flex-1 px-4 py-2.5 text-sm font-medium text-th-text-secondary bg-surface-primary border border-th-border rounded-lg hover:bg-surface-secondary transition-colors"
          >
            Cancel
          </button>
        </div>
      </form>
    </Modal>
  );
}

import { useState, useEffect, useCallback } from 'react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { InputField, SelectField, TextareaField, SubmitButton } from './FormField';
import { useForm } from '../hooks/useForm';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import { logAuditEvent, AUDIT_ACTIONS } from '@mpbhealth/auth';
import type { Lead } from '@mpbhealth/crm-core';

interface AddTaskModalProps {
  open: boolean;
  onClose: () => void;
  leadId?: string;
  onSuccess?: () => void;
}

interface TaskFormValues {
  lead_id: string;
  title: string;
  description: string;
  task_type: string;
  due_date: string;
  due_time: string;
  priority: string;
}

const TASK_TYPE_OPTIONS = [
  { value: 'follow_up', label: 'Follow Up' },
  { value: 'call', label: 'Call' },
  { value: 'email', label: 'Email' },
  { value: 'meeting', label: 'Meeting' },
  { value: 'other', label: 'Other' },
];

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

export function AddTaskModal({ open, onClose, leadId, onSuccess }: AddTaskModalProps) {
  const { taskService, leadService, refreshTasks } = useCRM();
  const { activeOrgId } = useOrg();
  const [leadSearch, setLeadSearch] = useState('');
  const [leadResults, setLeadResults] = useState<Lead[]>([]);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [showLeadDropdown, setShowLeadDropdown] = useState(false);

  // Default due date to tomorrow
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const defaultDue = tomorrow.toISOString().split('T')[0];

  const { values, errors, loading, handleChange, handleSubmit, setFieldValue } = useForm<TaskFormValues>({
    initialValues: {
      lead_id: leadId || '',
      title: '',
      description: '',
      task_type: 'follow_up',
      due_date: defaultDue,
      due_time: '',
      priority: 'medium',
    },
    validate: (vals) => {
      const errs: Partial<Record<keyof TaskFormValues, string>> = {};
      if (!vals.title.trim()) errs.title = 'Title is required';
      if (!vals.due_date) errs.due_date = 'Due date is required';
      if (!vals.lead_id) errs.lead_id = 'Lead is required';
      return errs;
    },
    onSubmit: async (vals) => {
      const result = await taskService.createTask({
        lead_id: vals.lead_id,
        title: vals.title,
        description: vals.description || undefined,
        task_type: vals.task_type as 'follow_up' | 'call' | 'email' | 'meeting' | 'other',
        due_date: vals.due_time ? `${vals.due_date}T${vals.due_time}` : vals.due_date,
        priority: vals.priority as 'low' | 'medium' | 'high',
      });

      if (!result.success) {
        toast.error(result.error || 'Failed to create task');
        return;
      }

      toast.success('Task created');
      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.TASK_CREATED,
        entityType: 'task',
        after: { title: vals.title, lead_id: vals.lead_id, task_type: vals.task_type },
      }).catch(console.error);
      refreshTasks();
      onSuccess?.();
      onClose();
    },
  });

  // Lead search with debounce
  const searchLeads = useCallback(async (query: string) => {
    if (query.length < 2) {
      setLeadResults([]);
      return;
    }
    const { leads } = await leadService.getLeads({ search: query }, 5, 0);
    setLeadResults(leads);
    setShowLeadDropdown(true);
  }, [leadService]);

  useEffect(() => {
    const timer = setTimeout(() => searchLeads(leadSearch), 300);
    return () => clearTimeout(timer);
  }, [leadSearch, searchLeads]);

  const selectLead = (lead: Lead) => {
    setSelectedLead(lead);
    setFieldValue('lead_id', lead.id);
    setLeadSearch(`${lead.first_name} ${lead.last_name}`);
    setShowLeadDropdown(false);
  };

  return (
    <Modal open={open} onClose={onClose} title="Add Task" size="md">
      <form onSubmit={handleSubmit} className="space-y-4">
        {/* Lead selector (only if no leadId prop) */}
        {!leadId && (
          <div className="relative">
            <InputField
              label="Lead"
              name="lead_search"
              value={leadSearch}
              onChange={(e) => {
                setLeadSearch(e.target.value);
                if (!e.target.value) {
                  setSelectedLead(null);
                  setFieldValue('lead_id', '');
                }
              }}
              placeholder="Search for a lead..."
              required
              error={errors.lead_id}
            />
            {showLeadDropdown && leadResults.length > 0 && (
              <div className="absolute z-10 w-full mt-1 bg-surface-primary border border-th-border rounded-lg shadow-lg max-h-40 overflow-y-auto">
                {leadResults.map((lead) => (
                  <button
                    key={lead.id}
                    type="button"
                    onClick={() => selectLead(lead)}
                    className="w-full text-left px-3 py-2 text-sm hover:bg-surface-secondary"
                  >
                    <span className="font-medium">{lead.first_name} {lead.last_name}</span>
                    <span className="text-th-text-tertiary ml-2">{lead.email}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        )}

        <InputField
          label="Title"
          name="title"
          value={values.title}
          onChange={handleChange}
          error={errors.title}
          required
          placeholder="e.g. Follow up on quote"
        />

        <TextareaField
          label="Description"
          name="description"
          value={values.description}
          onChange={handleChange}
          placeholder="Additional details..."
          rows={2}
        />

        <div className="grid grid-cols-2 gap-4">
          <SelectField
            label="Type"
            name="task_type"
            value={values.task_type}
            onChange={handleChange}
