}

// ============================================================================
// Command Palette Component
// ============================================================================

interface CommandPaletteProps {
  onCreateEntity?: (entityType: string) => void;
}

export default function CommandPalette({ onCreateEntity }: CommandPaletteProps) {
  const navigate = useNavigate();
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);

  const { isOpen, mode, setMode, close } = useCommandPalette();
  const [selectedIndex, setSelectedIndex] = useState(0);

  const { query, setQuery, results, loading, durationMs } = useCRMSearch({
    debounceMs: 200,
    minQueryLength: 2,
    limit: 10,
  });

  const { actions, filterActions } = useQuickActions();

  // Filter actions based on query when in commands mode
  const filteredActions = useMemo(() => {
    if (mode === 'commands') {
      return query ? filterActions(query) : actions;
    }
    return [];
  }, [mode, query, actions, filterActions]);

  // Combined items for navigation
  const items = useMemo(() => {
    if (mode === 'commands') {
      return filteredActions;
    }
    if (query.length >= 2) {
      return results;
    }
    return [];
  }, [mode, query, results, filteredActions]);

  // Reset selection when items change
  useEffect(() => {
    setSelectedIndex(0);
  }, [items]);

  // Focus input when opening
  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 50);
      setQuery('');
      setSelectedIndex(0);
    }
  }, [isOpen, setQuery]);

  // Keyboard navigation
  useEffect(() => {
    if (!isOpen) return;

    function handleKeyDown(event: KeyboardEvent) {
      switch (event.key) {
        case 'ArrowDown':
          event.preventDefault();
          setSelectedIndex((prev) => Math.min(prev + 1, items.length - 1));
          break;
        case 'ArrowUp':
          event.preventDefault();
          setSelectedIndex((prev) => Math.max(prev - 1, 0));
          break;
        case 'Enter':
          event.preventDefault();
          if (items.length > 0) {
            handleSelect(items[selectedIndex]);
          }
          break;
        case 'Tab':
          event.preventDefault();
          setMode(mode === 'search' ? 'commands' : 'search');
          break;
      }
    }

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, items, selectedIndex, mode, setMode]);

  // Scroll selected item into view
  useEffect(() => {
    if (listRef.current) {
      const selectedElement = listRef.current.querySelector('[data-selected="true"]');
      selectedElement?.scrollIntoView({ block: 'nearest' });
    }
  }, [selectedIndex]);

  const handleSelect = useCallback(
    (item: CRMSearchResult | QuickAction) => {
      close();

      // Search result
      if ('entity_type' in item) {
        const path = getEntityPath(item.entity_type, item.entity_id);
        navigate(path);
        return;
      }

      // Quick action
      const action = item as QuickAction;
      switch (action.action_type) {
        case 'navigate':
          if (action.action_data.url) {
            navigate(action.action_data.url);
          }
          break;
        case 'create':
          if (action.action_data.entity && onCreateEntity) {
            onCreateEntity(action.action_data.entity);
          } else if (action.action_data.entity) {
            // Fallback: navigate to list page with create param
            const entityPaths: Record<string, string> = {
              lead: '/leads?action=create',
              account: '/accounts?action=create',
              contact: '/contacts?action=create',
              deal: '/deals?action=create',
              task: '/tasks?action=create',
              quote: '/quotes?action=create',
              invoice: '/invoices?action=create',
            };
            const path = entityPaths[action.action_data.entity];
            if (path) {
              navigate(path);
              toast.success(`Creating new ${action.action_data.entity}...`);
            }
          }
          break;
        case 'toggle':
          if (action.action_data.modal === 'shortcuts') {
            toast('Press Cmd+K for search, Tab to switch modes, arrow keys to navigate, Enter to select.');
          }
          break;
        case 'custom':
          handleCustomAction(action.action_data.action);
          break;
      }
    },
    [close, navigate, onCreateEntity]
  );

  const handleCustomAction = (actionId?: string) => {
    switch (actionId) {
      case 'refresh-data':
        window.location.reload();
        break;
      case 'copy-page-url':
        navigator.clipboard.writeText(window.location.href);
        toast.success('URL copied to clipboard');
        break;
      case 'export-view':
        // Trigger CSV export of the current page's data
        window.dispatchEvent(new CustomEvent('crm:export-view'));
        toast.success('Export initiated');
        break;
      case 'open-docs':
        window.open('https://docs.mpbhealth.com', '_blank');
        break;
      default:
        toast.error(`Unknown action: ${actionId}`);
    }
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Backdrop */}
      <div
        className="fixed inset-0 bg-black/50 z-50 backdrop-blur-sm"
        onClick={close}
        aria-hidden="true"
      />

      {/* Modal */}
      <div className="fixed inset-x-4 top-[15%] md:inset-x-auto md:left-1/2 md:-translate-x-1/2 md:w-full md:max-w-2xl z-50">
        <div className="bg-white dark:bg-gray-900 rounded-xl shadow-2xl border border-gray-200 dark:border-gray-700 overflow-hidden">
          {/* Header */}
          <div className="flex items-center gap-3 px-4 py-3 border-b border-gray-200 dark:border-gray-700">
            {mode === 'search' ? (
              <Search className="w-5 h-5 text-gray-400" />
            ) : (
              <Command className="w-5 h-5 text-gray-400" />
            )}
            <input
              ref={inputRef}
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={
                mode === 'search'
                  ? 'Search leads, accounts, contacts, deals...'
                  : 'Type a command or action...'
              }
              className="flex-1 bg-transparent border-none outline-none text-gray-900 dark:text-gray-100 placeholder:text-gray-400"
            />
            {loading && <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />}
            <button
              onClick={close}
              className="p-1 text-gray-400 hover:text-gray-600 rounded transition-colors"
              title="Close (Esc)"
              aria-label="Close command palette"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          {/* Mode Tabs */}
          <div className="flex border-b border-gray-200 dark:border-gray-700">
            <button
              onClick={() => setMode('search')}
              className={`flex-1 px-4 py-2 text-sm font-medium transition-colors ${
                mode === 'search'
                  ? 'text-blue-600 border-b-2 border-blue-600'
                  : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'
              }`}
            >
              <Search className="w-4 h-4 inline mr-2" />
              Search
            </button>
            <button
              onClick={() => setMode('commands')}
              className={`flex-1 px-4 py-2 text-sm font-medium transition-colors ${
                mode === 'commands'
                  ? 'text-blue-600 border-b-2 border-blue-600'
                  : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'
              }`}
            >
              <Command className="w-4 h-4 inline mr-2" />
              Commands
            </button>
          </div>

          {/* Results */}
          <div ref={listRef} className="max-h-96 overflow-y-auto">
            {mode === 'search' && (
              <>
                {/* Search Results */}
                {query.length >= 2 && results.length > 0 && (
                  <div>
                    <div className="px-4 py-2 text-xs font-medium text-gray-500 uppercase tracking-wider bg-gray-50 dark:bg-gray-800">
                      Results
                      {durationMs && (
                        <span className="ml-2 font-normal">({durationMs}ms)</span>
                      )}
                    </div>
                    {results.map((result, index) => (
                      <div key={`${result.entity_type}-${result.entity_id}`} data-selected={index === selectedIndex}>
                        <ResultItem
                          result={result}
                          isSelected={index === selectedIndex}
                          onSelect={() => handleSelect(result)}
                        />
                      </div>
                    ))}
                  </div>
                )}

                {/* No Results */}
                {query.length >= 2 && !loading && results.length === 0 && (
                  <div className="px-4 py-8 text-center">
                    <Search className="w-10 h-10 text-gray-300 mx-auto mb-3" />
                    <p className="text-gray-600 dark:text-gray-400">No results found for "{query}"</p>
                    <p className="text-sm text-gray-400 mt-1">
                      Try a different search term
                    </p>
                  </div>
                )}

                {/* Empty State */}
                {query.length < 2 && (
                  <div className="px-4 py-8 text-center">
                    <Search className="w-10 h-10 text-gray-300 mx-auto mb-3" />
                    <p className="text-gray-600 dark:text-gray-400">Start typing to search</p>
                    <p className="text-sm text-gray-400 mt-1">
                      Search across leads, accounts, contacts, deals, and more
                    </p>
                  </div>
                )}
              </>
            )}

            {mode === 'commands' && (
              <>
                {filteredActions.length > 0 ? (
                  <div>
                    {/* Group by category */}
                    {['navigation', 'create', 'tools', 'help'].map((category) => {
                      const categoryActions = filteredActions.filter(
                        (a) => a.category === category
                      );
                      if (categoryActions.length === 0) return null;

                      const categoryLabels: Record<string, string> = {
                        navigation: 'Go to',
                        create: 'Create',
                        tools: 'Tools',
                        help: 'Help',
                      };

                      return (
                        <div key={category}>
                          <div className="px-4 py-2 text-xs font-medium text-gray-500 uppercase tracking-wider bg-gray-50 dark:bg-gray-800">
                            {categoryLabels[category] || category}
                          </div>
                          {categoryActions.map((action) => {
                            const globalIndex = filteredActions.indexOf(action);
                            return (
                              <div
                                key={action.id}
                                data-selected={globalIndex === selectedIndex}
                              >
                                <ActionItem
                                  action={action}
                                  isSelected={globalIndex === selectedIndex}
                                  onSelect={() => handleSelect(action)}
                                />
                              </div>
                            );
                          })}
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="px-4 py-8 text-center">
                    <Command className="w-10 h-10 text-gray-300 mx-auto mb-3" />
                    <p className="text-gray-600 dark:text-gray-400">No commands found</p>
                  </div>
                )}
              </>
            )}
          </div>

          {/* Footer */}
          <div className="px-4 py-2 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 flex items-center justify-between text-xs text-gray-500">
            <div className="flex items-center gap-4">
              <span>
                <kbd className="px-1.5 py-0.5 bg-white dark:bg-gray-700 rounded border border-gray-300 dark:border-gray-600 font-mono">
                  ΓåæΓåô
                </kbd>{' '}
                Navigate
              </span>
              <span>
                <kbd className="px-1.5 py-0.5 bg-white dark:bg-gray-700 rounded border border-gray-300 dark:border-gray-600 font-mono">
                  Γå╡
                </kbd>{' '}
                Select
              </span>
              <span>
                <kbd className="px-1.5 py-0.5 bg-white dark:bg-gray-700 rounded border border-gray-300 dark:border-gray-600 font-mono">
                  Tab
                </kbd>{' '}
                Switch mode
              </span>
            </div>
            <span>
              <kbd className="px-1.5 py-0.5 bg-white dark:bg-gray-700 rounded border border-gray-300 dark:border-gray-600 font-mono">
                Esc
              </kbd>{' '}
              Close
            </span>
          </div>
        </div>
      </div>
    </>
  );
}

export { useCommandPalette };

import { useState, useEffect, useCallback } from 'react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { useOrg } from '../contexts/OrgContext';
import { logAuditEvent, AUDIT_ACTIONS } from '@mpbhealth/auth';
import { supabase } from '../lib/supabase';
import { UserPlus, Building2, Mail, Phone, User } from 'lucide-react';
import {
  createContactService,
  createAccountService,
  type AccountWithRelations,
  type Lead,
} from '@mpbhealth/crm-core';

const contactService = createContactService(supabase);
const accountService = createAccountService(supabase);

interface ConvertLeadModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess?: (contactId: string, accountId?: string) => void;
  lead: Lead | null;
}

export function ConvertLeadModal({ open, onClose, onSuccess, lead }: ConvertLeadModalProps) {
  const { activeOrgId } = useOrg();

  const [accounts, setAccounts] = useState<AccountWithRelations[]>([]);
  const [loading, setLoading] = useState(false);
  const [loadingAccounts, setLoadingAccounts] = useState(true);

  // Form state
  const [accountMode, setAccountMode] = useState<'new' | 'existing'>('new');
  const [newAccountName, setNewAccountName] = useState('');
  const [selectedAccountId, setSelectedAccountId] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Load accounts for dropdown
  const loadAccounts = useCallback(async () => {
    setLoadingAccounts(true);
    const { accounts: data } = await accountService.getAccounts({}, 200, 0);
    setAccounts(data);
    setLoadingAccounts(false);
  }, []);

  useEffect(() => {
    if (open) {
      loadAccounts();
      // Pre-fill account name with lead name if creating new
      if (lead) {
        setNewAccountName(`${lead.first_name} ${lead.last_name}`);
      }
    }
  }, [open, loadAccounts, lead]);

  // Reset form when modal opens
  useEffect(() => {
    if (open) {
      setAccountMode('new');
      setSelectedAccountId('');
      setErrors({});
      if (lead) {
        setNewAccountName(`${lead.first_name} ${lead.last_name}`);
      }
    }
  }, [open, lead]);

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (accountMode === 'new' && !newAccountName.trim()) {
      newErrors.accountName = 'Account name is required';
    }

    if (accountMode === 'existing' && !selectedAccountId) {
      newErrors.accountId = 'Please select an account';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleConvert = async () => {
    if (!lead) return;

    if (!validate()) {
      return;
    }

    setLoading(true);

    try {
      const result = await contactService.convertLeadToContact({
        leadId: lead.id,
        accountId: accountMode === 'existing' ? selectedAccountId : undefined,
        createAccount: accountMode === 'new',
        accountName: accountMode === 'new' ? newAccountName.trim() : undefined,
      });

      if (!result.success) {
        toast.error(result.error || 'Failed to convert lead');
        setLoading(false);
        return;
      }

      toast.success('Lead converted to contact successfully');

      // Log audit events
      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.LEAD_CONVERTED || 'lead.converted',
        entityType: 'lead',
        entityId: lead.id,
        after: {
          contactId: result.contactId,
          accountId: result.accountId,
        },
      }).catch(console.error);

      if (result.accountId && accountMode === 'new') {
        logAuditEvent({
          orgId: activeOrgId || '',
          action: AUDIT_ACTIONS.ACCOUNT_CREATED || 'account.created',
          entityType: 'account',
          entityId: result.accountId,
          after: { name: newAccountName },
        }).catch(console.error);
      }

      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.CONTACT_CREATED || 'contact.created',
        entityType: 'contact',
        entityId: result.contactId,
        after: {
          first_name: lead.first_name,
          last_name: lead.last_name,
          email: lead.email,
          converted_from_lead_id: lead.id,
        },
      }).catch(console.error);

      onSuccess?.(result.contactId!, result.accountId);
      onClose();
    } catch (error) {
      console.error('Convert lead error:', error);
      toast.error('An error occurred during conversion');
    } finally {
      setLoading(false);
    }
  };

  if (!lead) return null;

  return (
    <Modal
      open={open}
      onClose={onClose}
      title="Convert Lead to Contact"
      description="Convert this lead into a contact and optionally create an account"
      variant="modal"
      size="lg"
    >
      <div className="space-y-6">
        {/* Lead Info Summary */}
        <div className="bg-surface-secondary rounded-lg p-4">
          <h3 className="text-sm font-semibold text-th-text-tertiary uppercase tracking-wider mb-3">
            Lead Information
          </h3>
          <div className="flex items-center space-x-4">
            <div className="w-12 h-12 bg-th-accent-100 rounded-full flex items-center justify-center">
              <User className="w-6 h-6 text-th-accent-700" />
            </div>
            <div className="flex-1">
              <p className="text-lg font-medium text-th-text-primary">
                {lead.first_name} {lead.last_name}
              </p>
              <div className="flex items-center space-x-4 text-sm text-th-text-secondary mt-1">
                {lead.email && (
                  <span className="flex items-center">
                    <Mail className="w-4 h-4 mr-1" />
                    {lead.email}
                  </span>
                )}
                {lead.phone && (
                  <span className="flex items-center">
                    <Phone className="w-4 h-4 mr-1" />
                    {lead.phone}
                  </span>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Account Options */}
        <div>
          <h3 className="text-sm font-semibold text-th-text-tertiary uppercase tracking-wider mb-3">
            Account Association
          </h3>

          {/* Toggle between new and existing */}
          <div className="flex items-center space-x-4 mb-4">
            <label className="flex items-center space-x-2 cursor-pointer">
              <input
                type="radio"
                name="accountMode"
                value="new"
                checked={accountMode === 'new'}
                onChange={() => setAccountMode('new')}
                className="w-4 h-4 text-th-accent-600 focus:ring-th-accent-500"
              />
              <span className="text-sm text-th-text-secondary">Create New Account</span>
            </label>
            <label className="flex items-center space-x-2 cursor-pointer">
              <input
                type="radio"
                name="accountMode"
                value="existing"
                checked={accountMode === 'existing'}
                onChange={() => setAccountMode('existing')}
                className="w-4 h-4 text-th-accent-600 focus:ring-th-accent-500"
              />
              <span className="text-sm text-th-text-secondary">Use Existing Account</span>
            </label>
          </div>

          {/* New Account Name Input */}
          {accountMode === 'new' && (
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Account Name <span className="text-red-500">*</span>
              </label>
              <div className="relative">
                <Building2 className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary" />
                <input
                  type="text"
                  value={newAccountName}
                  onChange={(e) => {
                    setNewAccountName(e.target.value);
                    if (errors.accountName) {
                      setErrors((prev) => {
                        const newErrors = { ...prev };
                        delete newErrors.accountName;
                        return newErrors;
                      });
                    }
                  }}
                  placeholder="Enter account name"
                  className={`w-full border rounded-lg pl-10 pr-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500 ${
                    errors.accountName ? 'border-red-500' : 'border-th-border'
                  }`}
                />
              </div>
              {errors.accountName && (
                <p className="text-xs text-red-500 mt-1">{errors.accountName}</p>
              )}
              <p className="text-xs text-th-text-tertiary mt-1">
                A new account will be created with this name
              </p>
            </div>
          )}

          {/* Existing Account Selector */}
          {accountMode === 'existing' && (
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Select Account <span className="text-red-500">*</span>
              </label>
              <select
                value={selectedAccountId}
                onChange={(e) => {
                  setSelectedAccountId(e.target.value);
                  if (errors.accountId) {
                    setErrors((prev) => {
                      const newErrors = { ...prev };
                      delete newErrors.accountId;
                      return newErrors;
                    });
                  }
                }}
                disabled={loadingAccounts}
                className={`w-full border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500 disabled:opacity-50 ${
                  errors.accountId ? 'border-red-500' : 'border-th-border'
                }`}
              >
                <option value="">Select an account...</option>
                {accounts.map((account) => (
                  <option key={account.id} value={account.id}>
                    {account.name}
                  </option>
                ))}
              </select>
              {errors.accountId && (
                <p className="text-xs text-red-500 mt-1">{errors.accountId}</p>
              )}
              {loadingAccounts && (
                <p className="text-xs text-th-text-tertiary mt-1">Loading accounts...</p>
              )}
            </div>
          )}
        </div>

        {/* Conversion Summary */}
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
          <h4 className="text-sm font-medium text-blue-800 mb-2">What will happen:</h4>
          <ul className="text-sm text-blue-700 space-y-1">
            <li>- A new contact will be created with the lead's information</li>
            {accountMode === 'new' ? (
              <li>- A new account "{newAccountName || '...'}" will be created</li>
            ) : (
              <li>
                - The contact will be linked to{' '}
                {selectedAccountId
                  ? accounts.find((a) => a.id === selectedAccountId)?.name || 'the selected account'
                  : 'the selected account'}
              </li>
            )}
            <li>- The lead will be marked as converted</li>
          </ul>
        </div>

        {/* Actions */}
        <div className="flex items-center justify-end space-x-3 pt-4 border-t border-th-border">
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-th-text-secondary hover:bg-surface-secondary rounded-lg"
          >
            Cancel
          </button>
          <button
            onClick={handleConvert}
            disabled={loading}
            className="flex items-center space-x-2 px-4 py-2 bg-th-accent-600 text-white text-sm font-medium rounded-lg hover:bg-th-accent-700 disabled:opacity-50"
          >
            <UserPlus className="w-4 h-4" />
            <span>{loading ? 'Converting...' : 'Convert Lead'}</span>
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ============================================================================
// Entity Header Component
// Unified header for record pages with breadcrumbs and quick actions
// ============================================================================

import { Link, useNavigate } from 'react-router-dom';
import {
  ChevronRight,
  Phone,
  Mail,
  CheckSquare,
  StickyNote,
  Paperclip,
  RefreshCw,
  MoreHorizontal,
  ArrowLeft,
  ExternalLink,
  Edit2,
  Trash2,
  Copy,
  Star,
  StarOff,
  Share2,
} from 'lucide-react';
import type { LucideIcon } from 'lucide-react';
import { useState, useRef, useEffect } from 'react';

// ============================================================================
// Types
// ============================================================================

export interface Breadcrumb {
  label: string;
  href?: string;
}

export interface QuickAction {
  id: string;
  label: string;
  icon: LucideIcon;
  onClick: () => void;
  variant?: 'default' | 'primary' | 'danger';
  disabled?: boolean;
}

export interface EntityHeaderProps {
  // Breadcrumb configuration
  breadcrumbs: Breadcrumb[];

  // Entity information
  entityType: string; // e.g., 'Lead', 'Deal', 'Contact'
  entityName: string;
  entitySubtitle?: string;
  entityIcon?: LucideIcon;
  entityStatus?: {
    label: string;
    color: 'gray' | 'blue' | 'green' | 'yellow' | 'red' | 'blue';
  };

  // Quick actions
  quickActions?: QuickAction[];
  onCall?: () => void;
  onEmail?: () => void;
  onAddTask?: () => void;
  onAddNote?: () => void;
  onAttach?: () => void;
  onConvert?: () => void;

  // Overflow menu actions
  overflowActions?: QuickAction[];
  onEdit?: () => void;
  onDelete?: () => void;
  onDuplicate?: () => void;
  onShare?: () => void;

  // Favorite/star
  isFavorite?: boolean;
  onToggleFavorite?: () => void;

  // Optional refresh
  onRefresh?: () => void;
  isRefreshing?: boolean;

  // Custom content slots
  headerRight?: React.ReactNode;
  belowHeader?: React.ReactNode;
}

// ============================================================================
// Status Badge Component
// ============================================================================

const statusColors = {
  gray: 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300',
  blue: 'bg-blue-100 text-blue-700 dark:bg-blue-900/50 dark:text-blue-300',
  green: 'bg-green-100 text-green-700 dark:bg-green-900/50 dark:text-green-300',
  yellow: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/50 dark:text-yellow-300',
  red: 'bg-red-100 text-red-700 dark:bg-red-900/50 dark:text-red-300',
};

function StatusBadge({ label, color }: { label: string; color: keyof typeof statusColors }) {
  return (
    <span className={`px-2.5 py-1 text-xs font-medium rounded-full ${statusColors[color]}`}>
      {label}
    </span>
  );
}

// ============================================================================
// Quick Action Button Component
// ============================================================================

interface QuickActionButtonProps {
  icon: LucideIcon;
  label: string;
  onClick: () => void;
  variant?: 'default' | 'primary' | 'danger';
  disabled?: boolean;
  showLabel?: boolean;
}

function QuickActionButton({
  icon: Icon,
  label,
  onClick,
  variant = 'default',
  disabled = false,
  showLabel = false,
}: QuickActionButtonProps) {
  const variantStyles = {
    default: 'text-gray-600 hover:text-gray-900 hover:bg-gray-100 dark:text-gray-400 dark:hover:text-gray-100 dark:hover:bg-gray-800',
    primary: 'text-blue-600 hover:text-blue-700 hover:bg-blue-50 dark:text-blue-400 dark:hover:bg-blue-900/30',
    danger: 'text-red-600 hover:text-red-700 hover:bg-red-50 dark:text-red-400 dark:hover:bg-red-900/30',
  };

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      title={label}
      className={`
        flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-colors
        ${variantStyles[variant]}
        ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
      `}
    >
      <Icon className="w-4 h-4" />
      {showLabel && <span className="hidden lg:inline">{label}</span>}
    </button>
  );
}

// ============================================================================
// Overflow Menu Component
// ============================================================================

interface OverflowMenuProps {
  actions: QuickAction[];
}

function OverflowMenu({ actions }: OverflowMenuProps) {
  const [isOpen, setIsOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  // Close on outside click
  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  if (actions.length === 0) return null;

  return (
    <div ref={menuRef} className="relative">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="p-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg transition-colors"
        title="More actions"
      >
        <MoreHorizontal className="w-5 h-5" />
      </button>

      {isOpen && (
        <div className="absolute right-0 top-full mt-1 w-48 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg shadow-lg z-50 py-1">
          {actions.map((action) => {
            const Icon = action.icon;
            const variantColors = {
              default: 'text-gray-700 dark:text-gray-300',
              primary: 'text-blue-600 dark:text-blue-400',
              danger: 'text-red-600 dark:text-red-400',
            };
            return (
              <button
                key={action.id}
                onClick={() => {
                  action.onClick();
                  setIsOpen(false);
                }}
                disabled={action.disabled}
                className={`
                  w-full flex items-center gap-3 px-4 py-2 text-sm text-left
                  hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors
                  ${action.disabled ? 'opacity-50 cursor-not-allowed' : ''}
                  ${variantColors[action.variant || 'default']}
                `}
              >
                <Icon className="w-4 h-4" />
                {action.label}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ============================================================================
// Entity Header Component
// ============================================================================

export function EntityHeader({
  breadcrumbs,
  entityType,
  entityName,
  entitySubtitle,
  entityIcon: EntityIcon,
  entityStatus,
  quickActions = [],
  onCall,
  onEmail,
  onAddTask,
  onAddNote,
  onAttach,
  onConvert,
  overflowActions = [],
  onEdit,
  onDelete,
  onDuplicate,
  onShare,
  isFavorite,
  onToggleFavorite,
  onRefresh,
  isRefreshing,
  headerRight,
  belowHeader,
}: EntityHeaderProps) {
  const navigate = useNavigate();

  // Build default quick actions
  const defaultQuickActions: QuickAction[] = [];
  if (onCall) defaultQuickActions.push({ id: 'call', label: 'Call', icon: Phone, onClick: onCall });
  if (onEmail) defaultQuickActions.push({ id: 'email', label: 'Email', icon: Mail, onClick: onEmail });
  if (onAddTask) defaultQuickActions.push({ id: 'task', label: 'Add Task', icon: CheckSquare, onClick: onAddTask });
  if (onAddNote) defaultQuickActions.push({ id: 'note', label: 'Add Note', icon: StickyNote, onClick: onAddNote });
  if (onAttach) defaultQuickActions.push({ id: 'attach', label: 'Attach File', icon: Paperclip, onClick: onAttach });
  if (onConvert) defaultQuickActions.push({ id: 'convert', label: 'Convert', icon: RefreshCw, onClick: onConvert, variant: 'primary' });

  const allQuickActions = [...defaultQuickActions, ...quickActions];

  // Build default overflow actions
  const defaultOverflowActions: QuickAction[] = [];
  if (onEdit) defaultOverflowActions.push({ id: 'edit', label: 'Edit', icon: Edit2, onClick: onEdit });
  if (onDuplicate) defaultOverflowActions.push({ id: 'duplicate', label: 'Duplicate', icon: Copy, onClick: onDuplicate });
  if (onShare) defaultOverflowActions.push({ id: 'share', label: 'Share', icon: Share2, onClick: onShare });
  if (onDelete) defaultOverflowActions.push({ id: 'delete', label: 'Delete', icon: Trash2, onClick: onDelete, variant: 'danger' });

  const allOverflowActions = [...defaultOverflowActions, ...overflowActions];

  return (
    <div className="bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-700">
      {/* Breadcrumbs */}
      <div className="px-6 py-2 border-b border-gray-100 dark:border-gray-800">
        <nav className="flex items-center gap-2 text-sm">
          <button
            onClick={() => navigate(-1)}
            className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
            title="Go back"
          >
            <ArrowLeft className="w-4 h-4" />
          </button>
          
          {breadcrumbs.map((crumb, index) => (
            <span key={index} className="flex items-center gap-2">
              {index > 0 && <ChevronRight className="w-4 h-4 text-gray-300 dark:text-gray-600" />}
              {crumb.href ? (
                <Link
                  to={crumb.href}
                  className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200 transition-colors"
                >
                  {crumb.label}
                </Link>
              ) : (
                <span className="text-gray-900 dark:text-gray-100 font-medium">
                  {crumb.label}
                </span>
              )}
            </span>
          ))}
        </nav>
      </div>

      {/* Header */}
      <div className="px-6 py-4">
        <div className="flex items-start justify-between gap-4">
          {/* Left: Entity info */}
          <div className="flex items-center gap-4 min-w-0">
            {EntityIcon && (
              <div className="w-12 h-12 bg-blue-100 dark:bg-blue-900/30 rounded-xl flex items-center justify-center flex-shrink-0">
                <EntityIcon className="w-6 h-6 text-blue-600 dark:text-blue-400" />
              </div>
            )}
            <div className="min-w-0">
              <div className="flex items-center gap-3">
                <span className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wide">
                  {entityType}
                </span>
                {entityStatus && (
                  <StatusBadge label={entityStatus.label} color={entityStatus.color} />
                )}
              </div>
              <h1 className="text-xl font-semibold text-gray-900 dark:text-gray-100 truncate mt-1">
                {entityName}
              </h1>
              {entitySubtitle && (
                <p className="text-sm text-gray-500 dark:text-gray-400 truncate mt-0.5">
                  {entitySubtitle}
                </p>
              )}
            </div>
          </div>

          {/* Right: Actions */}
          <div className="flex items-center gap-2 flex-shrink-0">
            {/* Favorite button */}
            {onToggleFavorite && (
              <button
                onClick={onToggleFavorite}
                className={`p-2 rounded-lg transition-colors ${
                  isFavorite
                    ? 'text-yellow-500 hover:bg-yellow-50 dark:hover:bg-yellow-900/30'
                    : 'text-gray-400 hover:text-gray-600 hover:bg-gray-100 dark:hover:bg-gray-800'
                }`}
                title={isFavorite ? 'Remove from favorites' : 'Add to favorites'}
              >
                {isFavorite ? <Star className="w-5 h-5 fill-current" /> : <StarOff className="w-5 h-5" />}
              </button>
            )}

            {/* Refresh button */}
            {onRefresh && (
              <button
                onClick={onRefresh}
                disabled={isRefreshing}
                className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg transition-colors disabled:opacity-50"
                title="Refresh"
              >
                <RefreshCw className={`w-5 h-5 ${isRefreshing ? 'animate-spin' : ''}`} />
              </button>
            )}

            {/* Divider */}
            {(onToggleFavorite || onRefresh) && allQuickActions.length > 0 && (
              <div className="w-px h-6 bg-gray-200 dark:bg-gray-700" />
            )}

            {/* Quick actions */}
            <div className="hidden sm:flex items-center gap-1">
              {allQuickActions.slice(0, 5).map((action) => (
                <QuickActionButton
                  key={action.id}
                  icon={action.icon}
                  label={action.label}
                  onClick={action.onClick}
                  variant={action.variant}
                  disabled={action.disabled}
                />
              ))}
            </div>

            {/* Header right slot */}
            {headerRight}

            {/* Overflow menu */}
            <OverflowMenu actions={allOverflowActions} />
          </div>
        </div>
      </div>

      {/* Below header slot (for tabs, etc.) */}
      {belowHeader}
    </div>
  );
}

export default EntityHeader;

// ============================================================================
// Error Boundary Components
// Provides graceful error handling at different levels of the app
// ============================================================================

import React, { Component, type ReactNode } from 'react';
import { AlertTriangle, RefreshCw, Home, Bug, ChevronDown, ChevronUp } from 'lucide-react';

// ============================================================================
// Types
// ============================================================================

interface ErrorBoundaryProps {
  children: ReactNode;
  fallback?: ReactNode;
  onError?: (error: Error, errorInfo: React.ErrorInfo) => void;
  level?: 'app' | 'route' | 'widget';
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
  errorInfo: React.ErrorInfo | null;
}

// ============================================================================
// Route-level Error Boundary
// Used to wrap individual routes/pages - nav stays intact
// ============================================================================

export class RouteErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error('[RouteErrorBoundary] Error caught:', error, errorInfo);
    this.setState({ errorInfo });
    this.props.onError?.(error, errorInfo);
  }

  handleRetry = () => {
    this.setState({ hasError: false, error: null, errorInfo: null });
  };

  handleGoHome = () => {
    window.location.href = '/';
  };

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }

      return (
        <RouteErrorFallback
          error={this.state.error}
          errorInfo={this.state.errorInfo}
          onRetry={this.handleRetry}
          onGoHome={this.handleGoHome}
        />
      );
    }

    return this.props.children;
  }
}

// ============================================================================
// Widget-level Error Boundary
// Used for dashboard widgets - keeps other widgets working
// ============================================================================

interface WidgetErrorBoundaryProps {
  children: ReactNode;
  widgetName?: string;
  onError?: (error: Error) => void;
}

interface WidgetErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

export class WidgetErrorBoundary extends Component<WidgetErrorBoundaryProps, WidgetErrorBoundaryState> {
  constructor(props: WidgetErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): Partial<WidgetErrorBoundaryState> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error) {
    console.error(`[WidgetErrorBoundary] ${this.props.widgetName || 'Widget'} error:`, error);
    this.props.onError?.(error);
  }

  handleRetry = () => {
    this.setState({ hasError: false, error: null });
  };

  render() {
    if (this.state.hasError) {
      return (
        <WidgetErrorFallback
          error={this.state.error}
          widgetName={this.props.widgetName}
          onRetry={this.handleRetry}
        />
      );
    }

    return this.props.children;
  }
}

// ============================================================================
// Route Error Fallback UI
// ============================================================================

interface RouteErrorFallbackProps {
  error: Error | null;
  errorInfo: React.ErrorInfo | null;
  onRetry: () => void;
  onGoHome: () => void;
}

function RouteErrorFallback({ error, errorInfo, onRetry, onGoHome }: RouteErrorFallbackProps) {
  const [showDetails, setShowDetails] = React.useState(false);

  return (
    <div className="min-h-[400px] flex items-center justify-center p-8">
      <div className="max-w-lg w-full">
        {/* Error Icon */}
        <div className="flex justify-center mb-6">
          <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center">
            <AlertTriangle className="w-8 h-8 text-red-600 dark:text-red-400" />
          </div>
        </div>

        {/* Error Message */}
        <div className="text-center mb-6">
          <h2 className="text-xl font-semibold text-gray-900 dark:text-gray-100 mb-2">
            Something went wrong
          </h2>
          <p className="text-gray-600 dark:text-gray-400">
            This page encountered an error. Don't worry, your data is safe.
          </p>
        </div>

        {/* Error Details (collapsible) */}
        {error && (
          <div className="mb-6">
            <button
              onClick={() => setShowDetails(!showDetails)}
              className="flex items-center gap-2 text-sm text-gray-500 hover:text-gray-700 dark:hover:text-gray-300 mx-auto"
            >
              <Bug className="w-4 h-4" />
              <span>Technical details</span>
              {showDetails ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
            </button>
            {showDetails && (
              <div className="mt-3 p-4 bg-gray-100 dark:bg-gray-800 rounded-lg text-sm font-mono overflow-auto max-h-48">
                <p className="text-red-600 dark:text-red-400 font-semibold mb-2">
                  {error.name}: {error.message}
                </p>
                {errorInfo?.componentStack && (
                  <pre className="text-gray-600 dark:text-gray-400 text-xs whitespace-pre-wrap">
                    {errorInfo.componentStack}
                  </pre>
                )}
              </div>
            )}
          </div>
        )}

        {/* Action Buttons */}
        <div className="flex flex-col sm:flex-row gap-3 justify-center">
          <button
            onClick={onRetry}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            <RefreshCw className="w-4 h-4" />
            Try Again
          </button>
          <button
            onClick={onGoHome}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors"
          >
            <Home className="w-4 h-4" />
            Go to Dashboard
          </button>
        </div>
      </div>
    </div>
  );
}

// ============================================================================
// Widget Error Fallback UI
// ============================================================================

interface WidgetErrorFallbackProps {
  error: Error | null;
  widgetName?: string;
  onRetry: () => void;
}

function WidgetErrorFallback({ error, widgetName, onRetry }: WidgetErrorFallbackProps) {
  return (
    <div className="p-4 text-center">
      <div className="w-10 h-10 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-3">
        <AlertTriangle className="w-5 h-5 text-red-500" />
      </div>
      <p className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
        {widgetName ? `${widgetName} failed to load` : 'Widget error'}
      </p>
      <p className="text-xs text-gray-500 mb-3">
        {error?.message || 'An unexpected error occurred'}
      </p>
      <button
        onClick={onRetry}
        className="text-sm text-blue-600 hover:text-blue-700 font-medium flex items-center gap-1 mx-auto"
      >
        <RefreshCw className="w-3 h-3" />
        Retry
      </button>
    </div>
  );
}

// ============================================================================
// App-level Error Boundary
// Last resort - catches errors that escape route boundaries
// ============================================================================

interface AppErrorBoundaryProps {
  children: ReactNode;
}

interface AppErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

export class AppErrorBoundary extends Component<AppErrorBoundaryProps, AppErrorBoundaryState> {
  constructor(props: AppErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): Partial<AppErrorBoundaryState> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error('[AppErrorBoundary] Critical error:', error, errorInfo);
    // Error reporting (e.g. Sentry) can be wired here when configured
  }

  handleRefresh = () => {
    window.location.reload();
  };

  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex items-center justify-center p-8">
          <div className="max-w-md w-full text-center">
            <div className="w-20 h-20 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
              <AlertTriangle className="w-10 h-10 text-red-600 dark:text-red-400" />
            </div>
            <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100 mb-2">
              Application Error
            </h1>
            <p className="text-gray-600 dark:text-gray-400 mb-6">
              The application encountered a critical error. Please refresh the page to continue.
            </p>
            <button
              onClick={this.handleRefresh}
              className="inline-flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
            >
              <RefreshCw className="w-5 h-5" />
              Refresh Page
            </button>
            {this.state.error && (
              <div className="mt-6 p-4 bg-gray-100 dark:bg-gray-800 rounded-lg text-left">
                <p className="text-sm font-mono text-red-600 dark:text-red-400">
                  {this.state.error.message}
                </p>
              </div>
            )}
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default RouteErrorBoundary;

import { useState, useCallback, useRef } from 'react';
import { X, Upload, FileSpreadsheet, CheckCircle, AlertCircle, ArrowRight, Loader2 } from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import type { ImportFieldMapping, ImportPreview, ImportResult } from '@mpbhealth/crm-core';

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  entityType: 'leads' | 'contacts';
  onSuccess?: (result: ImportResult) => void;
}

type Step = 'upload' | 'mapping' | 'preview' | 'importing' | 'complete';

export function ImportModal({ isOpen, onClose, entityType, onSuccess }: ImportModalProps) {
  const { importService } = useCRM();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [step, setStep] = useState<Step>('upload');
  const [csvContent, setCsvContent] = useState<string>('');
  const [fileName, setFileName] = useState<string>('');
  const [preview, setPreview] = useState<ImportPreview | null>(null);
  const [mappings, setMappings] = useState<ImportFieldMapping[]>([]);
  const [result, setResult] = useState<ImportResult | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Options
  const [skipDuplicates, setSkipDuplicates] = useState(true);
  const [source, setSource] = useState('CSV Import');

  const targetFields = entityType === 'leads'
    ? ['first_name', 'last_name', 'email', 'phone', 'company', 'title', 'source', 'notes']
    : ['first_name', 'last_name', 'email', 'phone', 'mobile', 'title', 'department', 'mailing_address', 'mailing_city', 'mailing_state', 'mailing_zip'];

  const handleFileSelect = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setError(null);
    setFileName(file.name);

    try {
      const content = await file.text();
      setCsvContent(content);

      const previewData = importService.parseCSVPreview(content, entityType);
      setPreview(previewData);
      setMappings(previewData.suggestedMappings);
      setStep('mapping');
    } catch (err) {
      setError('Failed to read file. Please ensure it is a valid CSV file.');
    }
  }, [importService, entityType]);

  const handleMappingChange = (index: number, targetField: string) => {
    const newMappings = [...mappings];
    newMappings[index] = { ...newMappings[index], targetField };
    setMappings(newMappings);
  };

  const handleImport = async () => {
    setIsProcessing(true);
    setError(null);

    try {
      const options = {
        skipDuplicates,
        duplicateCheckFields: ['email'],
        updateExisting: false,
        defaultValues: {},
        source,
        tags: [],
      };

      let importResult: ImportResult;
      if (entityType === 'leads') {
        importResult = await importService.importLeads(csvContent, mappings, options);
      } else {
        importResult = await importService.importContacts(csvContent, mappings, options);
      }

      setResult(importResult);
      setStep('complete');
      onSuccess?.(importResult);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Import failed');
    } finally {
      setIsProcessing(false);
    }
  };

  const resetAndClose = () => {
    setStep('upload');
    setCsvContent('');
    setFileName('');
    setPreview(null);
    setMappings([]);
    setResult(null);
    setError(null);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto">
      <div className="fixed inset-0 bg-black/50" onClick={resetAndClose} />

      <div className="relative min-h-screen flex items-center justify-center p-4">
        <div className="relative bg-white rounded-xl shadow-xl w-full max-w-3xl max-h-[90vh] overflow-hidden flex flex-col">
          {/* Header */}
          <div className="px-6 py-4 border-b border-th-border flex items-center justify-between">
            <h2 className="text-lg font-semibold text-th-text-primary">
              Import {entityType === 'leads' ? 'Leads' : 'Contacts'}
            </h2>
            <button
              onClick={resetAndClose}
              className="p-1 rounded hover:bg-surface-secondary transition-colors"
            >
              <X className="w-5 h-5 text-th-text-tertiary" />
            </button>
          </div>

          {/* Steps indicator */}
          <div className="px-6 py-3 bg-surface-secondary border-b border-th-border">
            <div className="flex items-center gap-2 text-sm">
              <span className={step === 'upload' ? 'text-th-accent-600 font-medium' : 'text-th-text-tertiary'}>
                1. Upload
              </span>
              <ArrowRight className="w-4 h-4 text-th-text-tertiary" />
              <span className={step === 'mapping' ? 'text-th-accent-600 font-medium' : 'text-th-text-tertiary'}>
                2. Map Fields
              </span>
              <ArrowRight className="w-4 h-4 text-th-text-tertiary" />
              <span className={step === 'importing' || step === 'complete' ? 'text-th-accent-600 font-medium' : 'text-th-text-tertiary'}>
                3. Import
              </span>
            </div>
          </div>

          {/* Content */}
          <div className="flex-1 overflow-y-auto p-6">
            {error && (
              <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-2 text-red-700 text-sm">
                <AlertCircle className="w-4 h-4" />
                {error}
              </div>
            )}

            {/* Step 1: Upload */}
            {step === 'upload' && (
              <div className="text-center py-8">
                <FileSpreadsheet className="w-16 h-16 mx-auto text-th-text-tertiary mb-4" />
                <h3 className="text-lg font-medium text-th-text-primary mb-2">
                  Upload CSV File
                </h3>
                <p className="text-sm text-th-text-secondary mb-6 max-w-md mx-auto">
                  Select a CSV file containing your {entityType}. The first row should contain column headers.
                </p>

                <input
                  ref={fileInputRef}
                  type="file"
                  accept=".csv,text/csv"
                  onChange={handleFileSelect}
                  className="hidden"
                />

                <button
                  onClick={() => fileInputRef.current?.click()}
                  className="inline-flex items-center gap-2 px-6 py-3 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700 transition-colors"
                >
                  <Upload className="w-5 h-5" />
                  Select CSV File
                </button>

                <p className="mt-4 text-xs text-th-text-tertiary">
                  Maximum file size: 10MB. Supported format: CSV
                </p>
              </div>
            )}

            {/* Step 2: Mapping */}
            {step === 'mapping' && preview && (
              <div>
                <div className="mb-4">
                  <p className="text-sm text-th-text-secondary">
                    <span className="font-medium">{fileName}</span> - {preview.totalRows} rows detected
                  </p>
                </div>

                <div className="mb-6">
                  <h4 className="text-sm font-medium text-th-text-primary mb-3">Field Mapping</h4>
                  <div className="space-y-2 max-h-64 overflow-y-auto">
                    {mappings.map((mapping, index) => (
                      <div key={index} className="flex items-center gap-4 p-2 bg-surface-secondary rounded-lg">
                        <div className="w-1/3">
                          <span className="text-sm font-medium text-th-text-primary">
                            {mapping.sourceColumn}
                          </span>
                        </div>
                        <ArrowRight className="w-4 h-4 text-th-text-tertiary flex-shrink-0" />
                        <div className="flex-1">
                          <select
                            value={mapping.targetField}
                            onChange={(e) => handleMappingChange(index, e.target.value)}
                            className="w-full border border-th-border rounded px-2 py-1 text-sm"
                          >
                            <option value="">-- Skip this column --</option>
                            {targetFields.map((field) => (
                              <option key={field} value={field}>
                                {field.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase())}
                              </option>
                            ))}
                          </select>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="mb-6">
                  <h4 className="text-sm font-medium text-th-text-primary mb-3">Import Options</h4>
                  <div className="space-y-3">
                    <label className="flex items-center gap-2">
                      <input
                        type="checkbox"
                        checked={skipDuplicates}
                        onChange={(e) => setSkipDuplicates(e.target.checked)}
                        className="h-4 w-4 rounded border-th-border text-th-accent-600"
                      />
                      <span className="text-sm text-th-text-secondary">Skip duplicate records (based on email)</span>
                    </label>

                    <div>
                      <label className="block text-sm text-th-text-secondary mb-1">Source Label</label>
                      <input
                        type="text"
                        value={source}
                        onChange={(e) => setSource(e.target.value)}
                        className="w-full border border-th-border rounded-lg px-3 py-2 text-sm"
                        placeholder="e.g., CSV Import, Trade Show 2024"
                      />
                    </div>
                  </div>
                </div>

                {/* Sample data preview */}
                {preview.sampleRows.length > 0 && (
                  <div>
                    <h4 className="text-sm font-medium text-th-text-primary mb-3">Data Preview</h4>
                    <div className="overflow-x-auto border border-th-border rounded-lg">
                      <table className="min-w-full text-sm">
                        <thead className="bg-surface-secondary">
                          <tr>
                            {preview.headers.map((h) => (
                              <th key={h} className="px-3 py-2 text-left text-xs font-medium text-th-text-secondary">
                                {h}
                              </th>
                            ))}
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-th-border">
                          {preview.sampleRows.slice(0, 3).map((row, i) => (
                            <tr key={i}>
                              {preview.headers.map((h) => (
                                <td key={h} className="px-3 py-2 text-th-text-primary truncate max-w-[150px]">
                                  {row[h]}
                                </td>
                              ))}
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Step 3: Importing */}
            {step === 'importing' && (
              <div className="text-center py-12">
                <Loader2 className="w-12 h-12 mx-auto text-th-accent-600 animate-spin mb-4" />
                <h3 className="text-lg font-medium text-th-text-primary mb-2">
                  Importing...
                </h3>
                <p className="text-sm text-th-text-secondary">
                  Please wait while we process your data.
                </p>
              </div>
            )}

            {/* Step 4: Complete */}
            {step === 'complete' && result && (
              <div className="text-center py-8">
                {result.successCount > 0 ? (
                  <CheckCircle className="w-16 h-16 mx-auto text-green-500 mb-4" />
                ) : (
                  <AlertCircle className="w-16 h-16 mx-auto text-red-500 mb-4" />
                )}

                <h3 className="text-lg font-medium text-th-text-primary mb-4">
                  Import Complete
                </h3>

                <div className="grid grid-cols-3 gap-4 max-w-md mx-auto mb-6">
                  <div className="p-3 bg-green-50 rounded-lg">
                    <div className="text-2xl font-bold text-green-600">{result.successCount}</div>
                    <div className="text-xs text-green-700">Imported</div>
                  </div>
                  <div className="p-3 bg-yellow-50 rounded-lg">
                    <div className="text-2xl font-bold text-yellow-600">{result.duplicateCount}</div>
                    <div className="text-xs text-yellow-700">Skipped</div>
                  </div>
                  <div className="p-3 bg-red-50 rounded-lg">
                    <div className="text-2xl font-bold text-red-600">{result.errorCount}</div>
                    <div className="text-xs text-red-700">Errors</div>
                  </div>
                </div>

                {result.errors.length > 0 && (
                  <div className="text-left max-h-32 overflow-y-auto border border-th-border rounded-lg p-3 mb-4">
                    <h4 className="text-sm font-medium text-th-text-primary mb-2">Errors:</h4>
                    <ul className="text-xs text-red-600 space-y-1">
                      {result.errors.slice(0, 10).map((err, i) => (
                        <li key={i}>Row {err.row}: {err.message}</li>
                      ))}
                      {result.errors.length > 10 && (
                        <li>...and {result.errors.length - 10} more errors</li>
                      )}
                    </ul>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="px-6 py-4 border-t border-th-border flex items-center justify-end gap-3">
            {step === 'mapping' && (
              <>
                <button
                  onClick={() => setStep('upload')}
                  className="px-4 py-2 border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
                >
                  Back
                </button>
                <button
                  onClick={() => {
                    setStep('importing');
                    handleImport();
                  }}
                  disabled={isProcessing}
                  className="px-4 py-2 bg-th-accent-600 text-white rounded-lg text-sm font-medium hover:bg-th-accent-700 disabled:opacity-50"
                >
                  Start Import
                </button>
              </>
            )}

            {step === 'complete' && (
              <button
                onClick={resetAndClose}
                className="px-4 py-2 bg-th-accent-600 text-white rounded-lg text-sm font-medium hover:bg-th-accent-700"
              >
                Done
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

