  GitBranch,
  Briefcase,
  FileEdit,
  Trophy,
  XCircle,
  ListTodo,
  CheckCircle,
  AlertTriangle,
  Activity,
  Building,
  FileText,
  DollarSign,
  FileCheck,
  ThumbsUp,
  Megaphone,
  Mail,
  Calendar,
  Bell,
  Info,
  ChevronRight,
  X,
  Pause,
  Play,
} from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import type { TickerItem, TickerEventType } from '@mpbhealth/crm-core';
import { TICKER_EVENT_CONFIG } from '@mpbhealth/crm-core';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Icon Map
// ============================================================================

const ICON_MAP: Record<string, React.ElementType> = {
  UserPlus,
  UserCog,
  GitBranch,
  Briefcase,
  FileEdit,
  Trophy,
  XCircle,
  ListTodo,
  CheckCircle,
  AlertTriangle,
  Activity,
  Building,
  FileText,
  DollarSign,
  FileCheck,
  ThumbsUp,
  Megaphone,
  Mail,
  Calendar,
  Bell,
  Info,
};

// ============================================================================
// Color Utilities
// ============================================================================

const getColorClasses = (color: string) => {
  const colors: Record<string, { bg: string; text: string; border: string; dot: string }> = {
    green: { bg: 'bg-green-500/10', text: 'text-green-600 dark:text-green-400', border: 'border-green-500/20', dot: 'bg-green-500' },
    blue: { bg: 'bg-blue-500/10', text: 'text-blue-600 dark:text-blue-400', border: 'border-blue-500/20', dot: 'bg-blue-500' },
    emerald: { bg: 'bg-green-500/10', text: 'text-green-600 dark:text-green-400', border: 'border-green-500/20', dot: 'bg-green-500' },
    yellow: { bg: 'bg-yellow-500/10', text: 'text-yellow-600 dark:text-yellow-400', border: 'border-yellow-500/20', dot: 'bg-yellow-500' },
    red: { bg: 'bg-red-500/10', text: 'text-red-600 dark:text-red-400', border: 'border-red-500/20', dot: 'bg-red-500' },
    orange: { bg: 'bg-orange-500/10', text: 'text-orange-600 dark:text-orange-400', border: 'border-orange-500/20', dot: 'bg-orange-500' },
    cyan: { bg: 'bg-cyan-500/10', text: 'text-cyan-600 dark:text-cyan-400', border: 'border-cyan-500/20', dot: 'bg-cyan-500' },
    teal: { bg: 'bg-teal-500/10', text: 'text-teal-600 dark:text-teal-400', border: 'border-teal-500/20', dot: 'bg-teal-500' },
    pink: { bg: 'bg-pink-500/10', text: 'text-pink-600 dark:text-pink-400', border: 'border-pink-500/20', dot: 'bg-pink-500' },
    amber: { bg: 'bg-amber-500/10', text: 'text-amber-600 dark:text-amber-400', border: 'border-amber-500/20', dot: 'bg-amber-500' },
    sky: { bg: 'bg-sky-500/10', text: 'text-sky-600 dark:text-sky-400', border: 'border-sky-500/20', dot: 'bg-sky-500' },
    slate: { bg: 'bg-slate-500/10', text: 'text-slate-600 dark:text-slate-400', border: 'border-slate-500/20', dot: 'bg-slate-500' },
    gray: { bg: 'bg-gray-500/10', text: 'text-gray-600 dark:text-gray-400', border: 'border-gray-500/20', dot: 'bg-gray-500' },
  };
  return colors[color] || colors.gray;
};

const getPriorityGlow = (priority: string) => {
  switch (priority) {
    case 'urgent':
      return 'shadow-[0_0_12px_rgba(239,68,68,0.4)] animate-pulse';
    case 'high':
      return 'shadow-[0_0_8px_rgba(249,115,22,0.3)]';
    default:
      return '';
  }
};

// ============================================================================
// Time Formatting
// ============================================================================

const formatTimeAgo = (timestamp: string) => {
  const now = new Date();
  const time = new Date(timestamp);
  const diff = Math.floor((now.getTime() - time.getTime()) / 1000);

  if (diff < 60) return 'just now';
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return `${Math.floor(diff / 86400)}d ago`;
};

// ============================================================================
// Single Ticker Item Component
// ============================================================================

interface TickerItemProps {
  item: TickerItem;
  onClick?: () => void;
  isNew?: boolean;
}

function TickerItemCard({ item, onClick, isNew }: TickerItemProps) {
  const config = TICKER_EVENT_CONFIG[item.type] || TICKER_EVENT_CONFIG.system;
  const Icon = ICON_MAP[item.icon || config.icon] || Bell;
  const colors = getColorClasses(item.color || config.color);
  const priorityGlow = getPriorityGlow(item.priority);

  return (
    <button
      onClick={onClick}
      className={cn(
        'flex items-center gap-2 px-3 py-1.5 rounded-lg border transition-all duration-200',
        'hover:scale-[1.02] hover:shadow-md cursor-pointer',
        'shrink-0 min-w-fit',
        colors.bg,
        colors.border,
        priorityGlow,
        isNew && 'animate-[slideIn_0.3s_ease-out]'
      )}
    >
      {/* Priority dot for urgent/high */}
      {(item.priority === 'urgent' || item.priority === 'high') && (
        <span className={cn(
          'w-2 h-2 rounded-full shrink-0',
          item.priority === 'urgent' ? 'bg-red-500 animate-pulse' : 'bg-orange-500'
        )} />
      )}

      {/* Icon */}
      <Icon className={cn('w-4 h-4 shrink-0', colors.text)} />

      {/* Content */}
      <span className={cn('text-sm font-medium whitespace-nowrap', colors.text)}>
        {item.title}
      </span>
      <span className="text-sm text-th-text-tertiary whitespace-nowrap truncate max-w-[200px]">
        {item.message}
      </span>

      {/* Time */}
      <span className="text-xs text-th-text-tertiary whitespace-nowrap">
        {formatTimeAgo(item.timestamp)}
      </span>

      {/* Arrow */}
      <ChevronRight className="w-3 h-3 text-th-text-tertiary opacity-0 group-hover:opacity-100 transition-opacity" />
    </button>
  );
}

// ============================================================================
// Main Notification Ticker Component
// ============================================================================

export function NotificationTicker() {
  const { tickerService } = useCRM();
  const navigate = useNavigate();
  const containerRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const [items, setItems] = useState<TickerItem[]>([]);
  const [isPaused, setIsPaused] = useState(false);
  const [isVisible, setIsVisible] = useState(true);
  const [isLoading, setIsLoading] = useState(true);
  const [newItemIds, setNewItemIds] = useState<Set<string>>(new Set());

  // Load initial items
  useEffect(() => {
    if (!tickerService) return;

    const loadItems = async () => {
      setIsLoading(true);
      try {
        const recentItems = await tickerService.getRecentItems({ limit: 30 });
        setItems(recentItems);
      } catch (error) {
        console.error('[NotificationTicker] Error loading items:', error);
      } finally {
        setIsLoading(false);
      }
    };

    loadItems();

    // Subscribe to real-time updates
    const unsubscribe = tickerService.subscribeToTicker((newItem) => {
      setItems((prev) => {
        // Add new item at the beginning, keep max 50
        const updated = [newItem, ...prev.filter((i) => i.id !== newItem.id)].slice(0, 50);
        return updated;
      });
      // Mark as new for animation
      setNewItemIds((prev) => new Set(prev).add(newItem.id));
      // Remove new marker after animation
      setTimeout(() => {
        setNewItemIds((prev) => {
          const next = new Set(prev);
          next.delete(newItem.id);
          return next;
        });
      }, 2000);
    });

    return () => {
      unsubscribe();
    };
  }, [tickerService]);

  // Auto-scroll animation
  useEffect(() => {
    if (isPaused || items.length === 0 || !scrollRef.current) return;

    let animationId: number;
    let scrollPosition = 0;
    const scrollSpeed = 0.5; // pixels per frame

    const animate = () => {
      if (!scrollRef.current || isPaused) return;

      scrollPosition += scrollSpeed;
      const maxScroll = scrollRef.current.scrollWidth - scrollRef.current.clientWidth;

      if (scrollPosition >= maxScroll) {
        scrollPosition = 0;
      }

      scrollRef.current.scrollLeft = scrollPosition;
      animationId = requestAnimationFrame(animate);
    };

    animationId = requestAnimationFrame(animate);

    return () => {
      cancelAnimationFrame(animationId);
    };
  }, [isPaused, items.length]);

  // Handle item click - navigate to entity
  const handleItemClick = useCallback((item: TickerItem) => {
    if (!item.entityType || !item.entityId) return;

    const routes: Record<string, string> = {
      lead: `/leads/${item.entityId}`,
      task: `/tasks`,
      deal: `/deals/${item.entityId}`,
      contact: `/contacts/${item.entityId}`,
      account: `/accounts/${item.entityId}`,
      calendar_event: `/calendar`,
      activity: `/leads/${item.metadata?.leadId || ''}`,
    };

    const route = routes[item.entityType];
    if (route) {
      navigate(route);
    }
  }, [navigate]);

  if (!isVisible) return null;

  return (
    <div
      ref={containerRef}
      className={cn(
        'relative w-full overflow-hidden',
        'bg-gradient-to-r from-surface-primary via-surface-secondary to-surface-primary',
        'border-b border-th-border/50',
        'shadow-sm'
      )}
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      {/* Live indicator */}
      <div className="absolute left-0 top-0 bottom-0 flex items-center z-10 pl-3 pr-6 bg-gradient-to-r from-surface-primary via-surface-primary to-transparent">
        <div className="flex items-center gap-2">
          <span className="relative flex h-2 w-2">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75" />
            <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500" />
          </span>
          <span className="text-xs font-semibold uppercase tracking-wider text-green-600 dark:text-green-400">
            Live
          </span>
        </div>
      </div>

      {/* Scrolling ticker content */}
      <div
        ref={scrollRef}
        className="flex items-center gap-3 px-20 py-2 overflow-x-hidden"
        style={{ scrollBehavior: 'auto' }}
      >
        {isLoading ? (
          <div className="flex items-center gap-2 text-th-text-tertiary text-sm">
            <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-th-accent-600" />
            <span>Loading activity feed...</span>
          </div>
        ) : items.length === 0 ? (
          <div className="flex items-center gap-2 text-th-text-tertiary text-sm">
            <Activity className="w-4 h-4" />
            <span>No recent activity - new events will appear here in real-time</span>
          </div>
        ) : (
          /* Duplicate items for seamless loop */
          [...items, ...items].map((item, index) => (
            <TickerItemCard
              key={`${item.id}-${index}`}
              item={item}
              onClick={() => handleItemClick(item)}
              isNew={newItemIds.has(item.id) && index < items.length}
            />
          ))
        )}
      </div>

      {/* Controls */}
      <div className="absolute right-0 top-0 bottom-0 flex items-center z-10 pr-3 pl-6 bg-gradient-to-l from-surface-primary via-surface-primary to-transparent">
        <div className="flex items-center gap-1">
          {/* Pause/Play */}
          <button
            onClick={() => setIsPaused(!isPaused)}
            className="p-1.5 rounded-md hover:bg-surface-tertiary text-th-text-tertiary hover:text-th-text-secondary transition-colors"
            title={isPaused ? 'Resume' : 'Pause'}
          >
            {isPaused ? <Play className="w-3.5 h-3.5" /> : <Pause className="w-3.5 h-3.5" />}
          </button>

          {/* Close */}
          <button
            onClick={() => setIsVisible(false)}
            className="p-1.5 rounded-md hover:bg-surface-tertiary text-th-text-tertiary hover:text-th-text-secondary transition-colors"
            title="Hide ticker"
          >
            <X className="w-3.5 h-3.5" />
          </button>
        </div>
      </div>

      {/* Gradient fades for smooth edges */}
      <div className="absolute inset-y-0 left-16 w-8 bg-gradient-to-r from-surface-primary to-transparent pointer-events-none" />
      <div className="absolute inset-y-0 right-16 w-8 bg-gradient-to-l from-surface-primary to-transparent pointer-events-none" />

      {/* Custom animation keyframes */}
      <style>{`
        @keyframes slideIn {
          from {
            opacity: 0;
            transform: translateY(-10px) scale(0.95);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }
      `}</style>
    </div>
  );
}

export default NotificationTicker;

// ============================================================================
// PermissionGate ΓÇö Conditionally render children based on org permissions
// ============================================================================

import type { ReactNode } from 'react';
import { useOrg } from '../contexts/OrgContext';

interface PermissionGateProps {
  /** Required permission key (e.g. "leads.view") */
  permission?: string;
  /** Require any one of these permissions */
  anyOf?: string[];
  /** Require all of these permissions */
  allOf?: string[];
  /** What to render when permission is denied (defaults to null) */
  fallback?: ReactNode;
  children: ReactNode;
}

export function PermissionGate({
  permission,
  anyOf,
  allOf,
  fallback = null,
  children,
}: PermissionGateProps) {
  const { can, canAny, canAll, permissionsLoading } = useOrg();

  if (permissionsLoading) return null;

  let allowed = false;

  if (permission) {
    allowed = can(permission);
  } else if (anyOf) {
    allowed = canAny(anyOf);
  } else if (allOf) {
    allowed = canAll(allOf);
  } else {
    // No permission specified ΓÇö allow by default
    allowed = true;
  }

  return allowed ? <>{children}</> : <>{fallback}</>;
}

/** Full-page access denied fallback */
export function AccessDenied() {
  return (
    <div className="min-h-[60vh] flex flex-col items-center justify-center text-center px-4">
      <div className="w-16 h-16 rounded-full bg-red-100 flex items-center justify-center mb-4">
        <svg className="w-8 h-8 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={2}
            d="M12 9v2m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
          />
        </svg>
      </div>
      <h2 className="text-xl font-semibold text-th-text-primary mb-2">Access Denied</h2>
      <p className="text-th-text-secondary max-w-md">
        You don't have permission to access this page. Contact your organization admin if you believe
        this is an error.
      </p>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { Bookmark, Plus, Star, Trash2, Share2, X } from 'lucide-react';
import type { SavedView } from '@mpbhealth/crm-core';

interface SavedViewsBarProps {
  views: SavedView[];
  activeViewId: string | null;
  loading: boolean;
  onApplyView: (view: SavedView) => void;
  onSaveView: (name: string, isShared: boolean) => Promise<any>;
  onDeleteView: (id: string) => void;
  onSetDefault: (id: string) => void;
  onClearView: () => void;
}

export function SavedViewsBar({
  views,
  activeViewId,
  loading,
  onApplyView,
  onSaveView,
  onDeleteView,
  onSetDefault,
  onClearView,
}: SavedViewsBarProps) {
  const [showForm, setShowForm] = useState(false);
  const [newName, setNewName] = useState('');
  const [isShared, setIsShared] = useState(false);
  const [menuViewId, setMenuViewId] = useState<string | null>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Focus name input when form opens
  useEffect(() => {
    if (showForm && nameInputRef.current) {
      nameInputRef.current.focus();
    }
  }, [showForm]);

  // Close menu on outside click
  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setMenuViewId(null);
      }
    }
    if (menuViewId) {
      document.addEventListener('mousedown', handleClick);
      return () => document.removeEventListener('mousedown', handleClick);
    }
  }, [menuViewId]);

  const handleSave = async () => {
    const trimmed = newName.trim();
    if (!trimmed) return;
    await onSaveView(trimmed, isShared);
    setNewName('');
    setIsShared(false);
    setShowForm(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSave();
    if (e.key === 'Escape') {
      setShowForm(false);
      setNewName('');
    }
  };

  return (
    <div className="flex items-center gap-2 px-1 py-2 overflow-x-auto">
      {/* Label */}
      <div className="flex items-center gap-1.5 text-xs font-medium th-text-secondary shrink-0">
        <Bookmark className="w-3.5 h-3.5" />
        <span>Views</span>
      </div>

      {/* Divider */}
      <div className="w-px h-5 th-border bg-current opacity-20 shrink-0" />

      {/* View pills */}
      {views.map((view) => (
        <div key={view.id} className="relative shrink-0">
          <button
            onClick={() => onApplyView(view)}
            onContextMenu={(e) => {
              e.preventDefault();
              setMenuViewId(menuViewId === view.id ? null : view.id);
            }}
            className={`
              inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium
              transition-colors duration-150 border
              ${
                activeViewId === view.id
                  ? 'th-accent-bg th-accent-text border-transparent'
                  : 'surface-primary th-text-primary th-border hover:th-accent-bg/10'
              }
            `}
          >
            {view.is_default && (
              <Star className="w-3 h-3 fill-current opacity-70" />
            )}
            {view.is_shared && <Share2 className="w-3 h-3 opacity-50" />}
            <span>{view.name}</span>
          </button>

          {/* Context menu */}
          {menuViewId === view.id && (
            <div
              ref={menuRef}
              className="absolute top-full left-0 mt-1 z-50 min-w-[140px] surface-primary th-border border rounded-lg shadow-lg py-1"
            >
              <button
                onClick={() => {
                  onSetDefault(view.id);
                  setMenuViewId(null);
                }}
                className="w-full flex items-center gap-2 px-3 py-1.5 text-xs th-text-primary hover:th-accent-bg/10 transition-colors"
              >
                <Star className="w-3.5 h-3.5" />
                Set as Default
              </button>
              <button
                onClick={() => {
                  onDeleteView(view.id);
                  setMenuViewId(null);
                }}
                className="w-full flex items-center gap-2 px-3 py-1.5 text-xs text-red-600 hover:bg-red-50 dark:hover:bg-red-950/20 transition-colors"
              >
                <Trash2 className="w-3.5 h-3.5" />
                Delete
              </button>
            </div>
          )}
        </div>
      ))}

      {/* Clear active view */}
      {activeViewId && (
        <button
          onClick={onClearView}
          className="inline-flex items-center gap-1 px-2 py-1.5 rounded-full text-xs th-text-secondary hover:th-text-primary transition-colors shrink-0"
          title="Clear active view"
        >
          <X className="w-3.5 h-3.5" />
        </button>
      )}

      {/* Divider before save */}
      {views.length > 0 && (
        <div className="w-px h-5 th-border bg-current opacity-20 shrink-0" />
      )}

      {/* Save view form / button */}
      {showForm ? (
        <div className="flex items-center gap-2 shrink-0">
          <input
            ref={nameInputRef}
            type="text"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="View name..."
            className="w-36 px-2.5 py-1.5 text-xs rounded-md th-border border surface-primary th-text-primary placeholder:th-text-secondary focus:outline-none focus:ring-1 focus:th-accent-ring"
          />
          <label className="flex items-center gap-1 text-xs th-text-secondary cursor-pointer shrink-0">
            <input
              type="checkbox"
              checked={isShared}
              onChange={(e) => setIsShared(e.target.checked)}
              className="w-3.5 h-3.5 rounded th-border"
            />
            Shared
          </label>
          <button
            onClick={handleSave}
            disabled={!newName.trim() || loading}
            className="px-3 py-1.5 text-xs font-medium rounded-md th-accent-bg th-accent-text disabled:opacity-50 transition-colors shrink-0"
          >
            {loading ? 'Saving...' : 'Save'}
          </button>
          <button
            onClick={() => {
              setShowForm(false);
              setNewName('');
            }}
            className="p-1.5 rounded-md th-text-secondary hover:th-text-primary transition-colors shrink-0"
          >
            <X className="w-3.5 h-3.5" />
          </button>
        </div>
      ) : (
        <button
          onClick={() => setShowForm(true)}
          className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium th-text-secondary hover:th-text-primary border th-border border-dashed hover:border-solid transition-all shrink-0"
        >
          <Plus className="w-3.5 h-3.5" />
          Save View
        </button>
      )}
    </div>
  );
}

// ============================================================================
// Saved Views Toolbar
// Unified toolbar for list pages with saved views, filters, segments, and export
// ============================================================================

import { useState, useRef, useEffect } from 'react';
import {
  BookmarkPlus,
  ChevronDown,
  Filter,
  LayoutGrid,
  List,
  Download,
  MoreHorizontal,
  Search,
  SlidersHorizontal,
  Star,
  Trash2,
  Edit2,
  Check,
  X,
  Plus,
  RefreshCw,
} from 'lucide-react';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Types
// ============================================================================

export interface SavedView {
  id: string;
  name: string;
  filters: FilterCondition[];
  columns?: string[];
  sortBy?: string;
  sortOrder?: 'asc' | 'desc';
  isDefault?: boolean;
  isPinned?: boolean;
  createdAt: string;
  updatedAt: string;
}

export interface FilterCondition {
  field: string;
  operator: 'equals' | 'contains' | 'starts_with' | 'ends_with' | 'gt' | 'lt' | 'gte' | 'lte' | 'in' | 'not_in' | 'is_null' | 'is_not_null';
  value: string | number | string[] | null;
  label?: string;
}

export interface FilterField {
  id: string;
  label: string;
  type: 'text' | 'number' | 'select' | 'date' | 'boolean';
  options?: { value: string; label: string }[];
}

interface SavedViewsToolbarProps {
  // Views
  savedViews: SavedView[];
  activeView?: SavedView | null;
  onViewChange: (view: SavedView | null) => void;
  onViewSave: (view: Omit<SavedView, 'id' | 'createdAt' | 'updatedAt'>) => void;
  onViewDelete?: (viewId: string) => void;
  onViewUpdate?: (viewId: string, updates: Partial<SavedView>) => void;

  // Filters
  availableFilters: FilterField[];
  activeFilters: FilterCondition[];
  onFiltersChange: (filters: FilterCondition[]) => void;

  // Search
  searchQuery?: string;
  onSearchChange?: (query: string) => void;
  searchPlaceholder?: string;

  // View mode
  viewMode?: 'list' | 'grid';
  onViewModeChange?: (mode: 'list' | 'grid') => void;
  showViewModeToggle?: boolean;

  // Export
  onExport?: () => void;
  showExport?: boolean;

  // Refresh
  onRefresh?: () => void;
  isRefreshing?: boolean;

  // Custom actions
  customActions?: React.ReactNode;
}

// ============================================================================
// Saved Views Toolbar Component
// ============================================================================

export function SavedViewsToolbar({
  savedViews,
  activeView,
  onViewChange,
  onViewSave,
  onViewDelete,
  onViewUpdate,
  availableFilters,
  activeFilters,
  onFiltersChange,
  searchQuery = '',
  onSearchChange,
  searchPlaceholder = 'Search...',
  viewMode = 'list',
  onViewModeChange,
  showViewModeToggle = true,
  onExport,
  showExport = true,
  onRefresh,
  isRefreshing = false,
  customActions,
}: SavedViewsToolbarProps) {
  const [showViewsDropdown, setShowViewsDropdown] = useState(false);
  const [showFiltersPanel, setShowFiltersPanel] = useState(false);
  const [showSaveViewModal, setShowSaveViewModal] = useState(false);
  const [newViewName, setNewViewName] = useState('');

  const viewsRef = useRef<HTMLDivElement>(null);

  // Close dropdowns on outside click
  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (viewsRef.current && !viewsRef.current.contains(e.target as Node)) {
        setShowViewsDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const handleSaveView = () => {
    if (!newViewName.trim()) return;
    onViewSave({
      name: newViewName.trim(),
      filters: activeFilters,
    });
    setNewViewName('');
    setShowSaveViewModal(false);
  };

  const handleClearFilters = () => {
    onFiltersChange([]);
    onViewChange(null);
  };

  const hasActiveFilters = activeFilters.length > 0;

  return (
    <div className="bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-700">
      {/* Main Toolbar Row */}
      <div className="px-4 py-3 flex items-center gap-3 flex-wrap">
        {/* Saved Views Selector */}
        <div ref={viewsRef} className="relative">
          <button
            onClick={() => setShowViewsDropdown(!showViewsDropdown)}
            className={cn(
              'flex items-center gap-2 px-3 py-2 text-sm font-medium rounded-lg border transition-colors',
              activeView
                ? 'bg-blue-50 border-blue-200 text-blue-700 dark:bg-blue-900/30 dark:border-blue-700 dark:text-blue-300'
                : 'bg-white border-gray-300 text-gray-700 hover:bg-gray-50 dark:bg-gray-800 dark:border-gray-600 dark:text-gray-300 dark:hover:bg-gray-700'
            )}
          >
            <LayoutGrid className="w-4 h-4" />
            <span>{activeView?.name || 'All Records'}</span>
            <ChevronDown className="w-4 h-4" />
          </button>

          {/* Views Dropdown */}
          {showViewsDropdown && (
            <div className="absolute top-full left-0 mt-1 w-64 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg shadow-lg z-50">
              {/* Default View */}
              <button
                onClick={() => {
                  onViewChange(null);
                  setShowViewsDropdown(false);
                }}
                className={cn(
                  'w-full flex items-center gap-3 px-4 py-2.5 text-sm text-left hover:bg-gray-50 dark:hover:bg-gray-800',
                  !activeView && 'bg-blue-50 dark:bg-blue-900/30'
                )}
              >
                <LayoutGrid className="w-4 h-4 text-gray-400" />
                <span>All Records</span>
                {!activeView && <Check className="w-4 h-4 text-blue-600 ml-auto" />}
              </button>

              {/* Saved Views */}
              {savedViews.length > 0 && (
                <>
                  <div className="border-t border-gray-200 dark:border-gray-700 my-1" />
                  <div className="px-3 py-1.5 text-xs font-medium text-gray-500 uppercase">
                    Saved Views
                  </div>
                  {savedViews.map((view) => (
                    <div
                      key={view.id}
                      className={cn(
                        'group flex items-center gap-2 px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-800',
                        activeView?.id === view.id && 'bg-blue-50 dark:bg-blue-900/30'
                      )}
                    >
                      <button
                        onClick={() => {
                          onViewChange(view);
                          setShowViewsDropdown(false);
                        }}
                        className="flex-1 flex items-center gap-2 text-sm text-left"
                      >
                        {view.isPinned && <Star className="w-3 h-3 text-yellow-500 fill-current" />}
                        <span className="truncate">{view.name}</span>
                        {activeView?.id === view.id && (
                          <Check className="w-4 h-4 text-blue-600 ml-auto" />
                        )}
                      </button>
                      {onViewDelete && (
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            onViewDelete(view.id);
                          }}
                          className="opacity-0 group-hover:opacity-100 p-1 text-gray-400 hover:text-red-500 transition-opacity"
                        >
                          <Trash2 className="w-3 h-3" />
                        </button>
                      )}
                    </div>
                  ))}
                </>
              )}

              {/* Save Current View */}
              <div className="border-t border-gray-200 dark:border-gray-700 mt-1">
                <button
                  onClick={() => {
                    setShowViewsDropdown(false);
                    setShowSaveViewModal(true);
                  }}
                  className="w-full flex items-center gap-2 px-4 py-2.5 text-sm text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/30"
                >
                  <BookmarkPlus className="w-4 h-4" />
                  Save Current View
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Filters Button */}
        <button
          onClick={() => setShowFiltersPanel(!showFiltersPanel)}
          className={cn(
            'flex items-center gap-2 px-3 py-2 text-sm font-medium rounded-lg border transition-colors',
            hasActiveFilters
              ? 'bg-blue-50 border-blue-200 text-blue-700 dark:bg-blue-900/30 dark:border-blue-700 dark:text-blue-300'
              : 'bg-white border-gray-300 text-gray-700 hover:bg-gray-50 dark:bg-gray-800 dark:border-gray-600 dark:text-gray-300 dark:hover:bg-gray-700'
          )}
        >
          <SlidersHorizontal className="w-4 h-4" />
          <span>Filters</span>
          {hasActiveFilters && (
            <span className="bg-blue-600 text-white text-xs px-1.5 py-0.5 rounded-full">
              {activeFilters.length}
            </span>
          )}
        </button>

        {/* Clear Filters */}
        {hasActiveFilters && (
          <button
            onClick={handleClearFilters}
            className="flex items-center gap-1 px-2 py-2 text-sm text-gray-500 hover:text-gray-700 dark:hover:text-gray-300"
          >
            <X className="w-4 h-4" />
            Clear
          </button>
        )}

        {/* Spacer */}
        <div className="flex-1" />

        {/* Search */}
        {onSearchChange && (
          <div className="relative w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => onSearchChange(e.target.value)}
              placeholder={searchPlaceholder}
              className="w-full pl-9 pr-3 py-2 text-sm border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
        )}

        {/* View Mode Toggle */}
        {showViewModeToggle && onViewModeChange && (
          <div className="flex items-center border border-gray-300 dark:border-gray-600 rounded-lg overflow-hidden">
            <button
              onClick={() => onViewModeChange('list')}
              className={cn(
                'p-2 transition-colors',
                viewMode === 'list'
                  ? 'bg-gray-100 dark:bg-gray-700 text-gray-900 dark:text-gray-100'
                  : 'text-gray-400 hover:text-gray-600 dark:hover:text-gray-300'
              )}
              title="List view"
            >
              <List className="w-4 h-4" />
            </button>
            <button
              onClick={() => onViewModeChange('grid')}
              className={cn(
                'p-2 transition-colors',
                viewMode === 'grid'
                  ? 'bg-gray-100 dark:bg-gray-700 text-gray-900 dark:text-gray-100'
                  : 'text-gray-400 hover:text-gray-600 dark:hover:text-gray-300'
              )}
              title="Grid view"
            >
              <LayoutGrid className="w-4 h-4" />
            </button>
          </div>
        )}

        {/* Refresh */}
        {onRefresh && (
          <button
            onClick={onRefresh}
            disabled={isRefreshing}
            className="p-2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 disabled:opacity-50"
            title="Refresh"
          >
            <RefreshCw className={cn('w-4 h-4', isRefreshing && 'animate-spin')} />
          </button>
        )}

        {/* Export */}
        {showExport && onExport && (
          <button
            onClick={onExport}
            className="p-2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
            title="Export"
          >
            <Download className="w-4 h-4" />
          </button>
        )}

        {/* Custom Actions */}
        {customActions}
      </div>

      {/* Filters Panel */}
      {showFiltersPanel && (
        <FiltersPanel
          availableFilters={availableFilters}
          activeFilters={activeFilters}
          onFiltersChange={onFiltersChange}
          onClose={() => setShowFiltersPanel(false)}
        />
      )}

      {/* Active Filters Pills */}
      {hasActiveFilters && (
        <div className="px-4 py-2 border-t border-gray-100 dark:border-gray-800 flex items-center gap-2 flex-wrap">
          {activeFilters.map((filter, index) => (
            <FilterPill
              key={index}
              filter={filter}
              availableFilters={availableFilters}
              onRemove={() => {
                onFiltersChange(activeFilters.filter((_, i) => i !== index));
              }}
            />
          ))}
        </div>
      )}

      {/* Save View Modal */}
      {showSaveViewModal && (
        <SaveViewModal
          viewName={newViewName}
          onViewNameChange={setNewViewName}
          onSave={handleSaveView}
          onClose={() => {
            setShowSaveViewModal(false);
            setNewViewName('');
          }}
        />
      )}
    </div>
  );
}

// ============================================================================
// Filters Panel Component
// ============================================================================

interface FiltersPanelProps {
  availableFilters: FilterField[];
  activeFilters: FilterCondition[];
  onFiltersChange: (filters: FilterCondition[]) => void;
  onClose: () => void;
}

function FiltersPanel({ availableFilters, activeFilters, onFiltersChange, onClose }: FiltersPanelProps) {
  const [pendingFilters, setPendingFilters] = useState<FilterCondition[]>(activeFilters);

  const handleAddFilter = () => {
    if (availableFilters.length === 0) return;
    setPendingFilters([
      ...pendingFilters,
      {
        field: availableFilters[0].id,
        operator: 'contains',
        value: '',
      },
    ]);
  };

  const handleApply = () => {
    onFiltersChange(pendingFilters.filter((f) => f.value !== '' && f.value !== null));
    onClose();
  };

  return (
    <div className="border-t border-gray-200 dark:border-gray-700 px-4 py-4 bg-gray-50 dark:bg-gray-800/50">
      <div className="space-y-3">
        {pendingFilters.map((filter, index) => (
          <div key={index} className="flex items-center gap-2">
            {/* Field Select */}
            <select
              value={filter.field}
              onChange={(e) => {
                const updated = [...pendingFilters];
                updated[index] = { ...filter, field: e.target.value };
                setPendingFilters(updated);
              }}
              className="px-3 py-2 text-sm border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800"
            >
              {availableFilters.map((f) => (
                <option key={f.id} value={f.id}>
                  {f.label}
                </option>
              ))}
            </select>

            {/* Operator Select */}
            <select
              value={filter.operator}
              onChange={(e) => {
                const updated = [...pendingFilters];
                updated[index] = { ...filter, operator: e.target.value as FilterCondition['operator'] };
                setPendingFilters(updated);
              }}
              className="px-3 py-2 text-sm border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800"
            >
              <option value="contains">contains</option>
              <option value="equals">equals</option>
              <option value="starts_with">starts with</option>
              <option value="ends_with">ends with</option>
              <option value="gt">greater than</option>
              <option value="lt">less than</option>
              <option value="is_null">is empty</option>
              <option value="is_not_null">is not empty</option>
            </select>

            {/* Value Input */}
            {!['is_null', 'is_not_null'].includes(filter.operator) && (
              <input
                type="text"
                value={filter.value as string || ''}
                onChange={(e) => {
                  const updated = [...pendingFilters];
                  updated[index] = { ...filter, value: e.target.value };
                  setPendingFilters(updated);
                }}
                placeholder="Value..."
                className="flex-1 px-3 py-2 text-sm border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800"
              />
            )}

            {/* Remove */}
            <button
              onClick={() => setPendingFilters(pendingFilters.filter((_, i) => i !== index))}
              className="p-2 text-gray-400 hover:text-red-500"
            >
              <X className="w-4 h-4" />
            </button>
          </div>
        ))}

        {/* Add Filter Button */}
        <button
          onClick={handleAddFilter}
          className="flex items-center gap-2 text-sm text-blue-600 hover:text-blue-700"
        >
          <Plus className="w-4 h-4" />
          Add Filter
        </button>
      </div>

      {/* Actions */}
      <div className="flex items-center justify-end gap-2 mt-4 pt-4 border-t border-gray-200 dark:border-gray-700">
        <button
          onClick={onClose}
          className="px-3 py-2 text-sm text-gray-600 hover:text-gray-800 dark:text-gray-400 dark:hover:text-gray-200"
        >
          Cancel
        </button>
        <button
          onClick={handleApply}
          className="px-4 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 rounded-lg"
        >
          Apply Filters
        </button>
      </div>
    </div>
  );
}

// ============================================================================
// Filter Pill Component
// ============================================================================

interface FilterPillProps {
  filter: FilterCondition;
  availableFilters: FilterField[];
  onRemove: () => void;
}

function FilterPill({ filter, availableFilters, onRemove }: FilterPillProps) {
  const field = availableFilters.find((f) => f.id === filter.field);
  const operatorLabels: Record<string, string> = {
    equals: '=',
    contains: 'contains',
    starts_with: 'starts with',
    ends_with: 'ends with',
    gt: '>',
    lt: '<',
    gte: '>=',
    lte: '<=',
    is_null: 'is empty',
    is_not_null: 'is not empty',
  };

  return (
    <span className="inline-flex items-center gap-1 px-2 py-1 bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 rounded-full text-xs">
      <span className="font-medium">{field?.label || filter.field}</span>
      <span className="text-blue-500">{operatorLabels[filter.operator]}</span>
      {filter.value !== null && <span>"{filter.value}"</span>}
      <button
        onClick={onRemove}
        className="ml-1 hover:text-blue-900 dark:hover:text-blue-100"
      >
        <X className="w-3 h-3" />
      </button>
    </span>
  );
}

// ============================================================================
// Save View Modal
// ============================================================================

interface SaveViewModalProps {
  viewName: string;
  onViewNameChange: (name: string) => void;
  onSave: () => void;
  onClose: () => void;
}

function SaveViewModal({ viewName, onViewNameChange, onSave, onClose }: SaveViewModalProps) {
  return (
    <>
      <div className="fixed inset-0 bg-black/50 z-50" onClick={onClose} />
      <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-md bg-white dark:bg-gray-900 rounded-xl shadow-2xl z-50 p-6">
        <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-100 mb-4">
          Save Current View
        </h3>
        <input
          type="text"
          value={viewName}
          onChange={(e) => onViewNameChange(e.target.value)}
          placeholder="View name..."
          className="w-full px-4 py-2 text-sm border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 mb-4"
          autoFocus
        />
        <div className="flex justify-end gap-2">
          <button
            onClick={onClose}
            className="px-4 py-2 text-sm text-gray-600 hover:text-gray-800 dark:text-gray-400"
          >
            Cancel
          </button>
          <button
            onClick={onSave}
            disabled={!viewName.trim()}
            className="px-4 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 rounded-lg disabled:opacity-50"
          >
            Save View
          </button>
        </div>
      </div>
    </>
  );
}

export default SavedViewsToolbar;

import { useState, useEffect } from 'react';
import { BarChart3, RefreshCw } from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import type { LeadScoreBreakdown } from '@mpbhealth/crm-core';

interface Props {
  leadId: string;
}

export function ScoreBreakdownPanel({ leadId }: Props) {
  const { scoringService } = useCRM();
  const [breakdown, setBreakdown] = useState<LeadScoreBreakdown | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      const data = await scoringService.getScoreBreakdown(leadId);
      setBreakdown(data);
      setLoading(false);
    };
    load();
  }, [scoringService, leadId]);

  if (loading) {
    return (
      <div className="bg-surface-primary rounded-xl border border-th-border p-4">
        <div className="flex items-center justify-center py-6">
          <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-th-accent-600" />
        </div>
      </div>
    );
  }

  if (!breakdown) {
    return (
      <div className="bg-surface-primary rounded-xl border border-th-border p-4">
        <div className="flex items-center gap-2 mb-3">
          <BarChart3 className="w-4 h-4 text-th-text-tertiary" />
          <h3 className="text-sm font-semibold text-th-text-primary">Lead Score</h3>
        </div>
        <p className="text-sm text-th-text-tertiary">No score data available.</p>
      </div>
    );
  }

  const maxPoints = Math.max(...breakdown.factors.map((f) => Math.abs(f.points)), 1);

  return (
    <div className="bg-surface-primary rounded-xl border border-th-border p-4">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <BarChart3 className="w-4 h-4 text-th-text-tertiary" />
          <h3 className="text-sm font-semibold text-th-text-primary">Lead Score</h3>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-2xl font-bold text-th-accent-600">{breakdown.total_score}</span>
          <span className="text-xs text-th-text-tertiary">/ 100</span>
        </div>
      </div>

      {/* Score bar */}
      <div className="h-2 bg-surface-tertiary rounded-full mb-4 overflow-hidden">
        <div
          className="h-full rounded-full transition-all duration-500"
          style={{
            width: `${Math.min(breakdown.total_score, 100)}%`,
            backgroundColor: breakdown.total_score >= 70 ? '#10B981' : breakdown.total_score >= 40 ? '#F59E0B' : '#EF4444',
          }}
        />
      </div>

      {/* Factor breakdown */}
      {breakdown.factors.length > 0 && (
        <div className="space-y-2">
          {breakdown.factors.map((factor, i) => (
            <div key={i} className="flex items-center gap-2">
              <span className="text-xs text-th-text-secondary w-28 truncate">{factor.factor}</span>
              <div className="flex-1 h-4 bg-surface-tertiary rounded overflow-hidden">
                <div
                  className={`h-full rounded transition-all ${factor.positive ? 'bg-green-500' : 'bg-red-400'}`}
                  style={{ width: `${(Math.abs(factor.points) / maxPoints) * 100}%` }}
                />
              </div>
              <span className={`text-xs font-medium w-8 text-right ${factor.positive ? 'text-green-600' : 'text-red-500'}`}>
                {factor.positive ? '+' : '-'}{Math.abs(factor.points)}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { InputField, TextareaField, SubmitButton } from './FormField';
import { useForm } from '../hooks/useForm';
import { useCRM } from '../contexts/CRMContext';

interface SendDraftModalProps {
  open: boolean;
  onClose: () => void;
  leadId: string;
  leadEmail: string;
  subject?: string;
  body: string;
  draftType: 'email' | 'sms';
}

interface SendFormValues {
  to: string;
  subject: string;
  body: string;
  save_as_template: string;
  template_name: string;
}

export function SendDraftModal({
  open,
  onClose,
  leadId,
  leadEmail,
  subject,
  body,
  draftType,
}: SendDraftModalProps) {
  const { emailService, templateService } = useCRM();

  const { values, errors, loading, handleChange, handleSubmit } = useForm<SendFormValues>({
    initialValues: {
      to: leadEmail,
      subject: subject || '',
      body: body,
      save_as_template: 'false',
      template_name: '',
    },
    validate: (vals) => {
      const errs: Partial<Record<keyof SendFormValues, string>> = {};
      if (!vals.to.trim()) errs.to = 'Recipient is required';
      if (draftType === 'email' && !vals.subject.trim()) errs.subject = 'Subject is required';
      if (!vals.body.trim()) errs.body = 'Body is required';
      if (vals.save_as_template === 'true' && !vals.template_name.trim()) {
        errs.template_name = 'Template name is required';
      }
      return errs;
    },
    onSubmit: async (vals) => {
      // Send email
      const result = await emailService.sendDirect(vals.to, vals.subject, vals.body, leadId);

      if (!result.success) {
        toast.error(result.error || 'Failed to send email');
        return;
      }

      toast.success('Email sent');

      // Optionally save as template
      if (vals.save_as_template === 'true' && vals.template_name) {
        const templateResult = await templateService.createTemplate({
          name: vals.template_name,
          template_type: draftType === 'sms' ? 'sms' : 'email',
          subject: vals.subject || undefined,
          body: vals.body,
          is_ai_generated: true,
          category: 'general',
        });
        if (templateResult.success) {
          toast.success('Saved as template');
        }
      }

      onClose();
    },
  });

  return (
    <Modal open={open} onClose={onClose} title={`Send ${draftType === 'sms' ? 'SMS' : 'Email'}`} size="md">
      <form onSubmit={handleSubmit} className="space-y-4">
        <InputField
          label="To"
          name="to"
          type="email"
          value={values.to}
          onChange={handleChange}
          error={errors.to}
          required
        />

        {draftType === 'email' && (
          <InputField
            label="Subject"
            name="subject"
            value={values.subject}
            onChange={handleChange}
            error={errors.subject}
            required
          />
        )}

        <TextareaField
          label="Body"
          name="body"
          value={values.body}
          onChange={handleChange}
          error={errors.body}
          required
          rows={6}
        />

        <div className="border-t border-th-border pt-4">
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              checked={values.save_as_template === 'true'}
              onChange={(e) =>
                handleChange({
                  target: { name: 'save_as_template', value: e.target.checked ? 'true' : 'false' },
                } as any)
              }
              className="w-4 h-4 rounded border-th-border"
            />
            <span className="text-sm text-th-text-secondary">Save as reusable template</span>
          </label>
          {values.save_as_template === 'true' && (
            <div className="mt-2">
              <InputField
                label="Template Name"
                name="template_name"
                value={values.template_name}
                onChange={handleChange}
                error={errors.template_name}
                placeholder="e.g. AI Follow-up Email"
              />
            </div>
          )}
        </div>

        <div className="flex items-center gap-3 pt-2">
          <SubmitButton loading={loading} label="Send" />
          <button
            type="button"
            onClick={onClose}
            className="flex-1 px-4 py-2.5 text-sm font-medium text-th-text-secondary bg-surface-primary border border-th-border rounded-lg hover:bg-surface-secondary transition-colors"
          >
            Cancel
          </button>
        </div>
      </form>
    </Modal>
  );
}

import { useEffect } from 'react';
import toast from 'react-hot-toast';
import { Modal } from './Modal';
import { InputField, SelectField, TextareaField, SubmitButton } from './FormField';
import { useForm } from '../hooks/useForm';
import { useCRM } from '../contexts/CRMContext';
import { TemplatePreview } from './TemplatePreview';
import type { CRMTemplate } from '@mpbhealth/crm-core';

interface TemplateModalProps {
  open: boolean;
  onClose: () => void;
  template?: CRMTemplate | null;
  onSuccess?: () => void;
}

interface TemplateFormValues {
  name: string;
  description: string;
  template_type: string;
  category: string;
  subject: string;
  body: string;
  is_active: string;
}

const TYPE_OPTIONS = [
  { value: 'email', label: 'Email' },
  { value: 'sms', label: 'SMS' },
  { value: 'both', label: 'Both' },
];

const CATEGORY_OPTIONS = [
  { value: 'general', label: 'General' },
  { value: 'follow_up', label: 'Follow Up' },
  { value: 'welcome', label: 'Welcome' },
  { value: 'appointment', label: 'Appointment' },
  { value: 'nurture', label: 'Nurture' },
];

const VARIABLES = [
  { key: 'first_name', label: 'First Name' },
  { key: 'last_name', label: 'Last Name' },
  { key: 'email', label: 'Email' },
  { key: 'phone', label: 'Phone' },
  { key: 'company', label: 'Company' },
];

export function TemplateModal({ open, onClose, template, onSuccess }: TemplateModalProps) {
  const { templateService } = useCRM();
  const isEdit = !!template;

  const { values, errors, loading, handleChange, handleSubmit, setFieldValue, reset } =
    useForm<TemplateFormValues>({
      initialValues: {
        name: template?.name || '',
        description: template?.description || '',
        template_type: template?.template_type || 'email',
        category: template?.category || 'general',
        subject: template?.subject || '',
        body: template?.body || '',
        is_active: template?.is_active !== false ? 'true' : 'false',
      },
      validate: (vals) => {
        const errs: Partial<Record<keyof TemplateFormValues, string>> = {};
        if (!vals.name.trim()) errs.name = 'Name is required';
        if (!vals.body.trim()) errs.body = 'Body is required';
        if ((vals.template_type === 'email' || vals.template_type === 'both') && !vals.subject.trim()) {
          errs.subject = 'Subject is required for email templates';
        }
        return errs;
      },
      onSubmit: async (vals) => {
        const input = {
          name: vals.name,
          description: vals.description || undefined,
          template_type: vals.template_type as 'email' | 'sms' | 'both',
          category: vals.category,
          subject: vals.subject || undefined,
          body: vals.body,
          variables: VARIABLES.filter((v) => vals.body.includes(`{{${v.key}}}`)),
          is_active: vals.is_active === 'true',
        };

        const result = isEdit
          ? await templateService.updateTemplate(template!.id, input)
          : await templateService.createTemplate(input);

        if (!result.success) {
          toast.error(result.error || `Failed to ${isEdit ? 'update' : 'create'} template`);
          return;
        }

        toast.success(isEdit ? 'Template updated' : 'Template created');
        onSuccess?.();
        onClose();
      },
    });

  // Reset form when template changes
  useEffect(() => {
    if (open) {
      reset();
      setFieldValue('name', template?.name || '');
      setFieldValue('description', template?.description || '');
      setFieldValue('template_type', template?.template_type || 'email');
      setFieldValue('category', template?.category || 'general');
      setFieldValue('subject', template?.subject || '');
      setFieldValue('body', template?.body || '');
      setFieldValue('is_active', template?.is_active !== false ? 'true' : 'false');
    }
  }, [open, template]);

  const insertVariable = (key: string) => {
    setFieldValue('body', values.body + `{{${key}}}`);
  };

  const showSubject = values.template_type === 'email' || values.template_type === 'both';

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={isEdit ? 'Edit Template' : 'New Template'}
      variant="slideOver"
      size="lg"
    >
      <form onSubmit={handleSubmit} className="space-y-4">
        <InputField
          label="Name"
          name="name"
          value={values.name}
          onChange={handleChange}
          error={errors.name}
          required
          placeholder="e.g. Follow Up Email"
        />

        <InputField
          label="Description"
          name="description"
          value={values.description}
          onChange={handleChange}
          placeholder="Optional description"
        />

        <div className="grid grid-cols-2 gap-4">
          <SelectField
            label="Type"
            name="template_type"
            value={values.template_type}
            onChange={handleChange}
            options={TYPE_OPTIONS}
          />
          <SelectField
            label="Category"
            name="category"
            value={values.category}
            onChange={handleChange}
            options={CATEGORY_OPTIONS}
          />
        </div>

        {showSubject && (
          <InputField
            label="Subject"
            name="subject"
            value={values.subject}
            onChange={handleChange}
            error={errors.subject}
            required
            placeholder="e.g. Following up on your inquiry"
          />
        )}

        <div>
          <TextareaField
            label="Body"
            name="body"
            value={values.body}
            onChange={handleChange}
            error={errors.body}
            required
            rows={6}
            placeholder="Write your template content here..."
          />
          <div className="flex flex-wrap gap-1.5 mt-2">
            <span className="text-xs text-th-text-tertiary mr-1">Insert:</span>
            {VARIABLES.map((v) => (
              <button
                key={v.key}
                type="button"
                onClick={() => insertVariable(v.key)}
                className="px-2 py-0.5 text-xs bg-surface-tertiary text-th-text-secondary rounded hover:bg-surface-secondary transition-colors"
              >
                {`{{${v.key}}}`}
              </button>
            ))}
          </div>
        </div>

        <SelectField
          label="Status"
          name="is_active"
          value={values.is_active}
          onChange={handleChange}
          options={[
            { value: 'true', label: 'Active' },
            { value: 'false', label: 'Inactive' },
          ]}
        />

        {/* Preview */}
        {values.body && (
          <TemplatePreview body={values.body} subject={showSubject ? values.subject : undefined} />
        )}

        <div className="flex items-center gap-3 pt-2">
          <SubmitButton loading={loading} label={isEdit ? 'Save Changes' : 'Create Template'} />
          <button
            type="button"
            onClick={onClose}
            className="flex-1 px-4 py-2.5 text-sm font-medium text-th-text-secondary bg-surface-primary border border-th-border rounded-lg hover:bg-surface-secondary transition-colors"
          >
            Cancel
          </button>
        </div>
      </form>
    </Modal>
  );
}

