            {/* Stage change metadata */}
            {entry.type === 'stage_change' && meta.from_stage && meta.to_stage && (
              <span className="text-xs text-th-text-tertiary flex items-center gap-1">
                <ArrowRightLeft className="w-3 h-3" />
