            {/* Deal metadata */}
            {entry.type === 'deal' && meta.deal_value && (
              <span className="text-xs text-cyan-600 flex items-center gap-1">
                <DollarSign className="w-3 h-3" />
                ${Number(meta.deal_value).toLocaleString()}
