export function UnifiedTimeline({
  leadId,
  contactId,
  accountId,
  dealId,
  limit = 50,
  showFilters = true,
}: UnifiedTimelineProps) {
  const { supabase, taskService } = useCRM();
  const { activeOrgId } = useOrg();

  // State
  const [allEntries, setAllEntries] = useState<TimelineEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [hasMore, setHasMore] = useState(false);
  const [page, setPage] = useState(0);

  // Filters
  const [activeFilters, setActiveFilters] = useState<Set<FilterType>>(
    new Set(FILTER_OPTIONS.map((f) => f.key)),
  );
  const [searchQuery, setSearchQuery] = useState('');
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [showFilterPanel, setShowFilterPanel] = useState(false);

  // Reply modal
  const [replyModal, setReplyModal] = useState<{
    open: boolean;
    emailId?: string;
    leadId?: string;
    contactId?: string;
    to?: string[];
    subject?: string;
  }>({ open: false });

  // ----------------------------------------------------------------
  // Data fetching
  // ----------------------------------------------------------------

  const fetchEmails = useCallback(
    async (offset: number, pageSize: number): Promise<TimelineEntry[]> => {
      if (!leadId) return [];

      const query = supabase
        .from('crm_email_log')
        .select('*')
        .eq('lead_id', leadId)
        .order('created_at', { ascending: false })
        .range(offset, offset + pageSize - 1);

      const { data, error } = await query;
      if (error || !data) return [];

      return data.map((email: Record<string, unknown>) => ({
        id: `email-${email.id}`,
        type: email.direction === 'inbound' ? ('email_inbound' as const) : ('email_outbound' as const),
        timestamp: String(email.sent_at || email.created_at),
        title: String(email.subject || '(No subject)'),
        description: email.preview_text ? String(email.preview_text) : undefined,
        metadata: {
          from_address: email.from_address,
          to_address: email.to_address,
          subject: email.subject,
          body: email.body_text,
          html_body: email.body_html,
          open_count: email.open_count ?? 0,
          click_count: email.click_count ?? 0,
          has_attachments: Boolean(email.has_attachments),
          email_id: email.id,
        },
        raw: email,
      }));
    },
    [leadId, supabase],
  );

  const fetchActivities = useCallback(
    async (offset: number, pageSize: number): Promise<TimelineEntry[]> => {
      if (!leadId) return [];

      const query = supabase
        .from('lead_activities')
        .select('*')
        .eq('lead_id', leadId)
        .order('created_at', { ascending: false })
        .range(offset, offset + pageSize - 1);

      const { data, error } = await query;
      if (error || !data) return [];

      return data.map((activity: Record<string, unknown>) => {
        const actType = mapActivityType(String(activity.type || 'note'));
        const actMeta = (activity.metadata as Record<string, unknown>) || {};
        return {
          id: `activity-${activity.id}`,
          type: actType,
          timestamp: String(activity.created_at),
          title: String(activity.title || activity.description || 'Activity'),
          description: activity.description ? String(activity.description) : undefined,
          metadata: {
            ...actMeta,
            duration: actMeta.duration,
            location: actMeta.location,
            meeting_link: actMeta.meeting_link,
            attendees: actMeta.attendees,
            from_stage: actMeta.from_stage,
            to_stage: actMeta.to_stage,
          },
          raw: activity,
        };
      });
    },
    [leadId, supabase],
  );

  const fetchCalendarEvents = useCallback(
    async (offset: number, pageSize: number): Promise<TimelineEntry[]> => {
      if (!leadId) return [];

      const query = supabase
        .from('calendar_events')
        .select('*')
        .eq('lead_id', leadId)
        .order('start_time', { ascending: false })
        .range(offset, offset + pageSize - 1);

      const { data, error } = await query;
      if (error || !data) return [];

      return data.map((event: Record<string, unknown>) => ({
        id: `event-${event.id}`,
        type: 'calendar_event' as const,
        timestamp: String(event.start_time || event.created_at),
        title: String(event.title || 'Calendar Event'),
        description: event.description ? String(event.description) : undefined,
        metadata: {
          location: event.location,
          meeting_link: event.meeting_link || event.video_link,
          attendees: event.attendees,
          end_time: event.end_time,
          event_type: event.event_type,
        },
        raw: event,
      }));
    },
    [leadId, supabase],
  );

  const fetchTasks = useCallback(
    async (offset: number, pageSize: number): Promise<TimelineEntry[]> => {
      if (!leadId) return [];

      const query = supabase
        .from('lead_tasks')
        .select('*')
        .eq('lead_id', leadId)
        .order('created_at', { ascending: false })
        .range(offset, offset + pageSize - 1);

      const { data, error } = await query;
      if (error || !data) return [];

      return data.map((task: Record<string, unknown>) => {
        const isCompleted = Boolean(task.completed);
        const dueDate = task.due_date ? new Date(String(task.due_date)) : null;
        const isOverdue = !isCompleted && dueDate ? dueDate < new Date() : false;
        const status = isCompleted ? 'completed' : isOverdue ? 'overdue' : 'pending';

        return {
          id: String(task.id),
          type: 'task' as const,
          timestamp: String(task.created_at),
          title: String(task.title || 'Task'),
          description: task.description ? String(task.description) : undefined,
          metadata: {
            due_date: task.due_date,
            status,
            priority: task.priority,
            completed: isCompleted,
            task_type: task.task_type,
          },
          raw: task,
        };
      });
    },
    [leadId, supabase],
  );

  const fetchDealActivities = useCallback(
    async (offset: number, pageSize: number): Promise<TimelineEntry[]> => {
      if (!dealId) return [];

      const query = supabase
        .from('lead_activities')
        .select('*')
        .eq('deal_id', dealId)
        .order('created_at', { ascending: false })
        .range(offset, offset + pageSize - 1);

      const { data, error } = await query;
      if (error || !data) return [];

      return data.map((activity: Record<string, unknown>) => {
        const actMeta = (activity.metadata as Record<string, unknown>) || {};
        return {
          id: `deal-${activity.id}`,
          type: (activity.type === 'stage_change' ? 'stage_change' : 'deal') as TimelineEntryType,
          timestamp: String(activity.created_at),
          title: String(activity.title || activity.description || 'Deal Activity'),
          description: activity.description ? String(activity.description) : undefined,
          metadata: {
            ...actMeta,
            deal_value: actMeta.deal_value,
            from_stage: actMeta.from_stage,
            to_stage: actMeta.to_stage,
          },
          raw: activity,
        };
      });
    },
    [dealId, supabase],
  );

  const loadTimeline = useCallback(
    async (pageNum: number, append = false) => {
      if (!leadId && !dealId) {
        setLoading(false);
        return;
      }

      if (pageNum === 0) {
        setLoading(true);
      } else {
        setLoadingMore(true);
      }

      try {
        const offset = pageNum * limit;
        const results = await Promise.all([
          fetchEmails(offset, limit),
          fetchActivities(offset, limit),
          fetchCalendarEvents(offset, limit),
          fetchTasks(offset, limit),
          fetchDealActivities(offset, limit),
        ]);

        const newEntries = results
          .flat()
          .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

        // Deduplicate by id
        if (append) {
          setAllEntries((prev) => {
            const existingIds = new Set(prev.map((e) => e.id));
            const unique = newEntries.filter((e) => !existingIds.has(e.id));
            return [...prev, ...unique];
          });
        } else {
          setAllEntries(newEntries);
        }

        // If any source returned a full page, there may be more
        setHasMore(results.some((r) => r.length >= limit));
      } catch (err) {
        console.error('Error loading timeline:', err);
      } finally {
        setLoading(false);
        setLoadingMore(false);
      }
    },
    [leadId, dealId, limit, fetchEmails, fetchActivities, fetchCalendarEvents, fetchTasks, fetchDealActivities],
  );

  useEffect(() => {
    setPage(0);
    loadTimeline(0);
  }, [leadId, contactId, accountId, dealId, activeOrgId]);

  const handleLoadMore = () => {
    const nextPage = page + 1;
    setPage(nextPage);
    loadTimeline(nextPage, true);
  };

  // ----------------------------------------------------------------
  // Filtering
  // ----------------------------------------------------------------

  const filteredEntries = useMemo(() => {
    let entries = allEntries;

    // Type filters
    if (activeFilters.size < FILTER_OPTIONS.length) {
      entries = entries.filter((entry) =>
        Array.from(activeFilters).some((filter) => matchesFilterType(entry.type, filter)),
      );
    }

    // Search
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      entries = entries.filter(
        (entry) =>
          entry.title.toLowerCase().includes(q) ||
          (entry.description && entry.description.toLowerCase().includes(q)),
      );
    }

    // Date range
    if (dateFrom) {
      const from = new Date(dateFrom);
      entries = entries.filter((entry) => new Date(entry.timestamp) >= from);
    }
    if (dateTo) {
      const to = new Date(dateTo);
      to.setHours(23, 59, 59, 999);
      entries = entries.filter((entry) => new Date(entry.timestamp) <= to);
    }

    return entries;
  }, [allEntries, activeFilters, searchQuery, dateFrom, dateTo]);

  const groupedEntries = useMemo(() => groupByDate(filteredEntries), [filteredEntries]);

  // ----------------------------------------------------------------
  // Handlers
  // ----------------------------------------------------------------

  const toggleFilter = (key: FilterType) => {
    setActiveFilters((prev) => {
      const next = new Set(prev);
      if (next.has(key)) {
        next.delete(key);
      } else {
        next.add(key);
      }
      return next;
    });
  };

  const selectAllFilters = () => {
    setActiveFilters(new Set(FILTER_OPTIONS.map((f) => f.key)));
  };

  const clearAllFilters = () => {
    setActiveFilters(new Set());
  };

  const handleReply = (entry: TimelineEntry) => {
    const meta = entry.metadata || {};
    setReplyModal({
      open: true,
      emailId: meta.email_id ? String(meta.email_id) : undefined,
      leadId,
      contactId,
      to: meta.from_address ? [String(meta.from_address)] : undefined,
      subject: meta.subject ? `Re: ${String(meta.subject).replace(/^Re:\s*/i, '')}` : undefined,
    });
  };

  const handleCompleteTask = async (taskId: string) => {
    try {
      const result = await taskService.completeTask(taskId);
      if (result.success) {
        // Optimistically update the entry
        setAllEntries((prev) =>
          prev.map((entry) =>
            entry.id === taskId
              ? {
                  ...entry,
                  metadata: { ...entry.metadata, status: 'completed', completed: true },
                }
              : entry,
          ),
        );
      }
    } catch (err) {
      console.error('Failed to complete task:', err);
    }
  };

  // ----------------------------------------------------------------
  // Render
  // ----------------------------------------------------------------

  return (
    <div className="space-y-4">
      {/* Filters bar */}
      {showFilters && (
        <div className="space-y-3">
          {/* Search + filter toggle */}
          <div className="flex items-center gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary" />
              <input
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search timeline..."
                className="w-full pl-9 pr-4 py-2 text-sm border border-th-border rounded-lg bg-surface-primary text-th-text-primary placeholder:text-th-text-tertiary focus:outline-none focus:ring-2 focus:ring-th-accent-600/20 focus:border-th-accent-600"
              />
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery('')}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-th-text-tertiary hover:text-th-text-secondary"
                  title="Clear search"
                >
                  <X className="w-4 h-4" />
                </button>
              )}
            </div>
            <button
              onClick={() => setShowFilterPanel(!showFilterPanel)}
              className={`inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium border rounded-lg transition-colors ${
                showFilterPanel || activeFilters.size < FILTER_OPTIONS.length
                  ? 'border-th-accent-600 text-th-accent-600 bg-th-accent-600/5'
                  : 'border-th-border text-th-text-secondary bg-surface-primary hover:bg-surface-secondary'
              }`}
            >
              <Filter className="w-4 h-4" />
              Filters
              {activeFilters.size < FILTER_OPTIONS.length && (
                <span className="ml-1 w-5 h-5 rounded-full bg-th-accent-600 text-white text-xs flex items-center justify-center">
                  {activeFilters.size}
                </span>
              )}
            </button>
          </div>

          {/* Filter panel */}
          {showFilterPanel && (
            <div className="bg-surface-primary border border-th-border rounded-xl p-4 space-y-4">
              {/* Type filters */}
              <div>
                <div className="flex items-center justify-between mb-2">
                  <span className="text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Activity Type
                  </span>
                  <div className="flex gap-2">
                    <button
                      onClick={selectAllFilters}
                      className="text-xs text-th-accent-600 hover:underline"
                    >
                      Select all
                    </button>
                    <button
                      onClick={clearAllFilters}
                      className="text-xs text-th-text-tertiary hover:underline"
                    >
                      Clear
                    </button>
                  </div>
                </div>
                <div className="flex flex-wrap gap-2">
                  {FILTER_OPTIONS.map((opt) => {
                    const isActive = activeFilters.has(opt.key);
                    return (
                      <button
                        key={opt.key}
                        onClick={() => toggleFilter(opt.key)}
                        className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border transition-colors ${
                          isActive
                            ? 'border-th-accent-600 bg-th-accent-600/10 text-th-accent-600'
                            : 'border-th-border bg-surface-secondary text-th-text-tertiary hover:text-th-text-secondary'
                        }`}
                      >
                        {isActive && <CheckCircle2 className="w-3 h-3" />}
                        {opt.label}
                      </button>
                    );
                  })}
                </div>
              </div>

              {/* Date range */}
              <div>
                <span className="text-xs font-medium text-th-text-tertiary uppercase tracking-wider block mb-2">
                  Date Range
                </span>
                <div className="flex items-center gap-2">
                  <input
                    type="date"
                    value={dateFrom}
                    onChange={(e) => setDateFrom(e.target.value)}
                    title="Start date"
                    className="px-3 py-1.5 text-sm border border-th-border rounded-lg bg-surface-primary text-th-text-primary focus:outline-none focus:ring-2 focus:ring-th-accent-600/20"
                  />
                  <span className="text-th-text-tertiary text-sm">to</span>
                  <input
                    type="date"
                    value={dateTo}
                    onChange={(e) => setDateTo(e.target.value)}
                    title="End date"
                    className="px-3 py-1.5 text-sm border border-th-border rounded-lg bg-surface-primary text-th-text-primary focus:outline-none focus:ring-2 focus:ring-th-accent-600/20"
                  />
                  {(dateFrom || dateTo) && (
                    <button
                      onClick={() => {
                        setDateFrom('');
                        setDateTo('');
                      }}
                      className="text-xs text-th-text-tertiary hover:text-th-text-secondary"
                      title="Clear date range"
                    >
                      <X className="w-4 h-4" />
                    </button>
                  )}
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Timeline */}
      {loading ? (
        <TimelineSkeleton />
      ) : filteredEntries.length === 0 ? (
        <EmptyState />
      ) : (
        <div>
          {Array.from(groupedEntries.entries()).map(([dateKey, entries]) => (
            <div key={dateKey}>
              {/* Date header */}
              <div className="flex items-center gap-3 mb-4 mt-6 first:mt-0">
                <div className="text-xs font-semibold text-th-text-tertiary uppercase tracking-wider whitespace-nowrap">
                  {formatRelativeDate(dateKey)}
                </div>
                <div className="flex-1 h-px bg-th-border" />
              </div>

              {/* Entries for this date */}
              {entries.map((entry) => (
                <TimelineCard
                  key={entry.id}
                  entry={entry}
                  onReply={handleReply}
                  onCompleteTask={handleCompleteTask}
                />
              ))}
            </div>
          ))}

          {/* Load more */}
          {hasMore && (
            <div className="flex justify-center pt-4">
              <button
                onClick={handleLoadMore}
                disabled={loadingMore}
                className="inline-flex items-center gap-2 px-6 py-2.5 text-sm font-medium text-th-accent-600 bg-th-accent-600/5 hover:bg-th-accent-600/10 border border-th-accent-600/20 rounded-lg transition-colors disabled:opacity-50"
              >
                {loadingMore ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Loading...
                  </>
                ) : (
                  'Load More'
                )}
              </button>
            </div>
          )}
        </div>
      )}

      {/* Email reply modal */}
      <EmailComposerModal
        open={replyModal.open}
        onClose={() => setReplyModal({ open: false })}
        mode="reply"
        replyToEmailId={replyModal.emailId}
        leadId={replyModal.leadId}
        contactId={replyModal.contactId}
        initialTo={replyModal.to}
        initialSubject={replyModal.subject}
        onSent={() => {
          setReplyModal({ open: false });
          // Refresh the timeline
          setPage(0);
          loadTimeline(0);
        }}
      />
    </div>
  );
}

export default UnifiedTimeline;

// ============================================================================
// Dashboard Container Component
// Main container for the Championship Command Center
// ============================================================================

import { useEffect } from 'react';
import { Loader2, AlertCircle, LayoutDashboard } from 'lucide-react';
import { createClientLogger } from '@mpbhealth/utils';
import { DashboardProvider, useDashboardStore } from '../../contexts/DashboardContext';
import { DashboardToolbar } from './DashboardToolbar';
import { WidgetGrid } from './WidgetGrid';
import { useKeyboardShortcuts } from './KeyboardShortcuts';

const log = createClientLogger('DashboardContainer');
const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Dashboard Container (with Provider)
// ============================================================================

export function DashboardContainer() {
  return (
    <DashboardProvider>
      <DashboardContent />
    </DashboardProvider>
  );
}

// ============================================================================
// Dashboard Content (uses context)
// ============================================================================

function DashboardContent() {
  const { isLoading, error, widgets, editMode, clearError } = useDashboardStore();

  // Enable keyboard shortcuts
  useKeyboardShortcuts();

  // Listen for refresh events
  useEffect(() => {
    const handleRefresh = () => {
      // Trigger widget refresh by dispatching a custom event
      // Individual widgets listen for this
      log.info('Dashboard refresh triggered');
    };

    window.addEventListener('dashboard:refresh', handleRefresh);
    return () => window.removeEventListener('dashboard:refresh', handleRefresh);
  }, []);

  // Loading state
  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] text-gray-500">
        <Loader2 className="h-8 w-8 animate-spin mb-4" />
        <p>Loading dashboard...</p>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px]">
        <div className="p-4 rounded-lg bg-red-50 dark:bg-red-900/20 text-center max-w-md">
          <AlertCircle className="h-8 w-8 text-red-500 mx-auto mb-3" />
          <h3 className="font-medium text-red-800 dark:text-red-200 mb-2">
            Failed to load dashboard
          </h3>
          <p className="text-sm text-red-600 dark:text-red-300 mb-4">{error}</p>
          <button
            onClick={clearError}
            className="px-4 py-2 text-sm font-medium text-white bg-red-600 hover:bg-red-700 rounded-lg transition-colors"
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  // Empty state
  if (widgets.length === 0) {
    return (
      <div className="flex flex-col">
        <DashboardToolbar />
        <div className="flex flex-col items-center justify-center min-h-[400px] text-gray-500">
          <LayoutDashboard className="h-12 w-12 mb-4 opacity-50" />
          <h3 className="text-lg font-medium mb-2">No widgets yet</h3>
          <p className="text-sm text-center max-w-md mb-4">
            Your dashboard is empty. Click "Edit Dashboard" and then "Add Widget" to customize your command center.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div
      className={cn(
        'flex flex-col min-h-screen',
        editMode && 'bg-blue-50/50 dark:bg-blue-950/20'
      )}
    >
      {/* Toolbar */}
      <DashboardToolbar />

      {/* Edit mode indicator */}
      {editMode && (
        <div className="bg-blue-100 dark:bg-blue-900/30 px-4 py-2 text-sm text-blue-700 dark:text-blue-300 border-b border-blue-200 dark:border-blue-800">
          <span className="font-medium">Edit Mode:</span> Drag widgets to reorder, resize using the controls, or remove widgets you don't need.
        </div>
      )}

      {/* Widget Grid */}
      <div className="flex-1">
        <WidgetGrid />
      </div>
    </div>
  );
}

export default DashboardContainer;

// ============================================================================
// AI Insights Widget
// Shows AI-powered recommendations and hot leads
// ============================================================================

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Sparkles, TrendingUp, AlertTriangle, Lightbulb, ArrowRight, RefreshCw, Flame, Star } from 'lucide-react';
import { useCRM } from '../../../contexts/CRMContext';
import type { BaseWidgetProps } from '../types';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Types
// ============================================================================

interface AIInsight {
  id: string;
  type: 'hot_lead' | 'recommendation' | 'trend' | 'warning';
  title: string;
  description: string;
  confidence: number;
  actionLabel?: string;
  actionLink?: string;
  metadata?: Record<string, unknown>;
}

// ============================================================================
// AI Insights Widget Component
// ============================================================================

export default function AIInsightsWidget({ config, size }: BaseWidgetProps) {
  const { recentLeads, dashboardStats, pipelineStages } = useCRM();
  const [insights, setInsights] = useState<AIInsight[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);

  const insightType = (config.insightType as string) || 'all';

  useEffect(() => {
    generateInsights();
  }, [recentLeads, dashboardStats, insightType]);

  const generateInsights = async () => {
    setIsLoading(true);

    // Simulate AI processing delay
    await new Promise((resolve) => setTimeout(resolve, 500));

    const stats = (dashboardStats as unknown) as Record<string, unknown>;
    const generatedInsights: AIInsight[] = [];

    // Hot leads analysis
    const highPriorityLeads = recentLeads.filter(
      (l) => l.priority === 'urgent' || l.priority === 'high'
    );

    highPriorityLeads.slice(0, 2).forEach((lead) => {
      const score = calculateLeadScore(lead);
      if (score > 70) {
        generatedInsights.push({
          id: `hot-${lead.id}`,
          type: 'hot_lead',
          title: 'Hot Lead Detected',
          description: `${lead.first_name} ${lead.last_name} shows high engagement signals. Recommend immediate follow-up.`,
          confidence: score,
          actionLabel: 'View Lead',
          actionLink: `/leads/${lead.id}`,
          metadata: { leadId: lead.id, score },
        });
      }
    });

    // Conversion trend insights
    const conversionRate = ((stats.leads_converted as number) || 0) / Math.max((stats.total_leads as number) || 1, 1);
    if (conversionRate > 0.15) {
      generatedInsights.push({
        id: 'trend-conversion',
        type: 'trend',
        title: 'Conversion Rate Trending Up',
        description: `Your conversion rate of ${(conversionRate * 100).toFixed(1)}% is above average. Keep up the momentum!`,
        confidence: 85,
      });
    } else if (conversionRate < 0.05 && (stats.total_leads as number) > 10) {
      generatedInsights.push({
        id: 'warning-conversion',
        type: 'warning',
        title: 'Low Conversion Rate',
        description: 'Your conversion rate is below target. Consider reviewing your follow-up process.',
        confidence: 90,
        actionLabel: 'View Pipeline',
        actionLink: '/pipeline',
      });
    }

    // Overdue tasks warning
    const overdueTasks = (stats.overdue_tasks as number) || 0;
    if (overdueTasks > 5) {
      generatedInsights.push({
        id: 'warning-tasks',
        type: 'warning',
        title: 'Multiple Overdue Tasks',
        description: `You have ${overdueTasks} overdue tasks. Prioritizing these could improve your pipeline health.`,
        confidence: 95,
        actionLabel: 'View Tasks',
        actionLink: '/tasks',
      });
    }

    // Recommendations based on pipeline
    const stageWithMostLeads = findStageWithMostLeads(stats.leads_by_stage as Record<string, number>);
    if (stageWithMostLeads) {
      generatedInsights.push({
        id: 'rec-pipeline',
        type: 'recommendation',
        title: 'Pipeline Bottleneck',
        description: `Most leads are in "${stageWithMostLeads}" stage. Consider focusing on moving these forward.`,
        confidence: 80,
        actionLabel: 'View Pipeline',
        actionLink: '/pipeline',
      });
    }

    // Best time to call recommendation
    generatedInsights.push({
      id: 'rec-timing',
      type: 'recommendation',
      title: 'Optimal Call Time',
      description: 'Based on historical data, leads are most responsive between 10-11 AM and 2-3 PM.',
      confidence: 75,
    });

    // Filter by type if specified
    let filtered = generatedInsights;
    if (insightType !== 'all') {
      filtered = generatedInsights.filter((i) => i.type === insightType);
    }

    // Sort by confidence
    filtered.sort((a, b) => b.confidence - a.confidence);

    setInsights(filtered.slice(0, 5));
    setIsLoading(false);
  };

  const handleRefresh = async () => {
    setIsRefreshing(true);
    await generateInsights();
    setIsRefreshing(false);
  };

  if (isLoading) {
    return (
      <div className="p-4">
        <div className="flex items-center gap-2 mb-4">
          <Sparkles className="h-5 w-5 text-blue-500 animate-pulse" />
          <span className="text-sm text-gray-500">Analyzing your data...</span>
        </div>
        <div className="space-y-3 animate-pulse">
          <div className="h-20 bg-gray-200 dark:bg-gray-700 rounded-lg" />
          <div className="h-20 bg-gray-200 dark:bg-gray-700 rounded-lg" />
        </div>
      </div>
    );
  }

  if (insights.length === 0) {
    return (
      <div className="p-4 text-center text-gray-500">
        <Sparkles className="h-8 w-8 mx-auto mb-2 opacity-50" />
        <p className="text-sm">No insights available</p>
        <p className="text-xs text-gray-400 mt-1">Add more data to generate AI insights</p>
      </div>
    );
  }

  return (
    <div className="p-4">
      {/* Header */}
      <div className="flex items-center justify-between mb-4 pb-4 border-b dark:border-gray-700">
        <div className="flex items-center gap-2">
          <div className="p-2 rounded-lg bg-gradient-to-br from-blue-500 to-blue-600 text-white">
            <Sparkles className="h-5 w-5" />
          </div>
          <div>
            <p className="text-sm font-medium">AI Insights</p>
            <p className="text-xs text-gray-500">{insights.length} recommendations</p>
          </div>
        </div>
        <button
          onClick={handleRefresh}
          disabled={isRefreshing}
          className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors disabled:opacity-50"
          title="Refresh insights"
        >
          <RefreshCw className={cn('h-4 w-4', isRefreshing && 'animate-spin')} />
        </button>
      </div>

      {/* Insights List */}
      <div className="space-y-3">
        {insights.map((insight) => (
          <InsightCard key={insight.id} insight={insight} />
        ))}
      </div>
    </div>
  );
}

// ============================================================================
// Insight Card Component
// ============================================================================

interface InsightCardProps {
  insight: AIInsight;
}

const INSIGHT_ICONS: Record<string, typeof Sparkles> = {
  hot_lead: Flame,
  recommendation: Lightbulb,
  trend: TrendingUp,
  warning: AlertTriangle,
};

const INSIGHT_STYLES: Record<string, { bg: string; border: string; icon: string }> = {
  hot_lead: {
    bg: 'bg-gradient-to-r from-orange-50 to-red-50 dark:from-orange-900/20 dark:to-red-900/20',
    border: 'border-l-orange-500',
    icon: 'text-orange-500',
  },
  recommendation: {
    bg: 'bg-gradient-to-r from-blue-50 to-cyan-50 dark:from-blue-900/20 dark:to-cyan-900/20',
    border: 'border-l-blue-500',
    icon: 'text-blue-500',
  },
  trend: {
    bg: 'bg-gradient-to-r from-green-50 to-green-50 dark:from-green-900/20 dark:to-green-900/20',
    border: 'border-l-green-500',
    icon: 'text-green-500',
  },
  warning: {
    bg: 'bg-gradient-to-r from-amber-50 to-yellow-50 dark:from-amber-900/20 dark:to-yellow-900/20',
    border: 'border-l-amber-500',
    icon: 'text-amber-500',
  },
};

function InsightCard({ insight }: InsightCardProps) {
  const Icon = INSIGHT_ICONS[insight.type] || Sparkles;
  const styles = INSIGHT_STYLES[insight.type] || INSIGHT_STYLES.recommendation;

  return (
    <div
      className={cn(
        'p-3 rounded-lg border-l-4',
        styles.bg,
        styles.border
      )}
    >
      <div className="flex gap-3">
        <div className={cn('mt-0.5', styles.icon)}>
          <Icon className="h-5 w-5" />
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-start justify-between gap-2">
            <p className="text-sm font-medium">{insight.title}</p>
            <ConfidenceBadge confidence={insight.confidence} />
          </div>
          <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
            {insight.description}
          </p>
          {insight.actionLink && (
            <Link
              to={insight.actionLink}
              className="inline-flex items-center gap-1 mt-2 text-sm text-blue-600 hover:text-blue-700 font-medium"
            >
