// ============================================================================
// Confidence Badge Component
// ============================================================================

interface ConfidenceBadgeProps {
  confidence: number;
}

function ConfidenceBadge({ confidence }: ConfidenceBadgeProps) {
  const getColor = () => {
    if (confidence >= 90) return 'bg-green-100 text-green-700 dark:bg-green-900/30';
    if (confidence >= 70) return 'bg-blue-100 text-blue-700 dark:bg-blue-900/30';
    return 'bg-gray-100 text-gray-700 dark:bg-gray-700';
  };

  return (
    <span className={cn('px-2 py-0.5 rounded-full text-xs font-medium flex items-center gap-1', getColor())}>
      <Star className="h-3 w-3" />
      {confidence}%
    </span>
  );
}

// ============================================================================
// Helper Functions
// ============================================================================

function calculateLeadScore(lead: { priority?: string; created_at?: string }): number {
  let score = 50;

  // Priority boost
  if (lead.priority === 'urgent') score += 30;
  else if (lead.priority === 'high') score += 20;
  else if (lead.priority === 'medium') score += 10;

  // Recency boost
  if (lead.created_at) {
    const daysSinceCreated = (Date.now() - new Date(lead.created_at).getTime()) / 86400000;
    if (daysSinceCreated < 1) score += 20;
    else if (daysSinceCreated < 3) score += 10;
  }

  return Math.min(score, 100);
}

function findStageWithMostLeads(leadsByStage?: Record<string, number>): string | null {
  if (!leadsByStage) return null;

  let maxStage: string | null = null;
  let maxCount = 0;

  Object.entries(leadsByStage).forEach(([stage, count]) => {
    if (count > maxCount) {
      maxCount = count;
      maxStage = stage;
    }
  });

  return maxStage;
}

// ============================================================================
// Action Queue Widget
// "What needs attention right now" - prioritized action items
// ============================================================================

import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  ArrowRight,
  AlertTriangle,
  Clock,
  FileWarning,
  DollarSign,
  UserX,
  CheckCircle2,
  ChevronRight,
  Sparkles,
  RefreshCw,
} from 'lucide-react';
import { useCRM } from '../../../contexts/CRMContext';
import { useOrg } from '../../../contexts/OrgContext';
import type { BaseWidgetProps } from '../types';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Types
// ============================================================================

interface ActionItem {
  id: string;
  type: 'overdue_task' | 'stale_deal' | 'unpaid_invoice' | 'missing_docs' | 'follow_up' | 'at_risk';
  title: string;
  description: string;
  priority: 'urgent' | 'high' | 'medium' | 'low';
  entityType: string;
  entityId: string;
  link: string;
  dueDate?: string;
  createdAt: string;
}

// ============================================================================
// Action Queue Widget Component
// ============================================================================

type QueueFilter = 'all' | 'urgent' | 'tasks' | 'deals' | 'invoices';

export default function ActionQueueWidget({ config, size }: BaseWidgetProps) {
  const navigate = useNavigate();
  const { tasksDueToday, overdueTasks, recentActivities, taskService } = useCRM();
  const { activeOrgId } = useOrg();
  
  const [filter, setFilter] = useState<QueueFilter>((config.filter as QueueFilter) || 'all');
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [dismissedIds, setDismissedIds] = useState<Set<string>>(new Set());

  // Build action items from CRM data
  useEffect(() => {
    const items: ActionItem[] = [];

    // Add overdue tasks
    overdueTasks.forEach((task) => {
      items.push({
        id: `task-${task.id}`,
        type: 'overdue_task',
        title: `Overdue: ${task.title}`,
        description: `Was due ${formatRelativeDate(task.due_date)}`,
        priority: 'urgent',
        entityType: 'task',
        entityId: task.id,
        link: '/tasks',
        dueDate: task.due_date,
        createdAt: task.created_at,
      });
    });

    // Add tasks due today
    tasksDueToday.forEach((task) => {
      items.push({
        id: `task-today-${task.id}`,
        type: 'follow_up',
        title: task.title,
        description: 'Due today',
        priority: 'high',
        entityType: 'task',
        entityId: task.id,
        link: '/tasks',
        dueDate: task.due_date,
        createdAt: task.created_at,
      });
    });

    // Sort by priority and date
    items.sort((a, b) => {
      const priorityOrder = { urgent: 0, high: 1, medium: 2, low: 3 };
      if (priorityOrder[a.priority] !== priorityOrder[b.priority]) {
        return priorityOrder[a.priority] - priorityOrder[b.priority];
      }
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });

    setActionItems(items);
  }, [overdueTasks, tasksDueToday]);

  // Filter items
  const filteredItems = actionItems.filter((item) => {
    if (dismissedIds.has(item.id)) return false;
    if (filter === 'all') return true;
    if (filter === 'urgent') return item.priority === 'urgent';
    if (filter === 'tasks') return item.type === 'overdue_task' || item.type === 'follow_up';
    if (filter === 'deals') return item.type === 'stale_deal' || item.type === 'at_risk';
    if (filter === 'invoices') return item.type === 'unpaid_invoice';
    return true;
  });

  const handleDismiss = (id: string) => {
    setDismissedIds((prev) => new Set([...prev, id]));
  };

  const handleAction = (item: ActionItem) => {
    navigate(item.link);
  };

  const maxItems = size === 'sm' ? 3 : size === 'md' ? 5 : 8;

  // Empty state
  if (filteredItems.length === 0) {
    return (
      <div className="p-4">
        <div className="flex gap-2 mb-4 flex-wrap">
          <FilterButton active={filter === 'all'} onClick={() => setFilter('all')}>All</FilterButton>
          <FilterButton active={filter === 'urgent'} onClick={() => setFilter('urgent')}>Urgent</FilterButton>
          <FilterButton active={filter === 'tasks'} onClick={() => setFilter('tasks')}>Tasks</FilterButton>
        </div>
        <div className="text-center py-8 text-gray-500">
          <CheckCircle2 className="h-10 w-10 mx-auto mb-3 text-green-500" />
          <p className="font-medium text-gray-900 dark:text-gray-100">All caught up!</p>
          <p className="text-sm mt-1">No items need your attention right now.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="p-4">
      {/* Filter Tabs */}
      <div className="flex gap-2 mb-4 flex-wrap">
        <FilterButton active={filter === 'all'} onClick={() => setFilter('all')}>
          All ({actionItems.filter((i) => !dismissedIds.has(i.id)).length})
        </FilterButton>
        <FilterButton active={filter === 'urgent'} onClick={() => setFilter('urgent')}>
          <AlertTriangle className="h-3 w-3" />
          Urgent
        </FilterButton>
        <FilterButton active={filter === 'tasks'} onClick={() => setFilter('tasks')}>
          Tasks
        </FilterButton>
      </div>

      {/* Action Items */}
      <div className="space-y-2">
        {filteredItems.slice(0, maxItems).map((item) => (
          <ActionItemCard
            key={item.id}
            item={item}
            onAction={() => handleAction(item)}
            onDismiss={() => handleDismiss(item.id)}
          />
        ))}
      </div>

      {/* See All Link */}
      {filteredItems.length > maxItems && (
        <div className="mt-4 pt-4 border-t dark:border-gray-700 text-center">
          <span className="text-sm text-gray-500">
            +{filteredItems.length - maxItems} more items
          </span>
        </div>
      )}
    </div>
  );
}

// ============================================================================
// Sub Components
