    id: string;
    title: string;
    event_type: string;
    start_time: string;
    end_time?: string;
    location?: string;
  };
}

const EVENT_ICONS: Record<string, typeof Video> = {
  meeting: Video,
  call: Phone,
  appointment: Calendar,
};

const EVENT_COLORS: Record<string, string> = {
  meeting: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30',
  call: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30',
  appointment: 'bg-green-100 text-green-600 dark:bg-green-900/30',
};

function EventCard({ event }: EventCardProps) {
  const Icon = EVENT_ICONS[event.event_type] || Calendar;
  const colorClass = EVENT_COLORS[event.event_type] || 'bg-gray-100 text-gray-600 dark:bg-gray-700';

  const startTime = new Date(event.start_time);
  const isToday = startTime.toDateString() === new Date().toDateString();

  return (
    <div className="flex gap-3 p-2 -mx-2 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
      <div className={cn('p-2 rounded-lg', colorClass)}>
        <Icon className="h-4 w-4" />
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-sm font-medium truncate">{event.title}</p>
        <div className="flex items-center gap-2 mt-1">
          <span className="flex items-center gap-1 text-xs text-gray-500">
            <Clock className="h-3 w-3" />
            {isToday ? formatTime(startTime) : formatDateTime(startTime)}
          </span>
          {event.location && (
            <span className="flex items-center gap-1 text-xs text-gray-500">
              <MapPin className="h-3 w-3" />
              {event.location}
            </span>
          )}
        </div>
      </div>
    </div>
  );
}

// ============================================================================
// Helper Functions
// ============================================================================

function formatTime(date: Date): string {
  return date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
}

function formatDateTime(date: Date): string {
  return date.toLocaleDateString('en-US', { weekday: 'short', hour: 'numeric', minute: '2-digit' });
}

// ============================================================================
// Deals Widget
// Shows deal statistics and recent deals
// ============================================================================

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight, Briefcase, DollarSign, TrendingUp } from 'lucide-react';
import { useOrg } from '../../../contexts/OrgContext';
import { supabase } from '../../../lib/supabase';
import { createDealService, type DealWithRelations } from '@mpbhealth/crm-core/deals';
import type { BaseWidgetProps } from '../types';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Deals Widget Component
// ============================================================================

const dealService = createDealService(supabase);

export default function DealsWidget({ config, size }: BaseWidgetProps) {
  const { activeOrgId } = useOrg();
  const [deals, setDeals] = useState<DealWithRelations[]>([]);
  const [stats, setStats] = useState({ total: 0, totalValue: 0, wonValue: 0 });
  const [isLoading, setIsLoading] = useState(true);

  const showClosedDeals = config.showClosedDeals === true;
  const limit = (config.limit as number) || 5;

  useEffect(() => {
    if (activeOrgId) {
      loadDeals();
    }
  }, [activeOrgId, showClosedDeals]);

  const loadDeals = async () => {
    setIsLoading(true);
    try {
      // getDeals returns { deals, total }
      const result = await dealService.getDeals({});
      const allDeals = result.deals || [];

      // Set recent deals (limited)
      setDeals(allDeals.slice(0, limit));

      // Calculate stats
      const total = result.total || allDeals.length;
      const totalValue = allDeals.reduce((sum: number, d: DealWithRelations) => sum + (d.amount || 0), 0);
      const wonValue = allDeals
        .filter((d: DealWithRelations) => d.stage?.is_won_stage === true)
        .reduce((sum: number, d: DealWithRelations) => sum + (d.amount || 0), 0);

      setStats({ total, totalValue, wonValue });
    } catch (error) {
      console.error('Failed to load deals:', error);
    } finally {
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="p-4 animate-pulse">
        <div className="h-16 bg-gray-200 dark:bg-gray-700 rounded mb-4" />
        <div className="space-y-2">
          <div className="h-10 bg-gray-200 dark:bg-gray-700 rounded" />
          <div className="h-10 bg-gray-200 dark:bg-gray-700 rounded" />
        </div>
      </div>
    );
  }

  return (
    <div className="p-4">
      {/* Stats */}
      <div className="grid grid-cols-3 gap-3 mb-4 pb-4 border-b dark:border-gray-700">
        <StatCard
          icon={Briefcase}
          label="Total Deals"
          value={stats.total.toString()}
          color="blue"
        />
        <StatCard
          icon={DollarSign}
          label="Pipeline Value"
          value={formatCurrency(stats.totalValue)}
          color="blue"
        />
        <StatCard
          icon={TrendingUp}
          label="Won Value"
          value={formatCurrency(stats.wonValue)}
          color="green"
        />
      </div>

      {/* Recent Deals */}
      {deals.length === 0 ? (
        <div className="text-center py-4 text-gray-500">
          <Briefcase className="h-8 w-8 mx-auto mb-2 opacity-50" />
          <p className="text-sm">No deals yet</p>
        </div>
      ) : (
        <div className="space-y-2">
          {deals.map((deal) => (
            <Link
              key={deal.id}
              to={`/deals/${deal.id}`}
              className="flex items-center justify-between p-2 -mx-2 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
            >
              <div className="min-w-0">
                <p className="text-sm font-medium truncate">{deal.name}</p>
                <p className="text-xs text-gray-500">{deal.stage?.display_name || 'No stage'}</p>
              </div>
              <span className="text-sm font-medium text-green-600">
                {formatCurrency(deal.amount || 0)}
              </span>
            </Link>
          ))}
        </div>
      )}

      <Link
        to="/deals"
        className="flex items-center justify-center gap-1 mt-4 pt-4 border-t dark:border-gray-700 text-sm text-blue-600 hover:text-blue-700 transition-colors"
      >
        View all deals
        <ArrowRight className="h-4 w-4" />
      </Link>
    </div>
  );
}

// ============================================================================
// Stat Card Component
// ============================================================================

interface StatCardProps {
  icon: typeof Briefcase;
  label: string;
  value: string;
  color: 'blue' | 'green';
}

const COLOR_CLASSES = {
  blue: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30',
  green: 'bg-green-100 text-green-600 dark:bg-green-900/30',
};

function StatCard({ icon: Icon, label, value, color }: StatCardProps) {
  return (
    <div className="text-center">
      <div className={cn('inline-flex p-2 rounded-lg mb-2', COLOR_CLASSES[color])}>
        <Icon className="h-4 w-4" />
      </div>
      <p className="text-lg font-bold">{value}</p>
      <p className="text-xs text-gray-500">{label}</p>
    </div>
  );
}

// ============================================================================
// Helper Functions
// ============================================================================

function formatCurrency(amount: number): string {
  if (amount >= 1000000) {
    return `$${(amount / 1000000).toFixed(1)}M`;
  }
  if (amount >= 1000) {
    return `$${(amount / 1000).toFixed(0)}K`;
  }
  return `$${amount.toFixed(0)}`;
}

// ============================================================================
// Goals Widget
// Shows targets vs actuals with progress tracking
// ============================================================================

import { useState, useEffect } from 'react';
import { Target, TrendingUp, TrendingDown, Plus, Trophy, Flag } from 'lucide-react';
import { useOrg } from '../../../contexts/OrgContext';
import { supabase } from '../../../lib/supabase';
import { createUserGoalsService, type UserGoal } from '@mpbhealth/crm-core/dashboard';
import { useCRM } from '../../../contexts/CRMContext';
import type { BaseWidgetProps } from '../types';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Goals Widget Component
// ============================================================================

const goalsService = createUserGoalsService(supabase);

export default function GoalsWidget({ config, size }: BaseWidgetProps) {
  const { activeOrgId } = useOrg();
  const { dashboardStats } = useCRM();
  const [goals, setGoals] = useState<UserGoal[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const showTeamGoals = config.showTeamGoals === true;
  const period = (config.period as string) || 'monthly';

  useEffect(() => {
    if (activeOrgId) {
      loadGoals();
    }
  }, [activeOrgId, period, showTeamGoals]);

  const loadGoals = async () => {
    if (!activeOrgId) return;
    setIsLoading(true);
    try {
      const data = await goalsService.getGoals(activeOrgId, { status: 'active' });

      // Update current values from dashboard stats
      const stats = (dashboardStats as unknown) as Record<string, unknown>;
      const updatedGoals = data.map((goal) => {
        let currentValue = goal.current_value;
        switch (goal.metric_type) {
          case 'leads_created':
            currentValue = (stats.total_leads as number) || 0;
            break;
          case 'leads_converted':
            currentValue = (stats.leads_converted as number) || 0;
            break;
          case 'calls_made':
            currentValue = (stats.total_calls as number) || 0;
            break;
        }
        return { ...goal, current_value: currentValue };
      });

      setGoals(updatedGoals);
    } catch (error) {
      console.error('Failed to load goals:', error);
      setGoals([]);
    } finally {
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="p-4 animate-pulse">
        <div className="space-y-4">
          <div className="h-16 bg-gray-200 dark:bg-gray-700 rounded" />
          <div className="h-16 bg-gray-200 dark:bg-gray-700 rounded" />
          <div className="h-16 bg-gray-200 dark:bg-gray-700 rounded" />
        </div>
      </div>
    );
  }

  if (goals.length === 0) {
    return (
      <div className="p-4 text-center text-gray-500">
        <Target className="h-8 w-8 mx-auto mb-2 opacity-50" />
        <p className="text-sm">No goals set</p>
        <button className="flex items-center gap-1 mx-auto mt-3 px-3 py-1.5 text-sm text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors">
          <Plus className="h-4 w-4" />
          Add a goal
        </button>
      </div>
    );
  }

  // Calculate overall progress
  const totalProgress = goals.reduce((sum, g) => sum + (g.current_value / g.target_value), 0) / goals.length;
  const completedGoals = goals.filter((g) => g.current_value >= g.target_value).length;

  return (
    <div className="p-4">
      {/* Summary */}
      <div className="flex items-center gap-4 mb-4 pb-4 border-b dark:border-gray-700">
        <div className="flex items-center gap-2">
          <div className="p-2 rounded-lg bg-blue-100 dark:bg-blue-900/30 text-blue-600">
            <Trophy className="h-5 w-5" />
          </div>
          <div>
            <p className="text-2xl font-bold">{completedGoals}/{goals.length}</p>
            <p className="text-xs text-gray-500">goals completed</p>
          </div>
        </div>
        <div className="flex-1">
          <div className="flex items-center justify-between mb-1">
            <span className="text-xs text-gray-500">Overall progress</span>
            <span className="text-xs font-medium">{Math.round(totalProgress * 100)}%</span>
          </div>
          <div className="h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
            <div
              className={cn(
                'h-full rounded-full transition-all',
                totalProgress >= 1 ? 'bg-green-500' : totalProgress >= 0.5 ? 'bg-blue-500' : 'bg-amber-500'
              )}
              style={{ width: `${Math.min(totalProgress * 100, 100)}%` }}
            />
          </div>
        </div>
      </div>

      {/* Goals List */}
      <div className="space-y-4">
        {goals.map((goal) => (
          <GoalCard key={goal.id} goal={goal} />
        ))}
      </div>

      <button className="flex items-center justify-center gap-1 w-full mt-4 pt-4 border-t dark:border-gray-700 text-sm text-blue-600 hover:text-blue-700 transition-colors">
        <Plus className="h-4 w-4" />
        Add new goal
      </button>
    </div>
  );
}

// ============================================================================
// Goal Card Component
// ============================================================================

interface GoalCardProps {
  goal: UserGoal;
}

const METRIC_ICONS: Record<string, typeof Target> = {
  leads_created: Flag,
  leads_converted: Trophy,
  deals_won: Trophy,
  deals_value: TrendingUp,
  calls_made: TrendingUp,
  emails_sent: TrendingUp,
  meetings_held: TrendingUp,
  tasks_completed: TrendingUp,
  custom: Target,
};

const METRIC_COLORS: Record<string, string> = {
  leads_created: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30',
  leads_converted: 'bg-green-100 text-green-600 dark:bg-green-900/30',
  deals_won: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30',
  deals_value: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30',
  calls_made: 'bg-cyan-100 text-cyan-600 dark:bg-cyan-900/30',
  emails_sent: 'bg-amber-100 text-amber-600 dark:bg-amber-900/30',
  meetings_held: 'bg-pink-100 text-pink-600 dark:bg-pink-900/30',
  tasks_completed: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30',
  custom: 'bg-gray-100 text-gray-600 dark:bg-gray-700',
};

function GoalCard({ goal }: GoalCardProps) {
  const Icon = METRIC_ICONS[goal.metric_type] || Target;
  const colorClass = METRIC_COLORS[goal.metric_type] || 'bg-gray-100 text-gray-600 dark:bg-gray-700';

  const progress = goal.current_value / goal.target_value;
  const isComplete = progress >= 1;
  const isOnTrack = progress >= getExpectedProgress(goal);

  return (
    <div className="group">
      <div className="flex items-center gap-3 mb-2">
        <div className={cn('p-1.5 rounded-lg', colorClass)}>
          <Icon className="h-4 w-4" />
        </div>
        <div className="flex-1 min-w-0">
          <p className="text-sm font-medium truncate">{goal.name}</p>
          <p className="text-xs text-gray-500">{goal.period}</p>
        </div>
        <div className="flex items-center gap-1 text-sm">
          {isComplete ? (
            <span className="text-green-600 font-medium flex items-center gap-1">
              <Trophy className="h-3.5 w-3.5" />
              Complete!
            </span>
          ) : isOnTrack ? (
            <span className="text-green-600 flex items-center gap-1">
              <TrendingUp className="h-3.5 w-3.5" />
              On track
            </span>
          ) : (
            <span className="text-amber-600 flex items-center gap-1">
              <TrendingDown className="h-3.5 w-3.5" />
              Behind
            </span>
          )}
        </div>
      </div>
      <div className="flex items-center gap-3">
        <div className="flex-1 h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
          <div
            className={cn(
              'h-full rounded-full transition-all',
              isComplete ? 'bg-green-500' : isOnTrack ? 'bg-blue-500' : 'bg-amber-500'
            )}
            style={{ width: `${Math.min(progress * 100, 100)}%` }}
          />
        </div>
        <span className="text-sm font-medium min-w-[80px] text-right">
          {formatValue(goal.current_value, goal.metric_type)} / {formatValue(goal.target_value, goal.metric_type)}
        </span>
      </div>
    </div>
  );
}

// ============================================================================
// Helper Functions
// ============================================================================

function getExpectedProgress(goal: UserGoal): number {
  const now = new Date();
  const start = new Date(goal.start_date);
  const end = new Date(goal.end_date);
  const totalDuration = end.getTime() - start.getTime();
  const elapsed = now.getTime() - start.getTime();
  return Math.max(0, Math.min(1, elapsed / totalDuration));
}

function formatValue(value: number, metricType: string): string {
  if (metricType === 'revenue') {
    if (value >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `$${(value / 1000).toFixed(0)}K`;
    return `$${value.toFixed(0)}`;
  }
  return value.toString();
}

// ============================================================================
// KPI Strip Widget
// Horizontal strip of key metrics for dashboard header
// ============================================================================

import { useState, useEffect } from 'react';
import {
  TrendingUp,
  TrendingDown,
  Minus,
  Users,
  DollarSign,
  Percent,
  Clock,
  CheckSquare,
  AlertTriangle,
  Target,
  GitBranch,
} from 'lucide-react';
import { useCRM } from '../../../contexts/CRMContext';
import { useOrg } from '../../../contexts/OrgContext';
import type { BaseWidgetProps } from '../types';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Types
// ============================================================================

interface KPIMetric {
  id: string;
  label: string;
  value: string | number;
  trend?: 'up' | 'down' | 'flat';
  trendValue?: string;
  icon: React.ElementType;
  color: 'blue' | 'green' | 'blue' | 'orange' | 'red' | 'gray';
  onClick?: () => void;
}

// ============================================================================
// KPI Strip Widget Component
// ============================================================================

export default function KPIStripWidget({ config, size }: BaseWidgetProps) {
  const { dashboardStats, tasksDueToday, overdueTasks, pipelineStages } = useCRM();

  // Calculate metrics
  const totalLeads = dashboardStats?.total_leads || 0;
  const newLeadsToday = dashboardStats?.new_leads || 0;
  const pipelineValue = pipelineStages.reduce((sum, stage) => sum + (stage.count || 0), 0);
  const tasksDue = tasksDueToday.length;
  const overdueCount = overdueTasks.length;
  
  // Calculate conversion rate (mock for now)
  const conversionRate = dashboardStats?.conversion_rate || 0;

  const metrics: KPIMetric[] = [
    {
      id: 'new-leads',
      label: 'New Today',
      value: newLeadsToday,
      trend: newLeadsToday > 0 ? 'up' : 'flat',
      trendValue: newLeadsToday > 0 ? `+${newLeadsToday}` : '0',
      icon: Users,
      color: 'green',
    },
    {
      id: 'pipeline',
      label: 'In Pipeline',
      value: totalLeads,
      trend: 'flat',
      icon: GitBranch,
      color: 'blue',
    },
    {
      id: 'conversion',
      label: 'Conversion',
      value: `${conversionRate.toFixed(1)}%`,
      trend: conversionRate >= 10 ? 'up' : conversionRate >= 5 ? 'flat' : 'down',
      icon: Percent,
      color: conversionRate >= 10 ? 'green' : conversionRate >= 5 ? 'blue' : 'orange',
    },
    {
      id: 'tasks-due',
      label: 'Tasks Due',
      value: tasksDue,
      trend: tasksDue === 0 ? 'up' : 'flat',
      icon: CheckSquare,
      color: tasksDue === 0 ? 'green' : 'blue',
    },
    {
      id: 'overdue',
      label: 'Overdue',
      value: overdueCount,
      trend: overdueCount > 0 ? 'down' : 'up',
      icon: AlertTriangle,
      color: overdueCount === 0 ? 'green' : 'red',
    },
  ];

  // Determine how many metrics to show based on size
  const visibleCount = size === 'full' ? metrics.length : size === 'lg' ? 5 : size === 'md' ? 4 : 3;
  const visibleMetrics = metrics.slice(0, visibleCount);

  return (
    <div className="p-4">
      <div className={cn(
        'grid gap-4',
        size === 'full' ? 'grid-cols-5' : size === 'lg' ? 'grid-cols-5' : size === 'md' ? 'grid-cols-4' : 'grid-cols-3'
      )}>
        {visibleMetrics.map((metric) => (
          <KPICard key={metric.id} metric={metric} />
        ))}
      </div>
    </div>
  );
}

// ============================================================================
// KPI Card Component
// ============================================================================

interface KPICardProps {
  metric: KPIMetric;
}

function KPICard({ metric }: KPICardProps) {
  const Icon = metric.icon;
  const colorStyles = getColorStyles(metric.color);
  const TrendIcon = metric.trend === 'up' ? TrendingUp : metric.trend === 'down' ? TrendingDown : Minus;
  const trendColor = metric.trend === 'up' ? 'text-green-500' : metric.trend === 'down' ? 'text-red-500' : 'text-gray-400';

  return (
    <div
      className={cn(
        'relative p-4 rounded-xl border transition-all',
        'bg-white dark:bg-gray-800',
        'border-gray-200 dark:border-gray-700',
        'hover:shadow-md hover:border-gray-300 dark:hover:border-gray-600',
        metric.onClick && 'cursor-pointer'
      )}
      onClick={metric.onClick}
    >
      {/* Icon */}
      <div className={cn('w-10 h-10 rounded-lg flex items-center justify-center mb-3', colorStyles.bg)}>
        <Icon className={cn('h-5 w-5', colorStyles.icon)} />
      </div>

      {/* Value */}
      <div className="flex items-end justify-between">
        <div>
          <p className="text-2xl font-bold text-gray-900 dark:text-gray-100">
            {metric.value}
          </p>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">
            {metric.label}
          </p>
        </div>

        {/* Trend */}
        {metric.trend && (
          <div className={cn('flex items-center gap-1', trendColor)}>
            <TrendIcon className="h-4 w-4" />
            {metric.trendValue && (
              <span className="text-xs font-medium">{metric.trendValue}</span>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

// ============================================================================
// Helper Functions
// ============================================================================

function getColorStyles(color: KPIMetric['color']) {
  const colors = {
    blue: {
      bg: 'bg-blue-100 dark:bg-blue-900/30',
      icon: 'text-blue-600 dark:text-blue-400',
    },
    green: {
      bg: 'bg-green-100 dark:bg-green-900/30',
      icon: 'text-green-600 dark:text-green-400',
    },
    orange: {
      bg: 'bg-orange-100 dark:bg-orange-900/30',
      icon: 'text-orange-600 dark:text-orange-400',
    },
    red: {
      bg: 'bg-red-100 dark:bg-red-900/30',
      icon: 'text-red-600 dark:text-red-400',
    },
    gray: {
      bg: 'bg-gray-100 dark:bg-gray-700',
      icon: 'text-gray-600 dark:text-gray-400',
    },
  };
  return colors[color];
}

// ============================================================================
// Compact KPI Strip for Dashboard Header
