// ============================================================================
// Pipeline Widget
// Shows lead distribution across pipeline stages
// ============================================================================

import { Link } from 'react-router-dom';
import { ArrowRight } from 'lucide-react';
import { useCRM } from '../../../contexts/CRMContext';
