// ============================================================================
// Helper Functions
// ============================================================================

function getInitials(firstName?: string, lastName?: string): string {
  const first = firstName?.charAt(0) || '';
  const last = lastName?.charAt(0) || '';
  return (first + last).toUpperCase() || '?';
}

function formatTimeAgo(dateString: string): string {
  const date = new Date(dateString);
  const seconds = Math.floor((new Date().getTime() - date.getTime()) / 1000);

  if (seconds < 60) return 'now';
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h`;
  if (seconds < 604800) return `${Math.floor(seconds / 86400)}d`;
  return date.toLocaleDateString();
}

// ============================================================================
// Tasks Widget
// Shows tasks due today and overdue
// ============================================================================

import { useState } from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight, CheckSquare, Circle, CheckCircle2, Clock, AlertTriangle } from 'lucide-react';
import { useCRM } from '../../../contexts/CRMContext';
import type { BaseWidgetProps } from '../types';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Tasks Widget Component
// ============================================================================

type TaskView = 'due-today' | 'overdue' | 'all';

export default function TasksWidget({ config }: BaseWidgetProps) {
  const { tasksDueToday, overdueTasks, taskService } = useCRM();

  const defaultView = (config.view as TaskView) || 'due-today';
  const showCompleted = config.showCompleted === true;

  const [view, setView] = useState<TaskView>(defaultView);
  const [completingId, setCompletingId] = useState<string | null>(null);

  const tasks = view === 'overdue' ? overdueTasks : view === 'due-today' ? tasksDueToday : [...tasksDueToday, ...overdueTasks];

  const handleComplete = async (taskId: string) => {
    setCompletingId(taskId);
    try {
      await taskService.completeTask(taskId);
    } finally {
      setCompletingId(null);
    }
  };

  if (tasks.length === 0) {
    return (
      <div className="p-4">
        <div className="flex gap-2 mb-4">
          <ViewButton active={view === 'due-today'} onClick={() => setView('due-today')}>Due Today</ViewButton>
          <ViewButton active={view === 'overdue'} onClick={() => setView('overdue')}>Overdue</ViewButton>
        </div>
        <div className="text-center py-6 text-gray-500">
          <CheckSquare className="h-8 w-8 mx-auto mb-2 opacity-50" />
          <p className="text-sm">No {view === 'overdue' ? 'overdue' : ''} tasks</p>
        </div>
      </div>
    );
  }

  return (
    <div className="p-4">
      {/* View Tabs */}
      <div className="flex gap-2 mb-4">
        <ViewButton active={view === 'due-today'} onClick={() => setView('due-today')}>
          <Clock className="h-3 w-3" />
          Due Today ({tasksDueToday.length})
        </ViewButton>
        <ViewButton active={view === 'overdue'} onClick={() => setView('overdue')}>
          <AlertTriangle className="h-3 w-3" />
          Overdue ({overdueTasks.length})
        </ViewButton>
      </div>

      {/* Task List */}
      <div className="space-y-2">
        {tasks.slice(0, 5).map((task) => (
          <div
            key={task.id}
            className="flex items-start gap-3 p-2 -mx-2 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
          >
            <button
              onClick={() => handleComplete(task.id)}
              disabled={completingId === task.id}
              className="mt-0.5 text-gray-400 hover:text-green-500 transition-colors"
            >
              {completingId === task.id ? (
                <CheckCircle2 className="h-5 w-5 text-green-500 animate-pulse" />
              ) : (
                <Circle className="h-5 w-5" />
              )}
            </button>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium truncate">{task.title}</p>
              <p className="text-xs text-gray-500 mt-0.5">
                Due: {formatDate(task.due_date)}
              </p>
            </div>
            <PriorityBadge priority={task.priority} />
          </div>
        ))}
      </div>

      <Link
        to="/tasks"
        className="flex items-center justify-center gap-1 mt-4 pt-4 border-t dark:border-gray-700 text-sm text-blue-600 hover:text-blue-700 transition-colors"
      >
        View all tasks
        <ArrowRight className="h-4 w-4" />
      </Link>
    </div>
  );
}

// ============================================================================
// Sub Components
// ============================================================================

function ViewButton({ active, onClick, children }: { active: boolean; onClick: () => void; children: React.ReactNode }) {
  return (
    <button
      onClick={onClick}
      className={cn(
        'flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium transition-colors',
        active
          ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300'
          : 'text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700'
      )}
    >
      {children}
    </button>
  );
}

function PriorityBadge({ priority }: { priority?: string }) {
  const colors: Record<string, string> = {
    urgent: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400',
    high: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400',
    medium: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400',
    low: 'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-400',
  };

  return (
    <span className={cn('px-2 py-0.5 rounded text-xs font-medium', colors[priority || 'medium'])}>
      {priority || 'medium'}
    </span>
  );
}

// ============================================================================
// Helper Functions
// ============================================================================

function formatDate(dateString: string): string {
  const date = new Date(dateString);
  const today = new Date();
  const tomorrow = new Date(today);
  tomorrow.setDate(tomorrow.getDate() + 1);

  if (date.toDateString() === today.toDateString()) return 'Today';
  if (date.toDateString() === tomorrow.toDateString()) return 'Tomorrow';
  return date.toLocaleDateString();
}

// ============================================================================
// Team Widget
// Shows team member activity and presence
// ============================================================================

import { useState, useEffect, useMemo } from 'react';
import { Users, Circle, Clock, MessageSquare, Phone, FileText, CheckSquare } from 'lucide-react';
import { useOrg } from '../../../contexts/OrgContext';
import { useAuth } from '../../../contexts/AuthContext';
import { supabase } from '../../../lib/supabase';
import { usePresence } from '@mpbhealth/database';
import type { BaseWidgetProps } from '../types';

const cn = (...classes: (string | boolean | undefined | null)[]) =>
  classes.filter(Boolean).join(' ');

// ============================================================================
// Types
// ============================================================================

interface TeamMember {
  id: string;
  full_name: string;
  avatar_url?: string;
  status: 'online' | 'away' | 'offline';
  last_active?: string;
  role?: string;
}

interface TeamActivity {
  id: string;
  user_id: string;
  user_name: string;
  action: 'call' | 'task' | 'note' | 'lead' | 'message';
  description: string;
  timestamp: string;
}

// ============================================================================
// Team Widget Component
// ============================================================================

export default function TeamWidget({ config, size }: BaseWidgetProps) {
  const { activeOrgId } = useOrg();
  const { user } = useAuth();
  const [members, setMembers] = useState<TeamMember[]>([]);
  const [activities, setActivities] = useState<TeamActivity[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const view = (config.view as string) || 'activity';

  // Track presence via Supabase Realtime
  const presenceMeta = useMemo(() => ({ org_id: activeOrgId }), [activeOrgId]);
  const { presenceState } = usePresence({
    channelName: `crm-presence:${activeOrgId || 'default'}`,
    userId: user?.id || 'anon',
    metadata: presenceMeta,
  });

  // Derive online user IDs from presence state
  const onlineUserIds = useMemo(() => new Set(Object.keys(presenceState)), [presenceState]);

  useEffect(() => {
    if (activeOrgId) {
      loadTeamData();
    }
  }, [activeOrgId]);

  // Update member presence status when realtime presence changes
  useEffect(() => {
    if (members.length > 0) {
      setMembers((prev) =>
        prev.map((m) => ({
          ...m,
          status: onlineUserIds.has(m.id) ? 'online' as const : 'offline' as const,
        }))
      );
    }
  }, [onlineUserIds]);

  const loadTeamData = async () => {
    setIsLoading(true);
    try {
      // Load organization members
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, full_name, avatar_url')
        .limit(10);

      if (profiles) {
        // Look up org membership roles for each profile
        const { data: memberships } = await supabase
          .from('org_memberships')
          .select('user_id, role')
          .eq('org_id', activeOrgId!)
          .in('user_id', profiles.map((p) => p.id));

        const roleMap = new Map(memberships?.map((m) => [m.user_id, m.role]) ?? []);

        const membersWithStatus: TeamMember[] = profiles.map((p) => ({
          id: p.id,
          full_name: p.full_name || 'Team Member',
          avatar_url: p.avatar_url,
          status: onlineUserIds.has(p.id) ? 'online' as const : 'offline' as const,
          role: (roleMap.get(p.id) || 'agent').replace(/^\w/, (c: string) => c.toUpperCase()),
        }));
        setMembers(membersWithStatus);

        // Load real recent activity from lead_activities
        const { data: recentActivities } = await supabase
          .from('lead_activities')
          .select('id, activity_type, title, description, created_at, created_by')
          .order('created_at', { ascending: false })
          .limit(8);

        if (recentActivities && recentActivities.length > 0) {
          const profileMap = new Map(profiles.map((p) => [p.id, p.full_name || 'Team Member']));

          const ACTION_TYPE_MAP: Record<string, TeamActivity['action']> = {
            call: 'call',
            note: 'note',
            email: 'message',
            meeting: 'call',
            status_change: 'lead',
            assignment: 'lead',
            task_created: 'task',
            task_completed: 'task',
          };

          const realActivities: TeamActivity[] = recentActivities.map((a) => ({
            id: a.id,
            user_id: a.created_by || '',
            user_name: profileMap.get(a.created_by || '') || 'Team Member',
            action: ACTION_TYPE_MAP[a.activity_type] || 'note',
            description: a.title || a.description || a.activity_type,
            timestamp: a.created_at,
          }));
          setActivities(realActivities);
        } else {
          setActivities([]);
        }
      }
    } catch (error) {
      console.error('Failed to load team data:', error);
    } finally {
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="p-4 animate-pulse">
        <div className="space-y-3">
          <div className="h-12 bg-gray-200 dark:bg-gray-700 rounded" />
          <div className="h-12 bg-gray-200 dark:bg-gray-700 rounded" />
          <div className="h-12 bg-gray-200 dark:bg-gray-700 rounded" />
        </div>
      </div>
    );
  }

  const onlineCount = members.filter((m) => m.status === 'online').length;

  return (
    <div className="p-4">
      {/* Header Stats */}
      <div className="flex items-center gap-4 mb-4 pb-4 border-b dark:border-gray-700">
        <div className="flex items-center gap-2">
          <div className="p-2 rounded-lg bg-green-100 dark:bg-green-900/30 text-green-600">
            <Users className="h-5 w-5" />
          </div>
          <div>
            <p className="text-sm font-medium">{onlineCount} online</p>
            <p className="text-xs text-gray-500">of {members.length} members</p>
          </div>
        </div>
        <div className="flex -space-x-2">
          {members.slice(0, 5).map((member) => (
            <div
              key={member.id}
              className="relative"
              title={member.full_name}
            >
              {member.avatar_url ? (
                <img
                  src={member.avatar_url}
                  alt={member.full_name}
                  className="h-8 w-8 rounded-full border-2 border-white dark:border-gray-800"
                />
              ) : (
                <div className="h-8 w-8 rounded-full border-2 border-white dark:border-gray-800 bg-blue-100 dark:bg-blue-900/50 flex items-center justify-center text-xs font-medium text-blue-600">
                  {member.full_name.charAt(0)}
                </div>
              )}
              <span
                className={cn(
                  'absolute -bottom-0.5 -right-0.5 h-3 w-3 rounded-full border-2 border-white dark:border-gray-800',
                  member.status === 'online' && 'bg-green-500',
                  member.status === 'away' && 'bg-amber-500',
                  member.status === 'offline' && 'bg-gray-400'
                )}
              />
            </div>
          ))}
          {members.length > 5 && (
            <div className="h-8 w-8 rounded-full border-2 border-white dark:border-gray-800 bg-gray-200 dark:bg-gray-700 flex items-center justify-center text-xs font-medium">
              +{members.length - 5}
            </div>
          )}
        </div>
      </div>

      {/* Content based on view */}
      {view === 'members' ? (
        <TeamMembersList members={members} />
      ) : (
        <TeamActivityFeed activities={activities} />
      )}
    </div>
  );
}

