  const [attachments, setAttachments] = useState<Array<{ file: File; id?: string }>>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // UI State
  const [sending, setSending] = useState(false);
  const [saving, setSaving] = useState(false);
  const [showScheduleModal, setShowScheduleModal] = useState(false);

  // Auto-save timer
  const autoSaveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [lastSavedAt, setLastSavedAt] = useState<Date | null>(null);

  // Initialize Tiptap editor
  const editor = useEditor({
    extensions: [
      StarterKit.configure({
        heading: false, // Disable headings for email
        link: false, // We configure Link separately below
        underline: false, // We configure Underline separately below
      }),
      Link.configure({
        openOnClick: false,
        HTMLAttributes: {
          class: 'text-th-accent-600 underline',
        },
      }),
      Image.configure({
        HTMLAttributes: {
          class: 'max-w-full h-auto',
        },
      }),
      TextAlign.configure({
        types: ['paragraph', 'heading'],
      }),
      Color,
      TextStyle,
      Underline,
      Placeholder.configure({
        placeholder: 'Write your message here...',
      }),
    ],
    content: initialBody,
    shouldRerenderOnTransaction: true,
    editorProps: {
      attributes: {
        class:
          'prose prose-sm max-w-none px-4 py-3 min-h-[200px] focus:outline-none text-th-text-primary',
      },
    },
    onUpdate: () => {
      // Trigger auto-save after 3 seconds of inactivity
      if (autoSaveTimerRef.current) {
        clearTimeout(autoSaveTimerRef.current);
      }
      autoSaveTimerRef.current = setTimeout(() => {
        handleAutoSave();
      }, 3000);
    },
  });

  // Load signatures and templates
  useEffect(() => {
    const load = async () => {
      try {
        // Load templates and signatures in parallel
        const [templateData, sigData] = await Promise.all([
          templateService.listTemplates(),
          activeOrgId ? signatureService.getUserSignatures(activeOrgId) : Promise.resolve([]),
        ]);
        setTemplates(templateData);
        setSignatures(sigData);

        // Auto-select default signature
        const defaultSig = sigData.find((s: EmailSignature) => s.is_default);
        if (defaultSig) {
          setSelectedSignatureId(defaultSig.id);
        }

        // Load connected mail accounts
        if (activeOrgId) {
          try {
            const accounts = await mailAccountService.getAccounts(activeOrgId);
            setConnectedAccounts(accounts.map(a => ({
              id: a.id,
              email_address: a.email_address,
              display_name: a.display_name,
              provider: a.provider,
            })));
            // Default to default connected account if available
            const defaultAcct = accounts.find(a => a.is_default);
            if (defaultAcct) {
              setSendViaAccountId(defaultAcct.id);
            }
          } catch {
            // Connected accounts not available - use CRM sender
          }
        }
      } catch (error) {
        console.error('Failed to load composer data:', error);
      }
    };
    load();
  }, [templateService, signatureService, mailAccountService, activeOrgId]);

  // Track current draft ID for auto-save
  const [currentDraftId, setCurrentDraftId] = useState<string | null>(draftId || null);

  // Auto-save handler
  const handleAutoSave = useCallback(async () => {
    if (!editor || !activeOrgId) return;
    try {
      const html = editor.getHTML();
      const draftData = {
        to_addresses: to,
        cc_addresses: cc,
        bcc_addresses: bcc,
        subject,
        body_html: html,
        lead_id: leadId,
        contact_id: contactId,
        account_id: accountId,
        thread_id: threadId,
        signature_id: selectedSignatureId || undefined,
      };

      if (currentDraftId) {
        await draftService.autoSaveDraft(currentDraftId, draftData);
      } else {
        const draft = await draftService.createDraft(activeOrgId, draftData);
        setCurrentDraftId(draft.id);
      }
      setLastSavedAt(new Date());
    } catch (error) {
      console.error('Auto-save failed:', error);
    }
  }, [editor, activeOrgId, to, cc, bcc, subject, leadId, contactId, accountId, threadId, selectedSignatureId, currentDraftId, draftService]);

  // Send email via v2 ComposerService (CC/BCC, attachments, tracking, threads)
  const handleSend = async () => {
    if (!editor || !activeOrgId) return;

    if (to.length === 0) {
      toast.error('Please add at least one recipient');
      return;
    }
    if (!subject.trim()) {
      toast.error('Please add a subject');
      return;
    }

    setSending(true);
    try {
      const html = editor.getHTML();

      // Collect attachment IDs from uploaded attachments
      const attachmentIds = attachments
        .filter((a) => a.id)
        .map((a) => a.id as string);

      const input: EnhancedEmailSendInput = {
        to,
        cc: cc.length > 0 ? cc : undefined,
        bcc: bcc.length > 0 ? bcc : undefined,
        subject,
        body_html: html,
        lead_id: leadId,
        contact_id: contactId,
        account_id: accountId,
        thread_id: threadId,
        signature_id: selectedSignatureId || undefined,
        attachment_ids: attachmentIds.length > 0 ? attachmentIds : undefined,
        track_opens: true,
        track_clicks: true,
      };

      // Route through connected account or CRM Resend sender
      let result;
      if (sendViaAccountId && sendViaAccountId !== 'crm') {
        // Send via connected M365/Gmail account
        const sendResult = await mailSyncService.sendViaProvider(sendViaAccountId, {
          to,
          cc: cc.length > 0 ? cc : undefined,
          bcc: bcc.length > 0 ? bcc : undefined,
          subject,
          html_body: html,
        });
        result = { success: true, email_id: sendResult.provider_message_id };
      } else {
        // Send via CRM Resend sender (existing flow)
        result = await composerService.sendEmail(activeOrgId, input);
      }

      if (result.success) {
        toast.success('Email sent successfully');
        // Clean up draft if one was created
        if (currentDraftId) {
          try { await draftService.deleteDraft(currentDraftId); } catch {}
        }
        onSent?.(result.email_id || '');
        onClose?.();
      } else {
        toast.error(result.error || 'Failed to send email');
      }
    } catch (error) {
      console.error('Send email error:', error);
      toast.error('Failed to send email');
    } finally {
      setSending(false);
    }
  };

  // Save as draft
  const handleSaveDraft = async () => {
    if (!editor || !activeOrgId) return;

    setSaving(true);
    try {
      const html = editor.getHTML();
      const draftData = {
        to_addresses: to,
        cc_addresses: cc,
        bcc_addresses: bcc,
        subject,
        body_html: html,
        lead_id: leadId,
        contact_id: contactId,
        account_id: accountId,
        thread_id: threadId,
        signature_id: selectedSignatureId || undefined,
      };

      if (currentDraftId) {
        await draftService.updateDraft(currentDraftId, draftData);
      } else {
        const draft = await draftService.createDraft(activeOrgId, draftData);
        setCurrentDraftId(draft.id);
      }

      toast.success('Draft saved');
      setLastSavedAt(new Date());
      onSaved?.(currentDraftId || '');
    } catch (error) {
      console.error('Save draft error:', error);
      toast.error('Failed to save draft');
    } finally {
      setSaving(false);
    }
  };

  // Discard draft
  const handleDiscard = () => {
    if (
      editor?.getText().trim() ||
      to.length > 0 ||
      subject.trim() ||
      attachments.length > 0
    ) {
      if (!window.confirm('Discard this message?')) {
        return;
      }
    }
    onDiscard?.();
    onClose?.();
  };

  // Apply template
  const applyTemplate = (template: CRMTemplate) => {
    setSubject(template.subject || '');
    editor?.commands.setContent(template.body);
    setShowTemplateDropdown(false);
    toast.success(`Template "${template.name}" applied`);
  };

  // Handle file selection - upload to Supabase storage via DraftService
  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    const maxSize = 50 * 1024 * 1024; // 50MB

    for (const file of files) {
      if (file.size > maxSize) {
        toast.error(`${file.name} exceeds 50MB limit`);
        continue;
      }

      // Ensure we have a draft to attach to
      let dId = currentDraftId;
      if (!dId && activeOrgId) {
        try {
          const draft = await draftService.createDraft(activeOrgId, {
            to_addresses: to,
            subject,
            body_html: editor?.getHTML() || '',
          });
          dId = draft.id;
          setCurrentDraftId(draft.id);
        } catch {
          toast.error('Failed to create draft for attachment');
          continue;
        }
      }

      if (dId) {
        try {
          const attachment = await draftService.uploadAttachment(dId, file);
          setAttachments((prev) => [...prev, { file, id: attachment.id }]);
        } catch (error) {
          toast.error(`Failed to upload ${file.name}`);
        }
      } else {
        // Fallback: store locally if no org
        setAttachments((prev) => [...prev, { file }]);
      }
    }

    // Reset input
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  // Remove attachment
  const removeAttachment = (index: number) => {
    setAttachments((prev) => prev.filter((_, i) => i !== index));
  };

  return (
    <div className="flex flex-col h-full bg-surface-primary border border-th-border rounded-lg shadow-lg overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-th-border bg-surface-secondary">
        <h2 className="text-sm font-semibold text-th-text-primary">
          {mode === 'reply' ? 'Reply' : mode === 'forward' ? 'Forward' : 'New Message'}
        </h2>
        <div className="flex items-center gap-2">
          {lastSavedAt && (
            <span className="text-xs text-th-text-tertiary">
              Saved {lastSavedAt.toLocaleTimeString()}
            </span>
          )}
          <button
            type="button"
            onClick={handleDiscard}
            aria-label="Close composer"
            className="p-1.5 text-th-text-tertiary hover:text-th-text-secondary hover:bg-surface-tertiary rounded-lg"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Send From (Connected Account Selector) */}
      {connectedAccounts.length > 0 && (
        <div className="flex items-center gap-2 px-4 py-2 border-b border-th-border">
          <label htmlFor="send-from-account" className="w-12 text-sm font-medium text-th-text-tertiary shrink-0">From:</label>
          <select
            id="send-from-account"
            value={sendViaAccountId}
            onChange={e => setSendViaAccountId(e.target.value)}
            className="flex-1 text-sm px-2 py-1 border border-th-border rounded bg-surface-primary text-th-text-primary"
          >
            <option value="crm">CRM Sender (Resend)</option>
            {connectedAccounts.map(a => (
              <option key={a.id} value={a.id}>
                {a.display_name ? `${a.display_name} <${a.email_address}>` : a.email_address}
                {' '}({a.provider === 'microsoft365' ? 'M365' : 'Gmail'})
              </option>
            ))}
          </select>
        </div>
      )}

      {/* Recipients */}
      <div className="px-4">
        <RecipientField
          label="To"
          value={to}
          onChange={setTo}
          placeholder="Recipients..."
          showExpand={!showCcBcc}
          onExpand={() => setShowCcBcc(true)}
        />
        {showCcBcc && (
          <>
            <RecipientField
              label="Cc"
              value={cc}
              onChange={setCc}
              placeholder="Carbon copy..."
            />
            <RecipientField
              label="Bcc"
              value={bcc}
              onChange={setBcc}
              placeholder="Blind carbon copy..."
            />
          </>
        )}

        {/* Subject */}
        <div className="flex items-center gap-2 py-2 border-b border-th-border">
          <label className="w-12 text-sm font-medium text-th-text-tertiary shrink-0">
            Subject:
          </label>
          <input
            type="text"
            value={subject}
            onChange={(e) => setSubject(e.target.value)}
            placeholder="Email subject..."
            className="flex-1 bg-transparent outline-none text-sm text-th-text-primary placeholder:text-th-text-tertiary"
          />
        </div>
      </div>

      {/* Toolbar */}
      <EditorToolbar editor={editor} />

      {/* Editor */}
      <div className="flex-1 overflow-y-auto">
        <EditorContent editor={editor} />
      </div>

      {/* Attachments */}
      {attachments.length > 0 && (
        <div className="px-4 py-2 border-t border-th-border bg-surface-secondary/50">
          <div className="flex flex-wrap gap-2">
            {attachments.map((att, index) => (
              <div
                key={index}
                className="flex items-center gap-2 px-2 py-1 bg-surface-primary border border-th-border rounded-lg text-xs"
              >
                <Paperclip className="w-3 h-3 text-th-text-tertiary" />
                <span className="text-th-text-secondary max-w-[150px] truncate">
                  {att.file.name}
                </span>
                <span className="text-th-text-tertiary">
                  ({(att.file.size / 1024).toFixed(1)}KB)
                </span>
                <button
                  type="button"
                  onClick={() => removeAttachment(index)}
                  aria-label={`Remove attachment ${att.file.name}`}
                  className="p-0.5 hover:bg-surface-secondary rounded"
                >
                  <X className="w-3 h-3 text-th-text-tertiary" />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Footer Actions */}
      <div className="flex items-center justify-between px-4 py-3 border-t border-th-border bg-surface-secondary">
        <div className="flex items-center gap-2">
          {/* Attach Files */}
          <input
            ref={fileInputRef}
            type="file"
            multiple
            onChange={handleFileSelect}
            aria-label="Attach files"
            className="hidden"
          />
          <button
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="flex items-center gap-1 px-3 py-1.5 text-sm text-th-text-secondary hover:bg-surface-tertiary rounded-lg"
            title="Attach files"
          >
            <Paperclip className="w-4 h-4" />
            <span className="hidden sm:inline">Attach</span>
          </button>

          {/* Templates */}
          <div className="relative">
            <button
              type="button"
              onClick={() => setShowTemplateDropdown(!showTemplateDropdown)}
              className="flex items-center gap-1 px-3 py-1.5 text-sm text-th-text-secondary hover:bg-surface-tertiary rounded-lg"
            >
              <FileText className="w-4 h-4" />
              <span className="hidden sm:inline">Templates</span>
              <ChevronDown className="w-3 h-3" />
            </button>
            {showTemplateDropdown && (
              <>
                <div
                  className="fixed inset-0 z-10"
                  onClick={() => setShowTemplateDropdown(false)}
                />
                <div className="absolute bottom-full left-0 mb-1 w-64 max-h-48 overflow-y-auto bg-surface-primary border border-th-border rounded-lg shadow-lg z-20">
                  {templates.length === 0 ? (
                    <p className="px-3 py-2 text-xs text-th-text-tertiary">
                      No templates available
                    </p>
                  ) : (
                    templates.map((t) => (
                      <button
                        key={t.id}
                        type="button"
                        onClick={() => applyTemplate(t)}
                        className="w-full px-3 py-2 text-left text-sm text-th-text-secondary hover:bg-surface-secondary border-b border-th-border last:border-0"
                      >
                        {t.name}
                      </button>
                    ))
                  )}
                </div>
              </>
            )}
          </div>

          {/* Signature Selector */}
          {signatures.length > 0 && (
            <select
              value={selectedSignatureId || ''}
              onChange={(e) => setSelectedSignatureId(e.target.value || null)}
              aria-label="Email signature"
              className="px-3 py-1.5 text-sm text-th-text-secondary bg-transparent border border-th-border rounded-lg hover:bg-surface-secondary"
            >
              <option value="">No signature</option>
              {signatures.map((sig) => (
                <option key={sig.id} value={sig.id}>
                  {sig.name}
                </option>
              ))}
            </select>
          )}
        </div>

        <div className="flex items-center gap-2">
          {/* Discard */}
          <button
            type="button"
            onClick={handleDiscard}
            className="flex items-center gap-1 px-3 py-1.5 text-sm text-th-text-secondary hover:bg-surface-tertiary rounded-lg"
          >
            <Trash2 className="w-4 h-4" />
            <span className="hidden sm:inline">Discard</span>
          </button>

          {/* Save Draft */}
          <button
            type="button"
            onClick={handleSaveDraft}
            disabled={saving}
            className="flex items-center gap-1 px-3 py-1.5 text-sm text-th-text-secondary border border-th-border rounded-lg hover:bg-surface-secondary disabled:opacity-50"
          >
            {saving ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <Save className="w-4 h-4" />
            )}
            <span className="hidden sm:inline">Save</span>
          </button>

          {/* Schedule */}
          <button
            type="button"
            onClick={() => setShowScheduleModal(true)}
            className="flex items-center gap-1 px-3 py-1.5 text-sm text-th-text-secondary border border-th-border rounded-lg hover:bg-surface-secondary"
          >
            <Clock className="w-4 h-4" />
            <span className="hidden sm:inline">Schedule</span>
          </button>

          {/* Send */}
          <button
            type="button"
            onClick={handleSend}
            disabled={sending || to.length === 0 || !subject.trim()}
            className="flex items-center gap-1 px-4 py-1.5 text-sm font-medium text-white bg-th-accent-600 rounded-lg hover:bg-th-accent-700 disabled:opacity-50"
          >
            {sending ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <Send className="w-4 h-4" />
            )}
            <span>Send</span>
          </button>
        </div>
      </div>

      {/* Schedule Modal (placeholder) */}
      {showScheduleModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
          <div className="bg-surface-primary border border-th-border rounded-lg shadow-xl p-6 w-full max-w-sm">
            <h3 className="text-sm font-semibold text-th-text-primary mb-4">
              Schedule Send
            </h3>
            <p className="text-sm text-th-text-secondary mb-4">
              Schedule functionality coming soon.
            </p>
            <div className="flex justify-end">
              <button
                type="button"
                onClick={() => setShowScheduleModal(false)}
                className="px-4 py-2 text-sm bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ============================================================================
// Utility Functions
// ============================================================================

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export default EmailComposer;

import { useState } from 'react';
import { X } from 'lucide-react';
import type { FormSettings, FormStyling, FormEntityType } from '@mpbhealth/crm-core';

interface FormSettingsDrawerProps {
  open: boolean;
  onClose: () => void;
  name: string;
  description: string;
  slug: string;
  entityType: FormEntityType;
  settings: FormSettings;
  styling: FormStyling;
  onUpdateName: (name: string) => void;
  onUpdateDescription: (description: string) => void;
  onUpdateSlug: (slug: string) => void;
  onUpdateEntityType: (entityType: FormEntityType) => void;
  onUpdateSettings: (settings: FormSettings) => void;
  onUpdateStyling: (styling: FormStyling) => void;
}

type Tab = 'general' | 'submit' | 'notifications' | 'lead' | 'styling';

export function FormSettingsDrawer({
  open,
  onClose,
  name,
  description,
  slug,
  entityType,
  settings,
  styling,
  onUpdateName,
  onUpdateDescription,
  onUpdateSlug,
  onUpdateEntityType,
  onUpdateSettings,
  onUpdateStyling,
}: FormSettingsDrawerProps) {
  const [activeTab, setActiveTab] = useState<Tab>('general');

  if (!open) return null;

  const tabs: { id: Tab; label: string }[] = [
    { id: 'general', label: 'General' },
    { id: 'submit', label: 'After Submit' },
    { id: 'notifications', label: 'Notifications' },
    { id: 'lead', label: 'Lead Settings' },
    { id: 'styling', label: 'Styling' },
  ];

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      <div className="fixed inset-0 bg-black/30" onClick={onClose} />
      <div className="relative w-[480px] bg-surface-primary shadow-xl overflow-y-auto">
        {/* Header */}
        <div className="sticky top-0 bg-surface-primary border-b border-th-border px-6 py-4 flex items-center justify-between z-10">
          <h2 className="text-lg font-semibold text-th-text-primary">Form Settings</h2>
          <button onClick={onClose} className="p-1.5 rounded-lg hover:bg-surface-secondary">
            <X className="w-5 h-5 text-th-text-tertiary" />
          </button>
        </div>

        {/* Tabs */}
        <div className="border-b border-th-border px-6">
          <div className="flex gap-1 -mb-px">
            {tabs.map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`px-3 py-2.5 text-sm font-medium border-b-2 transition-colors ${
                  activeTab === tab.id
                    ? 'border-th-accent-600 text-th-accent-600'
                    : 'border-transparent text-th-text-tertiary hover:text-th-text-secondary'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* Tab content */}
        <div className="p-6 space-y-4">
          {activeTab === 'general' && (
            <>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">Form Name</label>
                <input
                  type="text"
                  value={name}
                  onChange={(e) => onUpdateName(e.target.value)}
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">Description</label>
                <textarea
                  value={description}
                  onChange={(e) => onUpdateDescription(e.target.value)}
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                  rows={3}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  URL Slug
                </label>
                <div className="flex items-center gap-1">
                  <span className="text-sm text-th-text-tertiary">/forms/</span>
                  <input
                    type="text"
                    value={slug}
                    onChange={(e) => onUpdateSlug(e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '-'))}
                    className="flex-1 border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Entity Type
                </label>
                <select
                  value={entityType}
                  onChange={(e) => onUpdateEntityType(e.target.value as FormEntityType)}
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                >
                  <option value="lead">Lead</option>
                  <option value="contact">Contact</option>
                </select>
              </div>
            </>
          )}

          {activeTab === 'submit' && (
            <>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Redirect URL (optional)
                </label>
                <input
                  type="url"
                  value={settings.redirectUrl || ''}
                  onChange={(e) => onUpdateSettings({ ...settings, redirectUrl: e.target.value || undefined })}
                  placeholder="https://example.com/thank-you"
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
                <p className="text-xs text-th-text-tertiary mt-1">
                  Leave empty to show a success message instead
                </p>
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Success Message
                </label>
                <textarea
                  value={styling.successMessage || ''}
                  onChange={(e) => onUpdateStyling({ ...styling, successMessage: e.target.value })}
                  placeholder="Thank you! Your submission has been received."
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                  rows={3}
                />
              </div>
            </>
          )}

          {activeTab === 'notifications' && (
            <>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Notification Email
                </label>
                <input
                  type="email"
                  value={settings.notificationEmail || ''}
                  onChange={(e) => onUpdateSettings({ ...settings, notificationEmail: e.target.value || undefined })}
                  placeholder="notify@yourcompany.com"
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
                <p className="text-xs text-th-text-tertiary mt-1">
                  Receive an email each time someone submits this form
                </p>
              </div>

              <div className="border-t border-th-border pt-4">
                <div className="flex items-center justify-between mb-3">
                  <label className="text-sm font-medium text-th-text-secondary">Auto-Response Email</label>
                  <button
                    onClick={() => onUpdateSettings({ ...settings, autoResponseEnabled: !settings.autoResponseEnabled })}
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                      settings.autoResponseEnabled ? 'bg-th-accent-600' : 'bg-gray-200'
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        settings.autoResponseEnabled ? 'translate-x-6' : 'translate-x-1'
                      }`}
                    />
                  </button>
                </div>

                {settings.autoResponseEnabled && (
                  <div className="space-y-3">
                    <div>
                      <label className="block text-sm font-medium text-th-text-secondary mb-1">Subject</label>
                      <input
                        type="text"
                        value={settings.autoResponseSubject || ''}
                        onChange={(e) => onUpdateSettings({ ...settings, autoResponseSubject: e.target.value })}
                        placeholder="Thanks for reaching out!"
                        className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-th-text-secondary mb-1">Body (HTML)</label>
                      <textarea
                        value={settings.autoResponseBody || ''}
                        onChange={(e) => onUpdateSettings({ ...settings, autoResponseBody: e.target.value })}
                        placeholder="<p>Thank you for your interest! We'll be in touch soon.</p>"
                        className="w-full border border-th-border rounded-lg px-3 py-2 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                        rows={5}
                      />
                    </div>
                  </div>
                )}
              </div>
            </>
          )}

          {activeTab === 'lead' && (
            <>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Auto-Assign To (User ID)
                </label>
                <input
                  type="text"
                  value={settings.assignTo || ''}
                  onChange={(e) => onUpdateSettings({ ...settings, assignTo: e.target.value || undefined })}
                  placeholder="User ID to assign leads to"
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Tags (comma-separated)
                </label>
                <input
                  type="text"
                  value={(settings.tags || []).join(', ')}
                  onChange={(e) =>
                    onUpdateSettings({
                      ...settings,
                      tags: e.target.value.split(',').map((t) => t.trim()).filter(Boolean),
                    })
                  }
                  placeholder="web-form, inbound"
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Duplicate Handling
                </label>
                <select
                  value={settings.duplicateHandling || 'create_new'}
                  onChange={(e) => onUpdateSettings({ ...settings, duplicateHandling: e.target.value as any })}
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                >
                  <option value="create_new">Create New Record</option>
                  <option value="update">Update Existing</option>
                  <option value="skip">Skip Duplicate</option>
                </select>
              </div>
            </>
          )}

          {activeTab === 'styling' && (
            <>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Primary Color
                </label>
                <div className="flex items-center gap-2">
                  <input
                    type="color"
                    value={styling.primaryColor || '#2563eb'}
                    onChange={(e) => onUpdateStyling({ ...styling, primaryColor: e.target.value })}
                    className="w-10 h-10 rounded border border-th-border cursor-pointer"
                  />
                  <input
                    type="text"
                    value={styling.primaryColor || '#2563eb'}
                    onChange={(e) => onUpdateStyling({ ...styling, primaryColor: e.target.value })}
                    className="flex-1 border border-th-border rounded-lg px-3 py-2 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Button Text
                </label>
                <input
                  type="text"
                  value={styling.buttonText || ''}
                  onChange={(e) => onUpdateStyling({ ...styling, buttonText: e.target.value })}
                  placeholder="Submit"
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Form Header
                </label>
                <input
                  type="text"
                  value={styling.headerText || ''}
                  onChange={(e) => onUpdateStyling({ ...styling, headerText: e.target.value })}
                  placeholder="Contact Us"
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Form Description
                </label>
                <textarea
                  value={styling.descriptionText || ''}
                  onChange={(e) => onUpdateStyling({ ...styling, descriptionText: e.target.value })}
                  placeholder="Fill out the form below and we'll get back to you."
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                  rows={2}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-th-text-secondary mb-1">
                  Logo URL
                </label>
                <input
                  type="url"
                  value={styling.logoUrl || ''}
                  onChange={(e) => onUpdateStyling({ ...styling, logoUrl: e.target.value })}
                  placeholder="https://example.com/logo.png"
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

