// ---------------------------------------------------------------------------
// Multi-Lookup Field
// ---------------------------------------------------------------------------

interface MultiLookupFieldProps {
  field: StudioField;
  value: string[];
  onChange: (value: string[]) => void;
  disabled?: boolean;
}

function MultiLookupField({ field, value, onChange, disabled }: MultiLookupFieldProps) {
  const [inputValue, setInputValue] = useState('');

  const addValue = () => {
    if (inputValue && !value.includes(inputValue)) {
      onChange([...value, inputValue]);
      setInputValue('');
    }
  };

  const removeValue = (val: string) => {
    onChange(value.filter((v) => v !== val));
  };

  return (
    <div>
      <div className="flex flex-wrap gap-1 mb-2">
        {value.map((val) => (
          <span
            key={val}
            className="inline-flex items-center gap-1 px-2 py-0.5 rounded bg-th-accent-100 text-th-accent-700 text-xs"
          >
            {val}
            {!disabled && (
              <button
                type="button"
                onClick={() => removeValue(val)}
                className="hover:bg-th-accent-200 rounded"
              >
                <X className="w-3 h-3" />
              </button>
            )}
          </span>
        ))}
      </div>

      {!disabled && (
        <div className="flex gap-2">
          <div className="relative flex-1">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-th-text-tertiary">
              <Search className="w-4 h-4" />
            </div>
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), addValue())}
              placeholder={`Search ${field.config?.target_module || 'records'}...`}
              className="w-full border border-th-border rounded-lg pl-9 pr-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500 focus:border-transparent"
            />
          </div>
          <button
            type="button"
            onClick={addValue}
            className="px-3 py-2 bg-th-accent-600 text-white rounded-lg text-sm hover:bg-th-accent-700"
          >
            Add
          </button>
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Display Value Renderer (for read-only/list views)
// ---------------------------------------------------------------------------

interface DynamicFieldDisplayProps {
  field: StudioField;
  value: unknown;
}

export function DynamicFieldDisplay({ field, value }: DynamicFieldDisplayProps) {
  if (value === null || value === undefined) {
    return <span className="text-th-text-tertiary">-</span>;
  }

  switch (field.field_type) {
    case 'checkbox':
      return (
        <span className={value ? 'text-green-600' : 'text-th-text-tertiary'}>
          {value ? 'Yes' : 'No'}
        </span>
      );

    case 'currency':
      return (
        <span>
          {new Intl.NumberFormat('en-US', {
            style: 'currency',
            currency: 'USD',
          }).format(value as number)}
        </span>
      );

    case 'percent':
      return <span>{String(value)}%</span>;

    case 'date':
      return <span>{new Date(value as string).toLocaleDateString()}</span>;

    case 'datetime':
      return <span>{new Date(value as string).toLocaleString()}</span>;

    case 'picklist':
      const opt = field.config?.options?.find((o) => o.value === value);
      if (opt?.color) {
        return (
          <span
            className="px-2 py-0.5 rounded-full text-xs font-medium"
            style={{ backgroundColor: opt.color + '20', color: opt.color }}
          >
            {opt.label}
          </span>
        );
      }
      return <span>{opt?.label || String(value)}</span>;

    case 'multi_picklist':
      const values = value as string[];
      return (
        <div className="flex flex-wrap gap-1">
          {values.map((v) => {
            const o = field.config?.options?.find((opt) => opt.value === v);
            return (
              <span
                key={v}
                className="px-2 py-0.5 rounded bg-surface-secondary text-xs"
              >
                {o?.label || v}
              </span>
            );
          })}
        </div>
      );

    case 'url':
      return (
        <a
          href={value as string}
          target="_blank"
          rel="noopener noreferrer"
          className="text-th-accent-600 hover:underline"
        >
          {value as string}
        </a>
      );

    case 'email':
      return (
        <a href={`mailto:${value}`} className="text-th-accent-600 hover:underline">
          {value as string}
        </a>
      );

    case 'phone':
      return (
        <a href={`tel:${value}`} className="text-th-accent-600 hover:underline">
          {value as string}
        </a>
      );

    default:
      return <span>{String(value)}</span>;
  }
}

export default DynamicFieldRenderer;

import { createContext, useContext, useEffect, useState, type ReactNode } from 'react';
import type { User, Session } from '@supabase/supabase-js';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  signIn: (email: string, password: string) => Promise<{ error: Error | null }>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    supabase.auth.getSession()
      .then(({ data: { session }, error }) => {
        if (error) {
          console.error('Failed to get session:', error);
        }
        setSession(session);
        setUser(session?.user ?? null);
        setLoading(false);
      })
      .catch((error) => {
        console.error('Session retrieval failed:', error);
        setSession(null);
        setUser(null);
        setLoading(false);
      });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const signIn = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });
    return { error };
  };

  const signOut = async () => {
    try {
      await supabase.auth.signOut({ scope: 'local' });
    } catch (e) {
      console.warn('Sign out API error (session cleared locally):', e);
    }
    // Safety net: forcibly remove persisted session from storage
    try {
      localStorage.removeItem('mpb-auth-token');
    } catch (_) { /* storage may not be available */ }
    setUser(null);
    setSession(null);
  };

  return (
    <AuthContext.Provider value={{ user, session, loading, signIn, signOut }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// ============================================================================
// Dashboard Context
// State management for the Championship Command Center
// ============================================================================

import { createContext, useContext, useEffect, type ReactNode } from 'react';
import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { createClientLogger } from '@mpbhealth/utils';
import { useOrg } from './OrgContext';
import { supabase } from '../lib/supabase';
import {
  createDashboardLayoutService,
  type WidgetInstance,
  type DashboardLayout,
} from '@mpbhealth/crm-core/dashboard';

const log = createClientLogger('DashboardContext');

// Simple UUID generator using crypto API
const generateId = (): string => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  // Fallback for older browsers
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
};

// ============================================================================
// Types
// ============================================================================

interface DashboardState {
  // Layout state
  widgets: WidgetInstance[];
  layoutId: string | null;
  layoutName: string;

  // UI state
  editMode: boolean;
  selectedWidgetId: string | null;
  isDragging: boolean;

  // Loading state
  isLoading: boolean;
  isSaving: boolean;
  error: string | null;
  lastSaved: Date | null;
}

interface DashboardActions {
  // Layout management
  loadLayout: (orgId: string) => Promise<void>;
  saveLayout: (orgId: string) => Promise<boolean>;
  resetLayout: (orgId: string) => Promise<void>;

  // Widget management
  addWidget: (widgetId: string, config?: Record<string, unknown>) => void;
  removeWidget: (instanceId: string) => void;
  updateWidgetConfig: (instanceId: string, config: Record<string, unknown>) => void;
  updateWidgetSize: (instanceId: string, size: 'sm' | 'md' | 'lg' | 'full') => void;
  toggleWidgetCollapse: (instanceId: string) => void;
  reorderWidgets: (widgets: WidgetInstance[]) => void;
  moveWidget: (instanceId: string, position: { x: number; y: number }) => void;

  // Edit mode
  toggleEditMode: () => void;
  setEditMode: (editMode: boolean) => void;
  selectWidget: (instanceId: string | null) => void;
  setDragging: (isDragging: boolean) => void;

  // Error handling
  clearError: () => void;
}

type DashboardStore = DashboardState & DashboardActions;

// ============================================================================
// Default State
// ============================================================================

const DEFAULT_STATE: DashboardState = {
  widgets: [],
  layoutId: null,
  layoutName: 'Default',
  editMode: false,
  selectedWidgetId: null,
  isDragging: false,
  isLoading: false,
  isSaving: false,
  error: null,
  lastSaved: null,
};

// ============================================================================
// Zustand Store
// ============================================================================

const layoutService = createDashboardLayoutService(supabase);

export const useDashboardStore = create<DashboardStore>()(
  persist(
    (set, get) => ({
      ...DEFAULT_STATE,

      // -----------------------------------------------------------------------
      // Layout Management
      // -----------------------------------------------------------------------
      loadLayout: async (orgId: string) => {
        set({ isLoading: true, error: null });

        try {
          const layout = await layoutService.getLayout(orgId);

          if (layout && layout.widgets && layout.widgets.length > 0) {
            set({
              widgets: layout.widgets as WidgetInstance[],
              layoutId: layout.id,
              layoutName: layout.name,
              isLoading: false,
              lastSaved: layout.updated_at ? new Date(layout.updated_at) : null,
            });
          } else {
            // Use default widgets if no layout found or layout is empty
            const defaultWidgets = await layoutService.getDefaultWidgets(orgId);
            set({
              widgets: defaultWidgets,
              layoutId: null,
              layoutName: 'Default',
              isLoading: false,
            });
          }
        } catch (error) {
          console.error('Failed to load dashboard layout:', error);
          // On error, use hardcoded defaults instead of showing an error
          const defaultWidgets = await layoutService.getDefaultWidgets(orgId);
          set({
            widgets: defaultWidgets,
            layoutId: null,
            layoutName: 'Default',
            isLoading: false,
            error: null, // Clear any previous error - gracefully degrade
          });
        }
      },

      saveLayout: async (orgId: string) => {
        const { widgets, layoutName } = get();
        set({ isSaving: true, error: null });

        try {
          const result = await layoutService.saveLayout(orgId, widgets, layoutName);

          if (result.success && result.data) {
            set({
              layoutId: result.data.id,
              isSaving: false,
              lastSaved: new Date(),
            });
            return true;
          } else {
            set({
              isSaving: false,
              error: result.error || 'Failed to save layout',
            });
            return false;
          }
        } catch (error) {
          console.error('Failed to save dashboard layout:', error);
          set({
            isSaving: false,
            error: 'Failed to save dashboard layout',
          });
          return false;
        }
      },

      resetLayout: async (orgId: string) => {
        set({ isLoading: true, error: null });

        try {
          const result = await layoutService.resetLayout(orgId);

          if (result.success && result.data) {
            set({
              widgets: result.data.widgets as WidgetInstance[],
              layoutId: result.data.id,
              layoutName: result.data.name,
              isLoading: false,
              lastSaved: new Date(),
            });
          } else {
            set({
              isLoading: false,
              error: result.error || 'Failed to reset layout',
            });
          }
        } catch (error) {
          console.error('Failed to reset dashboard layout:', error);
          set({
            isLoading: false,
            error: 'Failed to reset dashboard layout',
          });
        }
      },

      // -----------------------------------------------------------------------
      // Widget Management
      // -----------------------------------------------------------------------
      addWidget: (widgetId: string, config: Record<string, unknown> = {}) => {
        const { widgets } = get();

        // Calculate next available position
        const maxY = widgets.reduce((max, w) => Math.max(max, w.position.y), -1);
        const newPosition = { x: 0, y: maxY + 1 };

        const newWidget: WidgetInstance = {
          instanceId: generateId(),
          widgetId: widgetId as WidgetInstance['widgetId'],
          size: 'md',
          position: newPosition,
          collapsed: false,
          config,
        };

        set({ widgets: [...widgets, newWidget] });
      },

      removeWidget: (instanceId: string) => {
        const { widgets, selectedWidgetId } = get();
        set({
          widgets: widgets.filter((w) => w.instanceId !== instanceId),
          selectedWidgetId: selectedWidgetId === instanceId ? null : selectedWidgetId,
        });
      },

      updateWidgetConfig: (instanceId: string, config: Record<string, unknown>) => {
        const { widgets } = get();
        set({
          widgets: widgets.map((w) =>
            w.instanceId === instanceId ? { ...w, config: { ...w.config, ...config } } : w
          ),
        });
      },

      updateWidgetSize: (instanceId: string, size: 'sm' | 'md' | 'lg' | 'full') => {
        const { widgets } = get();
        set({
          widgets: widgets.map((w) =>
            w.instanceId === instanceId ? { ...w, size } : w
          ),
        });
      },

      toggleWidgetCollapse: (instanceId: string) => {
        const { widgets } = get();
        set({
          widgets: widgets.map((w) =>
            w.instanceId === instanceId ? { ...w, collapsed: !w.collapsed } : w
          ),
        });
      },

      reorderWidgets: (widgets: WidgetInstance[]) => {
        set({ widgets });
      },

      moveWidget: (instanceId: string, position: { x: number; y: number }) => {
        const { widgets } = get();
        set({
          widgets: widgets.map((w) =>
            w.instanceId === instanceId ? { ...w, position } : w
          ),
        });
      },

      // -----------------------------------------------------------------------
      // Edit Mode
      // -----------------------------------------------------------------------
      toggleEditMode: () => {
        const { editMode, selectedWidgetId } = get();
        set({
          editMode: !editMode,
          selectedWidgetId: !editMode ? selectedWidgetId : null,
        });
      },

      setEditMode: (editMode: boolean) => {
        set({
          editMode,
          selectedWidgetId: editMode ? get().selectedWidgetId : null,
        });
      },

      selectWidget: (instanceId: string | null) => {
        set({ selectedWidgetId: instanceId });
      },

      setDragging: (isDragging: boolean) => {
        set({ isDragging });
      },

      // -----------------------------------------------------------------------
      // Error Handling
      // -----------------------------------------------------------------------
      clearError: () => {
        set({ error: null });
      },
    }),
    {
      name: 'crm-dashboard-local',
      partialize: (state) => ({
        // Only persist edit mode preference locally
        editMode: state.editMode,
      }),
    }
  )
);

// ============================================================================
// React Context (for additional dashboard services)
// ============================================================================

interface DashboardContextValue {
  // Services
  refreshWidget: (widgetId: string) => void;
  refreshAllWidgets: () => void;

  // Autosave
  autoSave: boolean;
  setAutoSave: (enabled: boolean) => void;
}

const DashboardContext = createContext<DashboardContextValue | null>(null);

// ============================================================================
// Provider Component
// ============================================================================

interface DashboardProviderProps {
  children: ReactNode;
}

export function DashboardProvider({ children }: DashboardProviderProps) {
  const { activeOrgId } = useOrg();
  const { loadLayout, saveLayout, widgets, editMode } = useDashboardStore();

  // Load layout when org changes
  useEffect(() => {
    if (activeOrgId) {
      loadLayout(activeOrgId);
    }
  }, [activeOrgId, loadLayout]);

  // Auto-save when widgets change (debounced)
  useEffect(() => {
    if (!activeOrgId || editMode) return;

    const timer = setTimeout(() => {
      saveLayout(activeOrgId);
    }, 2000); // 2 second debounce

    return () => clearTimeout(timer);
  }, [widgets, activeOrgId, editMode, saveLayout]);

  // Widget refresh tracking
  const refreshWidget = (_widgetId: string) => {
    // Trigger a re-render of specific widget
    // This is handled by individual widgets listening to their data
    log.info('Refresh widget:', _widgetId);
  };

  const refreshAllWidgets = () => {
    // Trigger global refresh
    window.dispatchEvent(new CustomEvent('dashboard:refresh'));
  };

  const value: DashboardContextValue = {
    refreshWidget,
    refreshAllWidgets,
    autoSave: true,
    setAutoSave: () => {},
  };

  return (
    <DashboardContext.Provider value={value}>
      {children}
    </DashboardContext.Provider>
  );
}

// ============================================================================
// Hooks
// ============================================================================

export function useDashboardContext(): DashboardContextValue {
  const context = useContext(DashboardContext);
  if (!context) {
    throw new Error('useDashboardContext must be used within a DashboardProvider');
  }
  return context;
}

// Convenience hooks for specific state slices
export function useWidgets(): WidgetInstance[] {
  return useDashboardStore((state) => state.widgets);
}

export function useEditMode(): boolean {
  return useDashboardStore((state) => state.editMode);
}

export function useSelectedWidget(): string | null {
  return useDashboardStore((state) => state.selectedWidgetId);
}

export function useDashboardLoading(): boolean {
  return useDashboardStore((state) => state.isLoading);
}

export function useDashboardError(): string | null {
  return useDashboardStore((state) => state.error);
}

// ============================================================================
// OrgContext ΓÇö Organization + Permission context for CRM app
// ============================================================================

import { createContext, useContext, useEffect, useState, useCallback, useRef, type ReactNode } from 'react';
import {
  getUserOrgs,
  getUserOrgRole,
  loadUserPermissions,
  hasPermission as checkPermission,
  invalidatePermissionCache,
  invalidateCache as invalidateOrgCache,
  DEFAULT_ORG_ID,
  DEFAULT_ORG_ID_ALT,
  type OrgWithMembership,
  type OrgRole,
  type UserPermissionSet,
} from '@mpbhealth/auth';
import { createClientLogger } from '@mpbhealth/utils';
import { useAuth } from './AuthContext';

const log = createClientLogger('OrgContext');

const ACTIVE_ORG_KEY = 'mpb_active_org_id';

interface OrgContextType {
  // Org state
  orgs: OrgWithMembership[];
  activeOrg: OrgWithMembership | null;
  activeOrgId: string | null;
  orgRole: OrgRole | null;
  orgLoading: boolean;

  // Permission state
  permissionSet: UserPermissionSet | null;
  permissionsLoading: boolean;

  // Permission checks
  can: (permissionKey: string) => boolean;
  canAny: (permissionKeys: string[]) => boolean;
  canAll: (permissionKeys: string[]) => boolean;

  // Actions
  switchOrg: (orgId: string) => void;
  refreshOrgs: () => Promise<void>;
  refreshPermissions: () => Promise<void>;
}

const OrgContext = createContext<OrgContextType | null>(null);

export function OrgProvider({ children }: { children: ReactNode }) {
  const { user } = useAuth();

  // Org state
  const [orgs, setOrgs] = useState<OrgWithMembership[]>([]);
  const [activeOrgId, setActiveOrgId] = useState<string | null>(() => {
    if (typeof window === 'undefined') return null;
    return localStorage.getItem(ACTIVE_ORG_KEY) || null;
  });
  const [orgRole, setOrgRole] = useState<OrgRole | null>(null);
  const [orgLoading, setOrgLoading] = useState(true);

  // Permission state
  const [permissionSet, setPermissionSet] = useState<UserPermissionSet | null>(null);
  const [permissionsLoading, setPermissionsLoading] = useState(true);
  const orgIdRef = useRef(activeOrgId);

  // --- Load orgs ---
  const loadOrgs = useCallback(async () => {
    if (!user) {
      setOrgs([]);
      setOrgLoading(false);
      return;
    }

    setOrgLoading(true);
    try {
      const userOrgs = await getUserOrgs();
      setOrgs(userOrgs);

      // Auto-select active org
      if (userOrgs.length > 0) {
        const storedId = localStorage.getItem(ACTIVE_ORG_KEY);
        const storedOrgValid = storedId && userOrgs.some((o) => o.id === storedId);

        if (!storedOrgValid) {
          const defaultOrg = userOrgs.find((o) => o.id === DEFAULT_ORG_ID || o.id === DEFAULT_ORG_ID_ALT) || userOrgs[0];
          setActiveOrgId(defaultOrg.id);
          localStorage.setItem(ACTIVE_ORG_KEY, defaultOrg.id);
        }
      }
    } catch (err) {
      console.error('[OrgContext] Failed to load orgs:', err);
    } finally {
      setOrgLoading(false);
    }
  }, [user]);

  useEffect(() => {
    loadOrgs();
  }, [loadOrgs]);

  // --- Load role for active org ---
  useEffect(() => {
    if (!activeOrgId || !user) {
      setOrgRole(null);
      return;
    }
    getUserOrgRole(activeOrgId)
      .then((role) => {
        log.info('[OrgContext] User role loaded:', role);
        setOrgRole(role);
      })
      .catch((err) => {
        console.error('[OrgContext] Failed to load role:', err);
        setOrgRole(null);
      });
  }, [activeOrgId, user]);

  // --- Load permissions when org changes ---
  const loadPermissions = useCallback(async () => {
    if (!activeOrgId) {
      setPermissionSet(null);
      setPermissionsLoading(false);
      return;
    }

    orgIdRef.current = activeOrgId;
    setPermissionsLoading(true);
    try {
      const ps = await loadUserPermissions(activeOrgId);
      if (orgIdRef.current === activeOrgId) {
        setPermissionSet(ps);
      }
    } catch (err) {
      console.error('[OrgContext] Failed to load permissions:', err);
    } finally {
      if (orgIdRef.current === activeOrgId) {
        setPermissionsLoading(false);
      }
    }
  }, [activeOrgId]);

  useEffect(() => {
    loadPermissions();
  }, [loadPermissions]);

  // --- Permission checks ---
  const isOrgOwnerOrAdmin = orgRole === 'owner' || orgRole === 'admin';

  const can = useCallback(
    (permissionKey: string): boolean => {
      // Owners and admins have all permissions
      if (isOrgOwnerOrAdmin) return true;
      // Otherwise check against actual permission set
      if (!permissionSet) return false;
      return permissionSet.permissions.includes(permissionKey);
    },
    [permissionSet, isOrgOwnerOrAdmin]
  );

  const canAny = useCallback(
    (permissionKeys: string[]): boolean => {
      if (isOrgOwnerOrAdmin) return true;
      if (!permissionSet) return false;
      return permissionKeys.some((k) => permissionSet.permissions.includes(k));
    },
    [permissionSet, isOrgOwnerOrAdmin]
  );

  const canAll = useCallback(
    (permissionKeys: string[]): boolean => {
      if (isOrgOwnerOrAdmin) return true;
      if (!permissionSet) return false;
      return permissionKeys.every((k) => permissionSet.permissions.includes(k));
    },
    [permissionSet, isOrgOwnerOrAdmin]
  );

  // --- Actions ---
  const switchOrg = useCallback((orgId: string) => {
    setActiveOrgId(orgId);
    localStorage.setItem(ACTIVE_ORG_KEY, orgId);
    invalidateOrgCache();
    invalidatePermissionCache(orgId);
  }, []);

  const refreshOrgs = useCallback(async () => {
    invalidateOrgCache();
    await loadOrgs();
  }, [loadOrgs]);

  const refreshPermissions = useCallback(async () => {
    if (activeOrgId) invalidatePermissionCache(activeOrgId);
    await loadPermissions();
  }, [activeOrgId, loadPermissions]);

  const activeOrg = orgs.find((o) => o.id === activeOrgId) ?? null;

  return (
    <OrgContext.Provider
      value={{
        orgs,
        activeOrg,
        activeOrgId,
        orgRole,
        orgLoading,
        permissionSet,
        permissionsLoading,
        can,
        canAny,
        canAll,
        switchOrg,
        refreshOrgs,
        refreshPermissions,
      }}
    >
      {children}
    </OrgContext.Provider>
  );
}

export function useOrg() {
  const context = useContext(OrgContext);
  if (!context) {
    throw new Error('useOrg must be used within an OrgProvider');
  }
  return context;
}

