// ============================================================================
// Command Palette State Hook
// ============================================================================

export function useCommandPalette() {
  const [isOpen, setIsOpen] = useState(false);
  const [mode, setMode] = useState<'search' | 'commands'>('search');

  // Keyboard shortcut to open (Cmd+K or Ctrl+K)
  useEffect(() => {
    function handleKeyDown(event: KeyboardEvent) {
      // Don't trigger if typing in an input
      const target = event.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) {
        return;
      }

      // Cmd+K or Ctrl+K
      if ((event.metaKey || event.ctrlKey) && event.key === 'k') {
        event.preventDefault();
        setIsOpen((prev) => !prev);
        setMode('search');
      }

      // Cmd+Shift+P or Ctrl+Shift+P for commands
      if ((event.metaKey || event.ctrlKey) && event.shiftKey && event.key === 'p') {
        event.preventDefault();
        setIsOpen(true);
        setMode('commands');
      }

      // Escape to close
      if (event.key === 'Escape' && isOpen) {
        event.preventDefault();
        setIsOpen(false);
      }
    }

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isOpen]);

  const open = useCallback((initialMode: 'search' | 'commands' = 'search') => {
    setMode(initialMode);
    setIsOpen(true);
  }, []);

  const close = useCallback(() => {
    setIsOpen(false);
  }, []);

  const toggle = useCallback(() => {
    setIsOpen((prev) => !prev);
  }, []);

  return {
    isOpen,
    mode,
    setMode,
    open,
    close,
    toggle,
  };
}

// ============================================================================
// Global Search Hook (CRM-specific)
// ============================================================================

export function useCRMSearch(options: {
  debounceMs?: number;
  minQueryLength?: number;
  limit?: number;
} = {}) {
  const { activeOrgId } = useOrg();

  const [query, setQuery] = useState('');
  const [results, setResults] = useState<CRMSearchResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [durationMs, setDurationMs] = useState<number | null>(null);

  const {
    debounceMs = 300,
    minQueryLength = 2,
    limit = 10,
  } = options;

  // Debounced search
  useEffect(() => {
    if (!activeOrgId || query.length < minQueryLength) {
      setResults([]);
      setDurationMs(null);
      return;
    }

    const startTime = performance.now();
    const timer = setTimeout(async () => {
      setLoading(true);
      setError(null);

      try {
        const { data, error: searchError } = await supabase.rpc('crm_global_search', {
          p_org_id: activeOrgId,
          p_query: query,
          p_limit: limit,
        });

        if (searchError) {
          throw searchError;
        }

        setResults((data as CRMSearchResult[]) || []);
        setDurationMs(Math.round(performance.now() - startTime));
      } catch (err) {
        console.error('[useCRMSearch] Search failed:', err);
        setError('Search failed');
        setResults([]);
      } finally {
        setLoading(false);
      }
    }, debounceMs);

    return () => clearTimeout(timer);
  }, [query, activeOrgId, limit, debounceMs, minQueryLength]);

  const clearSearch = useCallback(() => {
    setQuery('');
    setResults([]);
    setError(null);
    setDurationMs(null);
  }, []);

  return {
    query,
    setQuery,
    results,
    loading,
    error,
    durationMs,
    clearSearch,
    hasResults: results.length > 0,
  };
}

// ============================================================================
// Quick Actions Hook
// ============================================================================

export function useQuickActions() {
  const { can } = useOrg();

  // Filter actions based on permissions
  const actions = useMemo(() => {
    return CRM_QUICK_ACTIONS.filter((action) => {
      // Permission checks for specific actions
      if (action.id.startsWith('nav-leads') || action.id === 'create-lead') {
        return can('leads.read');
      }
      if (action.id.startsWith('nav-accounts') || action.id === 'create-account') {
        return can('accounts.read');
      }
      if (action.id.startsWith('nav-contacts') || action.id === 'create-contact') {
        return can('contacts.read');
      }
      if (action.id.startsWith('nav-deals') || action.id.startsWith('nav-deal-pipeline') || action.id === 'create-deal') {
        return can('deals.read');
      }
      if (action.id.startsWith('nav-tasks') || action.id.startsWith('nav-calendar') || action.id === 'create-task') {
        return can('tasks.read');
      }
      if (action.id.startsWith('nav-quotes') || action.id === 'create-quote') {
        return can('quotes.read');
      }
      if (action.id.startsWith('nav-invoices') || action.id === 'create-invoice') {
        return can('invoices.read');
      }
      if (action.id.startsWith('nav-campaigns')) {
        return can('campaigns.read');
      }
      if (action.id.startsWith('nav-settings')) {
        return can('settings.manage');
      }
      return true;
    });
  }, [can]);

  const filterActions = useCallback(
    (searchQuery: string) => {
      const lowerQuery = searchQuery.toLowerCase();
      return actions.filter(
        (action) =>
          action.name.toLowerCase().includes(lowerQuery) ||
          action.description?.toLowerCase().includes(lowerQuery) ||
          action.category.toLowerCase().includes(lowerQuery)
      );
    },
    [actions]
  );

  const groupedActions = useMemo(() => {
    return actions.reduce((groups, action) => {
      const category = action.category;
      if (!groups[category]) {
        groups[category] = [];
      }
      groups[category].push(action);
      return groups;
    }, {} as Record<string, QuickAction[]>);
  }, [actions]);

  return {
    actions,
    groupedActions,
    filterActions,
  };
}

import { useState, useCallback, type ChangeEvent, type FormEvent } from 'react';

interface UseFormOptions<T> {
  initialValues: T;
  validate?: (values: T) => Partial<Record<keyof T, string>>;
  onSubmit: (values: T) => Promise<void>;
}

interface UseFormReturn<T> {
  values: T;
  errors: Partial<Record<keyof T, string>>;
  loading: boolean;
  handleChange: (e: ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => void;
  handleSubmit: (e: FormEvent) => void;
  setFieldValue: (field: keyof T, value: unknown) => void;
  reset: (newValues?: T) => void;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useForm<T extends Record<string, any>>(
  options: UseFormOptions<T>
): UseFormReturn<T> {
  const { initialValues, validate, onSubmit } = options;
  const [values, setValues] = useState<T>(initialValues);
  const [errors, setErrors] = useState<Partial<Record<keyof T, string>>>({});
  const [loading, setLoading] = useState(false);

  const handleChange = useCallback(
    (e: ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
      const { name, value, type } = e.target;
      const newValue =
        type === 'checkbox' ? (e.target as HTMLInputElement).checked :
        type === 'number' ? (value === '' ? '' : Number(value)) :
        value;
      setValues((prev) => ({ ...prev, [name]: newValue }));
      // Clear field error on change
      setErrors((prev) => {
        if (prev[name as keyof T]) {
          const next = { ...prev };
          delete next[name as keyof T];
          return next;
        }
        return prev;
      });
    },
    []
  );

  const setFieldValue = useCallback((field: keyof T, value: unknown) => {
    setValues((prev) => ({ ...prev, [field]: value }));
    setErrors((prev) => {
      if (prev[field]) {
        const next = { ...prev };
        delete next[field];
        return next;
      }
      return prev;
    });
  }, []);

  const handleSubmit = useCallback(
    async (e: FormEvent) => {
      e.preventDefault();
      if (loading) return;

      // Run validation
      if (validate) {
        const validationErrors = validate(values);
        if (Object.keys(validationErrors).length > 0) {
          setErrors(validationErrors);
          return;
        }
      }

      setErrors({});
      setLoading(true);
      try {
        await onSubmit(values);
      } catch (err) {
        // Let caller handle via toast; re-throw so they can catch
        throw err;
      } finally {
        setLoading(false);
      }
    },
    [values, loading, validate, onSubmit]
  );

  const reset = useCallback((newValues?: T) => {
    setValues(newValues ?? initialValues);
    setErrors({});
    setLoading(false);
  }, [initialValues]);

  return { values, errors, loading, handleChange, handleSubmit, setFieldValue, reset };
}

import { useState, useEffect, useCallback } from 'react';
import { createSavedViewService, type SavedView } from '@mpbhealth/crm-core';
import { supabase } from '../lib/supabase';
import toast from 'react-hot-toast';

interface UseSavedViewsOptions<T> {
  module: string;
  currentFilters: T;
  onApplyFilters: (filters: T) => void;
}

export function useSavedViews<T extends Record<string, unknown>>({
  module,
  currentFilters,
  onApplyFilters,
}: UseSavedViewsOptions<T>) {
  const [service] = useState(() => createSavedViewService(supabase));
  const [views, setViews] = useState<SavedView[]>([]);
  const [activeViewId, setActiveViewId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const loadViews = useCallback(async () => {
    const data = await service.getViews(module);
    setViews(data);

    // Apply default view on first load
    const defaultView = data.find((v) => v.is_default);
    if (defaultView && !activeViewId) {
      setActiveViewId(defaultView.id);
      onApplyFilters(defaultView.filters as T);
    }
  }, [service, module]);

  useEffect(() => {
    loadViews();
  }, [loadViews]);

  const applyView = useCallback(
    (view: SavedView) => {
      setActiveViewId(view.id);
      onApplyFilters(view.filters as T);
    },
    [onApplyFilters]
  );

  const saveCurrentAsView = useCallback(
    async (name: string, isShared = false) => {
      setLoading(true);
      const result = await service.createView({
        module,
        name,
        filters: currentFilters,
        is_shared: isShared,
      });
      setLoading(false);

      if (result.success) {
        toast.success(`View "${name}" saved`);
        await loadViews();
        if (result.view) setActiveViewId(result.view.id);
      } else {
        toast.error(result.error || 'Failed to save view');
      }
      return result;
    },
    [service, module, currentFilters, loadViews]
  );

  const deleteView = useCallback(
    async (id: string) => {
      const result = await service.deleteView(id);
      if (result.success) {
        toast.success('View deleted');
        if (activeViewId === id) setActiveViewId(null);
        await loadViews();
      } else {
        toast.error(result.error || 'Failed to delete view');
      }
    },
    [service, activeViewId, loadViews]
  );

  const setDefaultView = useCallback(
    async (id: string) => {
      const result = await service.setDefault(id, module);
      if (result.success) {
        toast.success('Default view set');
        await loadViews();
      }
    },
    [service, module, loadViews]
  );

  return {
    views,
    activeViewId,
    loading,
    applyView,
    saveCurrentAsView,
    deleteView,
    setDefaultView,
    clearActiveView: () => setActiveViewId(null),
  };
}

