// Types for related data
interface Contact {
  id: string;
  first_name: string;
  last_name: string;
  email: string;
  phone: string | null;
  title: string | null;
  is_primary: boolean;
  created_at: string;
}

interface Deal {
  id: string;
  name: string;
  amount: number;
  stage: {
    id: string;
    name: string;
    display_name: string;
    color: string;
  } | null;
  probability: number;
