                          href={account.linkedin_url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="text-sm text-th-accent-600 hover:underline"
                        >
                          {account.linkedin_url}
                        </a>
                      </div>
                    </div>
                  )}
                  {account.twitter_handle && (
                    <div className="flex items-center space-x-3">
                      <div className="w-10 h-10 bg-surface-secondary rounded-lg flex items-center justify-center">
                        <Twitter className="w-5 h-5 text-th-text-tertiary" />
                      </div>
                      <div>
                        <label className="block text-xs font-medium text-th-text-tertiary">Twitter</label>
                        <a
                          href={`https://twitter.com/${account.twitter_handle.replace('@', '')}`}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="text-sm text-th-accent-600 hover:underline"
                        >
                          {account.twitter_handle}
                        </a>
                      </div>
                    </div>
                  )}
                  <div className="flex items-center space-x-3">
                    <div className="w-10 h-10 bg-surface-secondary rounded-lg flex items-center justify-center">
                      <Calendar className="w-5 h-5 text-th-text-tertiary" />
                    </div>
                    <div>
                      <label className="block text-xs font-medium text-th-text-tertiary">Created</label>
                      <p className="text-sm text-th-text-primary">{formatTimeAgo(account.created_at)}</p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Contacts Tab */}
          {activeTab === 'contacts' && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold text-th-text-primary">
                  Contacts ({contacts.length})
                </h3>
                <PermissionGate permission="contacts.write">
                  <button
                    onClick={() => navigate(`/contacts/new?account_id=${account.id}`)}
                    className="flex items-center space-x-2 px-3 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700"
                  >
                    <Plus className="w-4 h-4" />
                    <span>Add Contact</span>
                  </button>
                </PermissionGate>
              </div>
              {contacts.length === 0 ? (
                <div className="text-center py-12">
                  <Users className="w-12 h-12 text-th-text-tertiary mx-auto mb-4 opacity-50" />
                  <p className="text-th-text-tertiary">No contacts yet</p>
                  <p className="text-sm text-th-text-tertiary mt-1">
                    Add contacts to this account to keep track of your relationships
                  </p>
                </div>
              ) : (
                <div className="divide-y divide-th-border">
                  {contacts.map((contact) => (
                    <div
                      key={contact.id}
                      className="py-4 flex items-center justify-between hover:bg-surface-secondary px-4 -mx-4 rounded-lg cursor-pointer"
                      onClick={() => navigate(`/contacts/${contact.id}`)}
                    >
                      <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-th-accent-100 rounded-full flex items-center justify-center">
                          <span className="text-th-accent-700 font-medium text-sm">
                            {contact.first_name.charAt(0)}
                            {contact.last_name.charAt(0)}
                          </span>
                        </div>
                        <div>
                          <div className="flex items-center space-x-2">
                            <p className="text-sm font-medium text-th-text-primary">
                              {contact.first_name} {contact.last_name}
                            </p>
                            {contact.is_primary && (
                              <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full">
                                Primary
                              </span>
                            )}
                          </div>
                          <p className="text-xs text-th-text-tertiary">{contact.title || contact.email}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-4">
                        {contact.email && (
                          <a
                            href={`mailto:${contact.email}`}
                            onClick={(e) => e.stopPropagation()}
                            className="p-2 hover:bg-surface-tertiary rounded-lg"
                          >
                            <Mail className="w-4 h-4 text-th-text-tertiary" />
                          </a>
                        )}
                        {contact.phone && (
                          <a
                            href={`tel:${contact.phone}`}
                            onClick={(e) => e.stopPropagation()}
                            className="p-2 hover:bg-surface-tertiary rounded-lg"
                          >
                            <Phone className="w-4 h-4 text-th-text-tertiary" />
                          </a>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Deals Tab */}
          {activeTab === 'deals' && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold text-th-text-primary">Deals ({deals.length})</h3>
                <PermissionGate permission="deals.write">
                  <button
                    onClick={() => navigate(`/deals/new?account_id=${account.id}`)}
                    className="flex items-center space-x-2 px-3 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700"
                  >
                    <Plus className="w-4 h-4" />
                    <span>Add Deal</span>
                  </button>
                </PermissionGate>
              </div>
              {deals.length === 0 ? (
                <div className="text-center py-12">
                  <DollarSign className="w-12 h-12 text-th-text-tertiary mx-auto mb-4 opacity-50" />
                  <p className="text-th-text-tertiary">No deals yet</p>
                  <p className="text-sm text-th-text-tertiary mt-1">
                    Create deals to track opportunities with this account
                  </p>
                </div>
              ) : (
                <div className="divide-y divide-th-border">
                  {deals.map((deal) => (
                    <div
                      key={deal.id}
                      className="py-4 flex items-center justify-between hover:bg-surface-secondary px-4 -mx-4 rounded-lg cursor-pointer"
                      onClick={() => navigate(`/deals/${deal.id}`)}
                    >
                      <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-green-100 rounded-lg flex items-center justify-center">
                          <DollarSign className="w-5 h-5 text-green-600" />
                        </div>
                        <div>
                          <p className="text-sm font-medium text-th-text-primary">{deal.name}</p>
                          <p className="text-xs text-th-text-tertiary">
                            {deal.expected_close_date
                              ? `Expected close: ${new Date(deal.expected_close_date).toLocaleDateString()}`
                              : 'No close date set'}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-4">
                        <span className="text-sm font-medium text-th-text-primary">
                          {formatCurrency(deal.amount)}
                        </span>
                        {deal.stage && (
                          <span
                            className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium"
                            style={{
                              backgroundColor: `${deal.stage.color}20`,
                              color: deal.stage.color,
                            }}
                          >
                            {deal.stage.display_name}
                          </span>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Activities Tab */}
          {activeTab === 'activities' && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold text-th-text-primary">Activity Timeline</h3>
              </div>
              {activities.length === 0 ? (
                <div className="text-center py-12">
                  <Activity className="w-12 h-12 text-th-text-tertiary mx-auto mb-4 opacity-50" />
                  <p className="text-th-text-tertiary">No activities yet</p>
                  <p className="text-sm text-th-text-tertiary mt-1">
                    Activities from contacts and deals will appear here
                  </p>
                </div>
              ) : (
                <div className="activity-timeline">
                  {activities.map((activity) => (
                    <div key={activity.id} className="activity-item">
                      <p className="text-sm font-medium text-th-text-primary">{activity.title}</p>
                      {activity.description && (
                        <p className="text-sm text-th-text-tertiary mt-1">{activity.description}</p>
                      )}
                      <p className="text-xs text-th-text-tertiary mt-1">
                        {formatTimeAgo(activity.created_at)}
                      </p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Edit Account Modal */}
      <AddAccountModal
        open={showEditAccount}
        onClose={() => setShowEditAccount(false)}
        account={account}
        onSuccess={() => {
          setShowEditAccount(false);
          loadAccount();
        }}
      />
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  Search,
  Filter,
  Download,
  Plus,
  ChevronDown,
  Building2,
  Phone,
  Globe,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { PermissionGate } from '../components/PermissionGate';
import { AddAccountModal } from '../components/AddAccountModal';
import { useOrg } from '../contexts/OrgContext';
import {
  createAccountService,
  formatTimeAgo,
  type AccountWithRelations,
  type AccountFilters,
} from '@mpbhealth/crm-core';
import { supabase } from '../lib/supabase';

// Account type options
const ACCOUNT_TYPE_OPTIONS = [
  { value: '', label: 'All Types' },
  { value: 'prospect', label: 'Prospect' },
  { value: 'customer', label: 'Customer' },
  { value: 'partner', label: 'Partner' },
  { value: 'vendor', label: 'Vendor' },
  { value: 'other', label: 'Other' },
];

// Rating options
const RATING_OPTIONS = [
  { value: '', label: 'All Ratings' },
  { value: 'hot', label: 'Hot' },
  { value: 'warm', label: 'Warm' },
  { value: 'cold', label: 'Cold' },
];

// Get rating badge colors
function getRatingColors(rating: string | null) {
  switch (rating) {
    case 'hot':
      return { bg: 'bg-red-100', text: 'text-red-700' };
    case 'warm':
      return { bg: 'bg-orange-100', text: 'text-orange-700' };
    case 'cold':
      return { bg: 'bg-blue-100', text: 'text-blue-700' };
    default:
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
  }
}

// Get account type badge colors
function getTypeColors(type: string) {
  switch (type) {
    case 'customer':
      return { bg: 'bg-green-100', text: 'text-green-700' };
    case 'prospect':
      return { bg: 'bg-blue-100', text: 'text-blue-700' };
    case 'partner':
      return { bg: 'bg-blue-100', text: 'text-blue-700' };
    case 'vendor':
      return { bg: 'bg-yellow-100', text: 'text-yellow-700' };
    default:
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
  }
}

export default function Accounts() {
  const navigate = useNavigate();
  const { activeOrgId } = useOrg();

  // Initialize account service
  const [accountService] = useState(() => createAccountService(supabase));

  const [accounts, setAccounts] = useState<AccountWithRelations[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<AccountFilters>({});
  const [page, setPage] = useState(0);
  const [showFilters, setShowFilters] = useState(false);
  const [showAddAccount, setShowAddAccount] = useState(false);
  const [industries, setIndustries] = useState<string[]>([]);
  const pageSize = 20;

  // Bulk selection state
  const [selectedAccounts, setSelectedAccounts] = useState<Set<string>>(new Set());

  // Load accounts
  const loadAccounts = useCallback(async () => {
    setLoading(true);
    try {
      const { accounts: data, total: count } = await accountService.getAccounts(
        filters,
        pageSize,
        page * pageSize
      );
      setAccounts(data);
      setTotal(count);
    } catch (error) {
      console.error('Failed to load accounts:', error);
      toast.error('Failed to load accounts');
    } finally {
      setLoading(false);
    }
  }, [accountService, filters, page]);

  // Load industries for filter dropdown
  const loadIndustries = useCallback(async () => {
    const data = await accountService.getIndustries();
    setIndustries(data);
  }, [accountService]);

  useEffect(() => {
    loadAccounts();
  }, [loadAccounts]);

  useEffect(() => {
    loadIndustries();
  }, [loadIndustries]);

  // Clear selection when filters or page change
  useEffect(() => {
    setSelectedAccounts(new Set());
  }, [filters, page]);

  const handleSearch = (search: string) => {
    setFilters((prev) => ({ ...prev, search }));
    setPage(0);
  };

  const handleTypeFilter = (account_type: string) => {
    setFilters((prev) => ({ ...prev, account_type: account_type || undefined }));
    setPage(0);
  };

  const handleIndustryFilter = (industry: string) => {
    setFilters((prev) => ({ ...prev, industry: industry || undefined }));
    setPage(0);
  };

  const handleRatingFilter = (rating: string) => {
    setFilters((prev) => ({ ...prev, rating: rating || undefined }));
    setPage(0);
  };

  const handleExport = async () => {
    try {
      const exportAccounts = await accountService.getAccountsForExport(undefined, filters);
      const csv = generateAccountCSV(exportAccounts);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `accounts-export-${new Date().toISOString().split('T')[0]}.csv`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success('Export started');
    } catch (error) {
      console.error('Export failed:', error);
      toast.error('Failed to export accounts');
    }
  };

  const handleExportSelected = async () => {
    try {
      const ids = Array.from(selectedAccounts);
      const exportAccounts = await accountService.getAccountsForExport(ids);
      const csv = generateAccountCSV(exportAccounts);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `accounts-selected-export-${new Date().toISOString().split('T')[0]}.csv`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success('Export started');
    } catch (error) {
      console.error('Export failed:', error);
      toast.error('Failed to export accounts');
    }
  };

  // Generate CSV from accounts
  function generateAccountCSV(data: AccountWithRelations[]) {
    const headers = ['Name', 'Type', 'Industry', 'Phone', 'Website', 'Rating', 'Created'];
    const rows = data.map((account) => [
      account.name,
      account.account_type,
      account.industry || '',
      account.phone || '',
      account.website || '',
      account.rating || '',
      new Date(account.created_at).toLocaleDateString(),
    ]);
    return [headers.join(','), ...rows.map((row) => row.map((cell) => `"${cell}"`).join(','))].join('\n');
  }

  const toggleSelectAll = useCallback(() => {
    if (selectedAccounts.size === accounts.length) {
      setSelectedAccounts(new Set());
    } else {
      setSelectedAccounts(new Set(accounts.map((a) => a.id)));
    }
  }, [accounts, selectedAccounts.size]);

  const toggleSelectAccount = useCallback((accountId: string) => {
    setSelectedAccounts((prev) => {
      const next = new Set(prev);
      if (next.has(accountId)) {
        next.delete(accountId);
      } else {
        next.add(accountId);
      }
      return next;
    });
  }, []);

  const handleRowClick = (accountId: string) => {
    navigate(`/accounts/${accountId}`);
  };

  const totalPages = Math.ceil(total / pageSize);

  return (
    <div className="space-y-6">
      {/* Bulk Actions Toolbar */}
      {selectedAccounts.size > 0 && (
        <div className="bg-th-accent-50 border border-th-accent-200 rounded-lg px-4 py-3 flex items-center justify-between">
          <span className="text-sm font-medium text-th-accent-700">
            {selectedAccounts.size} account{selectedAccounts.size > 1 ? 's' : ''} selected
          </span>
          <div className="flex items-center space-x-3">
            <PermissionGate permission="accounts.read">
              <button
                onClick={handleExportSelected}
                className="text-sm text-th-accent-600 hover:text-th-accent-700 font-medium"
              >
                Export Selected
              </button>
            </PermissionGate>
            <button
              onClick={() => setSelectedAccounts(new Set())}
              className="text-sm text-th-text-tertiary hover:text-th-text-secondary"
            >
              Clear
            </button>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Accounts</h1>
          <p className="text-th-text-tertiary text-sm mt-1">{total} total accounts</p>
        </div>
        <div className="flex items-center space-x-3">
          <PermissionGate permission="accounts.read">
            <button
              onClick={handleExport}
              className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
            >
              <Download className="w-4 h-4" />
              <span>Export</span>
            </button>
          </PermissionGate>
          <PermissionGate permission="accounts.write">
            <button
              onClick={() => setShowAddAccount(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700"
            >
              <Plus className="w-4 h-4" />
              <span>New Account</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-surface-primary rounded-xl border border-th-border p-4">
        <div className="flex items-center space-x-4">
          {/* Search */}
          <div className="flex-1 flex items-center bg-surface-tertiary rounded-lg px-3 py-2">
            <Search className="w-4 h-4 text-th-text-tertiary mr-2" />
            <input
              type="text"
              placeholder="Search by name, industry, or website..."
              value={filters.search || ''}
              onChange={(e) => handleSearch(e.target.value)}
              className="bg-transparent border-none outline-none text-sm w-full text-th-text-secondary placeholder-th-text-tertiary"
            />
          </div>

          {/* Account Type filter */}
          <div className="relative">
            <select
              value={filters.account_type || ''}
              onChange={(e) => handleTypeFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              {ACCOUNT_TYPE_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* Industry filter */}
          <div className="relative">
            <select
              value={filters.industry || ''}
              onChange={(e) => handleIndustryFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              <option value="">All Industries</option>
              {industries.map((industry) => (
                <option key={industry} value={industry}>
                  {industry}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* Rating filter */}
          <div className="relative">
            <select
              value={filters.rating || ''}
              onChange={(e) => handleRatingFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              {RATING_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* More filters toggle */}
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center space-x-2 px-4 py-2 border rounded-lg text-sm font-medium transition-colors ${
              showFilters
                ? 'border-th-accent-500 text-th-accent-700 bg-th-accent-50'
                : 'border-th-border text-th-text-secondary hover:bg-surface-secondary'
            }`}
          >
            <Filter className="w-4 h-4" />
            <span>Filters</span>
          </button>
        </div>
      </div>

      {/* Accounts table */}
      <div className="bg-surface-primary rounded-xl border border-th-border overflow-hidden">
        {loading ? (
          <div className="flex items-center justify-center h-64">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
          </div>
        ) : accounts.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-th-text-tertiary">
            <Building2 className="w-12 h-12 mb-4 opacity-50" />
            <p>No accounts found</p>
            <p className="text-sm mt-1">Try adjusting your filters or create a new account</p>
          </div>
        ) : (
          <>
            <table className="w-full">
              <thead>
                <tr className="bg-surface-secondary border-b border-th-border">
                  <th className="w-12 px-4 py-3">
                    <input
                      type="checkbox"
                      checked={selectedAccounts.size === accounts.length && accounts.length > 0}
                      onChange={toggleSelectAll}
                      className="w-4 h-4 rounded border-th-border"
                    />
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Name
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Type
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Industry
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Phone
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Owner
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Created
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-th-border">
                {accounts.map((account) => {
                  const typeColors = getTypeColors(account.account_type);
                  const ratingColors = getRatingColors(account.rating);
                  const isSelected = selectedAccounts.has(account.id);

                  return (
                    <tr
                      key={account.id}
                      className={`hover:bg-surface-secondary cursor-pointer ${
                        isSelected ? 'bg-th-accent-50' : ''
                      }`}
                      onClick={() => handleRowClick(account.id)}
                    >
                      <td
                        className="w-12 px-4 py-4"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <input
                          type="checkbox"
                          checked={isSelected}
                          onChange={() => toggleSelectAccount(account.id)}
                          className="w-4 h-4 rounded border-th-border"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
