                showConfirmAction === 'start'
                  ? 'bg-green-600 hover:bg-green-700'
                  : showConfirmAction === 'pause'
                  ? 'bg-yellow-600 hover:bg-yellow-700'
                  : 'bg-blue-600 hover:bg-blue-700'
