// Helper component for stats rows
function StatRow({
  label,
  value,
  icon,
  color,
  percentage,
}: {
  label: string;
  value: number;
  icon: React.ReactNode;
  color: string;
  percentage?: number;
}) {
  const colorClasses: Record<string, { bg: string; text: string; bar: string }> = {
    gray: { bg: 'bg-gray-100', text: 'text-gray-700', bar: 'bg-gray-400' },
    blue: { bg: 'bg-blue-100', text: 'text-blue-700', bar: 'bg-blue-500' },
    cyan: { bg: 'bg-cyan-100', text: 'text-cyan-700', bar: 'bg-cyan-500' },
    green: { bg: 'bg-green-100', text: 'text-green-700', bar: 'bg-green-500' },
    emerald: { bg: 'bg-green-100', text: 'text-green-700', bar: 'bg-green-500' },
    orange: { bg: 'bg-orange-100', text: 'text-orange-700', bar: 'bg-orange-500' },
    red: { bg: 'bg-red-100', text: 'text-red-700', bar: 'bg-red-500' },
  };

  const colorClass = colorClasses[color] || colorClasses.gray;

  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className={`w-6 h-6 ${colorClass.bg} rounded flex items-center justify-center`}>
            <span className={colorClass.text}>{icon}</span>
          </div>
          <span className="text-sm text-th-text-secondary">{label}</span>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-sm font-medium text-th-text-primary">{value}</span>
          {percentage !== undefined && (
            <span className="text-xs text-th-text-tertiary">({percentage.toFixed(1)}%)</span>
          )}
        </div>
      </div>
      {percentage !== undefined && (
        <div className="w-full bg-surface-tertiary rounded-full h-1.5">
          <div
            className={`h-1.5 rounded-full ${colorClass.bar}`}
            style={{ width: `${Math.min(percentage, 100)}%` }}
          />
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import {
  Search,
  Filter,
  Plus,
  ChevronDown,
  Calendar,
  DollarSign,
  Users,
  Target,
  TrendingUp,
  Megaphone,
} from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import { PermissionGate } from '../components/PermissionGate';
import { AddCampaignModal } from '../components/AddCampaignModal';
import type { CampaignWithRelations, CampaignFilters, CampaignStatus, CampaignType } from '@mpbhealth/crm-core';

const statusColors: Record<CampaignStatus, { bg: string; text: string }> = {
  draft: { bg: 'bg-gray-100', text: 'text-gray-700' },
  scheduled: { bg: 'bg-blue-100', text: 'text-blue-700' },
  active: { bg: 'bg-green-100', text: 'text-green-700' },
  paused: { bg: 'bg-yellow-100', text: 'text-yellow-700' },
  completed: { bg: 'bg-blue-100', text: 'text-blue-700' },
  cancelled: { bg: 'bg-red-100', text: 'text-red-700' },
};

const typeLabels: Record<CampaignType, string> = {
  email: 'Email',
  social: 'Social Media',
  event: 'Event',
  webinar: 'Webinar',
  advertisement: 'Advertisement',
  referral: 'Referral',
  other: 'Other',
};

export default function Campaigns() {
  const { campaignService } = useCRM();
  const [campaigns, setCampaigns] = useState<CampaignWithRelations[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<CampaignFilters>({});
  const [page, setPage] = useState(0);
  const [showFilters, setShowFilters] = useState(false);
  const [showAddCampaign, setShowAddCampaign] = useState(false);
  const pageSize = 20;

  // Stats
  const [stats, setStats] = useState({
    totalCampaigns: 0,
    activeCampaigns: 0,
    totalBudget: 0,
    totalMembers: 0,
  });

  const loadCampaigns = useCallback(async () => {
    setLoading(true);
    const { campaigns, total } = await campaignService.getCampaigns(filters, pageSize, page * pageSize);
    setCampaigns(campaigns);
    setTotal(total);

    // Calculate stats from all campaigns
    const activeCampaigns = await campaignService.getActiveCampaigns();
    const totalBudget = campaigns.reduce((sum, c) => sum + (c.budget || 0), 0);
    const totalMembers = campaigns.reduce((sum, c) => sum + (c.members_count || 0), 0);

    setStats({
      totalCampaigns: total,
      activeCampaigns: activeCampaigns.length,
      totalBudget,
      totalMembers,
    });

    setLoading(false);
  }, [campaignService, filters, page]);

  useEffect(() => {
    loadCampaigns();
  }, [loadCampaigns]);

  const handleSearch = (search: string) => {
    setFilters((prev) => ({ ...prev, search }));
    setPage(0);
  };

  const handleStatusFilter = (status: string) => {
    setFilters((prev) => ({ ...prev, status: status as CampaignStatus || undefined }));
    setPage(0);
  };

  const handleTypeFilter = (type: string) => {
    setFilters((prev) => ({ ...prev, campaign_type: type as CampaignType || undefined }));
    setPage(0);
  };

