import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Search,
  Filter,
  Download,
  Plus,
  ChevronDown,
  Briefcase,
  AlertCircle,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { PermissionGate } from '../components/PermissionGate';
import { useOrg } from '../contexts/OrgContext';
import {
  createCaseService,
  formatTimeAgo,
  type CaseWithRelations,
  type CaseFilters,
  type CaseStatus,
  type CasePriority,
} from '@mpbhealth/crm-core';
import { supabase } from '../lib/supabase';

// Filter options
const STATUS_OPTIONS = [
  { value: '', label: 'All Statuses' },
  { value: 'new', label: 'New' },
  { value: 'assigned', label: 'Assigned' },
  { value: 'in_progress', label: 'In Progress' },
  { value: 'on_hold', label: 'On Hold' },
  { value: 'escalated', label: 'Escalated' },
  { value: 'resolved', label: 'Resolved' },
  { value: 'closed', label: 'Closed' },
];

const PRIORITY_OPTIONS = [
  { value: '', label: 'All Priorities' },
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
  { value: 'urgent', label: 'Urgent' },
];

// Status badge colors
function getStatusColors(status: CaseStatus) {
  switch (status) {
    case 'new':
      return { bg: 'bg-blue-100', text: 'text-blue-700' };
    case 'assigned':
      return { bg: 'bg-cyan-100', text: 'text-cyan-700' };
    case 'in_progress':
      return { bg: 'bg-indigo-100', text: 'text-indigo-700' };
    case 'on_hold':
      return { bg: 'bg-amber-100', text: 'text-amber-700' };
    case 'escalated':
      return { bg: 'bg-red-100', text: 'text-red-700' };
    case 'resolved':
      return { bg: 'bg-green-100', text: 'text-green-700' };
    case 'closed':
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
    default:
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
  }
}

// Priority badge colors
function getPriorityColors(priority: CasePriority) {
  switch (priority) {
    case 'low':
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
    case 'medium':
      return { bg: 'bg-blue-100', text: 'text-blue-700' };
    case 'high':
      return { bg: 'bg-orange-100', text: 'text-orange-700' };
    case 'urgent':
      return { bg: 'bg-red-100', text: 'text-red-700' };
    default:
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
  }
}

// Format status label: replace underscores with spaces, capitalize
function formatStatusLabel(status: string): string {
  return status
    .split('_')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

// Generate CSV from cases
function generateCaseCSV(data: CaseWithRelations[]) {
  const headers = ['Case #', 'Subject', 'Priority', 'Status', 'Account', 'Contact', 'Assigned To', 'Created'];
  const rows = data.map((c) => [
    c.case_number,
    c.subject,
    c.priority,
    c.status,
    c.account?.name || '',
    c.contact ? `${c.contact.first_name} ${c.contact.last_name}` : '',
    c.assigned_user?.full_name || c.assigned_user?.email || '',
    new Date(c.created_at).toLocaleDateString(),
  ]);
  return [headers.join(','), ...rows.map((row) => row.map((cell) => `"${cell}"`).join(','))].join('\n');
}

export default function Cases() {
  const navigate = useNavigate();
  const { activeOrgId } = useOrg();

  // Initialize case service
  const [caseService] = useState(() => createCaseService(supabase));

  const [cases, setCases] = useState<CaseWithRelations[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<CaseFilters>({});
  const [page, setPage] = useState(0);
  const [showFilters, setShowFilters] = useState(false);
  const pageSize = 20;

  // Bulk selection state
  const [selectedCases, setSelectedCases] = useState<Set<string>>(new Set());

  // Load cases
  const loadCases = useCallback(async () => {
    setLoading(true);
    try {
      const { cases: data, total: count } = await caseService.getCases(
        filters,
        pageSize,
        page * pageSize
      );
      setCases(data);
      setTotal(count);
    } catch (error) {
      console.error('Failed to load cases:', error);
      toast.error('Failed to load cases');
    } finally {
      setLoading(false);
    }
  }, [caseService, filters, page]);

  useEffect(() => {
    loadCases();
  }, [loadCases]);

  // Clear selection when filters or page change
  useEffect(() => {
    setSelectedCases(new Set());
  }, [filters, page]);

  const handleSearch = (search: string) => {
    setFilters((prev) => ({ ...prev, search }));
    setPage(0);
  };

  const handleStatusFilter = (status: string) => {
    setFilters((prev) => ({ ...prev, status: (status || undefined) as CaseStatus | undefined }));
    setPage(0);
  };

  const handlePriorityFilter = (priority: string) => {
    setFilters((prev) => ({ ...prev, priority: (priority || undefined) as CasePriority | undefined }));
    setPage(0);
  };

  const handleExport = async () => {
    try {
      const { cases: exportCases } = await caseService.getCases(filters, 10000, 0);
      const csv = generateCaseCSV(exportCases);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `cases-export-${new Date().toISOString().split('T')[0]}.csv`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success('Export started');
    } catch (error) {
      console.error('Export failed:', error);
      toast.error('Failed to export cases');
    }
  };

  const handleExportSelected = async () => {
    try {
      const selected = cases.filter((c) => selectedCases.has(c.id));
      const csv = generateCaseCSV(selected);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `cases-selected-export-${new Date().toISOString().split('T')[0]}.csv`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success('Export started');
    } catch (error) {
      console.error('Export failed:', error);
      toast.error('Failed to export cases');
    }
  };

  const toggleSelectAll = useCallback(() => {
    if (selectedCases.size === cases.length) {
      setSelectedCases(new Set());
    } else {
      setSelectedCases(new Set(cases.map((c) => c.id)));
    }
  }, [cases, selectedCases.size]);

  const toggleSelectCase = useCallback((caseId: string) => {
    setSelectedCases((prev) => {
      const next = new Set(prev);
      if (next.has(caseId)) {
        next.delete(caseId);
      } else {
        next.add(caseId);
      }
      return next;
    });
  }, []);

  const handleRowClick = (caseId: string) => {
    navigate(`/cases/${caseId}`);
  };

  const totalPages = Math.ceil(total / pageSize);

  return (
    <div className="space-y-6">
      {/* Bulk Actions Toolbar */}
      {selectedCases.size > 0 && (
        <div className="bg-th-accent-50 border border-th-accent-200 rounded-lg px-4 py-3 flex items-center justify-between">
          <span className="text-sm font-medium text-th-accent-700">
            {selectedCases.size} case{selectedCases.size > 1 ? 's' : ''} selected
          </span>
          <div className="flex items-center space-x-3">
            <PermissionGate permission="cases.read">
              <button
                onClick={handleExportSelected}
                className="text-sm text-th-accent-600 hover:text-th-accent-700 font-medium"
              >
                Export Selected
              </button>
            </PermissionGate>
            <button
              onClick={() => setSelectedCases(new Set())}
              className="text-sm text-th-text-tertiary hover:text-th-text-secondary"
            >
              Clear
            </button>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Cases</h1>
          <p className="text-th-text-tertiary text-sm mt-1">{total} total cases</p>
        </div>
        <div className="flex items-center space-x-3">
          <PermissionGate permission="cases.read">
            <button
              onClick={handleExport}
              className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
            >
              <Download className="w-4 h-4" />
              <span>Export</span>
            </button>
          </PermissionGate>
          <PermissionGate permission="cases.write">
            <button
              onClick={() => navigate('/cases/new')}
              className="flex items-center space-x-2 px-4 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700"
            >
              <Plus className="w-4 h-4" />
              <span>New Case</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-surface-primary rounded-xl border border-th-border p-4">
        <div className="flex items-center space-x-4">
          {/* Search */}
          <div className="flex-1 flex items-center bg-surface-tertiary rounded-lg px-3 py-2">
            <Search className="w-4 h-4 text-th-text-tertiary mr-2" />
            <input
              type="text"
              placeholder="Search by case number, subject, or account..."
              value={filters.search || ''}
              onChange={(e) => handleSearch(e.target.value)}
              className="bg-transparent border-none outline-none text-sm w-full text-th-text-secondary placeholder-th-text-tertiary"
            />
          </div>

          {/* Status filter */}
          <div className="relative">
            <select
              value={filters.status || ''}
              onChange={(e) => handleStatusFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              {STATUS_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* Priority filter */}
          <div className="relative">
            <select
              value={filters.priority || ''}
              onChange={(e) => handlePriorityFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              {PRIORITY_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* More filters toggle */}
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center space-x-2 px-4 py-2 border rounded-lg text-sm font-medium transition-colors ${
              showFilters
                ? 'border-th-accent-500 text-th-accent-700 bg-th-accent-50'
                : 'border-th-border text-th-text-secondary hover:bg-surface-secondary'
            }`}
          >
            <Filter className="w-4 h-4" />
            <span>Filters</span>
          </button>
        </div>
      </div>

      {/* Cases table */}
      <div className="bg-surface-primary rounded-xl border border-th-border overflow-hidden">
        {loading ? (
          <div className="flex items-center justify-center h-64">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
          </div>
        ) : cases.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-th-text-tertiary">
            <Briefcase className="w-12 h-12 mb-4 opacity-50" />
            <p>No cases found</p>
            <p className="text-sm mt-1">Try adjusting your filters or create a new case</p>
          </div>
        ) : (
          <>
            <table className="w-full">
              <thead>
                <tr className="bg-surface-secondary border-b border-th-border">
                  <th className="w-12 px-4 py-3">
                    <input
                      type="checkbox"
                      checked={selectedCases.size === cases.length && cases.length > 0}
                      onChange={toggleSelectAll}
                      className="w-4 h-4 rounded border-th-border"
                    />
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Case
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Priority
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Status
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Account
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Contact
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Assigned To
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Created
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-th-border">
                {cases.map((caseItem) => {
                  const statusColors = getStatusColors(caseItem.status);
                  const priorityColors = getPriorityColors(caseItem.priority);
                  const isSelected = selectedCases.has(caseItem.id);

                  return (
                    <tr
                      key={caseItem.id}
                      className={`hover:bg-surface-secondary cursor-pointer ${
                        isSelected ? 'bg-th-accent-50' : ''
                      }`}
                      onClick={() => handleRowClick(caseItem.id)}
                    >
                      <td
                        className="w-12 px-4 py-4"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <input
                          type="checkbox"
                          checked={isSelected}
                          onChange={() => toggleSelectCase(caseItem.id)}
                          className="w-4 h-4 rounded border-th-border"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <div>
                          <p className="text-sm font-medium text-th-text-primary">
                            {caseItem.case_number}
                          </p>
                          <p className="text-xs text-th-text-tertiary truncate max-w-[200px]">
                            {caseItem.subject}
                          </p>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${priorityColors.bg} ${priorityColors.text}`}
                        >
                          {formatStatusLabel(caseItem.priority)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${statusColors.bg} ${statusColors.text}`}
                        >
                          {formatStatusLabel(caseItem.status)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {caseItem.account?.name || '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {caseItem.contact
                            ? `${caseItem.contact.first_name} ${caseItem.contact.last_name}`
                            : '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {caseItem.assigned_user?.full_name || caseItem.assigned_user?.email || '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-sm text-th-text-tertiary">
                        {formatTimeAgo(caseItem.created_at)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex items-center justify-between px-6 py-4 border-t border-th-border">
                <p className="text-sm text-th-text-tertiary">
                  Showing {page * pageSize + 1} to {Math.min((page + 1) * pageSize, total)} of {total}
                </p>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page === 0}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Previous
                  </button>
                  <button
                    onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                    disabled={page >= totalPages - 1}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Next
                  </button>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

// ============================================================================
// Connected Inbox - Multi-account unified inbox with dynamic folders
// Three-pane layout: folders | message list | reading pane
// ============================================================================

import { useState, useEffect, useCallback, useRef } from 'react';
import {
  Inbox, Send, File, Star, Archive, Trash2, AlertTriangle,
  RefreshCw, Search, MailOpen, Mail, Flag, Reply, ReplyAll,
  Forward, MoreHorizontal, ChevronDown, Paperclip, Clock,
  CheckCheck, Eye, Folder, Tag, X, Maximize2, Minimize2,
} from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import type {
  MailAccount, MailFolder, MailMessage,
  MailMessageFilters, UnifiedInboxStats,
} from '@mpbhealth/crm-core';
import toast from 'react-hot-toast';

// ============================================================================
// Folder icon mapping
// ============================================================================

const FOLDER_ICONS: Record<string, typeof Inbox> = {
  inbox: Inbox,
  sent: Send,
  drafts: File,
  trash: Trash2,
  junk: AlertTriangle,
  starred: Star,
  archive: Archive,
  important: Flag,
  custom: Folder,
};

const FOLDER_ORDER = ['inbox', 'starred', 'sent', 'drafts', 'archive', 'junk', 'trash'];

// ============================================================================
// Component
// ============================================================================

export default function ConnectedInbox() {
  const { mailAccountService, mailSyncService } = useCRM();
  const { activeOrgId } = useOrg();

  // State
  const [accounts, setAccounts] = useState<MailAccount[]>([]);
  const [selectedAccountId, setSelectedAccountId] = useState<string>('all');
  const [folders, setFolders] = useState<MailFolder[]>([]);
  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
  const [selectedFolderType, setSelectedFolderType] = useState<string>('inbox');
  const [messages, setMessages] = useState<MailMessage[]>([]);
  const [selectedMessage, setSelectedMessage] = useState<MailMessage | null>(null);
  const [messageBody, setMessageBody] = useState<string>('');
  const [stats, setStats] = useState<UnifiedInboxStats | null>(null);

  // UI state
  const [loading, setLoading] = useState(true);
  const [loadingMessages, setLoadingMessages] = useState(false);
  const [loadingBody, setLoadingBody] = useState(false);
  const [syncing, setSyncing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [page, setPage] = useState(1);
  const [totalMessages, setTotalMessages] = useState(0);
  const [readingPaneExpanded, setReadingPaneExpanded] = useState(false);

  const messageListRef = useRef<HTMLDivElement>(null);

  // ========================================================================
  // Data Loading
  // ========================================================================

  const loadAccounts = useCallback(async () => {
    if (!activeOrgId) return;
    const data = await mailAccountService.getAccounts(activeOrgId);
    setAccounts(data);
    return data;
  }, [mailAccountService, activeOrgId]);

  const loadFolders = useCallback(async (accountIds: string[]) => {
    const allFolders: MailFolder[] = [];
    for (const id of accountIds) {
      const f = await mailAccountService.getFolders(id);
      allFolders.push(...f);
    }
    setFolders(allFolders);
    return allFolders;
  }, [mailAccountService]);

  const loadMessages = useCallback(async (filters: MailMessageFilters = {}) => {
    setLoadingMessages(true);
    try {
      const accountIds = selectedAccountId === 'all'
        ? accounts.map(a => a.id)
        : [selectedAccountId];

      const result = await mailSyncService.getMessages(
        {
          account_ids: accountIds,
          folder_id: selectedFolderId || undefined,
          search: searchQuery || undefined,
          ...filters,
        },
        { page, per_page: 25 }
      );

      setMessages(result.messages);
      setTotalMessages(result.total);
    } catch (err) {
      console.error('Failed to load messages:', err);
    } finally {
      setLoadingMessages(false);
    }
  }, [mailSyncService, accounts, selectedAccountId, selectedFolderId, searchQuery, page]);

  const loadStats = useCallback(async (accountIds: string[]) => {
    if (!accountIds.length) return;
    const data = await mailSyncService.getUnifiedStats(accountIds);
    setStats(data);
  }, [mailSyncService]);

  // Initial load
  useEffect(() => {
    (async () => {
      setLoading(true);
      const accts = await loadAccounts();
      if (accts && accts.length > 0) {
        const ids = accts.map(a => a.id);
        await Promise.all([loadFolders(ids), loadStats(ids)]);
      }
      setLoading(false);
    })();
  }, [loadAccounts, loadFolders, loadStats]);

  // Load messages when filters change
  useEffect(() => {
    if (!loading && accounts.length > 0) {
      loadMessages();
    }
  }, [loadMessages, loading, accounts.length, selectedFolderType, selectedFolderId, page]);

  // ========================================================================
  // Actions
  // ========================================================================

  const handleSync = async () => {
    setSyncing(true);
    try {
      const accountIds = selectedAccountId === 'all'
        ? accounts.map(a => a.id)
        : [selectedAccountId];

      for (const id of accountIds) {
        await mailSyncService.triggerSync(id);
      }
      toast.success('Sync complete');
      await loadMessages();
      await loadStats(accountIds);
    } catch {
      toast.error('Sync failed');
    } finally {
      setSyncing(false);
    }
  };

  const handleSelectMessage = async (msg: MailMessage) => {
    setSelectedMessage(msg);
    setMessageBody('');

    // Mark as read
    if (!msg.is_read) {
      await mailSyncService.markRead(msg.account_id, msg.id, true);
      setMessages(prev => prev.map(m => m.id === msg.id ? { ...m, is_read: true } : m));
    }

    // Fetch body if not cached
    if (!msg.body_fetched || !msg.body_html) {
      setLoadingBody(true);
      try {
        const { body_html } = await mailSyncService.fetchMessageBody(msg.account_id, msg.id);
        setMessageBody(body_html);
      } catch {
        setMessageBody('<p>Failed to load message body</p>');
      } finally {
        setLoadingBody(false);
      }
    } else {
      setMessageBody(msg.body_html || '');
    }
  };

  const handleToggleFlag = async (msg: MailMessage) => {
    const newValue = !msg.is_flagged;
    setMessages(prev => prev.map(m => m.id === msg.id ? { ...m, is_flagged: newValue } : m));
    if (selectedMessage?.id === msg.id) {
      setSelectedMessage(prev => prev ? { ...prev, is_flagged: newValue } : null);
    }
    await mailSyncService.toggleFlag(msg.account_id, msg.id, newValue);
  };

  const handleDelete = async (msg: MailMessage) => {
    await mailSyncService.deleteMessage(msg.account_id, msg.id);
    setMessages(prev => prev.filter(m => m.id !== msg.id));
    if (selectedMessage?.id === msg.id) {
      setSelectedMessage(null);
    }
    toast.success('Moved to trash');
  };

  const handleFolderClick = (folderType: string, folderId?: string) => {
    setSelectedFolderType(folderType);
    setSelectedFolderId(folderId || null);
    setSelectedMessage(null);
    setPage(1);
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setPage(1);
    loadMessages();
  };

  // ========================================================================
  // Computed
  // ========================================================================

  // Deduplicate folders by type for the sidebar
  const foldersByType = new Map<string, { type: string; unread: number; total: number; ids: string[] }>();
  for (const f of folders) {
    const type = f.folder_type || 'custom';
    const existing = foldersByType.get(type);
    if (existing) {
      existing.unread += f.unread_count;
      existing.total += f.total_count;
      existing.ids.push(f.id);
    } else {
      foldersByType.set(type, {
        type,
        unread: f.unread_count,
        total: f.total_count,
        ids: [f.id],
      });
    }
  }

  const sortedFolderTypes = Array.from(foldersByType.values()).sort((a, b) => {
    const ai = FOLDER_ORDER.indexOf(a.type);
    const bi = FOLDER_ORDER.indexOf(b.type);
    return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
  });

  // Custom folders
  const customFolders = folders.filter(f => f.folder_type === 'custom' || !f.folder_type);

  // ========================================================================
  // Render
  // ========================================================================

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  if (accounts.length === 0) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center max-w-md px-4">
          <Inbox className="w-16 h-16 text-th-text-tertiary mx-auto mb-4" />
          <h2 className="text-xl font-semibold text-th-text-primary mb-2">No mail accounts connected</h2>
          <p className="text-sm text-th-text-secondary mb-6">
            Connect your Microsoft 365 or Gmail account to see your emails here
          </p>
          <a
            href="/email/accounts"
            className="inline-flex items-center gap-2 px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700"
          >
            Connect Account
          </a>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-[calc(100vh-64px)] bg-white">
      {/* ================================================================ */}
      {/* Folder Sidebar */}
      {/* ================================================================ */}
      <div className="w-56 border-r border-neutral-200 flex flex-col bg-neutral-50/50">
        {/* Account Selector */}
        <div className="p-3 border-b border-neutral-200">
          <select
            value={selectedAccountId}
            onChange={e => {
              setSelectedAccountId(e.target.value);
              setPage(1);
              setSelectedMessage(null);
            }}
            className="w-full text-sm px-2 py-1.5 border border-neutral-200 rounded-lg bg-white"
          >
            <option value="all">All Accounts ({accounts.length})</option>
            {accounts.map(a => (
              <option key={a.id} value={a.id}>{a.email_address}</option>
            ))}
          </select>
        </div>

        {/* Folder List */}
        <div className="flex-1 overflow-y-auto py-2">
          {sortedFolderTypes.map(folder => {
            const Icon = FOLDER_ICONS[folder.type] || Folder;
            const isActive = selectedFolderType === folder.type;
            const displayName = folder.type.charAt(0).toUpperCase() + folder.type.slice(1);

            return (
              <button
                key={folder.type}
                onClick={() => handleFolderClick(folder.type)}
                className={`w-full flex items-center justify-between px-4 py-2 text-sm transition-colors ${
                  isActive
                    ? 'bg-th-accent-50 text-th-accent-700 font-medium'
                    : 'text-th-text-secondary hover:bg-neutral-100'
                }`}
              >
                <div className="flex items-center gap-2.5">
                  <Icon className="w-4 h-4" />
                  <span>{displayName}</span>
                </div>
                {folder.unread > 0 && (
                  <span className={`text-xs font-medium px-1.5 py-0.5 rounded-full ${
                    isActive ? 'bg-th-accent-600 text-white' : 'bg-neutral-200 text-neutral-600'
                  }`}>
                    {folder.unread}
                  </span>
                )}
              </button>
            );
          })}

          {/* Custom folders */}
          {customFolders.length > 0 && (
            <>
              <div className="px-4 py-2 mt-2">
                <span className="text-xs font-medium text-th-text-tertiary uppercase tracking-wider">Labels</span>
              </div>
              {customFolders.map(f => (
                <button
                  key={f.id}
                  onClick={() => handleFolderClick('custom', f.id)}
                  className={`w-full flex items-center justify-between px-4 py-1.5 text-sm transition-colors ${
                    selectedFolderId === f.id
                      ? 'bg-th-accent-50 text-th-accent-700 font-medium'
                      : 'text-th-text-secondary hover:bg-neutral-100'
                  }`}
                >
                  <div className="flex items-center gap-2.5">
                    {f.label_color && (
                      <span
                        className="w-2.5 h-2.5 rounded-full"
                        style={{ backgroundColor: f.label_color }}
                      />
                    )}
                    <Tag className="w-3.5 h-3.5" />
                    <span className="truncate">{f.display_name || f.name}</span>
                  </div>
                  {f.unread_count > 0 && (
                    <span className="text-xs text-neutral-500">{f.unread_count}</span>
                  )}
                </button>
              ))}
            </>
          )}
        </div>

        {/* Unread summary */}
        {stats && (
          <div className="p-3 border-t border-neutral-200 text-xs text-th-text-tertiary">
            {stats.total_unread} unread &middot; {stats.total_flagged} flagged
          </div>
        )}
      </div>

      {/* ================================================================ */}
      {/* Message List */}
      {/* ================================================================ */}
      <div className={`flex flex-col border-r border-neutral-200 ${
        readingPaneExpanded ? 'w-0 hidden' : selectedMessage ? 'w-96' : 'flex-1'
      }`}>
        {/* Search & Actions Bar */}
        <div className="flex items-center gap-2 p-3 border-b border-neutral-200">
          <form onSubmit={handleSearch} className="flex-1 relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-4 h-4 text-neutral-400" />
            <input
              type="text"
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              placeholder="Search messages..."
              className="w-full pl-8 pr-3 py-1.5 text-sm border border-neutral-200 rounded-lg"
            />
          </form>
          <button
            onClick={handleSync}
            disabled={syncing}
            className="p-2 text-th-text-tertiary hover:text-th-accent-600 hover:bg-th-accent-50 rounded-lg"
            title="Sync"
          >
            <RefreshCw className={`w-4 h-4 ${syncing ? 'animate-spin' : ''}`} />
          </button>
        </div>

        {/* Message List */}
        <div ref={messageListRef} className="flex-1 overflow-y-auto">
          {loadingMessages ? (
            <div className="flex justify-center py-12">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-th-accent-600" />
            </div>
          ) : messages.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-th-text-tertiary">
              <MailOpen className="w-10 h-10 mb-2" />
              <p className="text-sm">No messages</p>
            </div>
          ) : (
            messages.map(msg => {
              const isSelected = selectedMessage?.id === msg.id;
              const account = accounts.find(a => a.id === msg.account_id);

              return (
                <div
                  key={msg.id}
                  onClick={() => handleSelectMessage(msg)}
                  className={`px-4 py-3 border-b border-neutral-100 cursor-pointer transition-colors ${
                    isSelected ? 'bg-th-accent-50' : msg.is_read ? 'bg-white hover:bg-neutral-50' : 'bg-blue-50/30 hover:bg-blue-50/50'
                  }`}
                >
                  <div className="flex items-start gap-3">
                    {/* Unread indicator */}
                    <div className="mt-2 flex-shrink-0">
                      {!msg.is_read ? (
                        <div className="w-2 h-2 rounded-full bg-th-accent-600" />
                      ) : (
                        <div className="w-2 h-2" />
                      )}
                    </div>

                    <div className="flex-1 min-w-0">
                      {/* From + date */}
                      <div className="flex items-center justify-between gap-2">
                        <span className={`text-sm truncate ${!msg.is_read ? 'font-semibold text-th-text-primary' : 'text-th-text-secondary'}`}>
                          {msg.from_name || msg.from_address || 'Unknown'}
                        </span>
