              </button>
            </div>
          </div>
        )}
      </div>

      {/* ================================================================ */}
      {/* Reading Pane */}
      {/* ================================================================ */}
      {selectedMessage && (
        <div className={`flex flex-col ${readingPaneExpanded ? 'flex-1' : 'flex-1'} bg-white`}>
