                        className="block p-4 rounded-lg border border-th-border hover:bg-surface-secondary transition-colors"
                      >
                        <div className="flex items-center justify-between">
                          <div>
                            <p className="text-sm font-medium text-th-text-primary">{deal.name}</p>
                            <div className="flex items-center space-x-3 mt-1">
                              {deal.stage && (
                                <span
                                  className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium"
                                  style={{
                                    backgroundColor: `${deal.stage.color}20`,
                                    color: deal.stage.color,
                                  }}
                                >
                                  {deal.stage.display_name}
                                </span>
                              )}
                              {deal.contact_role && (
                                <span className="text-xs text-th-text-tertiary">
                                  Role: {deal.contact_role}
                                </span>
                              )}
                              {deal.is_primary && (
                                <span className="text-xs font-medium text-th-accent-600">
                                  Primary Contact
                                </span>
                              )}
                            </div>
                          </div>
                          <div className="text-right">
                            {deal.amount !== null && (
                              <p className="text-sm font-semibold text-th-text-primary">
                                ${deal.amount.toLocaleString()}
                              </p>
                            )}
                            {deal.expected_close_date && (
                              <p className="text-xs text-th-text-tertiary">
                                Close: {new Date(deal.expected_close_date).toLocaleDateString()}
                              </p>
                            )}
                          </div>
                        </div>
                      </Link>
                    ))
                  )}
                </div>
              )}

              {activeTab === 'activities' && (
                <div className="space-y-3">
                  {activities.length === 0 ? (
                    <div className="text-center py-8 text-th-text-tertiary">
                      <Calendar className="w-12 h-12 mx-auto mb-3 opacity-50" />
                      <p>No activities recorded for this contact</p>
                    </div>
                  ) : (
                    <div className="activity-timeline">
                      {activities.map((activity) => (
                        <div key={activity.id} className="activity-item pb-4 border-l-2 border-th-border pl-4 ml-2">
                          <div className="absolute -left-1.5 mt-1.5 w-3 h-3 rounded-full bg-th-accent-600" />
                          <p className="text-sm font-medium text-th-text-primary">
                            {activity.title}
                          </p>
                          {activity.description && (
                            <p className="text-sm text-th-text-tertiary mt-1">
                              {activity.description}
                            </p>
                          )}
                          <p className="text-xs text-th-text-tertiary mt-1">
                            {formatTimeAgo(activity.created_at)}
                          </p>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Edit Modal */}
      <AddContactModal
        open={showEditContact}
        onClose={() => setShowEditContact(false)}
        onSuccess={() => loadContact()}
        contact={contact}
      />
    </div>
  );
}

import { useState, useEffect, useCallback, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  Search,
  Filter,
  Download,
  Plus,
  ChevronDown,
  Mail,
  Phone,
  Users,
  Building2,
  Upload,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { PermissionGate } from '../components/PermissionGate';
import { AddContactModal } from '../components/AddContactModal';
import { ImportModal } from '../components/ImportModal';
import { supabase } from '../lib/supabase';
import {
  createContactService,
  createAccountService,
  formatTimeAgo,
  type ContactWithRelations,
  type ContactFilters,
  type AccountWithRelations,
} from '@mpbhealth/crm-core';

const contactService = createContactService(supabase);
const accountService = createAccountService(supabase);

export default function Contacts() {
  const navigate = useNavigate();
  const [contacts, setContacts] = useState<ContactWithRelations[]>([]);
  const [accounts, setAccounts] = useState<AccountWithRelations[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<ContactFilters>({});
  const [page, setPage] = useState(0);
  const [showFilters, setShowFilters] = useState(false);
  const [showAddContact, setShowAddContact] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const pageSize = 20;

  // Bulk selection state
  const [selectedContacts, setSelectedContacts] = useState<Set<string>>(new Set());

  // Lead source options (common sources)
  const leadSources = useMemo(() => [
    'Website',
    'Referral',
    'Cold Call',
    'LinkedIn',
    'Trade Show',
    'Partner',
    'Advertisement',
    'Other',
  ], []);

  const loadContacts = useCallback(async () => {
    setLoading(true);
    const { contacts: data, total: count } = await contactService.getContacts(filters, pageSize, page * pageSize);
    setContacts(data);
    setTotal(count);
    setLoading(false);
  }, [filters, page]);

  const loadAccounts = useCallback(async () => {
    const { accounts: data } = await accountService.getAccounts({}, 200, 0);
    setAccounts(data);
  }, []);

  useEffect(() => {
    loadContacts();
  }, [loadContacts]);

  useEffect(() => {
    loadAccounts();
  }, [loadAccounts]);

  // Clear selection when filters or page change
  useEffect(() => {
    setSelectedContacts(new Set());
  }, [filters, page]);

  const handleSearch = (search: string) => {
    setFilters((prev) => ({ ...prev, search }));
    setPage(0);
  };

  const handleAccountFilter = (accountId: string) => {
    setFilters((prev) => ({ ...prev, account_id: accountId || undefined }));
    setPage(0);
  };

  const handleLeadSourceFilter = (leadSource: string) => {
    setFilters((prev) => ({ ...prev, lead_source: leadSource || undefined }));
    setPage(0);
  };

  const handleExport = async () => {
    try {
      const exportContacts = await contactService.getContactsForExport(undefined, filters);
      const csv = generateCSV(exportContacts);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `contacts-export-${new Date().toISOString().split('T')[0]}.csv`;
      a.click();
      toast.success('Contacts exported successfully');
    } catch (error) {
      toast.error('Failed to export contacts');
    }
  };

  const handleExportSelected = async () => {
    try {
      const ids = Array.from(selectedContacts);
      const exportContacts = await contactService.getContactsForExport(ids);
      const csv = generateCSV(exportContacts);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `contacts-selected-export-${new Date().toISOString().split('T')[0]}.csv`;
      a.click();
      toast.success('Selected contacts exported successfully');
    } catch (error) {
      toast.error('Failed to export contacts');
    }
  };

  const generateCSV = (contactsData: any[]): string => {
    const headers = [
      'First Name',
      'Last Name',
      'Email',
      'Phone',
      'Mobile',
      'Title',
      'Department',
      'Account',
      'Lead Source',
      'Created At',
    ];
    const rows = contactsData.map((c) => [
      c.first_name,
      c.last_name,
      c.email || '',
      c.phone || '',
      c.mobile || '',
      c.title || '',
      c.department || '',
      c.account?.name || '',
      c.lead_source || '',
      c.created_at,
    ]);
    return [headers, ...rows].map((row) => row.map((cell) => `"${cell}"`).join(',')).join('\n');
  };

  const toggleSelectAll = useCallback(() => {
    if (selectedContacts.size === contacts.length) {
      setSelectedContacts(new Set());
    } else {
      setSelectedContacts(new Set(contacts.map((c) => c.id)));
    }
  }, [contacts, selectedContacts.size]);

  const toggleSelectContact = useCallback((contactId: string) => {
    setSelectedContacts((prev) => {
      const next = new Set(prev);
      if (next.has(contactId)) {
        next.delete(contactId);
      } else {
        next.add(contactId);
      }
      return next;
    });
  }, []);

  const handleRowClick = (contactId: string) => {
    navigate(`/contacts/${contactId}`);
  };

  const totalPages = Math.ceil(total / pageSize);

  return (
    <div className="space-y-6">
      {/* Bulk Actions Toolbar */}
      {selectedContacts.size > 0 && (
        <div className="bg-th-accent-50 border border-th-accent-200 rounded-xl p-4 flex items-center justify-between">
          <span className="text-sm font-medium text-th-accent-700">
            {selectedContacts.size} contact{selectedContacts.size > 1 ? 's' : ''} selected
          </span>
          <div className="flex items-center space-x-3">
            <button
              onClick={handleExportSelected}
              className="flex items-center space-x-2 px-3 py-1.5 text-sm font-medium text-th-accent-700 hover:bg-th-accent-100 rounded-lg"
            >
              <Download className="w-4 h-4" />
              <span>Export Selected</span>
            </button>
            <button
              onClick={() => setSelectedContacts(new Set())}
              className="px-3 py-1.5 text-sm font-medium text-th-text-secondary hover:bg-surface-secondary rounded-lg"
            >
              Clear Selection
            </button>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary flex items-center space-x-2">
            <Users className="w-7 h-7" />
            <span>Contacts</span>
          </h1>
          <p className="text-th-text-tertiary text-sm mt-1">
            {total} total contacts
          </p>
        </div>
        <div className="flex items-center space-x-3">
          <button
            onClick={handleExport}
            className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
          >
            <Download className="w-4 h-4" />
            <span>Export</span>
          </button>
          <PermissionGate permission="contacts.write">
            <button
              onClick={() => setShowImport(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
            >
              <Upload className="w-4 h-4" />
              <span>Import</span>
            </button>
          </PermissionGate>
          <PermissionGate permission="contacts.write">
            <button
              onClick={() => setShowAddContact(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700"
            >
              <Plus className="w-4 h-4" />
              <span>New Contact</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-surface-primary rounded-xl border border-th-border p-4">
        <div className="flex items-center space-x-4">
          {/* Search */}
          <div className="flex-1 flex items-center bg-surface-tertiary rounded-lg px-3 py-2">
            <Search className="w-4 h-4 text-th-text-tertiary mr-2" />
            <input
              type="text"
              placeholder="Search by name, email, or phone..."
              value={filters.search || ''}
              onChange={(e) => handleSearch(e.target.value)}
              className="bg-transparent border-none outline-none text-sm w-full text-th-text-secondary placeholder-th-text-tertiary"
            />
          </div>

          {/* Account filter */}
          <div className="relative">
            <select
              value={filters.account_id || ''}
              onChange={(e) => handleAccountFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              <option value="">All Accounts</option>
              {accounts.map((account) => (
                <option key={account.id} value={account.id}>
                  {account.name}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* Lead Source filter */}
          <div className="relative">
            <select
              value={filters.lead_source || ''}
              onChange={(e) => handleLeadSourceFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              <option value="">All Sources</option>
              {leadSources.map((source) => (
                <option key={source} value={source}>
                  {source}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* More filters */}
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center space-x-2 px-4 py-2 border rounded-lg text-sm font-medium transition-colors ${
              showFilters
                ? 'border-th-accent-500 text-th-accent-700 bg-th-accent-50'
                : 'border-th-border text-th-text-secondary hover:bg-surface-secondary'
            }`}
          >
            <Filter className="w-4 h-4" />
            <span>Filters</span>
          </button>
        </div>

        {/* Advanced filters */}
        {showFilters && (
          <div className="mt-4 pt-4 border-t border-th-border grid grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Do Not Call
              </label>
              <select
                value={filters.do_not_call === undefined ? '' : filters.do_not_call ? 'true' : 'false'}
                onChange={(e) => {
                  const val = e.target.value;
                  setFilters((prev) => ({
                    ...prev,
                    do_not_call: val === '' ? undefined : val === 'true',
                  }));
                  setPage(0);
                }}
                className="w-full border border-th-border rounded-lg px-3 py-2 text-sm"
              >
                <option value="">Any</option>
                <option value="true">Yes</option>
                <option value="false">No</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Do Not Email
              </label>
              <select
                value={filters.do_not_email === undefined ? '' : filters.do_not_email ? 'true' : 'false'}
                onChange={(e) => {
                  const val = e.target.value;
                  setFilters((prev) => ({
                    ...prev,
                    do_not_email: val === '' ? undefined : val === 'true',
                  }));
                  setPage(0);
                }}
                className="w-full border border-th-border rounded-lg px-3 py-2 text-sm"
              >
                <option value="">Any</option>
                <option value="true">Yes</option>
                <option value="false">No</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-th-text-secondary mb-1">
                Created After
              </label>
              <input
                type="date"
                value={filters.dateFrom || ''}
                onChange={(e) => {
                  setFilters((prev) => ({ ...prev, dateFrom: e.target.value || undefined }));
                  setPage(0);
                }}
                className="w-full border border-th-border rounded-lg px-3 py-2 text-sm"
              />
            </div>
          </div>
        )}
      </div>

      {/* Contacts table */}
      <div className="bg-surface-primary rounded-xl border border-th-border overflow-hidden">
        {loading ? (
          <div className="flex items-center justify-center h-64">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
          </div>
        ) : contacts.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-th-text-tertiary">
            <Users className="w-12 h-12 mb-3" />
            <p>No contacts found</p>
            <p className="text-sm mt-1">Try adjusting your filters or add a new contact</p>
          </div>
        ) : (
          <>
            <table className="w-full">
              <thead>
                <tr className="bg-surface-secondary border-b border-th-border">
                  <th className="w-12 px-4 py-3">
                    <input
                      type="checkbox"
                      checked={selectedContacts.size === contacts.length && contacts.length > 0}
                      onChange={toggleSelectAll}
                      className="w-4 h-4 rounded border-th-border"
                    />
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Name
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Email
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Phone
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Account
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Title
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Owner
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Created
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-th-border">
                {contacts.map((contact) => {
                  const isSelected = selectedContacts.has(contact.id);

                  return (
                    <tr
                      key={contact.id}
                      className={`hover:bg-surface-secondary cursor-pointer ${isSelected ? 'bg-th-accent-50' : ''}`}
                      onClick={() => handleRowClick(contact.id)}
                    >
                      <td className="w-12 px-4 py-4" onClick={(e) => e.stopPropagation()}>
                        <input
                          type="checkbox"
                          checked={isSelected}
                          onChange={() => toggleSelectContact(contact.id)}
                          className="w-4 h-4 rounded border-th-border"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 bg-th-accent-100 rounded-full flex items-center justify-center">
                            <span className="text-th-accent-700 font-medium text-sm">
                              {contact.first_name.charAt(0)}
                              {contact.last_name.charAt(0)}
                            </span>
                          </div>
                          <div>
                            <p className="text-sm font-medium text-th-text-primary hover:text-th-accent-600">
                              {contact.salutation ? `${contact.salutation} ` : ''}
                              {contact.first_name} {contact.last_name}
                            </p>
                            {contact.department && (
                              <p className="text-xs text-th-text-tertiary">
                                {contact.department}
                              </p>
                            )}
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        {contact.email ? (
                          <a
                            href={`mailto:${contact.email}`}
                            onClick={(e) => e.stopPropagation()}
                            className="flex items-center text-sm text-th-text-secondary hover:text-th-accent-600"
                          >
                            <Mail className="w-4 h-4 mr-2" />
                            {contact.email}
                          </a>
                        ) : (
                          <span className="text-sm text-th-text-tertiary">-</span>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        {contact.phone ? (
                          <a
                            href={`tel:${contact.phone}`}
                            onClick={(e) => e.stopPropagation()}
                            className="flex items-center text-sm text-th-text-secondary hover:text-th-accent-600"
                          >
                            <Phone className="w-4 h-4 mr-2" />
                            {contact.phone}
                          </a>
                        ) : (
                          <span className="text-sm text-th-text-tertiary">-</span>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        {contact.account ? (
                          <Link
                            to={`/accounts/${contact.account.id}`}
                            onClick={(e) => e.stopPropagation()}
                            className="flex items-center text-sm text-th-accent-600 hover:underline"
                          >
                            <Building2 className="w-4 h-4 mr-2" />
                            {contact.account.name}
                          </Link>
                        ) : (
                          <span className="text-sm text-th-text-tertiary">-</span>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {contact.title || '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {contact.owner?.full_name || contact.owner?.email || '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-sm text-th-text-tertiary">
                        {formatTimeAgo(contact.created_at)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex items-center justify-between px-6 py-4 border-t border-th-border">
                <p className="text-sm text-th-text-tertiary">
                  Showing {page * pageSize + 1} to{' '}
                  {Math.min((page + 1) * pageSize, total)} of {total}
                </p>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page === 0}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Previous
                  </button>
                  <button
                    onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                    disabled={page >= totalPages - 1}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Next
                  </button>
                </div>
              </div>
            )}
          </>
        )}
      </div>

      {/* Modals */}
      <AddContactModal
        open={showAddContact}
        onClose={() => setShowAddContact(false)}
        onSuccess={() => loadContacts()}
      />
      <ImportModal
        isOpen={showImport}
        onClose={() => setShowImport(false)}
        entityType="contacts"
        onSuccess={() => loadContacts()}
      />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import {
  ArrowLeft,
  Edit2,
  DollarSign,
  Building2,
  Calendar,
  User,
  Trophy,
  XCircle,
  Plus,
  Mail,
  Phone,
  Clock,
  Tag,
  FileText,
  Users,
  Package,
  Receipt,
  Activity,
  History,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import { PermissionGate } from '../components/PermissionGate';
import { AddDealModal } from '../components/AddDealModal';
import { Modal } from '../components/Modal';
import { logAuditEvent, AUDIT_ACTIONS } from '@mpbhealth/auth';
import type { DealWithRelations, DealStageHistory } from '@mpbhealth/crm-core';
import { formatTimeAgo } from '@mpbhealth/crm-core';

type TabType = 'overview' | 'contacts' | 'products' | 'quotes' | 'activities' | 'history';

export default function DealDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { dealService, activityService, dealStages, refreshDashboard } = useCRM();
  const { activeOrgId } = useOrg();

  const [deal, setDeal] = useState<DealWithRelations | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<TabType>('overview');
  const [showEditDeal, setShowEditDeal] = useState(false);
  const [showWonModal, setShowWonModal] = useState(false);
  const [showLostModal, setShowLostModal] = useState(false);
  const [lostReason, setLostReason] = useState('');
  const [saving, setSaving] = useState(false);

  // Related data
  const [dealContacts, setDealContacts] = useState<any[]>([]);
  const [dealProducts, setDealProducts] = useState<any[]>([]);
  const [stageHistory, setStageHistory] = useState<DealStageHistory[]>([]);
  const [activities, setActivities] = useState<any[]>([]);

  const loadDeal = async () => {
    if (!id) return;

    setLoading(true);
    const dealData = await dealService.getDeal(id);
    setDeal(dealData);

    if (dealData) {
      // Load related data in parallel
      const [contacts, products, history] = await Promise.all([
        dealService.getDealContacts(id),
        dealService.getDealProducts(id),
        dealService.getDealStageHistory(id),
      ]);
      setDealContacts(contacts);
      setDealProducts(products);
      setStageHistory(history);
    }

    setLoading(false);
  };

  useEffect(() => {
    loadDeal();
  }, [id]);

  const handleStageChange = async (newStageId: string) => {
    if (!deal) return;

    const result = await dealService.updateDealStage(deal.id, newStageId);
    if (result.success) {
      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.DEAL_STAGE_CHANGED || 'deal.stage_changed',
        entityType: 'deal',
        entityId: deal.id,
        before: { stage_id: deal.stage_id },
        after: { stage_id: newStageId },
      }).catch(console.error);
      toast.success('Stage updated');
      refreshDashboard();
      loadDeal();
    } else {
      toast.error('Failed to update stage');
    }
  };

  const handleMarkWon = async () => {
    if (!deal) return;

    setSaving(true);
    const result = await dealService.markDealWon(deal.id);
    setSaving(false);

    if (result.success) {
      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.DEAL_WON || 'deal.won',
        entityType: 'deal',
        entityId: deal.id,
        after: { amount: deal.amount },
      }).catch(console.error);
      toast.success('Deal marked as Won!');
      refreshDashboard();
      setShowWonModal(false);
      loadDeal();
    } else {
      toast.error(result.error || 'Failed to mark deal as won');
    }
  };

  const handleMarkLost = async () => {
    if (!deal || !lostReason.trim()) {
      toast.error('Please provide a reason');
      return;
    }

    setSaving(true);
    const result = await dealService.markDealLost(deal.id, lostReason);
    setSaving(false);

    if (result.success) {
      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.DEAL_LOST || 'deal.lost',
        entityType: 'deal',
        entityId: deal.id,
        after: { lost_reason: lostReason },
      }).catch(console.error);
      toast.success('Deal marked as Lost');
      refreshDashboard();
      setShowLostModal(false);
      setLostReason('');
      loadDeal();
    } else {
      toast.error(result.error || 'Failed to mark deal as lost');
    }
  };

  const formatCurrency = (amount: number | null) => {
    if (amount === null || amount === undefined) return '-';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: deal?.currency || 'USD',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(amount);
  };

  const formatDate = (date: string | null) => {
    if (!date) return '-';
    return new Date(date).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  if (!deal) {
    return (
      <div className="text-center py-12">
        <p className="text-th-text-tertiary">Deal not found</p>
        <Link to="/deals" className="text-th-accent-600 hover:underline mt-2 inline-block">
          Back to deals
        </Link>
      </div>
    );
  }

  const isWon = deal.won_at !== null;
  const isLost = deal.lost_at !== null;
  const isClosed = isWon || isLost;

  const tabs: { id: TabType; label: string; icon: React.ReactNode }[] = [
    { id: 'overview', label: 'Overview', icon: <FileText className="w-4 h-4" /> },
    { id: 'contacts', label: 'Contacts', icon: <Users className="w-4 h-4" /> },
    { id: 'products', label: 'Products', icon: <Package className="w-4 h-4" /> },
    { id: 'quotes', label: 'Quotes', icon: <Receipt className="w-4 h-4" /> },
    { id: 'activities', label: 'Activities', icon: <Activity className="w-4 h-4" /> },
    { id: 'history', label: 'Stage History', icon: <History className="w-4 h-4" /> },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button
            onClick={() => navigate('/deals')}
            className="p-2 hover:bg-surface-tertiary rounded-lg"
          >
            <ArrowLeft className="w-5 h-5 text-th-text-tertiary" />
          </button>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-2xl font-bold text-th-text-primary">{deal.name}</h1>
              <span
                className="inline-flex items-center px-3 py-1 rounded-full text-sm font-medium"
                style={{
                  backgroundColor: `${deal.stage?.color || '#6B7280'}20`,
                  color: deal.stage?.color || '#6B7280',
                }}
              >
                {deal.stage?.display_name || '-'}
              </span>
              {isWon && (
                <span className="inline-flex items-center gap-1 px-3 py-1 rounded-full text-sm font-medium bg-green-100 text-green-700">
                  <Trophy className="w-4 h-4" /> Won
                </span>
              )}
              {isLost && (
                <span className="inline-flex items-center gap-1 px-3 py-1 rounded-full text-sm font-medium bg-red-100 text-red-700">
                  <XCircle className="w-4 h-4" /> Lost
                </span>
              )}
            </div>
            <p className="text-2xl font-bold text-th-accent-600 mt-1">
              {formatCurrency(deal.amount)}
            </p>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          {!isClosed && (
            <PermissionGate permission="deals.write">
              <button
                onClick={() => setShowLostModal(true)}
                className="flex items-center space-x-2 px-4 py-2 bg-red-50 border border-red-200 rounded-lg text-sm font-medium text-red-700 hover:bg-red-100"
              >
                <XCircle className="w-4 h-4" />
                <span>Lost</span>
              </button>
              <button
                onClick={() => setShowWonModal(true)}
                className="flex items-center space-x-2 px-4 py-2 bg-green-50 border border-green-200 rounded-lg text-sm font-medium text-green-700 hover:bg-green-100"
              >
                <Trophy className="w-4 h-4" />
                <span>Won</span>
              </button>
            </PermissionGate>
          )}
          <PermissionGate permission="deals.write">
            <button
              onClick={() => setShowEditDeal(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
            >
              <Edit2 className="w-4 h-4" />
              <span>Edit</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      {/* Tabs */}
      <div className="border-b border-th-border">
        <div className="flex space-x-6">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-2 px-1 py-4 text-sm font-medium border-b-2 transition-colors ${
                activeTab === tab.id
                  ? 'text-th-accent-600 border-th-accent-600'
                  : 'text-th-text-tertiary border-transparent hover:text-th-text-secondary'
              }`}
            >
              {tab.icon}
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Tab content */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main content */}
        <div className="lg:col-span-2">
          {activeTab === 'overview' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6 space-y-6">
              <h2 className="text-lg font-semibold text-th-text-primary">Deal Details</h2>

              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Amount</label>
                  <p className="text-th-text-primary font-medium">{formatCurrency(deal.amount)}</p>
                </div>
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Probability</label>
                  <p className="text-th-text-primary font-medium">{deal.probability || deal.stage?.probability || 0}%</p>
                </div>
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Expected Close</label>
                  <p className="text-th-text-primary">{formatDate(deal.expected_close_date)}</p>
                </div>
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Deal Type</label>
                  <p className="text-th-text-primary capitalize">
                    {deal.deal_type?.replace('_', ' ') || '-'}
                  </p>
                </div>
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Lead Source</label>
                  <p className="text-th-text-primary">{deal.lead_source || '-'}</p>
                </div>
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Created</label>
                  <p className="text-th-text-primary">{formatDate(deal.created_at)}</p>
                </div>
              </div>

              {deal.next_step && (
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Next Step</label>
                  <p className="text-th-text-primary">{deal.next_step}</p>
                </div>
              )}

              {deal.description && (
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Description</label>
                  <p className="text-th-text-secondary whitespace-pre-wrap">{deal.description}</p>
                </div>
              )}

              {deal.tags && deal.tags.length > 0 && (
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-2">Tags</label>
                  <div className="flex flex-wrap gap-2">
                    {deal.tags.map((tag) => (
                      <span
                        key={tag}
                        className="inline-flex items-center gap-1 px-2 py-1 bg-surface-tertiary rounded text-sm text-th-text-secondary"
                      >
                        <Tag className="w-3 h-3" />
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>
              )}

              {isLost && deal.lost_reason && (
                <div className="p-4 bg-red-50 border border-red-200 rounded-lg">
                  <label className="block text-sm font-medium text-red-700 mb-1">Lost Reason</label>
                  <p className="text-red-600">{deal.lost_reason}</p>
                </div>
              )}
            </div>
          )}

          {activeTab === 'contacts' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-lg font-semibold text-th-text-primary">Contacts</h2>
                <PermissionGate permission="deals.write">
                  <button className="flex items-center gap-1 text-sm text-th-accent-600 hover:underline">
                    <Plus className="w-4 h-4" />
                    Add Contact
                  </button>
                </PermissionGate>
              </div>

              {dealContacts.length === 0 ? (
                <p className="text-th-text-tertiary text-center py-8">No contacts linked</p>
              ) : (
                <div className="space-y-4">
                  {dealContacts.map((dc) => (
                    <div
                      key={dc.contact.id}
                      className="flex items-center justify-between p-4 bg-surface-secondary rounded-lg"
                    >
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-th-accent-100 rounded-full flex items-center justify-center">
                          <span className="text-th-accent-700 font-medium">
                            {dc.contact.first_name?.[0]}
                            {dc.contact.last_name?.[0]}
                          </span>
                        </div>
                        <div>
                          <p className="font-medium text-th-text-primary">
                            {dc.contact.first_name} {dc.contact.last_name}
                          </p>
                          <p className="text-sm text-th-text-tertiary">{dc.role || dc.contact.title}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-3">
                        {dc.contact.email && (
                          <a
                            href={`mailto:${dc.contact.email}`}
                            className="p-2 hover:bg-surface-tertiary rounded-lg text-th-text-tertiary hover:text-th-accent-600"
                          >
                            <Mail className="w-4 h-4" />
                          </a>
                        )}
                        {dc.contact.phone && (
                          <a
                            href={`tel:${dc.contact.phone}`}
                            className="p-2 hover:bg-surface-tertiary rounded-lg text-th-text-tertiary hover:text-th-accent-600"
                          >
                            <Phone className="w-4 h-4" />
                          </a>
                        )}
                        {dc.is_primary && (
                          <span className="text-xs bg-th-accent-100 text-th-accent-700 px-2 py-1 rounded">
                            Primary
                          </span>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'products' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-lg font-semibold text-th-text-primary">Products</h2>
                <PermissionGate permission="deals.write">
                  <button className="flex items-center gap-1 text-sm text-th-accent-600 hover:underline">
                    <Plus className="w-4 h-4" />
                    Add Product
                  </button>
                </PermissionGate>
              </div>

              {dealProducts.length === 0 ? (
                <p className="text-th-text-tertiary text-center py-8">No products added</p>
              ) : (
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-th-border">
                      <th className="text-left py-2 text-sm font-medium text-th-text-tertiary">
                        Product
                      </th>
                      <th className="text-right py-2 text-sm font-medium text-th-text-tertiary">
                        Qty
                      </th>
                      <th className="text-right py-2 text-sm font-medium text-th-text-tertiary">
                        Unit Price
                      </th>
                      <th className="text-right py-2 text-sm font-medium text-th-text-tertiary">
                        Total
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {dealProducts.map((dp) => (
                      <tr key={dp.id} className="border-b border-th-border">
                        <td className="py-3 text-th-text-primary">{dp.product?.name || '-'}</td>
                        <td className="py-3 text-right text-th-text-secondary">{dp.quantity}</td>
                        <td className="py-3 text-right text-th-text-secondary">
                          {formatCurrency(dp.unit_price)}
                        </td>
                        <td className="py-3 text-right font-medium text-th-text-primary">
                          {formatCurrency(dp.total)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          )}

          {activeTab === 'quotes' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-lg font-semibold text-th-text-primary">Quotes</h2>
                <PermissionGate permission="deals.write">
                  <button className="flex items-center gap-1 text-sm text-th-accent-600 hover:underline">
                    <Plus className="w-4 h-4" />
                    Create Quote
                  </button>
                </PermissionGate>
              </div>
              <p className="text-th-text-tertiary text-center py-8">No quotes yet</p>
            </div>
          )}

          {activeTab === 'activities' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <h2 className="text-lg font-semibold text-th-text-primary mb-4">Activity Timeline</h2>
              {activities.length === 0 ? (
                <p className="text-th-text-tertiary text-center py-8">No activities yet</p>
              ) : (
                <div className="activity-timeline">
                  {activities.map((activity) => (
                    <div key={activity.id} className="activity-item">
                      <p className="text-sm font-medium text-th-text-primary">{activity.title}</p>
                      {activity.description && (
                        <p className="text-sm text-th-text-tertiary mt-1">{activity.description}</p>
                      )}
                      <p className="text-xs text-th-text-tertiary mt-1">
                        {formatTimeAgo(activity.created_at)}
                      </p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'history' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <h2 className="text-lg font-semibold text-th-text-primary mb-4">Stage History</h2>
              {stageHistory.length === 0 ? (
                <p className="text-th-text-tertiary text-center py-8">No stage changes yet</p>
              ) : (
                <div className="space-y-4">
                  {stageHistory.map((entry: any) => (
                    <div
                      key={entry.id}
                      className="flex items-center gap-4 p-4 bg-surface-secondary rounded-lg"
                    >
                      <div className="w-10 h-10 bg-th-accent-100 rounded-full flex items-center justify-center">
                        <Clock className="w-5 h-5 text-th-accent-600" />
                      </div>
                      <div className="flex-1">
                        <div className="flex items-center gap-2">
                          {entry.from_stage && (
                            <>
                              <span
                                className="px-2 py-0.5 rounded-full text-xs font-medium"
                                style={{
                                  backgroundColor: `${entry.from_stage.color}20`,
                                  color: entry.from_stage.color,
                                }}
                              >
                                {entry.from_stage.display_name}
                              </span>
                              <span className="text-th-text-tertiary">to</span>
                            </>
                          )}
                          <span
                            className="px-2 py-0.5 rounded-full text-xs font-medium"
                            style={{
                              backgroundColor: `${entry.to_stage?.color}20`,
                              color: entry.to_stage?.color,
                            }}
                          >
                            {entry.to_stage?.display_name}
                          </span>
                        </div>
                        {entry.notes && (
                          <p className="text-sm text-th-text-secondary mt-1">{entry.notes}</p>
                        )}
                        <p className="text-xs text-th-text-tertiary mt-1">
                          {formatTimeAgo(entry.changed_at)}
                        </p>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-1 space-y-6">
          {/* Stage selector */}
          {!isClosed && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <h2 className="text-lg font-semibold text-th-text-primary mb-4">Stage</h2>
              <select
                value={deal.stage_id}
                onChange={(e) => handleStageChange(e.target.value)}
                className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
              >
                {dealStages.map((stage) => (
                  <option key={stage.id} value={stage.id}>
                    {stage.display_name} ({stage.probability}%)
                  </option>
                ))}
              </select>
            </div>
          )}

          {/* Account */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Account</h2>
            {deal.account ? (
              <Link
                to={`/accounts/${deal.account.id}`}
                className="flex items-center gap-3 p-3 bg-surface-secondary rounded-lg hover:bg-surface-tertiary"
              >
                <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
                  <Building2 className="w-5 h-5 text-blue-600" />
                </div>
                <span className="font-medium text-th-text-primary">{deal.account.name}</span>
              </Link>
            ) : (
              <p className="text-th-text-tertiary">No account linked</p>
            )}
          </div>

          {/* Primary Contact */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Primary Contact</h2>
            {deal.contact ? (
              <Link
                to={`/contacts/${deal.contact.id}`}
                className="flex items-center gap-3 p-3 bg-surface-secondary rounded-lg hover:bg-surface-tertiary"
              >
                <div className="w-10 h-10 bg-th-accent-100 rounded-full flex items-center justify-center">
                  <span className="text-th-accent-700 font-medium">
                    {deal.contact.first_name?.[0]}
                    {deal.contact.last_name?.[0]}
                  </span>
                </div>
                <div>
                  <p className="font-medium text-th-text-primary">
                    {deal.contact.first_name} {deal.contact.last_name}
                  </p>
                  <p className="text-sm text-th-text-tertiary">{deal.contact.email}</p>
                </div>
              </Link>
            ) : (
              <p className="text-th-text-tertiary">No contact linked</p>
            )}
          </div>

          {/* Owner */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Owner</h2>
            {deal.owner_id ? (
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-th-accent-100 rounded-full flex items-center justify-center">
                  <User className="w-5 h-5 text-th-accent-700" />
                </div>
                <span className="text-th-text-secondary">Assigned</span>
              </div>
            ) : (
              <p className="text-th-text-tertiary">Unassigned</p>
            )}
          </div>

          {/* Key Dates */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Key Dates</h2>
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                <Calendar className="w-4 h-4 text-th-text-tertiary" />
                <div>
                  <p className="text-sm text-th-text-tertiary">Expected Close</p>
                  <p className="text-th-text-primary">{formatDate(deal.expected_close_date)}</p>
                </div>
              </div>
              {deal.actual_close_date && (
                <div className="flex items-center gap-3">
                  <Calendar className="w-4 h-4 text-th-text-tertiary" />
                  <div>
                    <p className="text-sm text-th-text-tertiary">Actual Close</p>
                    <p className="text-th-text-primary">{formatDate(deal.actual_close_date)}</p>
                  </div>
                </div>
              )}
              <div className="flex items-center gap-3">
                <Clock className="w-4 h-4 text-th-text-tertiary" />
                <div>
                  <p className="text-sm text-th-text-tertiary">Created</p>
                  <p className="text-th-text-primary">{formatDate(deal.created_at)}</p>
                </div>
              </div>
