            >
              {saving ? 'Saving...' : 'Confirm Lost'}
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { RefreshCw, Plus, DollarSign } from 'lucide-react';
import toast from 'react-hot-toast';
import {
  DndContext,
  DragOverlay,
  closestCorners,
  PointerSensor,
  useSensor,
  useSensors,
  type DragStartEvent,
  type DragEndEvent,
} from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy, useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import { PermissionGate } from '../components/PermissionGate';
import { AddDealModal } from '../components/AddDealModal';
import { DealCard } from '../components/DealCard';
import { logAuditEvent, AUDIT_ACTIONS } from '@mpbhealth/auth';
import type { DealWithRelations, DealStage } from '@mpbhealth/crm-core';

interface SortableDealCardProps {
  deal: DealWithRelations;
}

function SortableDealCard({ deal }: SortableDealCardProps) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: deal.id,
    data: { type: 'deal', deal },
  });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
  };

  return (
    <div ref={setNodeRef} style={style} {...attributes} {...listeners}>
      <DealCard deal={deal} isDragging={isDragging} />
    </div>
  );
}

export default function DealPipeline() {
  const navigate = useNavigate();
  const { dealService, dealStages, refreshDashboard } = useCRM();
  const { activeOrgId } = useOrg();

  const [dealsByStage, setDealsByStage] = useState<Record<string, DealWithRelations[]>>({});
  const [loading, setLoading] = useState(true);
  const [activeDeal, setActiveDeal] = useState<DealWithRelations | null>(null);
  const [showAddDeal, setShowAddDeal] = useState(false);
  const [addDealStageId, setAddDealStageId] = useState<string | undefined>();

  // Stage totals
  const [stageTotals, setStageTotals] = useState<Record<string, { count: number; value: number }>>({});

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 8,
      },
    })
  );

  const loadDeals = async () => {
    setLoading(true);
    const grouped = await dealService.getDealsByStage();
    setDealsByStage(grouped);

    // Calculate totals
    const totals: Record<string, { count: number; value: number }> = {};
    for (const [stageName, deals] of Object.entries(grouped)) {
      totals[stageName] = {
        count: deals.length,
        value: deals.reduce((sum, d) => sum + (d.amount || 0), 0),
      };
    }
    setStageTotals(totals);

    setLoading(false);
  };

  useEffect(() => {
    loadDeals();
  }, []);

  const handleDragStart = (event: DragStartEvent) => {
    const deal = event.active.data.current?.deal as DealWithRelations;
    setActiveDeal(deal);
  };

  const handleDragEnd = async (event: DragEndEvent) => {
    const { active, over } = event;
    setActiveDeal(null);

    if (!over) return;

    const activeDeal = active.data.current?.deal as DealWithRelations;
    if (!activeDeal) return;

    // Get the target stage from the droppable ID (column id is the stage name)
    const targetStageName = over.id as string;
    const targetStage = dealStages.find((s) => s.name === targetStageName);

    if (!targetStage) return;

    // Check if we're dropping on a different stage
    const currentStageName = activeDeal.stage?.name;
    if (currentStageName === targetStageName) return;

    const originalStage = activeDeal.stage;

    // Optimistic update
    setDealsByStage((prev) => {
      const newDealsByStage = { ...prev };

      // Remove from original stage
      if (currentStageName && newDealsByStage[currentStageName]) {
        newDealsByStage[currentStageName] = newDealsByStage[currentStageName].filter(
          (d) => d.id !== activeDeal.id
        );
      }

      // Add to target stage
      if (!newDealsByStage[targetStageName]) {
        newDealsByStage[targetStageName] = [];
      }
      newDealsByStage[targetStageName] = [
        { ...activeDeal, stage_id: targetStage.id, stage: targetStage },
        ...newDealsByStage[targetStageName],
      ];

      return newDealsByStage;
    });

    // Update totals
    setStageTotals((prev) => {
      const newTotals = { ...prev };
      const amount = activeDeal.amount || 0;

      if (currentStageName && newTotals[currentStageName]) {
        newTotals[currentStageName] = {
          count: newTotals[currentStageName].count - 1,
          value: newTotals[currentStageName].value - amount,
        };
      }

      if (!newTotals[targetStageName]) {
        newTotals[targetStageName] = { count: 0, value: 0 };
      }
      newTotals[targetStageName] = {
        count: newTotals[targetStageName].count + 1,
        value: newTotals[targetStageName].value + amount,
      };

      return newTotals;
    });

    // Update in database
    const result = await dealService.updateDealStage(activeDeal.id, targetStage.id);

    if (result.success) {
      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.DEAL_STAGE_CHANGED || 'deal.stage_changed',
        entityType: 'deal',
        entityId: activeDeal.id,
        before: { stage: originalStage?.display_name },
        after: { stage: targetStage.display_name },
      }).catch(console.error);
      toast.success(`Moved to ${targetStage.display_name}`);
      refreshDashboard();
    } else {
      // Revert on failure
      loadDeals();
      toast.error('Failed to update stage');
    }
  };

  const handleAddDealToStage = (stageId: string) => {
    setAddDealStageId(stageId);
    setShowAddDeal(true);
  };

  const formatCurrency = (amount: number) => {
    if (amount >= 1000000) {
      return `$${(amount / 1000000).toFixed(1)}M`;
    }
    if (amount >= 1000) {
      return `$${(amount / 1000).toFixed(0)}K`;
    }
    return `$${amount}`;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Deal Pipeline</h1>
          <p className="text-th-text-tertiary text-sm mt-1">
            Drag and drop deals between stages
          </p>
        </div>
        <div className="flex items-center space-x-3">
          <button
            onClick={loadDeals}
            className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
          >
            <RefreshCw className="w-4 h-4" />
            <span>Refresh</span>
          </button>
          <PermissionGate permission="deals.write">
            <button
              onClick={() => setShowAddDeal(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700"
            >
              <Plus className="w-4 h-4" />
              <span>New Deal</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      {/* Pipeline board */}
      <DndContext
        sensors={sensors}
        collisionDetection={closestCorners}
        onDragStart={handleDragStart}
        onDragEnd={handleDragEnd}
      >
        <div className="flex space-x-4 overflow-x-auto pb-4">
          {dealStages
            .filter((stage) => !stage.is_won_stage && !stage.is_lost_stage)
            .map((stage) => {
              const stageDeals = dealsByStage[stage.name] || [];
              const totals = stageTotals[stage.name] || { count: 0, value: 0 };

              return (
                <div
                  key={stage.id}
                  id={stage.name}
                  className="flex-shrink-0 w-80 bg-surface-secondary rounded-xl p-4"
                >
                  {/* Stage header */}
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center space-x-2">
                      <div
                        className="w-3 h-3 rounded-full"
                        style={{ backgroundColor: stage.color }}
                      />
                      <h3 className="font-semibold text-th-text-primary">{stage.display_name}</h3>
                    </div>
                    <PermissionGate permission="deals.write">
                      <button
                        onClick={() => handleAddDealToStage(stage.id)}
                        className="p-1 text-th-text-tertiary hover:text-th-accent-600 hover:bg-surface-primary rounded"
                      >
                        <Plus className="w-4 h-4" />
                      </button>
                    </PermissionGate>
                  </div>

                  {/* Stage totals */}
                  <div className="flex items-center justify-between mb-4 pb-3 border-b border-th-border">
                    <span className="text-sm text-th-text-tertiary">{totals.count} deals</span>
                    <div className="flex items-center gap-1 text-sm font-medium text-th-text-primary">
                      <DollarSign className="w-3 h-3" />
                      {formatCurrency(totals.value)}
                    </div>
                  </div>

                  {/* Droppable area */}
                  <SortableContext
                    id={stage.name}
                    items={stageDeals.map((d) => d.id)}
                    strategy={verticalListSortingStrategy}
                  >
                    <div className="space-y-3 min-h-[200px]">
                      {stageDeals.map((deal) => (
                        <SortableDealCard key={deal.id} deal={deal} />
                      ))}
                      {stageDeals.length === 0 && (
                        <div className="text-center py-8 text-th-text-tertiary text-sm border-2 border-dashed border-th-border rounded-lg">
                          Drop deals here
                        </div>
                      )}
                    </div>
                  </SortableContext>
                </div>
              );
            })}
        </div>

        {/* Drag overlay */}
        <DragOverlay>
          {activeDeal && <DealCard deal={activeDeal} isDragging />}
        </DragOverlay>
      </DndContext>

      {/* Add Deal Modal */}
      <AddDealModal
        open={showAddDeal}
        onClose={() => {
          setShowAddDeal(false);
          setAddDealStageId(undefined);
        }}
        onSuccess={() => loadDeals()}
        defaultStageId={addDealStageId}
      />
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import {
  Search,
  Filter,
  Download,
  Plus,
  ChevronDown,
  FileText,
  Upload,
  Folder,
  Image,
  Table,
  File,
  Trash2,
  ExternalLink,
} from 'lucide-react';
import toast from 'react-hot-toast';
import {
  createDocumentService,
  formatTimeAgo,
  type DocumentWithRelations,
  type DocumentFilters,
  type DocumentCategory,
} from '@mpbhealth/crm-core';
import { supabase } from '../lib/supabase';

// Category options
const CATEGORY_OPTIONS: { value: string; label: string }[] = [
  { value: '', label: 'All Categories' },
  { value: 'general', label: 'General' },
  { value: 'contract', label: 'Contract' },
  { value: 'proposal', label: 'Proposal' },
  { value: 'invoice', label: 'Invoice' },
  { value: 'report', label: 'Report' },
  { value: 'other', label: 'Other' },
];

// Category badge colors
function getCategoryColors(category: DocumentCategory) {
  switch (category) {
    case 'contract':
      return { bg: 'bg-blue-100', text: 'text-blue-700' };
    case 'proposal':
      return { bg: 'bg-purple-100', text: 'text-purple-700' };
    case 'invoice':
      return { bg: 'bg-green-100', text: 'text-green-700' };
    case 'report':
      return { bg: 'bg-cyan-100', text: 'text-cyan-700' };
    case 'general':
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
    case 'other':
    default:
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
  }
}

// MIME type icon mapping
function getMimeIcon(mimeType: string) {
  if (mimeType === 'application/pdf') {
    return { Icon: FileText, color: 'text-red-600', bg: 'bg-red-100' };
  }
  if (mimeType.startsWith('image/')) {
    return { Icon: Image, color: 'text-blue-600', bg: 'bg-blue-100' };
  }
  if (
    mimeType.includes('spreadsheet') ||
    mimeType.includes('excel') ||
    mimeType === 'text/csv'
  ) {
    return { Icon: Table, color: 'text-green-600', bg: 'bg-green-100' };
  }
  if (
    mimeType.includes('document') ||
    mimeType.includes('word') ||
    mimeType.includes('text/')
  ) {
    return { Icon: FileText, color: 'text-blue-600', bg: 'bg-blue-100' };
  }
  return { Icon: File, color: 'text-gray-600', bg: 'bg-gray-100' };
}

// Format file size
function formatFileSize(bytes: number): string {
  if (bytes === 0) return '0 B';
  const units = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(1024));
  const size = bytes / Math.pow(1024, i);
  return `${size.toFixed(i === 0 ? 0 : 1)} ${units[i]}`;
}

export default function Documents() {
  // Initialize document service
  const [documentService] = useState(() => createDocumentService(supabase));

  const [documents, setDocuments] = useState<DocumentWithRelations[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<DocumentFilters>({});
  const [page, setPage] = useState(0);
  const pageSize = 20;

  // Bulk selection state
  const [selectedDocs, setSelectedDocs] = useState<Set<string>>(new Set());

  // Load documents
  const loadDocuments = useCallback(async () => {
    setLoading(true);
    try {
      const { documents: data, total: count } = await documentService.getDocuments(
        filters,
        pageSize,
        page * pageSize
      );
      setDocuments(data);
      setTotal(count);
    } catch (error) {
      console.error('Failed to load documents:', error);
      toast.error('Failed to load documents');
    } finally {
      setLoading(false);
    }
  }, [documentService, filters, page]);

  useEffect(() => {
    loadDocuments();
  }, [loadDocuments]);

  // Clear selection when filters or page change
  useEffect(() => {
    setSelectedDocs(new Set());
  }, [filters, page]);

  const handleSearch = (search: string) => {
    setFilters((prev) => ({ ...prev, search }));
    setPage(0);
  };

  const handleCategoryFilter = (category: string) => {
    setFilters((prev) => ({
      ...prev,
      category: (category || undefined) as DocumentCategory | undefined,
    }));
    setPage(0);
  };

  const handleDownload = async (doc: DocumentWithRelations, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    try {
      const { data, error } = await supabase.storage
        .from('crm-documents')
        .createSignedUrl(doc.file_path, 60);

      if (error) {
        toast.error('Failed to generate download link');
        return;
      }

      const a = document.createElement('a');
      a.href = data.signedUrl;
      a.download = doc.file_name;
      a.target = '_blank';
      a.click();
    } catch {
      toast.error('Failed to download file');
    }
  };

  const handleOpenFile = async (doc: DocumentWithRelations) => {
    try {
      const { data, error } = await supabase.storage
        .from('crm-documents')
        .createSignedUrl(doc.file_path, 300);

      if (error) {
        toast.error('Failed to generate file link');
        return;
      }

      window.open(data.signedUrl, '_blank');
    } catch {
      toast.error('Failed to open file');
    }
  };

  const handleDelete = async (docId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to delete this document?')) return;

    const result = await documentService.deleteDocument(docId);
    if (result.success) {
      toast.success('Document deleted');
      loadDocuments();
    } else {
      toast.error(result.error || 'Failed to delete document');
    }
  };

  const handleExport = () => {
    const csv = generateDocumentCSV(documents);
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `documents-export-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success('Export started');
  };

  const handleExportSelected = () => {
    const selected = documents.filter((d) => selectedDocs.has(d.id));
    const csv = generateDocumentCSV(selected);
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `documents-selected-export-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success('Export started');
  };

  function generateDocumentCSV(data: DocumentWithRelations[]) {
    const headers = ['Name', 'File Name', 'Category', 'Size', 'MIME Type', 'Folder', 'Uploaded By', 'Created'];
    const rows = data.map((doc) => [
      doc.name,
      doc.file_name,
      doc.category,
      formatFileSize(doc.file_size),
      doc.mime_type,
      doc.folder || '',
      doc.uploader?.full_name || doc.uploader?.email || '',
      new Date(doc.created_at).toLocaleDateString(),
    ]);
    return [headers.join(','), ...rows.map((row) => row.map((cell) => `"${cell}"`).join(','))].join('\n');
  }

  const toggleSelectAll = useCallback(() => {
    if (selectedDocs.size === documents.length) {
      setSelectedDocs(new Set());
    } else {
      setSelectedDocs(new Set(documents.map((d) => d.id)));
    }
  }, [documents, selectedDocs.size]);

  const toggleSelectDoc = useCallback((docId: string) => {
    setSelectedDocs((prev) => {
      const next = new Set(prev);
      if (next.has(docId)) {
        next.delete(docId);
      } else {
        next.add(docId);
      }
      return next;
    });
  }, []);

  const totalPages = Math.ceil(total / pageSize);

  return (
    <div className="space-y-6">
      {/* Bulk Actions Toolbar */}
      {selectedDocs.size > 0 && (
        <div className="bg-th-accent-50 border border-th-accent-200 rounded-lg px-4 py-3 flex items-center justify-between">
          <span className="text-sm font-medium text-th-accent-700">
            {selectedDocs.size} document{selectedDocs.size > 1 ? 's' : ''} selected
          </span>
          <div className="flex items-center space-x-3">
            <button
              onClick={handleExportSelected}
              className="text-sm text-th-accent-600 hover:text-th-accent-700 font-medium"
            >
              Export Selected
            </button>
            <button
              onClick={() => setSelectedDocs(new Set())}
              className="text-sm text-th-text-tertiary hover:text-th-text-secondary"
            >
              Clear
            </button>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Documents</h1>
          <p className="text-th-text-tertiary text-sm mt-1">{total} total documents</p>
        </div>
        <div className="flex items-center space-x-3">
          <button
            onClick={handleExport}
            className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
          >
            <Download className="w-4 h-4" />
            <span>Export</span>
          </button>
          <button
            disabled
            title="Upload coming soon"
            className="flex items-center space-x-2 px-4 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700 disabled:opacity-60 disabled:cursor-not-allowed"
          >
            <Upload className="w-4 h-4" />
            <span>Upload</span>
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-surface-primary rounded-xl border border-th-border p-4">
        <div className="flex items-center space-x-4">
          {/* Search */}
          <div className="flex-1 flex items-center bg-surface-tertiary rounded-lg px-3 py-2">
            <Search className="w-4 h-4 text-th-text-tertiary mr-2" />
            <input
              type="text"
              placeholder="Search by name, file name, or description..."
              value={filters.search || ''}
              onChange={(e) => handleSearch(e.target.value)}
              className="bg-transparent border-none outline-none text-sm w-full text-th-text-secondary placeholder-th-text-tertiary"
            />
          </div>

          {/* Category filter */}
          <div className="relative">
            <select
              value={filters.category || ''}
              onChange={(e) => handleCategoryFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              {CATEGORY_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>
        </div>
      </div>

      {/* Documents table */}
      <div className="bg-surface-primary rounded-xl border border-th-border overflow-hidden">
        {loading ? (
          <div className="flex items-center justify-center h-64">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
          </div>
        ) : documents.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-th-text-tertiary">
            <FileText className="w-12 h-12 mb-4 opacity-50" />
            <p>No documents found</p>
            <p className="text-sm mt-1">Try adjusting your filters or upload a new document</p>
          </div>
        ) : (
          <>
            <table className="w-full">
              <thead>
                <tr className="bg-surface-secondary border-b border-th-border">
                  <th className="w-12 px-4 py-3">
                    <input
                      type="checkbox"
                      checked={selectedDocs.size === documents.length && documents.length > 0}
                      onChange={toggleSelectAll}
                      className="w-4 h-4 rounded border-th-border"
                    />
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Name
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Category
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Size
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Uploaded By
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Created
                  </th>
                  <th className="w-24 px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider text-right">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-th-border">
                {documents.map((doc) => {
                  const categoryColors = getCategoryColors(doc.category);
                  const mimeInfo = getMimeIcon(doc.mime_type);
                  const isSelected = selectedDocs.has(doc.id);

                  return (
                    <tr
                      key={doc.id}
                      className={`hover:bg-surface-secondary cursor-pointer ${
                        isSelected ? 'bg-th-accent-50' : ''
                      }`}
                      onClick={() => handleOpenFile(doc)}
                    >
                      <td
                        className="w-12 px-4 py-4"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <input
                          type="checkbox"
                          checked={isSelected}
                          onChange={() => toggleSelectDoc(doc.id)}
                          className="w-4 h-4 rounded border-th-border"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className={`w-10 h-10 ${mimeInfo.bg} rounded-lg flex items-center justify-center`}>
                            <mimeInfo.Icon className={`w-5 h-5 ${mimeInfo.color}`} />
                          </div>
                          <div>
                            <p className="text-sm font-medium text-th-text-primary hover:text-th-accent-600">
                              {doc.name}
                            </p>
                            <p className="text-xs text-th-text-tertiary">
                              {doc.file_name}
                            </p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${categoryColors.bg} ${categoryColors.text}`}
                        >
                          {doc.category.charAt(0).toUpperCase() + doc.category.slice(1)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {formatFileSize(doc.file_size)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {doc.uploader?.full_name || doc.uploader?.email || '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-sm text-th-text-tertiary">
                        {formatTimeAgo(doc.created_at)}
                      </td>
                      <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                        <div className="flex items-center justify-end space-x-2">
                          <button
                            onClick={(e) => handleDownload(doc, e)}
                            title="Download"
                            className="p-1.5 rounded-lg text-th-text-tertiary hover:text-th-accent-600 hover:bg-surface-secondary"
                          >
                            <Download className="w-4 h-4" />
                          </button>
                          <button
                            onClick={(e) => handleDelete(doc.id, e)}
                            title="Delete"
                            className="p-1.5 rounded-lg text-th-text-tertiary hover:text-red-600 hover:bg-red-50"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex items-center justify-between px-6 py-4 border-t border-th-border">
                <p className="text-sm text-th-text-tertiary">
                  Showing {page * pageSize + 1} to {Math.min((page + 1) * pageSize, total)} of {total}
                </p>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page === 0}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Previous
                  </button>
                  <button
                    onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                    disabled={page >= totalPages - 1}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Next
                  </button>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

// ============================================================================
// Domain Add-ons - SPF/DKIM/DMARC verification wizard
// Custom sender domain management with DNS verification
// ============================================================================

import { useState, useEffect, useCallback } from 'react';
import {
  Globe, Plus, Shield, ShieldCheck, ShieldAlert, ShieldX,
  RefreshCw, Trash2, Copy, CheckCircle2, XCircle, Clock,
  AlertTriangle, ChevronDown, ChevronRight, Mail,
} from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import type { MailDomain, DomainHealthResult, RequiredDnsRecords } from '@mpbhealth/crm-core';
import toast from 'react-hot-toast';

const STATUS_CONFIG: Record<string, { icon: typeof CheckCircle2; color: string; bgColor: string; label: string }> = {
  verified: { icon: CheckCircle2, color: 'text-green-600', bgColor: 'bg-green-50', label: 'Verified' },
  pending: { icon: Clock, color: 'text-yellow-600', bgColor: 'bg-yellow-50', label: 'Pending' },
  failed: { icon: XCircle, color: 'text-red-600', bgColor: 'bg-red-50', label: 'Failed' },
  expired: { icon: AlertTriangle, color: 'text-orange-600', bgColor: 'bg-orange-50', label: 'Expired' },
};

function StatusBadge({ status }: { status: string }) {
  const config = STATUS_CONFIG[status] || STATUS_CONFIG.pending;
  const Icon = config.icon;
  return (
    <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${config.color} ${config.bgColor}`}>
      <Icon className="w-3 h-3" />
      {config.label}
    </span>
  );
}

export default function DomainAddons() {
  const { domainService } = useCRM();
  const { activeOrgId } = useOrg();

  const [domains, setDomains] = useState<MailDomain[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newDomain, setNewDomain] = useState('');
  const [adding, setAdding] = useState(false);
  const [addResult, setAddResult] = useState<{ domain: MailDomain; required_records: RequiredDnsRecords } | null>(null);
  const [verifying, setVerifying] = useState<string | null>(null);
  const [healthData, setHealthData] = useState<Record<string, DomainHealthResult>>({});
  const [expandedDomain, setExpandedDomain] = useState<string | null>(null);

  const loadDomains = useCallback(async () => {
    if (!activeOrgId) return;
    try {
      const data = await domainService.getDomains(activeOrgId);
      setDomains(data);
    } catch (err) {
      console.error('Failed to load domains:', err);
    } finally {
      setLoading(false);
    }
  }, [domainService, activeOrgId]);

  useEffect(() => { loadDomains(); }, [loadDomains]);

  const handleAddDomain = async () => {
    if (!activeOrgId || !newDomain.trim()) return;
    setAdding(true);
    try {
      const result = await domainService.addDomain(activeOrgId, newDomain.trim().toLowerCase());
      setAddResult(result);
      toast.success('Domain added - configure DNS records below');
      await loadDomains();
    } catch (err: any) {
      toast.error(err.message || 'Failed to add domain');
    } finally {
      setAdding(false);
    }
  };

  const handleVerify = async (domainId: string) => {
    setVerifying(domainId);
    try {
      const result = await domainService.verifyDomain(domainId);
      toast.success('Verification complete');
      await loadDomains();
    } catch {
      toast.error('Verification failed');
    } finally {
      setVerifying(null);
    }
  };

  const handleCheckHealth = async (domainId: string) => {
    try {
      const health = await domainService.getDomainHealth(domainId);
      setHealthData(prev => ({ ...prev, [domainId]: health }));
    } catch {
      toast.error('Health check failed');
    }
  };

  const handleDelete = async (domain: MailDomain) => {
    if (!confirm(`Remove domain "${domain.domain}"? This cannot be undone.`)) return;
    try {
      await domainService.deleteDomain(domain.id);
      toast.success('Domain removed');
      await loadDomains();
    } catch {
      toast.error('Failed to remove domain');
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    toast.success('Copied to clipboard');
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Domain Add-ons</h1>
          <p className="text-sm text-th-text-secondary mt-1">
            Verify your sender domains for optimal email deliverability
          </p>
        </div>
        <button
          onClick={() => { setShowAddModal(true); setAddResult(null); setNewDomain(''); }}
          className="flex items-center gap-2 px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700 transition-colors"
        >
          <Plus className="w-4 h-4" />
          Add Domain
        </button>
      </div>

      {/* Domains List */}
      {domains.length === 0 ? (
        <div className="bg-white rounded-xl border border-neutral-200 p-12 text-center">
          <Globe className="w-12 h-12 text-th-text-tertiary mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-th-text-primary mb-2">No domains configured</h3>
          <p className="text-sm text-th-text-secondary mb-6 max-w-sm mx-auto">
            Add your sender domains and verify SPF, DKIM, and DMARC records to improve deliverability
          </p>
          <button
            onClick={() => setShowAddModal(true)}
            className="px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700"
          >
            Add Your First Domain
          </button>
        </div>
      ) : (
        <div className="space-y-4">
          {domains.map(domain => {
            const isExpanded = expandedDomain === domain.id;
            const health = healthData[domain.id];

            return (
              <div key={domain.id} className="bg-white rounded-xl border border-neutral-200 overflow-hidden">
                {/* Domain Header */}
                <div
                  className="p-5 cursor-pointer hover:bg-neutral-50/50 transition-colors"
                  onClick={() => setExpandedDomain(isExpanded ? null : domain.id)}
                >
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                        domain.is_verified ? 'bg-green-50' : 'bg-yellow-50'
                      }`}>
                        {domain.is_verified ? (
                          <ShieldCheck className="w-5 h-5 text-green-600" />
                        ) : (
                          <ShieldAlert className="w-5 h-5 text-yellow-600" />
                        )}
                      </div>
                      <div>
                        <div className="flex items-center gap-2">
                          <span className="font-semibold text-th-text-primary">{domain.domain}</span>
                          {domain.is_verified ? (
                            <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full">Verified</span>
                          ) : (
                            <span className="text-xs bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded-full">Pending</span>
                          )}
                        </div>
                        <div className="flex items-center gap-3 mt-1">
                          <div className="flex items-center gap-1">
                            <span className="text-xs text-th-text-tertiary">SPF:</span>
                            <StatusBadge status={domain.spf_status} />
                          </div>
                          <div className="flex items-center gap-1">
                            <span className="text-xs text-th-text-tertiary">DKIM:</span>
                            <StatusBadge status={domain.dkim_status} />
                          </div>
                          <div className="flex items-center gap-1">
                            <span className="text-xs text-th-text-tertiary">DMARC:</span>
                            <StatusBadge status={domain.dmarc_status} />
                          </div>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center gap-2">
                      <button
                        onClick={e => { e.stopPropagation(); handleVerify(domain.id); }}
                        disabled={verifying === domain.id}
                        className="flex items-center gap-1 px-3 py-1.5 text-xs font-medium text-th-accent-600 hover:bg-th-accent-50 rounded-lg transition-colors"
                      >
                        <RefreshCw className={`w-3.5 h-3.5 ${verifying === domain.id ? 'animate-spin' : ''}`} />
                        Verify
                      </button>
                      <button
                        onClick={e => { e.stopPropagation(); handleCheckHealth(domain.id); }}
                        className="flex items-center gap-1 px-3 py-1.5 text-xs font-medium text-th-text-tertiary hover:bg-neutral-50 rounded-lg"
                      >
                        <Shield className="w-3.5 h-3.5" />
                        Health
                      </button>
                      <button
                        onClick={e => { e.stopPropagation(); handleDelete(domain); }}
                        className="p-1.5 text-th-text-tertiary hover:text-red-500 rounded-lg"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                      {isExpanded ? (
                        <ChevronDown className="w-4 h-4 text-neutral-400" />
                      ) : (
                        <ChevronRight className="w-4 h-4 text-neutral-400" />
                      )}
                    </div>
                  </div>
                </div>

                {/* Expanded Details */}
                {isExpanded && (
                  <div className="border-t border-neutral-100 p-5 bg-neutral-50/50 space-y-4">
                    {/* Health Score */}
                    {health && (
                      <div className="bg-white rounded-lg border border-neutral-200 p-4">
                        <div className="flex items-center justify-between mb-3">
                          <h4 className="font-medium text-th-text-primary">Domain Health</h4>
                          <div className={`text-2xl font-bold ${
                            health.health_score >= 80 ? 'text-green-600' :
                            health.health_score >= 50 ? 'text-yellow-600' :
                            'text-red-600'
                          }`}>
                            {health.health_score}/100
                          </div>
                        </div>
                        {health.issues.length > 0 && (
                          <div className="space-y-1">
                            {health.issues.map((issue, i) => (
                              <div key={i} className="flex items-center gap-2 text-xs text-red-600">
                                <AlertTriangle className="w-3 h-3 flex-shrink-0" />
                                {issue}
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                    )}

                    {/* DNS Records */}
                    <div>
                      <h4 className="font-medium text-th-text-primary mb-3">Required DNS Records</h4>
                      <div className="space-y-3">
                        {/* SPF */}
                        <DnsRecordRow
                          label="SPF"
                          type="TXT"
                          host={domain.domain}
                          value={domain.spf_record || 'v=spf1 include:_spf.google.com ~all'}
                          status={domain.spf_status}
                          onCopy={copyToClipboard}
                        />
                        {/* DKIM */}
                        <DnsRecordRow
                          label="DKIM"
                          type="TXT"
                          host={`${domain.dkim_selector || 'mpbcrm'}._domainkey.${domain.domain}`}
                          value={domain.dkim_record || 'v=DKIM1; k=rsa; p=<your-public-key>'}
                          status={domain.dkim_status}
                          onCopy={copyToClipboard}
                        />
                        {/* DMARC */}
                        <DnsRecordRow
                          label="DMARC"
                          type="TXT"
                          host={`_dmarc.${domain.domain}`}
                          value={domain.dmarc_record || `v=DMARC1; p=quarantine; rua=mailto:dmarc@${domain.domain}`}
                          status={domain.dmarc_status}
                          onCopy={copyToClipboard}
                        />
                        {/* Verification */}
                        <DnsRecordRow
                          label="Verify"
                          type="TXT"
                          host={domain.domain}
                          value={`mpb-verify=${domain.verification_token}`}
                          status={domain.spf_status === 'verified' ? 'verified' : 'pending'}
                          onCopy={copyToClipboard}
                        />
                      </div>
                    </div>

                    {/* Compliance Footer */}
                    <div>
                      <h4 className="font-medium text-th-text-primary mb-2">Compliance Footer</h4>
                      <p className="text-xs text-th-text-tertiary mb-2">
                        Auto-injected at the bottom of every email sent from this domain
                      </p>
                      <textarea
                        defaultValue={domain.compliance_footer || ''}
                        onBlur={e => {
                          domainService.updateComplianceFooter(domain.id, e.target.value);
                          toast.success('Footer saved');
                        }}
                        placeholder="e.g., This message may contain PHI. If you received this in error..."
                        rows={3}
                        className="w-full px-3 py-2 border border-neutral-200 rounded-lg text-sm"
                      />
                    </div>

                    {/* Last check */}
                    {domain.last_check_at && (
                      <p className="text-xs text-th-text-tertiary">
                        Last checked: {new Date(domain.last_check_at).toLocaleString()}
                      </p>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Add Domain Modal */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" onClick={() => setShowAddModal(false)}>
          <div className="bg-white rounded-xl shadow-xl max-w-lg w-full mx-4 p-6" onClick={e => e.stopPropagation()}>
            {!addResult ? (
              <>
                <h2 className="text-lg font-semibold text-th-text-primary mb-1">Add Sender Domain</h2>
                <p className="text-sm text-th-text-secondary mb-4">
                  Enter the domain you want to send emails from
                </p>
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={newDomain}
                    onChange={e => setNewDomain(e.target.value)}
                    placeholder="e.g., mpb.health"
                    className="flex-1 px-3 py-2 border border-neutral-200 rounded-lg text-sm"
                    onKeyDown={e => e.key === 'Enter' && handleAddDomain()}
                  />
                  <button
                    onClick={handleAddDomain}
                    disabled={adding || !newDomain.trim()}
                    className="px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700 disabled:opacity-50 text-sm"
                  >
                    {adding ? 'Adding...' : 'Add'}
                  </button>
                </div>
              </>
            ) : (
              <>
                <h2 className="text-lg font-semibold text-th-text-primary mb-1">Configure DNS Records</h2>
                <p className="text-sm text-th-text-secondary mb-4">
                  Add these DNS records to your domain registrar, then click Verify
                </p>
                <div className="space-y-3 mb-4">
                  {Object.entries(addResult.required_records).map(([key, record]) => (
                    <div key={key} className="bg-neutral-50 rounded-lg p-3">
                      <div className="flex items-center justify-between mb-1">
                        <span className="text-xs font-medium text-th-text-primary uppercase">{key}</span>
                        <span className="text-xs text-th-text-tertiary">{record.type}</span>
                      </div>
                      <div className="text-xs text-th-text-secondary mb-1">
                        Host: <code className="bg-neutral-200 px-1 rounded">{record.host}</code>
                      </div>
                      <div className="flex items-center gap-2">
                        <code className="text-xs bg-neutral-200 px-2 py-1 rounded flex-1 break-all">
                          {record.value}
                        </code>
                        <button
                          onClick={() => copyToClipboard(record.value)}
                          className="p-1 text-th-text-tertiary hover:text-th-accent-600"
                        >
                          <Copy className="w-3.5 h-3.5" />
                        </button>
                      </div>
                      <p className="text-xs text-th-text-tertiary mt-1">{record.description}</p>
                    </div>
                  ))}
                </div>
                <button
                  onClick={() => { setShowAddModal(false); setExpandedDomain(addResult.domain.id); }}
                  className="w-full px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700 text-sm"
                >
                  Done - I'll verify after DNS propagates
                </button>
              </>
            )}

            <button
              onClick={() => setShowAddModal(false)}
              className="w-full mt-2 px-4 py-2 text-sm text-th-text-secondary hover:text-th-text-primary"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ============================================================================
// DNS Record Row Component
// ============================================================================

function DnsRecordRow({
  label, type, host, value, status, onCopy,
}: {
  label: string;
  type: string;
  host: string;
  value: string;
  status: string;
  onCopy: (text: string) => void;
}) {
  return (
    <div className="bg-white rounded-lg border border-neutral-200 p-3">
      <div className="flex items-center justify-between mb-1">
        <div className="flex items-center gap-2">
          <span className="text-xs font-semibold text-th-text-primary">{label}</span>
          <span className="text-xs bg-neutral-100 text-neutral-500 px-1.5 py-0.5 rounded">{type}</span>
        </div>
        <StatusBadge status={status} />
      </div>
      <div className="text-xs text-th-text-tertiary mb-1">
        Host: <code className="bg-neutral-100 px-1 rounded">{host}</code>
      </div>
      <div className="flex items-center gap-2">
        <code className="text-xs bg-neutral-100 px-2 py-1 rounded flex-1 break-all text-th-text-secondary">
          {value}
        </code>
        <button
          onClick={() => onCopy(value)}
          className="p-1 text-th-text-tertiary hover:text-th-accent-600 flex-shrink-0"
        >
          <Copy className="w-3.5 h-3.5" />
        </button>
      </div>
    </div>
  );
}

