export default function EmailSignatures() {
  const { signatureService } = useCRM();
  const { activeOrgId } = useOrg();

  // State
  const [signatures, setSignatures] = useState<EmailSignature[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // Modal state
  const [showEditor, setShowEditor] = useState(false);
  const [editingSignature, setEditingSignature] = useState<EmailSignature | null>(null);
  const [form, setForm] = useState<SignatureFormState>(emptyForm());

  // Delete state
  const [deleteTarget, setDeleteTarget] = useState<EmailSignature | null>(null);
  const [deleting, setDeleting] = useState(false);

  // Templates
  const [templates] = useState(() => signatureService.getSignatureTemplates());

  // ============================================================================
  // Data Loading
  // ============================================================================

  const loadSignatures = useCallback(async () => {
    if (!activeOrgId) return;
    setLoading(true);
    try {
      const data = await signatureService.getUserSignatures(activeOrgId);
      setSignatures(data);
    } catch (err: any) {
      toast.error(err.message || 'Failed to load signatures');
    } finally {
      setLoading(false);
    }
  }, [activeOrgId, signatureService]);

  useEffect(() => {
    loadSignatures();
  }, [loadSignatures]);

  // ============================================================================
  // Handlers
  // ============================================================================

  const openCreate = () => {
    setEditingSignature(null);
    setForm(emptyForm());
    setShowEditor(true);
  };

  const openCreateFromTemplate = (template: { name: string; content: string }) => {
    setEditingSignature(null);
    setForm({
      ...emptyForm(),
      name: template.name,
      content: template.content.trim(),
    });
    setShowEditor(true);
  };

  const openEdit = (sig: EmailSignature) => {
    setEditingSignature(sig);
    setForm(signatureToForm(sig));
    setShowEditor(true);
  };

  const closeEditor = () => {
    setShowEditor(false);
    setEditingSignature(null);
    setForm(emptyForm());
  };

  const handleSave = async () => {
    if (!activeOrgId || !form.name.trim() || !form.content.trim()) return;

    setSaving(true);
    try {
      const input: SignatureCreateInput = {
        name: form.name.trim(),
        is_default: form.is_default,
        content: form.content,
        variables: form.variables,
        social_links: form.social_links.filter((l) => l.url.trim()),
        font_family: form.font_family,
        primary_color: form.primary_color,
        logo_url: form.logo_url ?? undefined,
        logo_storage_path: form.logo_storage_path ?? undefined,
        banner_url: form.banner_url ?? undefined,
        banner_storage_path: form.banner_storage_path ?? undefined,
      };

      if (editingSignature) {
        await signatureService.updateSignature(editingSignature.id, input);
        toast.success('Signature updated');
      } else {
        const created = await signatureService.createSignature(activeOrgId, input);

        // Handle pending file uploads for new signatures
        const formAny = form as any;
        if (formAny._pendingLogoFile) {
          try {
            await signatureService.uploadLogo(created.id, formAny._pendingLogoFile);
          } catch {
            // Non-critical; logo can be uploaded later
          }
        }
        if (formAny._pendingBannerFile) {
          try {
            await signatureService.uploadBanner(created.id, formAny._pendingBannerFile);
          } catch {
            // Non-critical; banner can be uploaded later
          }
        }
        toast.success('Signature created');
      }

      closeEditor();
      await loadSignatures();
    } catch (err: any) {
      toast.error(err.message || 'Failed to save signature');
    } finally {
      setSaving(false);
    }
  };

  const handleDuplicate = async (sig: EmailSignature) => {
    try {
      await signatureService.duplicateSignature(sig.id);
      toast.success(`Duplicated "${sig.name}"`);
      await loadSignatures();
    } catch (err: any) {
      toast.error(err.message || 'Failed to duplicate signature');
    }
  };

  const handleSetDefault = async (sig: EmailSignature) => {
    try {
      await signatureService.updateSignature(sig.id, { is_default: true });
      toast.success(`"${sig.name}" set as default`);
      await loadSignatures();
    } catch (err: any) {
      toast.error(err.message || 'Failed to set default');
    }
  };

  const handleDelete = async () => {
    if (!deleteTarget) return;
    setDeleting(true);
    try {
      await signatureService.deleteSignature(deleteTarget.id);
      toast.success(`Deleted "${deleteTarget.name}"`);
      setDeleteTarget(null);
      await loadSignatures();
    } catch (err: any) {
      toast.error(err.message || 'Failed to delete signature');
    } finally {
      setDeleting(false);
    }
  };

  // ============================================================================
  // Render
  // ============================================================================

  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">
            Email Signatures
          </h1>
          <p className="text-sm text-th-text-tertiary mt-1">
            Create and manage professional email signatures for your outgoing
            messages.
          </p>
        </div>
        <button
          onClick={openCreate}
          className="flex items-center gap-2 px-4 py-2.5 text-sm font-medium text-white bg-th-accent-600 rounded-lg hover:bg-th-accent-700 transition-colors shrink-0"
        >
          <Plus className="w-4 h-4" />
          Create Signature
        </button>
      </div>

      {/* Loading State */}
      {loading && (
        <div className="flex items-center justify-center py-20">
          <div className="flex flex-col items-center gap-3">
            <Loader2 className="w-8 h-8 text-th-accent-600 animate-spin" />
            <p className="text-sm text-th-text-tertiary">Loading signatures...</p>
          </div>
        </div>
      )}

      {/* Empty State */}
      {!loading && signatures.length === 0 && (
        <div className="bg-surface-primary rounded-xl border border-th-border p-12 text-center">
          <div className="w-16 h-16 mx-auto mb-4 rounded-2xl bg-th-accent-600/10 flex items-center justify-center">
            <FileSignature className="w-8 h-8 text-th-accent-600" />
          </div>
          <h3 className="text-lg font-semibold text-th-text-primary mb-2">
            No signatures yet
          </h3>
          <p className="text-sm text-th-text-tertiary mb-6 max-w-md mx-auto">
            Create a professional email signature to include in your outgoing
            emails. Start from scratch or use one of our templates.
          </p>
          <button
            onClick={openCreate}
            className="inline-flex items-center gap-2 px-5 py-2.5 text-sm font-medium text-white bg-th-accent-600 rounded-lg hover:bg-th-accent-700 transition-colors"
          >
            <Plus className="w-4 h-4" />
            Create Your First Signature
          </button>
        </div>
      )}

      {/* Signature Grid */}
      {!loading && signatures.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
          {signatures.map((sig) => {
            const rendered = signatureService.renderSignature(sig);
            return (
              <SignatureCard
                key={sig.id}
                signature={sig}
                renderedHtml={rendered}
                onEdit={() => openEdit(sig)}
                onDuplicate={() => handleDuplicate(sig)}
                onSetDefault={() => handleSetDefault(sig)}
                onDelete={() => setDeleteTarget(sig)}
              />
            );
          })}
        </div>
      )}

      {/* Templates Section */}
      {!loading && (
        <div className="bg-surface-primary rounded-xl border border-th-border p-6">
          <div className="flex items-center gap-2 mb-1">
            <LayoutTemplate className="w-5 h-5 text-th-accent-600" />
            <h2 className="text-lg font-semibold text-th-text-primary">
              Start from Template
            </h2>
          </div>
          <p className="text-sm text-th-text-tertiary mb-5">
            Kickstart your signature with a pre-built template, then customize
            it.
          </p>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {templates.map((tpl) => (
              <button
                key={tpl.name}
                onClick={() => openCreateFromTemplate(tpl)}
                className="group text-left p-4 bg-surface-secondary rounded-xl border border-th-border hover:border-th-accent-600 hover:shadow-md transition-all"
              >
                {/* Mini preview */}
                <div className="relative h-24 overflow-hidden rounded-lg bg-white border border-gray-100 mb-3">
                  <div
                    className="absolute inset-0 p-2 pointer-events-none origin-top-left scale-50"
                    style={{ width: '200%' }}
                    dangerouslySetInnerHTML={{
                      __html: sanitizeHtml(tpl.content
                        .replace(/\{\{font_family\}\}/g, 'Arial, sans-serif')
                        .replace(/\{\{primary_color\}\}/g, '#6366F1')
                        .replace(/\{\{user_name\}\}/g, 'John Doe')
                        .replace(/\{\{user_title\}\}/g, 'Sales Manager')
                        .replace(/\{\{phone\}\}/g, '(555) 123-4567')
                        .replace(/\{\{email\}\}/g, 'john@company.com')
                        .replace(/\{\{company_name\}\}/g, 'Acme Corp')
                        .replace(/\{\{logo_url\}\}/g, '')),
                    }}
                  />
                </div>
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-sm font-semibold text-th-text-primary group-hover:text-th-accent-600 transition-colors">
                      {tpl.name}
                    </h3>
                    <p className="text-xs text-th-text-tertiary mt-0.5">
                      {tpl.description}
                    </p>
                  </div>
                  <ChevronRight className="w-4 h-4 text-th-text-tertiary group-hover:text-th-accent-600 transition-colors" />
                </div>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Editor Modal */}
      {showEditor && (
        <SignatureEditorModal
          editingSignature={editingSignature}
          form={form}
          setForm={setForm}
          saving={saving}
          onSave={handleSave}
          onCancel={closeEditor}
          signatureService={signatureService}
        />
      )}

      {/* Delete Confirmation Dialog */}
      {deleteTarget && (
        <DeleteDialog
          sigName={deleteTarget.name}
          onConfirm={handleDelete}
          onCancel={() => setDeleteTarget(null)}
          deleting={deleting}
        />
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Save, Eye, Settings, ArrowLeft, ChevronDown } from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import { FieldPalette } from '../components/forms/FieldPalette';
import { FormCanvas } from '../components/forms/FormCanvas';
import { FieldPropertyEditor } from '../components/forms/FieldPropertyEditor';
import { FormSettingsDrawer } from '../components/forms/FormSettingsDrawer';
import { FormPreviewModal } from '../components/forms/FormPreviewModal';
import type {
  FormField,
  FormFieldType,
  FormSettings,
  FormStyling,
  FormEntityType,
  FormStatus,
} from '@mpbhealth/crm-core';

const DEFAULT_LABEL: Record<FormFieldType, string> = {
  text: 'Text Field',
  email: 'Email',
  phone: 'Phone',
  number: 'Number',
  textarea: 'Message',
  select: 'Dropdown',
  radio: 'Radio Group',
  checkbox: 'Checkbox',
  date: 'Date',
  hidden: 'Hidden Field',
  heading: 'Section Heading',
  paragraph: 'Paragraph',
};

export default function FormBuilder() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { formService, orgId } = useCRM();
  const isEditing = Boolean(id);

  // Form state
  const [name, setName] = useState('Untitled Form');
  const [description, setDescription] = useState('');
  const [slug, setSlug] = useState('');
  const [entityType, setEntityType] = useState<FormEntityType>('lead');
  const [status, setStatus] = useState<FormStatus>('draft');
  const [fields, setFields] = useState<FormField[]>([]);
  const [settings, setSettings] = useState<FormSettings>({});
  const [styling, setStyling] = useState<FormStyling>({});

  // UI state
  const [selectedFieldId, setSelectedFieldId] = useState<string | null>(null);
  const [showSettings, setShowSettings] = useState(false);
  const [showPreview, setShowPreview] = useState(false);
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(isEditing);

  // Load existing form
  useEffect(() => {
    if (!id) return;

    const loadForm = async () => {
      setLoading(true);
      const form = await formService.getForm(id);
      if (form) {
        setName(form.name);
        setDescription(form.description || '');
        setSlug(form.slug);
        setEntityType(form.entity_type);
        setStatus(form.status);
        setFields(form.fields || []);
        setSettings(form.settings || {});
        setStyling(form.styling || {});
      }
      setLoading(false);
    };

    loadForm();
  }, [id, formService]);

  const generateSlug = useCallback((formName: string) => {
    return formName
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-|-$/g, '')
      || 'form';
  }, []);

  const createField = (type: FormFieldType): FormField => ({
    id: `field_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
    type,
    label: DEFAULT_LABEL[type] || type,
    placeholder: '',
    required: false,
    width: 'full',
    options: type === 'select' || type === 'radio' ? ['Option 1', 'Option 2'] : undefined,
    content: type === 'heading' || type === 'paragraph' ? DEFAULT_LABEL[type] : undefined,
  });

  const handleAddField = (type: FormFieldType) => {
    const newField = createField(type);
    setFields((prev) => [...prev, newField]);
    setSelectedFieldId(newField.id);
  };

  const handleAddFieldAtIndex = (type: FormFieldType, index: number) => {
    const newField = createField(type);
    setFields((prev) => {
      const next = [...prev];
      next.splice(index, 0, newField);
      return next;
    });
    setSelectedFieldId(newField.id);
  };

  const handleRemoveField = (fieldId: string) => {
    setFields((prev) => prev.filter((f) => f.id !== fieldId));
    if (selectedFieldId === fieldId) {
      setSelectedFieldId(null);
    }
  };

  const handleUpdateField = (updates: Partial<FormField>) => {
    if (!selectedFieldId) return;
    setFields((prev) =>
      prev.map((f) => (f.id === selectedFieldId ? { ...f, ...updates } : f))
    );
  };

  const handleSave = async () => {
    setSaving(true);

    const formSlug = slug || generateSlug(name);

    if (isEditing && id) {
      await formService.updateForm(id, {
        name,
        description: description || undefined,
        slug: formSlug,
        entity_type: entityType,
        status,
        fields,
        settings,
        styling,
      });
    } else {
      const result = await formService.createForm({
        name,
        description: description || undefined,
        slug: formSlug,
        entity_type: entityType,
        status,
        fields,
        settings,
        styling,
      });

      if (result.success && result.formId) {
        navigate(`/web-forms/${result.formId}/edit`, { replace: true });
      }
    }

    setSaving(false);
  };

  const handleNameChange = (newName: string) => {
    setName(newName);
    if (!isEditing && !slug) {
      setSlug(generateSlug(newName));
    }
  };

  const handleToggleStatus = () => {
    setStatus((prev) => (prev === 'active' ? 'draft' : 'active'));
  };

  const selectedField = fields.find((f) => f.id === selectedFieldId) || null;

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] -m-6">
      {/* Top bar */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-th-border bg-surface-primary shrink-0">
        <div className="flex items-center gap-3">
          <button
            onClick={() => navigate('/web-forms')}
            className="p-1.5 rounded-lg hover:bg-surface-secondary text-th-text-tertiary"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <input
            type="text"
            value={name}
            onChange={(e) => handleNameChange(e.target.value)}
            className="text-lg font-semibold text-th-text-primary bg-transparent border-none outline-none focus:ring-0 min-w-[200px]"
            placeholder="Form name"
          />
        </div>

        <div className="flex items-center gap-2">
          {/* Status toggle */}
          <button
            onClick={handleToggleStatus}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-medium border ${
              status === 'active'
                ? 'border-green-300 bg-green-50 text-green-700'
                : 'border-th-border text-th-text-secondary hover:bg-surface-secondary'
            }`}
          >
            <span className={`w-2 h-2 rounded-full ${status === 'active' ? 'bg-green-500' : 'bg-gray-400'}`} />
            {status === 'active' ? 'Active' : 'Draft'}
            <ChevronDown className="w-3 h-3" />
          </button>

          <button
            onClick={() => setShowSettings(true)}
            className="flex items-center gap-1.5 px-3 py-1.5 border border-th-border rounded-lg text-sm text-th-text-secondary hover:bg-surface-secondary"
          >
            <Settings className="w-4 h-4" />
            <span className="hidden sm:inline">Settings</span>
          </button>

          <button
            onClick={() => setShowPreview(true)}
            className="flex items-center gap-1.5 px-3 py-1.5 border border-th-border rounded-lg text-sm text-th-text-secondary hover:bg-surface-secondary"
          >
            <Eye className="w-4 h-4" />
            <span className="hidden sm:inline">Preview</span>
          </button>

          <button
            onClick={handleSave}
            disabled={saving}
            className="flex items-center gap-1.5 px-4 py-1.5 bg-th-accent-600 text-white rounded-lg text-sm font-medium hover:bg-th-accent-700 disabled:opacity-50"
          >
            <Save className="w-4 h-4" />
            {saving ? 'Saving...' : 'Save'}
          </button>
        </div>
      </div>

      {/* Builder area */}
      <div className="flex flex-1 overflow-hidden">
        {/* Left panel - Field palette */}
        <div className="w-56 border-r border-th-border bg-surface-primary overflow-y-auto p-4 shrink-0">
          <FieldPalette onAddField={handleAddField} />
        </div>

        {/* Center panel - Canvas */}
        <div className="flex-1 overflow-y-auto p-6 bg-surface-secondary">
          <div className="max-w-2xl mx-auto">
            <FormCanvas
              fields={fields}
              styling={styling}
              selectedFieldId={selectedFieldId}
              onSelectField={setSelectedFieldId}
              onReorderFields={setFields}
              onRemoveField={handleRemoveField}
              onAddFieldAtIndex={handleAddFieldAtIndex}
            />
          </div>
        </div>

        {/* Right panel - Field properties */}
        <div className="w-64 border-l border-th-border bg-surface-primary overflow-y-auto p-4 shrink-0">
          {selectedField ? (
            <FieldPropertyEditor
              field={selectedField}
              onUpdate={handleUpdateField}
            />
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-th-text-tertiary text-center">
              <p className="text-sm">Select a field to edit its properties</p>
            </div>
          )}
        </div>
      </div>

      {/* Settings drawer */}
      <FormSettingsDrawer
        open={showSettings}
        onClose={() => setShowSettings(false)}
        name={name}
        description={description}
        slug={slug}
        entityType={entityType}
        settings={settings}
        styling={styling}
        onUpdateName={setName}
        onUpdateDescription={setDescription}
        onUpdateSlug={setSlug}
        onUpdateEntityType={setEntityType}
        onUpdateSettings={setSettings}
        onUpdateStyling={setStyling}
      />

      {/* Preview modal */}
      <FormPreviewModal
        open={showPreview}
        onClose={() => setShowPreview(false)}
        fields={fields}
        styling={styling}
      />
    </div>
  );
}

