              {draft.to_addresses.join(', ')}
            </p>
          )}
          {draft.cc_addresses?.length > 0 && (
            <p className="text-sm text-th-text-secondary">
              <span className="font-medium text-th-text-tertiary">Cc: </span>
              {draft.cc_addresses.join(', ')}
            </p>
          )}
