// Main InvoiceDetail Component
// -------------------------------------------------------------------------
export default function InvoiceDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { invoiceService } = useCRM();
  const { activeOrgId } = useOrg();

  const [invoice, setInvoice] = useState<InvoiceWithRelations | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<TabType>('line_items');
  const [showEditInvoice, setShowEditInvoice] = useState(false);
  const [showAddLineItem, setShowAddLineItem] = useState(false);
  const [showRecordPayment, setShowRecordPayment] = useState(false);
  const [editingLineItem, setEditingLineItem] = useState<InvoiceLineItem | null>(null);
  const [showVoidModal, setShowVoidModal] = useState(false);
  const [showMarkPaidModal, setShowMarkPaidModal] = useState(false);
  const [actionLoading, setActionLoading] = useState(false);

  const loadInvoice = async () => {
    if (!id) return;

    setLoading(true);
    const invoiceData = await invoiceService.getInvoice(id);
    setInvoice(invoiceData);
    setLoading(false);
  };

  useEffect(() => {
    loadInvoice();
  }, [id]);

  const handleSendInvoice = async () => {
    if (!invoice) return;

    setActionLoading(true);
    const result = await invoiceService.sendInvoice(invoice.id);
    setActionLoading(false);

    if (result.success) {
      toast.success('Invoice sent');
      logAuditEvent({
        orgId: activeOrgId || '',
        action: 'invoice.sent',
        entityType: 'invoice',
        entityId: invoice.id,
      }).catch(console.error);
      loadInvoice();
    } else {
      toast.error(result.error || 'Failed to send invoice');
    }
  };

  const handleMarkPaid = async () => {
    if (!invoice) return;

    setActionLoading(true);
    const result = await invoiceService.markPaid(invoice.id);
    setActionLoading(false);

    if (result.success) {
      toast.success('Invoice marked as paid');
      logAuditEvent({
        orgId: activeOrgId || '',
        action: 'invoice.paid',
        entityType: 'invoice',
        entityId: invoice.id,
      }).catch(console.error);
      setShowMarkPaidModal(false);
      loadInvoice();
    } else {
      toast.error(result.error || 'Failed to mark invoice as paid');
    }
  };

  const handleVoidInvoice = async () => {
    if (!invoice) return;

    setActionLoading(true);
    const result = await invoiceService.voidInvoice(invoice.id);
    setActionLoading(false);

    if (result.success) {
      toast.success('Invoice voided');
      logAuditEvent({
        orgId: activeOrgId || '',
        action: 'invoice.voided',
        entityType: 'invoice',
        entityId: invoice.id,
      }).catch(console.error);
      setShowVoidModal(false);
      loadInvoice();
    } else {
      toast.error(result.error || 'Failed to void invoice');
    }
  };

  const handleDeleteLineItem = async (lineItemId: string) => {
    if (!confirm('Are you sure you want to delete this line item?')) return;

    const result = await invoiceService.removeLineItem(lineItemId);
    if (result.success) {
      toast.success('Line item removed');
      loadInvoice();
    } else {
      toast.error(result.error || 'Failed to remove line item');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  if (!invoice) {
    return (
      <div className="text-center py-12">
        <p className="text-th-text-tertiary">Invoice not found</p>
        <Link to="/invoices" className="text-th-accent-600 hover:underline mt-2 inline-block">
          Back to invoices
        </Link>
      </div>
    );
  }

  const statusColors = getStatusColors(invoice.status);
  const isVoided = invoice.status === 'void' || invoice.status === 'cancelled';
  const isPaid = invoice.status === 'paid';
  const canEdit = invoice.status === 'draft';
  const canSend = invoice.status === 'draft' && (invoice.line_items?.length || 0) > 0;
  const canRecordPayment = !isVoided && !isPaid && invoice.amount_due > 0;
  const canMarkPaid = !isVoided && !isPaid && invoice.amount_due > 0;
  const canVoid = !isVoided;

  const tabs: { id: TabType; label: string; icon: React.ReactNode }[] = [
    { id: 'line_items', label: `Line Items (${invoice.line_items?.length || 0})`, icon: <FileText className="w-4 h-4" /> },
    { id: 'payments', label: `Payments (${invoice.payments?.length || 0})`, icon: <CreditCard className="w-4 h-4" /> },
    { id: 'details', label: 'Details', icon: <FileText className="w-4 h-4" /> },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button
            onClick={() => navigate('/invoices')}
            className="p-2 hover:bg-surface-tertiary rounded-lg"
          >
            <ArrowLeft className="w-5 h-5 text-th-text-tertiary" />
          </button>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-2xl font-bold text-th-text-primary">{invoice.invoice_number}</h1>
              <span
                className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-medium ${statusColors.bg} ${statusColors.text}`}
              >
                {getStatusLabel(invoice.status)}
              </span>
            </div>
            <p className="text-th-text-tertiary text-sm mt-1">{invoice.name}</p>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          {canSend && (
            <PermissionGate permission="invoices.write">
              <button
                onClick={handleSendInvoice}
                disabled={actionLoading}
                className="flex items-center space-x-2 px-4 py-2 bg-blue-50 border border-blue-200 rounded-lg text-sm font-medium text-blue-700 hover:bg-blue-100 disabled:opacity-50"
              >
                <Send className="w-4 h-4" />
                <span>Send Invoice</span>
              </button>
            </PermissionGate>
          )}
          {canRecordPayment && (
            <PermissionGate permission="invoices.write">
              <button
                onClick={() => setShowRecordPayment(true)}
                className="flex items-center space-x-2 px-4 py-2 bg-green-50 border border-green-200 rounded-lg text-sm font-medium text-green-700 hover:bg-green-100"
              >
                <DollarSign className="w-4 h-4" />
                <span>Record Payment</span>
              </button>
            </PermissionGate>
          )}
          {canMarkPaid && (
            <PermissionGate permission="invoices.write">
              <button
                onClick={() => setShowMarkPaidModal(true)}
                className="flex items-center space-x-2 px-4 py-2 bg-green-50 border border-green-200 rounded-lg text-sm font-medium text-green-700 hover:bg-green-100"
              >
                <CheckCircle className="w-4 h-4" />
                <span>Mark Paid</span>
              </button>
            </PermissionGate>
          )}
          {canVoid && (
            <PermissionGate permission="invoices.write">
              <button
                onClick={() => setShowVoidModal(true)}
                className="flex items-center space-x-2 px-4 py-2 bg-red-50 border border-red-200 rounded-lg text-sm font-medium text-red-700 hover:bg-red-100"
              >
                <XCircle className="w-4 h-4" />
                <span>Void</span>
              </button>
            </PermissionGate>
          )}
          {/* Print */}
          <button
            onClick={() => window.open(`/invoices/${id}/print`, '_blank')}
            className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
          >
            <Printer className="w-4 h-4" />
            <span>Print</span>
          </button>
          <PermissionGate permission="invoices.write">
            <button
              onClick={() => setShowEditInvoice(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
            >
              <Edit2 className="w-4 h-4" />
              <span>Edit</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-5 gap-4">
        <div className="bg-surface-primary rounded-xl border border-th-border p-4">
          <p className="text-sm text-th-text-tertiary">Subtotal</p>
          <p className="text-xl font-bold text-th-text-primary mt-1">
            {formatCurrency(invoice.subtotal, invoice.currency)}
          </p>
        </div>
        <div className="bg-surface-primary rounded-xl border border-th-border p-4">
          <p className="text-sm text-th-text-tertiary">Tax</p>
          <p className="text-xl font-bold text-th-text-primary mt-1">
            {formatCurrency(invoice.tax_amount, invoice.currency)}
          </p>
        </div>
        <div className="bg-surface-primary rounded-xl border border-th-border p-4">
          <p className="text-sm text-th-text-tertiary">Total</p>
          <p className="text-xl font-bold text-th-text-primary mt-1">
            {formatCurrency(invoice.total, invoice.currency)}
          </p>
        </div>
        <div className="bg-surface-primary rounded-xl border border-th-border p-4">
          <p className="text-sm text-th-text-tertiary">Paid</p>
          <p className="text-xl font-bold text-green-600 mt-1">
            {formatCurrency(invoice.amount_paid, invoice.currency)}
          </p>
        </div>
        <div className="bg-surface-primary rounded-xl border border-th-border p-4">
          <p className="text-sm text-th-text-tertiary">Amount Due</p>
          <p className={`text-xl font-bold mt-1 ${invoice.amount_due > 0 ? 'text-red-600' : 'text-green-600'}`}>
            {formatCurrency(invoice.amount_due, invoice.currency)}
          </p>
        </div>
      </div>

      {/* Tabs */}
      <div className="border-b border-th-border">
        <div className="flex space-x-6">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-2 px-1 py-4 text-sm font-medium border-b-2 transition-colors ${
                activeTab === tab.id
                  ? 'text-th-accent-600 border-th-accent-600'
                  : 'text-th-text-tertiary border-transparent hover:text-th-text-secondary'
              }`}
            >
              {tab.icon}
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Tab content */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main content */}
        <div className="lg:col-span-2">
          {activeTab === 'line_items' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-lg font-semibold text-th-text-primary">Line Items</h2>
                {canEdit && (
                  <PermissionGate permission="invoices.write">
                    <button
                      onClick={() => {
                        setEditingLineItem(null);
                        setShowAddLineItem(true);
                      }}
                      className="flex items-center gap-1 text-sm text-th-accent-600 hover:underline"
                    >
                      <Plus className="w-4 h-4" />
                      Add Item
                    </button>
                  </PermissionGate>
                )}
              </div>

              {!invoice.line_items || invoice.line_items.length === 0 ? (
                <p className="text-th-text-tertiary text-center py-8">No line items yet</p>
              ) : (
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-th-border">
                      <th className="text-left py-2 text-sm font-medium text-th-text-tertiary">Item</th>
                      <th className="text-right py-2 text-sm font-medium text-th-text-tertiary">Qty</th>
                      <th className="text-right py-2 text-sm font-medium text-th-text-tertiary">Unit Price</th>
                      <th className="text-right py-2 text-sm font-medium text-th-text-tertiary">Discount</th>
                      <th className="text-right py-2 text-sm font-medium text-th-text-tertiary">Tax</th>
                      <th className="text-right py-2 text-sm font-medium text-th-text-tertiary">Total</th>
                      {canEdit && <th className="w-16"></th>}
                    </tr>
                  </thead>
                  <tbody>
                    {invoice.line_items.map((item) => (
                      <tr key={item.id} className="border-b border-th-border">
                        <td className="py-3">
                          <p className="text-th-text-primary font-medium">{item.name}</p>
                          {item.description && (
                            <p className="text-sm text-th-text-tertiary">{item.description}</p>
                          )}
                        </td>
                        <td className="py-3 text-right text-th-text-secondary">{item.quantity}</td>
                        <td className="py-3 text-right text-th-text-secondary">
                          {formatCurrency(item.unit_price, invoice.currency)}
                        </td>
                        <td className="py-3 text-right text-th-text-secondary">
                          {item.discount_percent ? `${item.discount_percent}%` : '-'}
                        </td>
                        <td className="py-3 text-right text-th-text-secondary">
                          {item.tax_rate ? `${item.tax_rate}%` : '-'}
                        </td>
                        <td className="py-3 text-right font-medium text-th-text-primary">
                          {formatCurrency(item.total, invoice.currency)}
                        </td>
                        {canEdit && (
                          <td className="py-3 text-right">
                            <div className="flex items-center justify-end gap-2">
                              <button
                                onClick={() => {
                                  setEditingLineItem(item);
                                  setShowAddLineItem(true);
                                }}
                                className="p-1 text-th-text-tertiary hover:text-th-accent-600"
                              >
                                <Edit2 className="w-4 h-4" />
                              </button>
                              <button
                                onClick={() => handleDeleteLineItem(item.id)}
                                className="p-1 text-th-text-tertiary hover:text-red-600"
                              >
                                <Trash2 className="w-4 h-4" />
                              </button>
                            </div>
                          </td>
                        )}
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          )}

          {activeTab === 'payments' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-lg font-semibold text-th-text-primary">Payment History</h2>
                {canRecordPayment && (
                  <PermissionGate permission="invoices.write">
                    <button
                      onClick={() => setShowRecordPayment(true)}
                      className="flex items-center gap-1 text-sm text-th-accent-600 hover:underline"
                    >
                      <Plus className="w-4 h-4" />
                      Record Payment
                    </button>
                  </PermissionGate>
                )}
              </div>

              {!invoice.payments || invoice.payments.length === 0 ? (
                <p className="text-th-text-tertiary text-center py-8">No payments recorded yet</p>
              ) : (
                <div className="space-y-4">
                  {invoice.payments.map((payment) => (
                    <div
                      key={payment.id}
                      className="flex items-center justify-between p-4 bg-surface-secondary rounded-lg"
                    >
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-green-100 rounded-full flex items-center justify-center">
                          <DollarSign className="w-5 h-5 text-green-600" />
                        </div>
                        <div>
                          <p className="font-medium text-th-text-primary">
                            {formatCurrency(payment.amount, invoice.currency)}
                          </p>
                          <p className="text-sm text-th-text-tertiary">
                            {payment.payment_method
                              ? payment.payment_method.replace('_', ' ').charAt(0).toUpperCase() +
                                payment.payment_method.replace('_', ' ').slice(1)
                              : 'Payment'}
                            {payment.reference_number && ` - ${payment.reference_number}`}
                          </p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-sm text-th-text-secondary">{formatDate(payment.payment_date)}</p>
                        {payment.notes && (
                          <p className="text-xs text-th-text-tertiary mt-1">{payment.notes}</p>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'details' && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6 space-y-6">
              <h2 className="text-lg font-semibold text-th-text-primary">Invoice Details</h2>

              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Invoice Number</label>
                  <p className="text-th-text-primary font-medium">{invoice.invoice_number}</p>
                </div>
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Currency</label>
                  <p className="text-th-text-primary">{invoice.currency}</p>
                </div>
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Issue Date</label>
                  <p className="text-th-text-primary">{formatDate(invoice.issue_date)}</p>
                </div>
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Due Date</label>
                  <p className="text-th-text-primary">{formatDate(invoice.due_date)}</p>
                </div>
                {invoice.sent_at && (
                  <div>
                    <label className="block text-sm text-th-text-tertiary mb-1">Sent At</label>
                    <p className="text-th-text-primary">{formatDate(invoice.sent_at)}</p>
                  </div>
                )}
                {invoice.paid_at && (
                  <div>
                    <label className="block text-sm text-th-text-tertiary mb-1">Paid At</label>
                    <p className="text-th-text-primary">{formatDate(invoice.paid_at)}</p>
                  </div>
                )}
              </div>

              {invoice.description && (
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Description</label>
                  <p className="text-th-text-secondary">{invoice.description}</p>
                </div>
              )}

              {invoice.notes && (
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Notes</label>
                  <p className="text-th-text-secondary whitespace-pre-wrap">{invoice.notes}</p>
                </div>
              )}

              {invoice.terms_and_conditions && (
                <div>
                  <label className="block text-sm text-th-text-tertiary mb-1">Terms and Conditions</label>
                  <p className="text-th-text-secondary whitespace-pre-wrap">{invoice.terms_and_conditions}</p>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-1 space-y-6">
          {/* Account */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Account</h2>
            {invoice.account ? (
              <Link
                to={`/accounts/${invoice.account.id}`}
                className="flex items-center gap-3 p-3 bg-surface-secondary rounded-lg hover:bg-surface-tertiary"
              >
                <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
                  <Building2 className="w-5 h-5 text-blue-600" />
                </div>
                <span className="font-medium text-th-text-primary">{invoice.account.name}</span>
              </Link>
            ) : (
              <p className="text-th-text-tertiary">No account linked</p>
            )}
          </div>

          {/* Contact */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Contact</h2>
            {invoice.contact ? (
              <Link
                to={`/contacts/${invoice.contact.id}`}
                className="flex items-center gap-3 p-3 bg-surface-secondary rounded-lg hover:bg-surface-tertiary"
              >
                <div className="w-10 h-10 bg-th-accent-100 rounded-full flex items-center justify-center">
                  <span className="text-th-accent-700 font-medium">
                    {invoice.contact.first_name?.[0]}
                    {invoice.contact.last_name?.[0]}
                  </span>
                </div>
                <div>
                  <p className="font-medium text-th-text-primary">
                    {invoice.contact.first_name} {invoice.contact.last_name}
                  </p>
                  <p className="text-sm text-th-text-tertiary">{invoice.contact.email}</p>
                </div>
              </Link>
            ) : (
              <p className="text-th-text-tertiary">No contact linked</p>
            )}
          </div>

          {/* Related Quote/Deal */}
          {(invoice.quote || invoice.deal) && (
            <div className="bg-surface-primary rounded-xl border border-th-border p-6">
              <h2 className="text-lg font-semibold text-th-text-primary mb-4">Related</h2>
              <div className="space-y-3">
                {invoice.quote && (
                  <Link
                    to={`/quotes/${invoice.quote.id}`}
                    className="flex items-center gap-3 p-3 bg-surface-secondary rounded-lg hover:bg-surface-tertiary"
                  >
                    <FileText className="w-5 h-5 text-th-text-tertiary" />
                    <div>
                      <p className="text-sm text-th-text-tertiary">Quote</p>
                      <p className="font-medium text-th-text-primary">{invoice.quote.quote_number}</p>
                    </div>
                  </Link>
                )}
                {invoice.deal && (
                  <Link
                    to={`/deals/${invoice.deal.id}`}
                    className="flex items-center gap-3 p-3 bg-surface-secondary rounded-lg hover:bg-surface-tertiary"
                  >
                    <DollarSign className="w-5 h-5 text-th-text-tertiary" />
                    <div>
                      <p className="text-sm text-th-text-tertiary">Deal</p>
                      <p className="font-medium text-th-text-primary">{invoice.deal.name}</p>
                    </div>
                  </Link>
                )}
              </div>
            </div>
          )}

          {/* Key Dates */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Key Dates</h2>
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                <Calendar className="w-4 h-4 text-th-text-tertiary" />
                <div>
                  <p className="text-sm text-th-text-tertiary">Due Date</p>
                  <p className="text-th-text-primary">{formatDate(invoice.due_date)}</p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                <Clock className="w-4 h-4 text-th-text-tertiary" />
                <div>
                  <p className="text-sm text-th-text-tertiary">Created</p>
                  <p className="text-th-text-primary">{formatTimeAgo(invoice.created_at)}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Modals */}
      <EditInvoiceModal
        open={showEditInvoice}
        onClose={() => setShowEditInvoice(false)}
        invoice={invoice}
        onSuccess={() => loadInvoice()}
      />

      <AddLineItemModal
        open={showAddLineItem}
        onClose={() => {
          setShowAddLineItem(false);
          setEditingLineItem(null);
        }}
        invoiceId={invoice.id}
        lineItem={editingLineItem}
        onSuccess={() => loadInvoice()}
      />

      <RecordPaymentModal
        open={showRecordPayment}
        onClose={() => setShowRecordPayment(false)}
        invoiceId={invoice.id}
        amountDue={invoice.amount_due}
        currency={invoice.currency}
        onSuccess={() => loadInvoice()}
      />

      {/* Void Confirmation Modal */}
      <Modal
        open={showVoidModal}
        onClose={() => setShowVoidModal(false)}
        title="Void Invoice"
        size="sm"
      >
        <div className="space-y-4">
          <p className="text-th-text-secondary">
            Are you sure you want to void this invoice? This action cannot be undone.
          </p>
          <div className="p-4 bg-red-50 rounded-lg">
            <p className="font-medium text-red-700">{invoice.invoice_number}</p>
            <p className="text-sm text-red-600">{formatCurrency(invoice.total, invoice.currency)}</p>
          </div>
          <div className="flex justify-end gap-3">
            <button
              onClick={() => setShowVoidModal(false)}
              className="px-4 py-2 text-sm font-medium text-th-text-secondary hover:bg-surface-secondary rounded-lg"
            >
              Cancel
            </button>
            <button
              onClick={handleVoidInvoice}
              disabled={actionLoading}
              className="px-4 py-2 text-sm font-medium text-white bg-red-600 hover:bg-red-700 rounded-lg disabled:opacity-50"
            >
              {actionLoading ? 'Voiding...' : 'Void Invoice'}
            </button>
          </div>
        </div>
      </Modal>

      {/* Mark Paid Confirmation Modal */}
      <Modal
        open={showMarkPaidModal}
        onClose={() => setShowMarkPaidModal(false)}
        title="Mark Invoice as Paid"
        size="sm"
      >
        <div className="space-y-4">
          <p className="text-th-text-secondary">
            This will record a payment for the full remaining amount and mark the invoice as paid.
          </p>
          <div className="p-4 bg-green-50 rounded-lg">
            <p className="font-medium text-green-700">{invoice.invoice_number}</p>
            <p className="text-2xl font-bold text-green-800">
              {formatCurrency(invoice.amount_due, invoice.currency)}
            </p>
          </div>
          <div className="flex justify-end gap-3">
            <button
              onClick={() => setShowMarkPaidModal(false)}
              className="px-4 py-2 text-sm font-medium text-th-text-secondary hover:bg-surface-secondary rounded-lg"
            >
              Cancel
            </button>
            <button
              onClick={handleMarkPaid}
              disabled={actionLoading}
              className="px-4 py-2 text-sm font-medium text-white bg-green-600 hover:bg-green-700 rounded-lg disabled:opacity-50"
            >
              {actionLoading ? 'Processing...' : 'Confirm Paid'}
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Search,
  Filter,
  Download,
  Plus,
  ChevronDown,
  FileText,
  Building2,
  Calendar,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { PermissionGate } from '../components/PermissionGate';
import { useCRM } from '../contexts/CRMContext';
import { Modal } from '../components/Modal';
import { InputField, SelectField, TextareaField, SubmitButton } from '../components/FormField';
import { useForm } from '../hooks/useForm';
import {
  formatTimeAgo,
  type InvoiceWithRelations,
  type InvoiceFilters,
  type AccountWithRelations,
} from '@mpbhealth/crm-core';

// Invoice status options
const STATUS_OPTIONS = [
  { value: '', label: 'All Statuses' },
  { value: 'draft', label: 'Draft' },
  { value: 'sent', label: 'Sent' },
  { value: 'paid', label: 'Paid' },
  { value: 'partially_paid', label: 'Partially Paid' },
  { value: 'overdue', label: 'Overdue' },
  { value: 'void', label: 'Void' },
];

// Get status badge colors
function getStatusColors(status: string) {
  switch (status) {
    case 'draft':
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
    case 'sent':
      return { bg: 'bg-blue-100', text: 'text-blue-700' };
    case 'paid':
      return { bg: 'bg-green-100', text: 'text-green-700' };
    case 'partially_paid':
      return { bg: 'bg-yellow-100', text: 'text-yellow-700' };
    case 'overdue':
      return { bg: 'bg-red-100', text: 'text-red-700' };
    case 'void':
      return { bg: 'bg-gray-100', text: 'text-gray-500' };
    case 'cancelled':
      return { bg: 'bg-gray-100', text: 'text-gray-500' };
    default:
      return { bg: 'bg-gray-100', text: 'text-gray-700' };
  }
}

// Format currency
function formatCurrency(amount: number | null | undefined, currency = 'USD') {
  if (amount === null || amount === undefined) return '-';
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency,
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(amount);
}

// Format date
function formatDate(date: string | null) {
  if (!date) return '-';
  return new Date(date).toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
  });
}

// Status display name
function getStatusLabel(status: string) {
  switch (status) {
    case 'draft':
      return 'Draft';
    case 'sent':
      return 'Sent';
    case 'paid':
      return 'Paid';
    case 'partially_paid':
      return 'Partially Paid';
    case 'overdue':
      return 'Overdue';
    case 'void':
      return 'Void';
    case 'cancelled':
      return 'Cancelled';
    default:
      return status;
  }
}

// Add Invoice Modal Props & Form
interface AddInvoiceModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess?: (invoiceId: string) => void;
}

interface InvoiceFormValues {
  name: string;
  description: string;
  account_id: string;
  due_date: string;
  issue_date: string;
  notes: string;
}

const defaultFormValues: InvoiceFormValues = {
  name: '',
  description: '',
  account_id: '',
  due_date: '',
  issue_date: new Date().toISOString().split('T')[0],
  notes: '',
};

function AddInvoiceModal({ open, onClose, onSuccess }: AddInvoiceModalProps) {
  const { invoiceService, accountService } = useCRM();
  const [accounts, setAccounts] = useState<AccountWithRelations[]>([]);

  // Load accounts for dropdown
  useEffect(() => {
    async function loadAccounts() {
      const { accounts: data } = await accountService.getAccounts({}, 100, 0);
      setAccounts(data);
    }
    if (open) {
      loadAccounts();
    }
  }, [open, accountService]);

  const handleSubmit = async (values: InvoiceFormValues) => {
    const result = await invoiceService.createInvoice({
      name: values.name,
      description: values.description || undefined,
      account_id: values.account_id || undefined,
      issue_date: values.issue_date || undefined,
      due_date: values.due_date || undefined,
      notes: values.notes || undefined,
      status: 'draft',
    });

    if (!result.success) {
      toast.error(result.error || 'Failed to create invoice');
      return;
    }

    toast.success('Invoice created');
    onSuccess?.(result.invoiceId!);
    onClose();
  };

  const { values, errors, loading, handleChange, handleSubmit: onFormSubmit, reset } = useForm<InvoiceFormValues>({
    initialValues: defaultFormValues,
    validate: (vals) => {
      const errs: Partial<Record<keyof InvoiceFormValues, string>> = {};
      if (!vals.name.trim()) errs.name = 'Invoice name is required';
      return errs;
    },
    onSubmit: handleSubmit,
  });

  // Reset form when modal opens/closes
  useEffect(() => {
    if (open) {
      reset();
    }
  }, [open]);

  return (
    <Modal
      open={open}
      onClose={onClose}
      title="New Invoice"
      description="Create a new invoice"
      variant="slideOver"
      size="lg"
    >
      <form onSubmit={onFormSubmit} className="space-y-6">
        <div className="space-y-4">
          <InputField
            label="Invoice Name"
            name="name"
            value={values.name}
            onChange={handleChange}
            error={errors.name}
            required
            placeholder="Enter invoice name"
          />

          <SelectField
            label="Account"
            name="account_id"
            value={values.account_id}
            onChange={handleChange}
            options={[
              { value: '', label: 'Select Account...' },
              ...accounts.map((a) => ({ value: a.id, label: a.name })),
            ]}
          />

          <div className="grid grid-cols-2 gap-4">
            <InputField
              label="Issue Date"
              name="issue_date"
              type="date"
              value={values.issue_date}
              onChange={handleChange}
            />
            <InputField
              label="Due Date"
              name="due_date"
              type="date"
              value={values.due_date}
              onChange={handleChange}
            />
          </div>

          <TextareaField
            label="Description"
            name="description"
            value={values.description}
            onChange={handleChange}
            rows={2}
            placeholder="Invoice description..."
          />

          <TextareaField
            label="Notes"
            name="notes"
            value={values.notes}
            onChange={handleChange}
            rows={2}
            placeholder="Internal notes..."
          />
        </div>

        <div className="flex items-center gap-3 pt-4 border-t border-th-border">
          <SubmitButton
            loading={loading}
            label="Create Invoice"
            loadingLabel="Creating..."
          />
          <button
            type="button"
            onClick={onClose}
            className="flex-1 px-4 py-2.5 text-sm font-medium text-th-text-secondary bg-surface-primary border border-th-border rounded-lg hover:bg-surface-secondary transition-colors"
          >
            Cancel
          </button>
        </div>
      </form>
    </Modal>
  );
}

export default function Invoices() {
  const navigate = useNavigate();
  const { invoiceService, accountService } = useCRM();

  const [invoices, setInvoices] = useState<InvoiceWithRelations[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<InvoiceFilters>({});
  const [page, setPage] = useState(0);
  const [showFilters, setShowFilters] = useState(false);
  const [showAddInvoice, setShowAddInvoice] = useState(false);
  const [accounts, setAccounts] = useState<AccountWithRelations[]>([]);
  const pageSize = 20;

  // Bulk selection state
  const [selectedInvoices, setSelectedInvoices] = useState<Set<string>>(new Set());

  // Load invoices
  const loadInvoices = useCallback(async () => {
    setLoading(true);
    try {
      const { invoices: data, total: count } = await invoiceService.getInvoices(
        filters,
        pageSize,
        page * pageSize
      );
      setInvoices(data);
      setTotal(count);
    } catch (error) {
      console.error('Failed to load invoices:', error);
      toast.error('Failed to load invoices');
    } finally {
      setLoading(false);
    }
  }, [invoiceService, filters, page]);

  // Load accounts for filter dropdown
  const loadAccounts = useCallback(async () => {
    const { accounts: data } = await accountService.getAccounts({}, 100, 0);
    setAccounts(data);
  }, [accountService]);

  useEffect(() => {
    loadInvoices();
  }, [loadInvoices]);

  useEffect(() => {
    loadAccounts();
  }, [loadAccounts]);

  // Clear selection when filters or page change
  useEffect(() => {
    setSelectedInvoices(new Set());
  }, [filters, page]);

  const handleSearch = (search: string) => {
    setFilters((prev) => ({ ...prev, search }));
    setPage(0);
  };

  const handleStatusFilter = (status: string) => {
    setFilters((prev) => ({ ...prev, status: status || undefined }));
    setPage(0);
  };

  const handleAccountFilter = (account_id: string) => {
    setFilters((prev) => ({ ...prev, account_id: account_id || undefined }));
    setPage(0);
  };

  const handleDueDateFilter = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFilters((prev) => ({
      ...prev,
      [name === 'due_from' ? 'dueFrom' : 'dueTo']: value || undefined,
    }));
    setPage(0);
  };

  const handleExport = async () => {
    try {
      const { invoices: exportInvoices } = await invoiceService.getInvoices(filters, 1000, 0);
      const csv = generateInvoiceCSV(exportInvoices);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `invoices-export-${new Date().toISOString().split('T')[0]}.csv`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success('Export started');
    } catch (error) {
      console.error('Export failed:', error);
      toast.error('Failed to export invoices');
    }
  };

  const handleExportSelected = async () => {
    try {
      const selected = invoices.filter((inv) => selectedInvoices.has(inv.id));
      const csv = generateInvoiceCSV(selected);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `invoices-selected-export-${new Date().toISOString().split('T')[0]}.csv`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success('Export started');
    } catch (error) {
      console.error('Export failed:', error);
      toast.error('Failed to export invoices');
    }
  };

  // Generate CSV from invoices
  function generateInvoiceCSV(data: InvoiceWithRelations[]) {
    const headers = ['Invoice Number', 'Name', 'Account', 'Total', 'Amount Due', 'Status', 'Due Date', 'Created'];
    const rows = data.map((invoice) => [
      invoice.invoice_number,
      invoice.name,
      invoice.account?.name || '',
      invoice.total?.toString() || '0',
      invoice.amount_due?.toString() || '0',
      invoice.status,
      invoice.due_date || '',
      new Date(invoice.created_at).toLocaleDateString(),
    ]);
    return [headers.join(','), ...rows.map((row) => row.map((cell) => `"${cell}"`).join(','))].join('\n');
  }

  const toggleSelectAll = useCallback(() => {
    if (selectedInvoices.size === invoices.length) {
      setSelectedInvoices(new Set());
    } else {
      setSelectedInvoices(new Set(invoices.map((i) => i.id)));
    }
  }, [invoices, selectedInvoices.size]);

  const toggleSelectInvoice = useCallback((invoiceId: string) => {
    setSelectedInvoices((prev) => {
      const next = new Set(prev);
      if (next.has(invoiceId)) {
        next.delete(invoiceId);
      } else {
        next.add(invoiceId);
      }
      return next;
    });
  }, []);

  const handleRowClick = (invoiceId: string) => {
    navigate(`/invoices/${invoiceId}`);
  };

  const totalPages = Math.ceil(total / pageSize);

  return (
    <div className="space-y-6">
      {/* Bulk Actions Toolbar */}
      {selectedInvoices.size > 0 && (
        <div className="bg-th-accent-50 border border-th-accent-200 rounded-lg px-4 py-3 flex items-center justify-between">
          <span className="text-sm font-medium text-th-accent-700">
            {selectedInvoices.size} invoice{selectedInvoices.size > 1 ? 's' : ''} selected
          </span>
          <div className="flex items-center space-x-3">
            <PermissionGate permission="invoices.read">
              <button
                onClick={handleExportSelected}
                className="text-sm text-th-accent-600 hover:text-th-accent-700 font-medium"
              >
                Export Selected
              </button>
            </PermissionGate>
            <button
              onClick={() => setSelectedInvoices(new Set())}
              className="text-sm text-th-text-tertiary hover:text-th-text-secondary"
            >
              Clear
            </button>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Invoices</h1>
          <p className="text-th-text-tertiary text-sm mt-1">{total} total invoices</p>
        </div>
        <div className="flex items-center space-x-3">
          <PermissionGate permission="invoices.read">
            <button
              onClick={handleExport}
              className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
            >
              <Download className="w-4 h-4" />
              <span>Export</span>
            </button>
          </PermissionGate>
          <PermissionGate permission="invoices.write">
            <button
              onClick={() => setShowAddInvoice(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700"
            >
              <Plus className="w-4 h-4" />
              <span>New Invoice</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-surface-primary rounded-xl border border-th-border p-4">
        <div className="flex items-center space-x-4">
          {/* Search */}
          <div className="flex-1 flex items-center bg-surface-tertiary rounded-lg px-3 py-2">
            <Search className="w-4 h-4 text-th-text-tertiary mr-2" />
            <input
              type="text"
              placeholder="Search by invoice number or name..."
              value={filters.search || ''}
              onChange={(e) => handleSearch(e.target.value)}
              className="bg-transparent border-none outline-none text-sm w-full text-th-text-secondary placeholder-th-text-tertiary"
            />
          </div>

          {/* Status filter */}
          <div className="relative">
            <select
              value={filters.status || ''}
              onChange={(e) => handleStatusFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              {STATUS_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* Account filter */}
          <div className="relative">
            <select
              value={filters.account_id || ''}
              onChange={(e) => handleAccountFilter(e.target.value)}
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              <option value="">All Accounts</option>
              {accounts.map((account) => (
                <option key={account.id} value={account.id}>
                  {account.name}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* More filters toggle */}
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center space-x-2 px-4 py-2 border rounded-lg text-sm font-medium transition-colors ${
              showFilters
                ? 'border-th-accent-500 text-th-accent-700 bg-th-accent-50'
                : 'border-th-border text-th-text-secondary hover:bg-surface-secondary'
            }`}
          >
            <Filter className="w-4 h-4" />
            <span>Filters</span>
          </button>
        </div>

        {/* Advanced Filters */}
        {showFilters && (
          <div className="mt-4 pt-4 border-t border-th-border">
            <div className="grid grid-cols-4 gap-4">
              <div>
                <label className="block text-xs font-medium text-th-text-tertiary mb-1">
                  Due Date From
                </label>
                <input
                  type="date"
                  name="due_from"
                  value={filters.dueFrom || ''}
                  onChange={handleDueDateFilter}
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-th-text-tertiary mb-1">
                  Due Date To
                </label>
                <input
                  type="date"
                  name="due_to"
                  value={filters.dueTo || ''}
                  onChange={handleDueDateFilter}
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-th-accent-500"
                />
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Invoices table */}
      <div className="bg-surface-primary rounded-xl border border-th-border overflow-hidden">
        {loading ? (
          <div className="flex items-center justify-center h-64">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
          </div>
        ) : invoices.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-th-text-tertiary">
            <FileText className="w-12 h-12 mb-4 opacity-50" />
            <p>No invoices found</p>
            <p className="text-sm mt-1">Try adjusting your filters or create a new invoice</p>
          </div>
        ) : (
          <>
            <table className="w-full">
              <thead>
                <tr className="bg-surface-secondary border-b border-th-border">
                  <th className="w-12 px-4 py-3">
                    <input
                      type="checkbox"
                      checked={selectedInvoices.size === invoices.length && invoices.length > 0}
                      onChange={toggleSelectAll}
                      className="w-4 h-4 rounded border-th-border"
                    />
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Invoice
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Account
                  </th>
                  <th className="text-right px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Total
                  </th>
                  <th className="text-right px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Amount Due
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Status
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Due Date
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Created
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-th-border">
                {invoices.map((invoice) => {
                  const statusColors = getStatusColors(invoice.status);
                  const isSelected = selectedInvoices.has(invoice.id);
                  const isOverdue =
                    invoice.status !== 'paid' &&
                    invoice.status !== 'void' &&
                    invoice.due_date &&
                    new Date(invoice.due_date) < new Date();

                  return (
                    <tr
                      key={invoice.id}
                      className={`hover:bg-surface-secondary cursor-pointer ${
                        isSelected ? 'bg-th-accent-50' : ''
                      }`}
                      onClick={() => handleRowClick(invoice.id)}
                    >
                      <td
                        className="w-12 px-4 py-4"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <input
                          type="checkbox"
                          checked={isSelected}
                          onChange={() => toggleSelectInvoice(invoice.id)}
                          className="w-4 h-4 rounded border-th-border"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 bg-th-accent-100 rounded-lg flex items-center justify-center">
                            <FileText className="w-5 h-5 text-th-accent-700" />
                          </div>
                          <div>
                            <p className="text-sm font-medium text-th-text-primary hover:text-th-accent-600">
                              {invoice.invoice_number}
                            </p>
                            <p className="text-xs text-th-text-tertiary">
                              {invoice.name}
                            </p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        {invoice.account ? (
                          <div className="flex items-center space-x-2">
                            <Building2 className="w-4 h-4 text-th-text-tertiary" />
                            <span className="text-sm text-th-text-secondary">
                              {invoice.account.name}
                            </span>
                          </div>
                        ) : (
                          <span className="text-sm text-th-text-tertiary">-</span>
                        )}
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="text-sm font-medium text-th-text-primary">
                          {formatCurrency(invoice.total, invoice.currency)}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span
                          className={`text-sm font-medium ${
                            invoice.amount_due > 0 ? 'text-red-600' : 'text-green-600'
                          }`}
                        >
                          {formatCurrency(invoice.amount_due, invoice.currency)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${statusColors.bg} ${statusColors.text}`}
                        >
                          {getStatusLabel(invoice.status)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-2">
                          <Calendar className="w-4 h-4 text-th-text-tertiary" />
                          <span
                            className={`text-sm ${
                              isOverdue ? 'text-red-600 font-medium' : 'text-th-text-secondary'
                            }`}
                          >
                            {formatDate(invoice.due_date)}
                          </span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-sm text-th-text-tertiary">
                        {formatTimeAgo(invoice.created_at)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex items-center justify-between px-6 py-4 border-t border-th-border">
                <p className="text-sm text-th-text-tertiary">
                  Showing {page * pageSize + 1} to {Math.min((page + 1) * pageSize, total)} of {total}
                </p>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page === 0}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Previous
                  </button>
                  <button
                    onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                    disabled={page >= totalPages - 1}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Next
                  </button>
                </div>
              </div>
            )}
          </>
        )}
      </div>

      {/* Add Invoice Modal */}
      <AddInvoiceModal
        open={showAddInvoice}
        onClose={() => setShowAddInvoice(false)}
        onSuccess={() => loadInvoices()}
      />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import {
  ArrowLeft,
  Mail,
  Phone,
  MapPin,
  Calendar,
  Edit2,
  Trash2,
  Plus,
  MessageSquare,
  PhoneCall,
  Video,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { useCRM } from '../contexts/CRMContext';
import { PermissionGate } from '../components/PermissionGate';
import { EditLeadModal } from '../components/EditLeadModal';
import { AddNoteModal, LogCallModal, LogMeetingModal } from '../components/QuickActionModals';
import { AddTaskModal } from '../components/AddTaskModal';
import { AIInsightsPanel } from '../components/AIInsightsPanel';
import { ScoreBreakdownPanel } from '../components/ScoreBreakdownPanel';
import { UnifiedTimeline } from '../components/UnifiedTimeline';
import { useOrg } from '../contexts/OrgContext';
import { logAuditEvent, AUDIT_ACTIONS } from '@mpbhealth/auth';
import type { Lead, LeadActivity, LeadTask } from '@mpbhealth/crm-core';
import { formatTimeAgo, getPriorityColor, getPriorityLabel } from '@mpbhealth/crm-core';

export default function LeadDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { leadService, activityService, taskService, automationService, pipelineStages } = useCRM();
  const { activeOrgId } = useOrg();

  const [lead, setLead] = useState<Lead | null>(null);
  const [activities, setActivities] = useState<LeadActivity[]>([]);
  const [tasks, setTasks] = useState<LeadTask[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'activities' | 'tasks' | 'timeline'>('activities');
  const [showEditLead, setShowEditLead] = useState(false);
  const [showAddNote, setShowAddNote] = useState(false);
  const [showLogCall, setShowLogCall] = useState(false);
  const [showLogMeeting, setShowLogMeeting] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);

  const loadLead = async () => {
    if (!id) return;

    setLoading(true);
    const [leadData, activityData, taskData] = await Promise.all([
      leadService.getLead(id),
      activityService.getActivities(id),
      taskService.getTasks(id, true),
    ]);

    setLead(leadData);
    setActivities(activityData);
    setTasks(taskData);
    setLoading(false);
  };

  useEffect(() => {
    loadLead();
  }, [id]);

  const handleStageChange = async (newStage: string) => {
    if (!lead) return;

    const result = await leadService.updateLeadStage(lead.id, newStage);
    if (result.success) {
      await activityService.logStageChange(lead.id, lead.pipeline_stage, newStage);
      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.LEAD_STAGE_CHANGED,
        entityType: 'lead',
        entityId: lead.id,
        before: { pipeline_stage: lead.pipeline_stage },
        after: { pipeline_stage: newStage },
      }).catch(console.error);
      automationService.evaluateEvent({
        type: 'stage_change',
        leadId: lead.id,
        data: { from_stage: lead.pipeline_stage, to_stage: newStage },
      }).catch(console.error);
      toast.success('Stage updated');
      loadLead();
    } else {
      toast.error('Failed to update stage');
    }
  };

  const handleCompleteTask = async (taskId: string) => {
    const result = await taskService.completeTask(taskId);
    if (result.success) {
      logAuditEvent({
        orgId: activeOrgId || '',
        action: AUDIT_ACTIONS.TASK_COMPLETED,
        entityType: 'task',
        entityId: taskId,
      }).catch(console.error);
      toast.success('Task completed');
      loadLead();
    } else {
      toast.error('Failed to complete task');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  if (!lead) {
    return (
      <div className="text-center py-12">
        <p className="text-th-text-tertiary">Lead not found</p>
        <Link to="/leads" className="text-th-accent-600 hover:underline mt-2 inline-block">
          Back to leads
        </Link>
      </div>
    );
  }

  const stage = pipelineStages.find((s) => s.name === lead.pipeline_stage);
  const priorityColors = getPriorityColor(lead.priority as any || 'normal');

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button
            onClick={() => navigate('/leads')}
            aria-label="Back to leads"
            className="p-2 hover:bg-surface-tertiary rounded-lg"
          >
            <ArrowLeft className="w-5 h-5 text-th-text-tertiary" />
          </button>
          <div>
            <h1 className="text-2xl font-bold text-th-text-primary">
              {lead.first_name} {lead.last_name}
            </h1>
            <p className="text-th-text-tertiary text-sm">{lead.email}</p>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          <PermissionGate permission="leads.update">
            <button
              onClick={() => setShowEditLead(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
            >
              <Edit2 className="w-4 h-4" />
              <span>Edit</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left column - Lead info */}
        <div className="lg:col-span-1 space-y-6">
          {/* Contact info */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Contact Info</h2>
            <div className="space-y-4">
              <div className="flex items-center text-sm">
                <Mail className="w-4 h-4 text-th-text-tertiary mr-3" />
                <a href={`mailto:${lead.email}`} className="text-th-accent-600 hover:underline">
                  {lead.email}
                </a>
              </div>
              {lead.phone && (
                <div className="flex items-center text-sm">
                  <Phone className="w-4 h-4 text-th-text-tertiary mr-3" />
                  <a href={`tel:${lead.phone}`} className="text-th-accent-600 hover:underline">
                    {lead.phone}
                  </a>
                </div>
              )}
              {lead.zip_code && (
                <div className="flex items-center text-sm">
                  <MapPin className="w-4 h-4 text-th-text-tertiary mr-3" />
                  <span className="text-th-text-secondary">{lead.zip_code}</span>
                </div>
              )}
              <div className="flex items-center text-sm">
                <Calendar className="w-4 h-4 text-th-text-tertiary mr-3" />
                <span className="text-th-text-secondary">
                  Created {formatTimeAgo(lead.created_at)}
                </span>
              </div>
            </div>
          </div>

          {/* Status */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Status</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm text-th-text-tertiary mb-2">Pipeline Stage</label>
                <select
                  value={lead.pipeline_stage}
                  onChange={(e) => handleStageChange(e.target.value)}
                  aria-label="Pipeline stage"
                  className="w-full border border-th-border rounded-lg px-3 py-2 text-sm"
                >
                  {pipelineStages.map((s) => (
                    <option key={s.id} value={s.name}>
                      {s.display_name}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-sm text-th-text-tertiary mb-2">Priority</label>
                <span
                  className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-medium ${priorityColors.bg} ${priorityColors.text}`}
                >
                  {getPriorityLabel(lead.priority as any || 'normal')}
                </span>
              </div>
            </div>
          </div>

          {/* Quick actions */}
          <div className="bg-surface-primary rounded-xl border border-th-border p-6">
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">Quick Actions</h2>
            <div className="grid grid-cols-3 gap-3">
              <button
                onClick={() => setShowAddNote(true)}
                className="flex flex-col items-center p-3 rounded-lg hover:bg-surface-secondary border border-th-border"
              >
                <MessageSquare className="w-5 h-5 text-th-text-secondary mb-1" />
                <span className="text-xs text-th-text-secondary">Note</span>
              </button>
              <button
                onClick={() => setShowLogCall(true)}
                className="flex flex-col items-center p-3 rounded-lg hover:bg-surface-secondary border border-th-border"
              >
                <PhoneCall className="w-5 h-5 text-th-text-secondary mb-1" />
                <span className="text-xs text-th-text-secondary">Call</span>
              </button>
              <button
                onClick={() => setShowLogMeeting(true)}
                className="flex flex-col items-center p-3 rounded-lg hover:bg-surface-secondary border border-th-border"
              >
                <Video className="w-5 h-5 text-th-text-secondary mb-1" />
                <span className="text-xs text-th-text-secondary">Meeting</span>
              </button>
            </div>
          </div>

          {/* AI Insights */}
          <AIInsightsPanel leadId={lead.id} leadEmail={lead.email} />

          {/* Score Breakdown */}
          <ScoreBreakdownPanel leadId={lead.id} />
        </div>

        {/* Right column - Activities and tasks */}
        <div className="lg:col-span-2">
          <div className="bg-surface-primary rounded-xl border border-th-border">
            {/* Tabs */}
            <div className="flex border-b border-th-border">
              <button
                onClick={() => setActiveTab('activities')}
                className={`flex-1 px-6 py-4 text-sm font-medium ${
                  activeTab === 'activities'
                    ? 'text-th-accent-600 border-b-2 border-th-accent-600'
                    : 'text-th-text-tertiary hover:text-th-text-secondary'
                }`}
              >
                Activities ({activities.length})
              </button>
              <button
                onClick={() => setActiveTab('tasks')}
                className={`flex-1 px-6 py-4 text-sm font-medium ${
                  activeTab === 'tasks'
                    ? 'text-th-accent-600 border-b-2 border-th-accent-600'
                    : 'text-th-text-tertiary hover:text-th-text-secondary'
                }`}
              >
                Tasks ({tasks.filter((t) => !t.completed).length})
              </button>
              <button
                onClick={() => setActiveTab('timeline')}
                className={`flex-1 px-6 py-4 text-sm font-medium ${
                  activeTab === 'timeline'
                    ? 'text-th-accent-600 border-b-2 border-th-accent-600'
                    : 'text-th-text-tertiary hover:text-th-text-secondary'
                }`}
              >
                Timeline
              </button>
              {activeTab === 'tasks' && (
                <button
                  onClick={() => setShowAddTask(true)}
                  aria-label="Add task"
                  className="px-3 py-2 mr-2 text-sm text-th-accent-600 hover:bg-th-accent-50 rounded-lg self-center"
                >
                  <Plus className="w-4 h-4" />
                </button>
              )}
            </div>

            {/* Content */}
            <div className="p-6">
              {activeTab === 'activities' ? (
                <div className="activity-timeline">
                  {activities.map((activity) => (
                    <div key={activity.id} className="activity-item">
                      <p className="text-sm font-medium text-th-text-primary">
                        {activity.title}
                      </p>
                      {activity.description && (
                        <p className="text-sm text-th-text-tertiary mt-1">
                          {activity.description}
                        </p>
                      )}
                      <p className="text-xs text-th-text-tertiary mt-1">
                        {formatTimeAgo(activity.created_at)}
                      </p>
                    </div>
                  ))}
                  {activities.length === 0 && (
                    <p className="text-th-text-tertiary text-center py-8">
                      No activities yet
                    </p>
                  )}
                </div>
              ) : activeTab === 'timeline' ? (
                <UnifiedTimeline leadId={id} />
              ) : (
                <div className="space-y-3">
                  {tasks.map((task) => (
                    <div
                      key={task.id}
                      className={`flex items-center justify-between p-4 rounded-lg border ${
                        task.completed
                          ? 'bg-surface-secondary border-th-border'
                          : 'bg-surface-primary border-th-border'
                      }`}
                    >
                      <div className="flex items-center space-x-3">
                        <input
                          type="checkbox"
                          checked={task.completed}
                          onChange={() => !task.completed && handleCompleteTask(task.id)}
                          aria-label={`Mark "${task.title}" as complete`}
                          className="w-5 h-5 rounded border-th-border"
                        />
                        <div>
                          <p
                            className={`text-sm font-medium ${
                              task.completed
                                ? 'text-th-text-tertiary line-through'
                                : 'text-th-text-primary'
                            }`}
                          >
                            {task.title}
                          </p>
                          <p className="text-xs text-th-text-tertiary">
                            Due: {new Date(task.due_date).toLocaleDateString()}
                          </p>
                        </div>
                      </div>
                    </div>
                  ))}
                  {tasks.length === 0 && (
                    <p className="text-th-text-tertiary text-center py-8">
                      No tasks yet
                    </p>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Modals */}
      <EditLeadModal
        open={showEditLead}
        onClose={() => setShowEditLead(false)}
        lead={lead}
        onSuccess={() => loadLead()}
      />
      <AddNoteModal
        open={showAddNote}
        onClose={() => setShowAddNote(false)}
        leadId={lead.id}
        onSuccess={() => loadLead()}
      />
      <LogCallModal
        open={showLogCall}
        onClose={() => setShowLogCall(false)}
        leadId={lead.id}
        onSuccess={() => loadLead()}
      />
      <LogMeetingModal
        open={showLogMeeting}
        onClose={() => setShowLogMeeting(false)}
        leadId={lead.id}
        onSuccess={() => loadLead()}
      />
      <AddTaskModal
        open={showAddTask}
        onClose={() => setShowAddTask(false)}
        leadId={lead.id}
        onSuccess={() => loadLead()}
      />
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import {
  Search,
  Filter,
  Download,
  Plus,
  ChevronDown,
  Mail,
  Phone,
  Upload,
} from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import { PermissionGate } from '../components/PermissionGate';
import { AddLeadModal } from '../components/AddLeadModal';
import { AdvancedFiltersPanel } from '../components/AdvancedFiltersPanel';
import { BulkActionsToolbar } from '../components/BulkActionsToolbar';
import { BulkAssignModal } from '../components/BulkAssignModal';
import { BulkStageModal } from '../components/BulkStageModal';
import { BulkEmailModal } from '../components/BulkEmailModal';
import { ImportModal } from '../components/ImportModal';
import type { Lead, LeadFilters } from '@mpbhealth/crm-core';
import { formatTimeAgo, getPriorityColor, getPriorityLabel } from '@mpbhealth/crm-core';

export default function LeadsList() {
  const { leadService, pipelineStages } = useCRM();
  const [leads, setLeads] = useState<Lead[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<LeadFilters>({});
  const [page, setPage] = useState(0);
  const [showFilters, setShowFilters] = useState(false);
  const [showAddLead, setShowAddLead] = useState(false);
  const pageSize = 20;

  // Bulk selection state
  const [selectedLeads, setSelectedLeads] = useState<Set<string>>(new Set());
  const [showBulkAssign, setShowBulkAssign] = useState(false);
  const [showBulkStage, setShowBulkStage] = useState(false);
  const [showBulkEmail, setShowBulkEmail] = useState(false);
  const [showImport, setShowImport] = useState(false);

  const loadLeads = async () => {
    setLoading(true);
    const { leads, total } = await leadService.getLeads(filters, pageSize, page * pageSize);
    setLeads(leads);
    setTotal(total);
    setLoading(false);
  };

  useEffect(() => {
    loadLeads();
  }, [filters, page]);

  // Clear selection when filters or page change
  useEffect(() => {
    setSelectedLeads(new Set());
  }, [filters, page]);

  const handleSearch = (search: string) => {
    setFilters((prev) => ({ ...prev, search }));
    setPage(0);
  };

  const handleStageFilter = (stage: string) => {
    setFilters((prev) => ({ ...prev, stage: stage || undefined }));
    setPage(0);
  };

  const handleExport = async () => {
    const exportLeads = await leadService.getLeadsForExport(undefined, filters);
    const csv = leadService.generateCSV(exportLeads);
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `leads-export-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
  };

  const handleExportSelected = async () => {
    const ids = Array.from(selectedLeads);
    const exportLeads = await leadService.getLeadsForExport(ids);
    const csv = leadService.generateCSV(exportLeads);
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `leads-selected-export-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
  };

  const toggleSelectAll = useCallback(() => {
    if (selectedLeads.size === leads.length) {
      setSelectedLeads(new Set());
    } else {
      setSelectedLeads(new Set(leads.map((l) => l.id)));
    }
  }, [leads, selectedLeads.size]);

  const toggleSelectLead = useCallback((leadId: string) => {
    setSelectedLeads((prev) => {
      const next = new Set(prev);
      if (next.has(leadId)) {
        next.delete(leadId);
      } else {
        next.add(leadId);
      }
      return next;
    });
  }, []);

  const handleBulkSuccess = () => {
    setSelectedLeads(new Set());
    loadLeads();
  };

  const selectedIds = Array.from(selectedLeads);
  const totalPages = Math.ceil(total / pageSize);

  return (
    <div className="space-y-6">
      {/* Bulk Actions Toolbar */}
      <BulkActionsToolbar
        selectedCount={selectedLeads.size}
        onAssign={() => setShowBulkAssign(true)}
        onChangeStage={() => setShowBulkStage(true)}
        onSendEmail={() => setShowBulkEmail(true)}
        onExport={handleExportSelected}
        onClear={() => setSelectedLeads(new Set())}
      />

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Leads</h1>
          <p className="text-th-text-tertiary text-sm mt-1">
            {total} total leads
          </p>
        </div>
        <div className="flex items-center space-x-3">
          <button
            onClick={handleExport}
            className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
          >
            <Download className="w-4 h-4" />
            <span>Export</span>
          </button>
          <PermissionGate permission="leads.write">
            <button
              onClick={() => setShowImport(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
            >
              <Upload className="w-4 h-4" />
              <span>Import</span>
            </button>
          </PermissionGate>
          <PermissionGate permission="leads.create">
            <button
              onClick={() => setShowAddLead(true)}
              className="flex items-center space-x-2 px-4 py-2 bg-th-accent-600 rounded-lg text-sm font-medium text-white hover:bg-th-accent-700"
            >
              <Plus className="w-4 h-4" />
              <span>Add Lead</span>
            </button>
          </PermissionGate>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-surface-primary rounded-xl border border-th-border p-4">
        <div className="flex items-center space-x-4">
          {/* Search */}
          <div className="flex-1 flex items-center bg-surface-tertiary rounded-lg px-3 py-2">
            <Search className="w-4 h-4 text-th-text-tertiary mr-2" />
            <input
              type="text"
              placeholder="Search by name, email, or phone..."
              value={filters.search || ''}
              onChange={(e) => handleSearch(e.target.value)}
              className="bg-transparent border-none outline-none text-sm w-full text-th-text-secondary placeholder-th-text-tertiary"
            />
          </div>

          {/* Stage filter */}
          <div className="relative">
            <select
              value={filters.stage || ''}
              onChange={(e) => handleStageFilter(e.target.value)}
              aria-label="Filter by pipeline stage"
              className="appearance-none bg-surface-primary border border-th-border rounded-lg px-4 py-2 pr-10 text-sm text-th-text-secondary focus:outline-none focus:ring-2 focus:ring-th-accent-500"
            >
              <option value="">All Stages</option>
              {pipelineStages.map((stage) => (
                <option key={stage.id} value={stage.name}>
                  {stage.display_name}
                </option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-th-text-tertiary pointer-events-none" />
          </div>

          {/* More filters */}
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center space-x-2 px-4 py-2 border rounded-lg text-sm font-medium transition-colors ${
              showFilters
                ? 'border-th-accent-500 text-th-accent-700 bg-th-accent-50'
                : 'border-th-border text-th-text-secondary hover:bg-surface-secondary'
            }`}
          >
            <Filter className="w-4 h-4" />
            <span>Filters</span>
          </button>
        </div>
      </div>

      {/* Advanced filters */}
      {showFilters && (
        <AdvancedFiltersPanel
          filters={filters}
          onChange={(newFilters) => {
            setFilters((prev) => ({ ...prev, ...newFilters }));
            setPage(0);
          }}
        />
      )}

      {/* Leads table */}
      <div className="bg-surface-primary rounded-xl border border-th-border overflow-hidden">
        {loading ? (
          <div className="flex items-center justify-center h-64">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
          </div>
        ) : leads.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-th-text-tertiary">
            <p>No leads found</p>
            <p className="text-sm mt-1">Try adjusting your filters</p>
          </div>
        ) : (
          <>
            <table className="w-full">
              <thead>
                <tr className="bg-surface-secondary border-b border-th-border">
                  <th className="w-12 px-4 py-3">
                    <input
                      type="checkbox"
                      checked={selectedLeads.size === leads.length && leads.length > 0}
                      onChange={toggleSelectAll}
                      aria-label="Select all leads"
                      className="w-4 h-4 rounded border-th-border"
                    />
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Lead
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Contact
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Stage
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Priority
                  </th>
                  <th className="text-left px-6 py-3 text-xs font-medium text-th-text-tertiary uppercase tracking-wider">
                    Created
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-th-border">
                {leads.map((lead) => {
                  const stage = pipelineStages.find((s) => s.name === lead.pipeline_stage);
                  const priorityColors = getPriorityColor(lead.priority as any || 'normal');
                  const isSelected = selectedLeads.has(lead.id);

                  return (
                    <tr
                      key={lead.id}
                      className={`hover:bg-surface-secondary ${isSelected ? 'bg-th-accent-50' : ''}`}
                    >
                      <td className="w-12 px-4 py-4">
                        <input
                          type="checkbox"
                          checked={isSelected}
                          onChange={() => toggleSelectLead(lead.id)}
                          aria-label={`Select ${lead.first_name} ${lead.last_name}`}
                          className="w-4 h-4 rounded border-th-border"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <Link
                          to={`/leads/${lead.id}`}
                          className="flex items-center space-x-3"
                        >
                          <div className="w-10 h-10 bg-th-accent-100 rounded-full flex items-center justify-center">
                            <span className="text-th-accent-700 font-medium text-sm">
                              {lead.first_name.charAt(0)}
                              {lead.last_name.charAt(0)}
                            </span>
                          </div>
                          <div>
                            <p className="text-sm font-medium text-th-text-primary hover:text-th-accent-600">
                              {lead.first_name} {lead.last_name}
                            </p>
                            {lead.zip_code && (
                              <p className="text-xs text-th-text-tertiary">
                                {lead.zip_code}
                              </p>
                            )}
                          </div>
                        </Link>
                      </td>
                      <td className="px-6 py-4">
                        <div className="space-y-1">
                          <a
                            href={`mailto:${lead.email}`}
                            className="flex items-center text-sm text-th-text-secondary hover:text-th-accent-600"
                          >
                            <Mail className="w-4 h-4 mr-2" />
                            {lead.email}
                          </a>
                          {lead.phone && (
                            <a
                              href={`tel:${lead.phone}`}
                              className="flex items-center text-sm text-th-text-secondary hover:text-th-accent-600"
                            >
                              <Phone className="w-4 h-4 mr-2" />
                              {lead.phone}
                            </a>
                          )}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium"
                          style={{
                            backgroundColor: `${stage?.color}20`,
                            color: stage?.color,
                          }}
                        >
                          {stage?.display_name || lead.pipeline_stage}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${priorityColors.bg} ${priorityColors.text}`}
                        >
                          {getPriorityLabel(lead.priority as any || 'normal')}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-sm text-th-text-tertiary">
                        {formatTimeAgo(lead.created_at)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex items-center justify-between px-6 py-4 border-t border-th-border">
                <p className="text-sm text-th-text-tertiary">
                  Showing {page * pageSize + 1} to{' '}
                  {Math.min((page + 1) * pageSize, total)} of {total}
                </p>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page === 0}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Previous
                  </button>
                  <button
                    onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                    disabled={page >= totalPages - 1}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Next
                  </button>
                </div>
              </div>
            )}
          </>
        )}
      </div>

      {/* Modals */}
      <AddLeadModal
        open={showAddLead}
        onClose={() => setShowAddLead(false)}
        onSuccess={() => loadLeads()}
      />
      <BulkAssignModal
        open={showBulkAssign}
        onClose={() => setShowBulkAssign(false)}
        leadIds={selectedIds}
        onSuccess={handleBulkSuccess}
      />
      <BulkStageModal
        open={showBulkStage}
        onClose={() => setShowBulkStage(false)}
        leadIds={selectedIds}
        onSuccess={handleBulkSuccess}
      />
      <BulkEmailModal
        open={showBulkEmail}
        onClose={() => setShowBulkEmail(false)}
        leadIds={selectedIds}
        onSuccess={handleBulkSuccess}
      />
      <ImportModal
        isOpen={showImport}
        onClose={() => setShowImport(false)}
        entityType="leads"
        onSuccess={() => loadLeads()}
      />
    </div>
  );
}

// ============================================================================
// Mail Accounts - Connect & manage M365/Gmail accounts
// Connected Inbox account management page
// ============================================================================

import { useState, useEffect, useCallback } from 'react';
import { useSearchParams } from 'react-router-dom';
import {
  Mail, Plus, RefreshCw, Trash2, Star, Shield, Users, Settings2,
  CheckCircle2, AlertCircle, Clock, XCircle, Wifi, WifiOff,
} from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import type { MailAccount, MailProvider } from '@mpbhealth/crm-core';
import toast from 'react-hot-toast';

// Provider brand config
const PROVIDERS: Record<MailProvider, { name: string; icon: string; color: string; bgColor: string }> = {
  microsoft365: {
    name: 'Microsoft 365',
    icon: '≡ƒÅó',
    color: 'text-blue-600',
    bgColor: 'bg-blue-50',
  },
  gmail: {
    name: 'Gmail',
    icon: '≡ƒôº',
    color: 'text-red-500',
    bgColor: 'bg-red-50',
  },
  imap: {
    name: 'IMAP/SMTP',
    icon: '≡ƒöº',
    color: 'text-gray-600',
    bgColor: 'bg-gray-50',
  },
};

const SYNC_STATUS_CONFIG: Record<string, { icon: typeof CheckCircle2; color: string; label: string }> = {
  idle: { icon: CheckCircle2, color: 'text-green-500', label: 'Connected' },
  syncing: { icon: RefreshCw, color: 'text-blue-500', label: 'Syncing...' },
  error: { icon: AlertCircle, color: 'text-red-500', label: 'Error' },
  disabled: { icon: XCircle, color: 'text-gray-400', label: 'Disabled' },
};

export default function MailAccounts() {
  const { mailAccountService } = useCRM();
  const { activeOrgId } = useOrg();
  const [searchParams, setSearchParams] = useSearchParams();

  const [accounts, setAccounts] = useState<MailAccount[]>([]);
  const [loading, setLoading] = useState(true);
  const [connecting, setConnecting] = useState<MailProvider | null>(null);
  const [showConnectModal, setShowConnectModal] = useState(false);

  const loadAccounts = useCallback(async () => {
    if (!activeOrgId) return;
    try {
      const data = await mailAccountService.getAccounts(activeOrgId);
      setAccounts(data);
    } catch (err) {
      console.error('Failed to load accounts:', err);
    } finally {
      setLoading(false);
    }
  }, [mailAccountService, activeOrgId]);

  useEffect(() => {
    loadAccounts();
  }, [loadAccounts]);

  // Handle OAuth callback redirect
  useEffect(() => {
    const code = searchParams.get('code');
    const state = searchParams.get('state');
    if (code && state) {
      handleOAuthCallback(code, state);
    }
  }, [searchParams]);

  const handleOAuthCallback = async (code: string, state: string) => {
    try {
      const decoded = JSON.parse(atob(state));
      const { provider, org_id } = decoded;

      setConnecting(provider);
      await mailAccountService.exchangeOAuthCode(code, provider, org_id);
      toast.success(`${PROVIDERS[provider as MailProvider].name} account connected successfully`);
      await loadAccounts();

      // Clean URL params
      setSearchParams({});
    } catch (err) {
      toast.error('Failed to connect account');
      console.error(err);
    } finally {
      setConnecting(null);
    }
  };

  const handleConnect = async (provider: MailProvider) => {
    if (!activeOrgId) return;
    try {
      setConnecting(provider);
      const url = await mailAccountService.getOAuthUrl(provider, activeOrgId);
      window.location.href = url;
    } catch (err) {
      toast.error('Failed to start connection');
      setConnecting(null);
    }
  };

  const handleDisconnect = async (account: MailAccount) => {
    if (!confirm(`Disconnect ${account.email_address}? Synced messages will be preserved.`)) return;
    try {
      await mailAccountService.disconnectAccount(account.id);
      toast.success('Account disconnected');
      await loadAccounts();
    } catch {
      toast.error('Failed to disconnect');
    }
  };

  const handleSetDefault = async (account: MailAccount) => {
    if (!activeOrgId) return;
    try {
      await mailAccountService.setDefaultAccount(account.id, activeOrgId);
      toast.success(`${account.email_address} set as default`);
      await loadAccounts();
    } catch {
      toast.error('Failed to set default');
    }
  };

  const handleSync = async (account: MailAccount) => {
    try {
      await mailAccountService.syncFolders(account.id);
      toast.success('Sync started');
      await loadAccounts();
    } catch {
      toast.error('Sync failed');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Mail Accounts</h1>
          <p className="text-sm text-th-text-secondary mt-1">
            Connect your Microsoft 365 or Gmail accounts for a unified inbox experience
          </p>
        </div>
        <button
          onClick={() => setShowConnectModal(true)}
          className="flex items-center gap-2 px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700 transition-colors"
        >
          <Plus className="w-4 h-4" />
          Connect Account
        </button>
      </div>

      {/* Connected Accounts */}
      {accounts.length === 0 ? (
        <div className="bg-white rounded-xl border border-neutral-200 p-12 text-center">
          <Mail className="w-12 h-12 text-th-text-tertiary mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-th-text-primary mb-2">No accounts connected</h3>
          <p className="text-sm text-th-text-secondary mb-6 max-w-sm mx-auto">
            Connect your email accounts to send and receive emails directly from the CRM
          </p>
          <button
            onClick={() => setShowConnectModal(true)}
            className="px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700"
          >
            Connect Your First Account
          </button>
        </div>
      ) : (
        <div className="space-y-4">
          {accounts.map(account => {
            const providerConfig = PROVIDERS[account.provider];
            const statusConfig = SYNC_STATUS_CONFIG[account.sync_status] || SYNC_STATUS_CONFIG.idle;
            const StatusIcon = statusConfig.icon;

            return (
              <div key={account.id} className="bg-white rounded-xl border border-neutral-200 p-5">
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-4">
                    {/* Avatar */}
                    <div className={`w-12 h-12 rounded-full ${providerConfig.bgColor} flex items-center justify-center text-xl`}>
                      {account.avatar_url && !account.avatar_url.startsWith('data:') ? (
                        <img src={account.avatar_url} alt="" className="w-12 h-12 rounded-full" />
                      ) : (
                        providerConfig.icon
                      )}
                    </div>

                    <div>
                      <div className="flex items-center gap-2">
                        <span className="font-semibold text-th-text-primary">
                          {account.display_name || account.email_address}
                        </span>
                        {account.is_default && (
                          <span className="text-xs bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded-full font-medium">
                            Default
                          </span>
                        )}
                      </div>
                      <p className="text-sm text-th-text-secondary">{account.email_address}</p>
                      <div className="flex items-center gap-3 mt-1">
                        <span className={`text-xs font-medium ${providerConfig.color}`}>
                          {providerConfig.name}
                        </span>
                        <span className="text-neutral-300">|</span>
                        <span className={`flex items-center gap-1 text-xs ${statusConfig.color}`}>
                          <StatusIcon className={`w-3.5 h-3.5 ${account.sync_status === 'syncing' ? 'animate-spin' : ''}`} />
                          {statusConfig.label}
                        </span>
                        {account.last_sync_at && (
                          <>
                            <span className="text-neutral-300">|</span>
                            <span className="text-xs text-th-text-tertiary">
                              Last sync: {new Date(account.last_sync_at).toLocaleTimeString()}
                            </span>
                          </>
                        )}
                      </div>
                      {account.sync_error && (
                        <p className="text-xs text-red-500 mt-1">{account.sync_error}</p>
                      )}
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => handleSync(account)}
                      className="p-2 text-th-text-tertiary hover:text-th-accent-600 hover:bg-th-accent-50 rounded-lg transition-colors"
                      title="Sync now"
                    >
                      <RefreshCw className="w-4 h-4" />
                    </button>
                    {!account.is_default && (
                      <button
                        onClick={() => handleSetDefault(account)}
                        className="p-2 text-th-text-tertiary hover:text-yellow-500 hover:bg-yellow-50 rounded-lg transition-colors"
                        title="Set as default"
                      >
                        <Star className="w-4 h-4" />
                      </button>
                    )}
                    <button
                      onClick={() => handleDisconnect(account)}
                      className="p-2 text-th-text-tertiary hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                      title="Disconnect"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>

                {/* Sync Settings Bar */}
                <div className="mt-4 pt-4 border-t border-neutral-100 flex items-center gap-6 text-xs text-th-text-tertiary">
                  <div className="flex items-center gap-1.5">
                    {account.auto_sync ? (
                      <Wifi className="w-3.5 h-3.5 text-green-500" />
                    ) : (
                      <WifiOff className="w-3.5 h-3.5 text-gray-400" />
                    )}
                    Auto-sync: {account.auto_sync ? `Every ${account.sync_interval_minutes}m` : 'Off'}
                  </div>
                  <div className="flex items-center gap-1.5">
                    <Shield className="w-3.5 h-3.5" />
                    {account.is_active ? 'Active' : 'Inactive'}
                  </div>
                  <div className="flex items-center gap-1.5">
                    <Clock className="w-3.5 h-3.5" />
                    Connected {new Date(account.created_at).toLocaleDateString()}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Connect Account Modal */}
      {showConnectModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" onClick={() => setShowConnectModal(false)}>
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full mx-4 p-6" onClick={e => e.stopPropagation()}>
            <h2 className="text-lg font-semibold text-th-text-primary mb-1">Connect Email Account</h2>
            <p className="text-sm text-th-text-secondary mb-6">
              Choose your email provider to get started
            </p>

            <div className="space-y-3">
              {/* Microsoft 365 */}
              <button
                onClick={() => {
                  setShowConnectModal(false);
                  handleConnect('microsoft365');
                }}
                disabled={connecting === 'microsoft365'}
                className="w-full flex items-center gap-4 p-4 border border-neutral-200 rounded-xl hover:border-blue-300 hover:bg-blue-50/50 transition-all group"
              >
                <div className="w-10 h-10 bg-blue-50 rounded-lg flex items-center justify-center text-lg group-hover:bg-blue-100 transition-colors">
                  ≡ƒÅó
                </div>
                <div className="text-left flex-1">
                  <div className="font-medium text-th-text-primary">Microsoft 365</div>
                  <div className="text-xs text-th-text-secondary">Outlook, Exchange, Office 365</div>
                </div>
                {connecting === 'microsoft365' && (
                  <RefreshCw className="w-4 h-4 animate-spin text-blue-500" />
                )}
              </button>

              {/* Gmail */}
              <button
                onClick={() => {
                  setShowConnectModal(false);
                  handleConnect('gmail');
                }}
                disabled={connecting === 'gmail'}
                className="w-full flex items-center gap-4 p-4 border border-neutral-200 rounded-xl hover:border-red-300 hover:bg-red-50/50 transition-all group"
              >
                <div className="w-10 h-10 bg-red-50 rounded-lg flex items-center justify-center text-lg group-hover:bg-red-100 transition-colors">
                  ≡ƒôº
                </div>
                <div className="text-left flex-1">
                  <div className="font-medium text-th-text-primary">Gmail</div>
                  <div className="text-xs text-th-text-secondary">Google Workspace, Gmail</div>
                </div>
                {connecting === 'gmail' && (
                  <RefreshCw className="w-4 h-4 animate-spin text-red-500" />
                )}
              </button>

              {/* IMAP (coming soon) */}
              <div className="w-full flex items-center gap-4 p-4 border border-neutral-200 rounded-xl opacity-50 cursor-not-allowed">
                <div className="w-10 h-10 bg-gray-50 rounded-lg flex items-center justify-center text-lg">
                  ≡ƒöº
                </div>
                <div className="text-left flex-1">
                  <div className="font-medium text-th-text-primary">IMAP / SMTP</div>
                  <div className="text-xs text-th-text-secondary">Custom mail servers</div>
                </div>
                <span className="text-xs bg-neutral-100 text-neutral-500 px-2 py-0.5 rounded-full">
                  Coming soon
                </span>
              </div>
            </div>

            <button
              onClick={() => setShowConnectModal(false)}
              className="w-full mt-4 px-4 py-2 text-sm text-th-text-secondary hover:text-th-text-primary transition-colors"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ============================================================================
// Mail Rules - Inbox rules management page
// Create, edit, and manage inbox automation rules
// ============================================================================

import { useState, useEffect, useCallback } from 'react';
import {
  Filter, Plus, Trash2, GripVertical, ToggleLeft, ToggleRight,
  ChevronDown, ChevronRight, Pencil, Copy, ArrowRight,
} from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import type {
  MailRule, MailRuleCreateInput, MailAccount, MailFolder,
  RuleCondition, RuleAction,
} from '@mpbhealth/crm-core';
import toast from 'react-hot-toast';

const CONDITION_FIELDS = [
  { value: 'from', label: 'From' },
  { value: 'to', label: 'To' },
  { value: 'subject', label: 'Subject' },
  { value: 'body', label: 'Body' },
  { value: 'has_attachments', label: 'Has Attachments' },
  { value: 'importance', label: 'Importance' },
];

const CONDITION_OPERATORS = [
  { value: 'contains', label: 'Contains' },
  { value: 'not_contains', label: 'Does not contain' },
  { value: 'equals', label: 'Equals' },
  { value: 'starts_with', label: 'Starts with' },
  { value: 'ends_with', label: 'Ends with' },
];

const ACTION_TYPES = [
  { value: 'move_to_folder', label: 'Move to folder' },
  { value: 'add_label', label: 'Add label' },
  { value: 'mark_read', label: 'Mark as read' },
  { value: 'mark_flagged', label: 'Flag/Star' },
  { value: 'forward', label: 'Forward to' },
  { value: 'delete', label: 'Delete' },
];

export default function MailRules() {
  const { mailRulesService, mailAccountService } = useCRM();
  const { activeOrgId } = useOrg();

  const [accounts, setAccounts] = useState<MailAccount[]>([]);
  const [selectedAccountId, setSelectedAccountId] = useState<string>('');
  const [rules, setRules] = useState<MailRule[]>([]);
  const [folders, setFolders] = useState<MailFolder[]>([]);
  const [loading, setLoading] = useState(true);
  const [showEditor, setShowEditor] = useState(false);
  const [editingRule, setEditingRule] = useState<MailRule | null>(null);

  // Editor state
  const [ruleName, setRuleName] = useState('');
  const [conditions, setConditions] = useState<RuleCondition[]>([
    { field: 'from', operator: 'contains', value: '' },
  ]);
  const [actions, setActions] = useState<RuleAction[]>([
    { type: 'move_to_folder' },
  ]);
  const [stopProcessing, setStopProcessing] = useState(false);
  const [saving, setSaving] = useState(false);

  const loadAccounts = useCallback(async () => {
    if (!activeOrgId) return;
    const data = await mailAccountService.getAccounts(activeOrgId);
    setAccounts(data);
    if (data.length > 0 && !selectedAccountId) {
      setSelectedAccountId(data[0].id);
    }
  }, [mailAccountService, activeOrgId, selectedAccountId]);

  const loadRules = useCallback(async () => {
    if (!selectedAccountId) return;
    setLoading(true);
    try {
      const [rulesData, foldersData] = await Promise.all([
        mailRulesService.getRules(selectedAccountId),
        mailAccountService.getFolders(selectedAccountId),
      ]);
      setRules(rulesData);
      setFolders(foldersData);
    } catch (err) {
      console.error('Failed to load rules:', err);
    } finally {
      setLoading(false);
    }
  }, [mailRulesService, mailAccountService, selectedAccountId]);

  useEffect(() => { loadAccounts(); }, [loadAccounts]);
  useEffect(() => { loadRules(); }, [loadRules]);

  const openEditor = (rule?: MailRule) => {
    if (rule) {
      setEditingRule(rule);
      setRuleName(rule.name);
      setConditions(rule.conditions);
      setActions(rule.actions);
      setStopProcessing(rule.stop_processing);
    } else {
      setEditingRule(null);
      setRuleName('');
      setConditions([{ field: 'from', operator: 'contains', value: '' }]);
      setActions([{ type: 'move_to_folder' }]);
      setStopProcessing(false);
    }
    setShowEditor(true);
  };

  const handleSave = async () => {
    if (!ruleName.trim()) {
      toast.error('Rule name is required');
      return;
    }

    setSaving(true);
    try {
      if (editingRule) {
        await mailRulesService.updateRule(editingRule.id, {
          name: ruleName,
          conditions,
          actions,
          stop_processing: stopProcessing,
        });
        toast.success('Rule updated');
      } else {
        await mailRulesService.createRule({
          account_id: selectedAccountId,
          name: ruleName,
          conditions,
          actions,
          stop_processing: stopProcessing,
        });
        toast.success('Rule created');
      }
      setShowEditor(false);
      await loadRules();
    } catch {
      toast.error('Failed to save rule');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (rule: MailRule) => {
    if (!confirm(`Delete rule "${rule.name}"?`)) return;
    try {
      await mailRulesService.deleteRule(rule.id);
      toast.success('Rule deleted');
      await loadRules();
    } catch {
      toast.error('Failed to delete');
    }
  };

  const handleToggle = async (rule: MailRule) => {
    try {
      await mailRulesService.toggleRule(rule.id, !rule.is_active);
      await loadRules();
    } catch {
      toast.error('Failed to toggle rule');
    }
  };

  const addCondition = () => {
    setConditions([...conditions, { field: 'subject', operator: 'contains', value: '' }]);
  };

  const removeCondition = (index: number) => {
    setConditions(conditions.filter((_, i) => i !== index));
  };

  const updateCondition = (index: number, updates: Partial<RuleCondition>) => {
    setConditions(conditions.map((c, i) => i === index ? { ...c, ...updates } : c));
  };

  const addAction = () => {
    setActions([...actions, { type: 'mark_read' }]);
  };

  const removeAction = (index: number) => {
    setActions(actions.filter((_, i) => i !== index));
  };

  const updateAction = (index: number, updates: Partial<RuleAction>) => {
    setActions(actions.map((a, i) => i === index ? { ...a, ...updates } : a));
  };

  if (accounts.length === 0 && !loading) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-6">
        <div className="bg-white rounded-xl border border-neutral-200 p-12 text-center">
          <Filter className="w-12 h-12 text-th-text-tertiary mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-th-text-primary mb-2">No mail accounts connected</h3>
          <p className="text-sm text-th-text-secondary">Connect an email account first to create inbox rules</p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Inbox Rules</h1>
          <p className="text-sm text-th-text-secondary mt-1">
            Automate your inbox with rules that filter, label, and organize messages
          </p>
        </div>
        <button
          onClick={() => openEditor()}
          className="flex items-center gap-2 px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700 transition-colors"
        >
          <Plus className="w-4 h-4" />
          New Rule
        </button>
      </div>

      {/* Account selector */}
      {accounts.length > 1 && (
        <select
          value={selectedAccountId}
          onChange={e => setSelectedAccountId(e.target.value)}
          className="px-3 py-2 border border-neutral-200 rounded-lg text-sm"
        >
          {accounts.map(a => (
            <option key={a.id} value={a.id}>{a.email_address}</option>
          ))}
        </select>
      )}

      {/* Rules List */}
      {loading ? (
        <div className="flex justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
        </div>
      ) : rules.length === 0 ? (
        <div className="bg-white rounded-xl border border-neutral-200 p-12 text-center">
          <Filter className="w-10 h-10 text-th-text-tertiary mx-auto mb-3" />
          <h3 className="font-semibold text-th-text-primary mb-1">No rules yet</h3>
          <p className="text-sm text-th-text-secondary">
            Create rules to automatically organize incoming emails
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {rules.map(rule => (
            <div
              key={rule.id}
              className={`bg-white rounded-xl border border-neutral-200 p-4 ${
                !rule.is_active ? 'opacity-50' : ''
              }`}
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <GripVertical className="w-4 h-4 text-neutral-300 cursor-grab" />
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="font-medium text-th-text-primary">{rule.name}</span>
                      {rule.stop_processing && (
                        <span className="text-xs bg-orange-100 text-orange-600 px-1.5 py-0.5 rounded">
                          Stop
                        </span>
                      )}
                    </div>
                    <div className="flex items-center gap-1 text-xs text-th-text-tertiary mt-1">
                      <span>
                        {rule.conditions.length} condition{rule.conditions.length !== 1 ? 's' : ''}
                      </span>
                      <ArrowRight className="w-3 h-3" />
                      <span>
                        {rule.actions.length} action{rule.actions.length !== 1 ? 's' : ''}
                      </span>
                      {rule.times_applied > 0 && (
                        <>
                          <span className="text-neutral-300 mx-1">|</span>
                          <span>Applied {rule.times_applied}x</span>
                        </>
                      )}
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-2">
                  <button
                    onClick={() => handleToggle(rule)}
                    className="p-1.5 hover:bg-neutral-50 rounded-lg"
                    title={rule.is_active ? 'Disable' : 'Enable'}
                  >
                    {rule.is_active ? (
                      <ToggleRight className="w-5 h-5 text-green-500" />
                    ) : (
                      <ToggleLeft className="w-5 h-5 text-neutral-400" />
                    )}
                  </button>
                  <button
                    onClick={() => openEditor(rule)}
                    className="p-1.5 text-th-text-tertiary hover:text-th-accent-600 hover:bg-th-accent-50 rounded-lg"
                  >
                    <Pencil className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => handleDelete(rule)}
                    className="p-1.5 text-th-text-tertiary hover:text-red-500 hover:bg-red-50 rounded-lg"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Rule Editor Modal */}
      {showEditor && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" onClick={() => setShowEditor(false)}>
          <div className="bg-white rounded-xl shadow-xl max-w-2xl w-full mx-4 max-h-[80vh] overflow-y-auto p-6" onClick={e => e.stopPropagation()}>
            <h2 className="text-lg font-semibold text-th-text-primary mb-4">
              {editingRule ? 'Edit Rule' : 'Create Rule'}
            </h2>

            {/* Rule Name */}
            <div className="mb-4">
              <label className="block text-sm font-medium text-th-text-secondary mb-1">Rule Name</label>
              <input
                type="text"
                value={ruleName}
                onChange={e => setRuleName(e.target.value)}
                placeholder="e.g., Move newsletters to folder"
                className="w-full px-3 py-2 border border-neutral-200 rounded-lg text-sm"
              />
            </div>

            {/* Conditions */}
            <div className="mb-4">
              <div className="flex items-center justify-between mb-2">
                <label className="text-sm font-medium text-th-text-secondary">
                  When ALL of these conditions match:
                </label>
                <button onClick={addCondition} className="text-xs text-th-accent-600 hover:text-th-accent-700">
                  + Add condition
                </button>
              </div>
              <div className="space-y-2">
                {conditions.map((cond, i) => (
                  <div key={i} className="flex items-center gap-2">
                    <select
                      value={cond.field}
                      onChange={e => updateCondition(i, { field: e.target.value as RuleCondition['field'] })}
                      className="px-2 py-1.5 border border-neutral-200 rounded text-sm"
                    >
                      {CONDITION_FIELDS.map(f => (
                        <option key={f.value} value={f.value}>{f.label}</option>
                      ))}
                    </select>
                    <select
                      value={cond.operator}
                      onChange={e => updateCondition(i, { operator: e.target.value as RuleCondition['operator'] })}
                      className="px-2 py-1.5 border border-neutral-200 rounded text-sm"
                    >
                      {CONDITION_OPERATORS.map(o => (
                        <option key={o.value} value={o.value}>{o.label}</option>
                      ))}
                    </select>
                    <input
                      type="text"
                      value={cond.value}
                      onChange={e => updateCondition(i, { value: e.target.value })}
                      placeholder="Value..."
                      className="flex-1 px-2 py-1.5 border border-neutral-200 rounded text-sm"
                    />
                    {conditions.length > 1 && (
                      <button onClick={() => removeCondition(i)} className="p-1 text-red-400 hover:text-red-500">
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Actions */}
            <div className="mb-4">
              <div className="flex items-center justify-between mb-2">
                <label className="text-sm font-medium text-th-text-secondary">
                  Then do these actions:
                </label>
                <button onClick={addAction} className="text-xs text-th-accent-600 hover:text-th-accent-700">
                  + Add action
                </button>
              </div>
              <div className="space-y-2">
                {actions.map((action, i) => (
                  <div key={i} className="flex items-center gap-2">
                    <select
                      value={action.type}
                      onChange={e => updateAction(i, { type: e.target.value as RuleAction['type'] })}
                      className="px-2 py-1.5 border border-neutral-200 rounded text-sm"
                    >
                      {ACTION_TYPES.map(a => (
                        <option key={a.value} value={a.value}>{a.label}</option>
                      ))}
                    </select>
                    {action.type === 'move_to_folder' && (
                      <select
                        value={action.folder_id || ''}
                        onChange={e => updateAction(i, { folder_id: e.target.value })}
                        className="flex-1 px-2 py-1.5 border border-neutral-200 rounded text-sm"
                      >
                        <option value="">Select folder...</option>
                        {folders.map(f => (
                          <option key={f.id} value={f.id}>{f.display_name || f.name}</option>
                        ))}
                      </select>
                    )}
                    {action.type === 'add_label' && (
                      <input
                        type="text"
                        value={action.label || ''}
                        onChange={e => updateAction(i, { label: e.target.value })}
                        placeholder="Label name..."
                        className="flex-1 px-2 py-1.5 border border-neutral-200 rounded text-sm"
                      />
                    )}
                    {action.type === 'forward' && (
                      <input
                        type="email"
                        value={action.forward_to || ''}
                        onChange={e => updateAction(i, { forward_to: e.target.value })}
                        placeholder="Forward to email..."
                        className="flex-1 px-2 py-1.5 border border-neutral-200 rounded text-sm"
                      />
                    )}
                    {actions.length > 1 && (
                      <button onClick={() => removeAction(i)} className="p-1 text-red-400 hover:text-red-500">
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Stop processing */}
            <label className="flex items-center gap-2 text-sm text-th-text-secondary mb-6">
              <input
                type="checkbox"
                checked={stopProcessing}
                onChange={e => setStopProcessing(e.target.checked)}
                className="rounded"
              />
              Stop processing more rules after this one matches
            </label>

            {/* Footer */}
            <div className="flex justify-end gap-3">
              <button
                onClick={() => setShowEditor(false)}
                className="px-4 py-2 text-sm text-th-text-secondary hover:text-th-text-primary"
              >
                Cancel
              </button>
              <button
                onClick={handleSave}
                disabled={saving}
                className="px-4 py-2 bg-th-accent-600 text-white rounded-lg hover:bg-th-accent-700 disabled:opacity-50 text-sm"
              >
                {saving ? 'Saving...' : editingRule ? 'Update Rule' : 'Create Rule'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ============================================================================
// Meeting Scheduler ΓÇö Shareable booking links for leads (Calendly-like)
// ============================================================================

import { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { createPortal } from 'react-dom';
import {
  Plus,
  Calendar,
  Clock,
  Copy,
  Trash2,
  Pencil,
  Eye,
  Link2,
  Video,
  Phone,
  MapPin,
  Settings,
  X,
  ChevronLeft,
  ChevronRight,
  Check,
  Search,
  Loader2,
  ExternalLink,
  ToggleLeft,
  ToggleRight,
  Users,
  CheckCircle2,
  XCircle,
  AlertTriangle,
  CalendarDays,
  Timer,
  Globe,
  Mail,
  User,
  MessageSquare,
  BarChart3,
  ArrowRight,
  Ban,
  CalendarCheck,
  CalendarX,
  Filter,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { useCRM } from '../contexts/CRMContext';
import { useOrg } from '../contexts/OrgContext';
import { useAuth } from '../contexts/AuthContext';

// ============================================================================
// Types
// ============================================================================

type LocationType = 'video' | 'phone' | 'in_person' | 'custom';
type BookingStatus = 'confirmed' | 'cancelled' | 'completed' | 'no_show';
type ViewMode = 'schedules' | 'bookings' | 'preview';

interface AvailableHours {
  [day: string]: { enabled: boolean; ranges: { start: string; end: string }[] };
}

interface MeetingSchedule {
  id: string;
  org_id: string;
  user_id: string;
  name: string;
  description: string | null;
  duration_minutes: number;
  buffer_minutes: number;
  slug: string;
  available_hours: AvailableHours;
  booking_window_days: number;
  confirmation_template_id: string | null;
  reminder_template_id: string | null;
  is_active: boolean;
  location_type: LocationType;
  location_config: Record<string, string> | null;
  created_at: string;
  updated_at: string;
}

interface MeetingBooking {
  id: string;
  schedule_id: string;
  lead_id: string | null;
  contact_id: string | null;
  booker_name: string;
  booker_email: string;
  booker_phone: string | null;
  start_time: string;
  end_time: string;
  status: BookingStatus;
  calendar_event_id: string | null;
  notes: string | null;
  cancellation_reason: string | null;
  created_at: string;
}

interface EmailTemplate {
  id: string;
  name: string;
  subject?: string;
}

interface ScheduleStats {
  total: number;
  upcoming: number;
  completed: number;
  no_shows: number;
}

// ============================================================================
// Constants
// ============================================================================

const DAYS_OF_WEEK = [
  { key: 'monday', label: 'Monday', short: 'Mon' },
  { key: 'tuesday', label: 'Tuesday', short: 'Tue' },
  { key: 'wednesday', label: 'Wednesday', short: 'Wed' },
  { key: 'thursday', label: 'Thursday', short: 'Thu' },
  { key: 'friday', label: 'Friday', short: 'Fri' },
  { key: 'saturday', label: 'Saturday', short: 'Sat' },
  { key: 'sunday', label: 'Sunday', short: 'Sun' },
];

const DURATION_OPTIONS = [
  { value: 15, label: '15 min' },
  { value: 30, label: '30 min' },
  { value: 45, label: '45 min' },
  { value: 60, label: '60 min' },
  { value: 90, label: '90 min' },
  { value: 0, label: 'Custom' },
];

const BUFFER_OPTIONS = [
  { value: 0, label: 'No buffer' },
  { value: 5, label: '5 min' },
  { value: 10, label: '10 min' },
  { value: 15, label: '15 min' },
  { value: 30, label: '30 min' },
];

const BOOKING_WINDOW_OPTIONS = [
  { value: 7, label: '1 week' },
  { value: 14, label: '2 weeks' },
  { value: 30, label: '30 days' },
  { value: 60, label: '60 days' },
  { value: 90, label: '90 days' },
];

const LOCATION_TYPES: { value: LocationType; label: string; icon: typeof Video; desc: string }[] = [
  { value: 'video', label: 'Video Call', icon: Video, desc: 'Zoom, Meet, Teams, etc.' },
  { value: 'phone', label: 'Phone Call', icon: Phone, desc: 'You or lead calls' },
  { value: 'in_person', label: 'In Person', icon: MapPin, desc: 'Office or venue' },
  { value: 'custom', label: 'Custom', icon: Settings, desc: 'Custom location details' },
];

const BOOKING_STATUS_CONFIG: Record<BookingStatus, { label: string; color: string; bg: string; icon: typeof Check }> = {
  confirmed: { label: 'Confirmed', color: 'text-blue-700', bg: 'bg-blue-100', icon: CalendarCheck },
  completed: { label: 'Completed', color: 'text-green-700', bg: 'bg-green-100', icon: CheckCircle2 },
  cancelled: { label: 'Cancelled', color: 'text-red-700', bg: 'bg-red-100', icon: CalendarX },
  no_show: { label: 'No Show', color: 'text-amber-700', bg: 'bg-amber-100', icon: AlertTriangle },
};

const TIMEZONES = [
  { value: 'America/New_York', label: 'Eastern (ET)' },
  { value: 'America/Chicago', label: 'Central (CT)' },
  { value: 'America/Denver', label: 'Mountain (MT)' },
  { value: 'America/Los_Angeles', label: 'Pacific (PT)' },
  { value: 'America/Phoenix', label: 'Arizona (MST)' },
  { value: 'America/Anchorage', label: 'Alaska (AKT)' },
  { value: 'Pacific/Honolulu', label: 'Hawaii (HST)' },
  { value: 'UTC', label: 'UTC' },
];

const TIME_SLOTS: string[] = [];
for (let h = 0; h < 24; h++) {
  for (let m = 0; m < 60; m += 15) {
    const hh = String(h).padStart(2, '0');
    const mm = String(m).padStart(2, '0');
    TIME_SLOTS.push(`${hh}:${mm}`);
  }
}

const DEFAULT_AVAILABLE_HOURS: AvailableHours = {
  monday: { enabled: true, ranges: [{ start: '09:00', end: '17:00' }] },
  tuesday: { enabled: true, ranges: [{ start: '09:00', end: '17:00' }] },
  wednesday: { enabled: true, ranges: [{ start: '09:00', end: '17:00' }] },
  thursday: { enabled: true, ranges: [{ start: '09:00', end: '17:00' }] },
  friday: { enabled: true, ranges: [{ start: '09:00', end: '17:00' }] },
  saturday: { enabled: false, ranges: [] },
  sunday: { enabled: false, ranges: [] },
};

const BOOKING_DOMAIN = 'yourdomain.com';

// ============================================================================
// Helpers
// ============================================================================

function formatTime24to12(t: string): string {
  const [hStr, mStr] = t.split(':');
  let h = parseInt(hStr, 10);
  const ampm = h >= 12 ? 'PM' : 'AM';
  if (h === 0) h = 12;
  else if (h > 12) h -= 12;
  return `${h}:${mStr} ${ampm}`;
}

function formatDate(iso: string): string {
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function formatDateTime(iso: string): string {
  return new Date(iso).toLocaleString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });
}

function slugify(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 60);
}

function generateId(): string {
  return crypto.randomUUID?.() ?? Math.random().toString(36).slice(2, 12);
}

function getLocationIcon(type: LocationType) {
  switch (type) {
    case 'video': return Video;
    case 'phone': return Phone;
    case 'in_person': return MapPin;
    default: return Settings;
  }
}

function getLocationLabel(type: LocationType) {
  return LOCATION_TYPES.find((l) => l.value === type)?.label ?? 'Custom';
}

// ============================================================================
// Sub-components
// ============================================================================

function StatusBadge({ status }: { status: BookingStatus }) {
  const cfg = BOOKING_STATUS_CONFIG[status];
  const Icon = cfg.icon;
  return (
    <span className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium ${cfg.color} ${cfg.bg}`}>
      <Icon className="w-3 h-3" />
      {cfg.label}
    </span>
  );
}

function LocationBadge({ type }: { type: LocationType }) {
  const Icon = getLocationIcon(type);
  return (
    <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-gray-100 text-gray-700">
      <Icon className="w-3 h-3" />
      {getLocationLabel(type)}
    </span>
  );
}

function StatCard({ label, value, icon: Icon }: { label: string; value: number; icon: typeof Calendar }) {
  return (
    <div className="flex items-center gap-3 px-4 py-3 rounded-lg bg-surface-secondary">
