// Main Component
// ============================================================================

export default function MeetingScheduler() {
  const { supabase, templateService } = useCRM();
  const { activeOrgId } = useOrg();
  const { user } = useAuth();

  // State
  const [schedules, setSchedules] = useState<MeetingSchedule[]>([]);
  const [scheduleStats, setScheduleStats] = useState<Record<string, ScheduleStats>>({});
  const [loading, setLoading] = useState(true);
  const [templates, setTemplates] = useState<EmailTemplate[]>([]);

  // Views
  const [viewMode, setViewMode] = useState<ViewMode>('schedules');
  const [selectedSchedule, setSelectedSchedule] = useState<MeetingSchedule | null>(null);
  const [editorOpen, setEditorOpen] = useState(false);
  const [editingSchedule, setEditingSchedule] = useState<Partial<MeetingSchedule> | null>(null);

  // Bookings for selected schedule
  const [bookings, setBookings] = useState<MeetingBooking[]>([]);
  const [bookingsLoading, setBookingsLoading] = useState(false);

  // Search
  const [searchQuery, setSearchQuery] = useState('');

  // -------------------------------------------------------------------------
  // Load schedules
  // -------------------------------------------------------------------------
  const loadSchedules = useCallback(async () => {
    if (!activeOrgId) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('crm_meeting_schedules')
        .select('*')
        .eq('org_id', activeOrgId)
        .order('created_at', { ascending: false });

      if (error) throw error;
      const scheduleList = (data || []) as MeetingSchedule[];
      setSchedules(scheduleList);

      // Load stats for all schedules
      const statsMap: Record<string, ScheduleStats> = {};
      const now = new Date().toISOString();

      for (const s of scheduleList) {
        const { data: bookingData } = await supabase
          .from('crm_meeting_bookings')
          .select('id, status, start_time')
          .eq('schedule_id', s.id);

        const all = bookingData || [];
        statsMap[s.id] = {
          total: all.length,
          upcoming: all.filter((b: { status: string; start_time: string }) => b.status === 'confirmed' && b.start_time > now).length,
          completed: all.filter((b: { status: string }) => b.status === 'completed').length,
          no_shows: all.filter((b: { status: string }) => b.status === 'no_show').length,
        };
      }
      setScheduleStats(statsMap);
    } catch (err) {
      console.error('Failed to load schedules:', err);
      toast.error('Failed to load meeting schedules');
    } finally {
      setLoading(false);
    }
  }, [activeOrgId, supabase]);

  // -------------------------------------------------------------------------
  // Load templates
  // -------------------------------------------------------------------------
  const loadTemplates = useCallback(async () => {
    try {
      const data = await templateService.listTemplates({ template_type: 'email', is_active: true });
      setTemplates((data || []).map((t) => ({ id: t.id, name: t.name, subject: t.subject ?? undefined })));
    } catch {
      // Templates are optional
    }
  }, [templateService]);

  // -------------------------------------------------------------------------
  // Load bookings for a schedule
  // -------------------------------------------------------------------------
  const loadBookings = useCallback(
    async (scheduleId: string) => {
      setBookingsLoading(true);
      try {
        const { data, error } = await supabase
          .from('crm_meeting_bookings')
          .select('*')
          .eq('schedule_id', scheduleId)
          .order('start_time', { ascending: false });

        if (error) throw error;
        setBookings((data || []) as MeetingBooking[]);
      } catch (err) {
        console.error('Failed to load bookings:', err);
        toast.error('Failed to load bookings');
      } finally {
        setBookingsLoading(false);
      }
    },
    [supabase],
  );

  // -------------------------------------------------------------------------
  // Effects
  // -------------------------------------------------------------------------
  useEffect(() => {
    loadSchedules();
    loadTemplates();
  }, [loadSchedules, loadTemplates]);

  // -------------------------------------------------------------------------
  // Handlers
  // -------------------------------------------------------------------------
  const handleCreateSchedule = () => {
    setEditingSchedule(null);
    setEditorOpen(true);
  };

  const handleEditSchedule = (schedule: MeetingSchedule) => {
    setEditingSchedule(schedule);
    setEditorOpen(true);
  };

  const handleSaveSchedule = async (data: Partial<MeetingSchedule> & { timezone?: string }) => {
    if (!activeOrgId || !user) return;
    try {
      const payload = {
        org_id: activeOrgId,
        user_id: user.id,
        name: data.name,
        description: data.description || null,
        duration_minutes: data.duration_minutes || 30,
        buffer_minutes: data.buffer_minutes || 0,
        slug: data.slug,
        available_hours: data.available_hours || DEFAULT_AVAILABLE_HOURS,
        booking_window_days: data.booking_window_days || 30,
        confirmation_template_id: data.confirmation_template_id || null,
        reminder_template_id: data.reminder_template_id || null,
        is_active: data.is_active ?? true,
        location_type: data.location_type || 'video',
        location_config: data.location_config || null,
      };

      if (data.id) {
        // Update
        const { error } = await supabase
          .from('crm_meeting_schedules')
          .update({ ...payload, updated_at: new Date().toISOString() })
          .eq('id', data.id);
        if (error) throw error;
        toast.success('Schedule updated');
      } else {
        // Insert
        const { error } = await supabase.from('crm_meeting_schedules').insert(payload);
        if (error) throw error;
        toast.success('Schedule created');
      }

      setEditorOpen(false);
      setEditingSchedule(null);
      await loadSchedules();
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Failed to save schedule';
      console.error('Failed to save schedule:', err);
      toast.error(message);
    }
  };

  const handleToggleActive = async (schedule: MeetingSchedule) => {
    try {
      const { error } = await supabase
        .from('crm_meeting_schedules')
        .update({ is_active: !schedule.is_active, updated_at: new Date().toISOString() })
        .eq('id', schedule.id);
      if (error) throw error;
      toast.success(schedule.is_active ? 'Schedule deactivated' : 'Schedule activated');
      await loadSchedules();
    } catch {
      toast.error('Failed to update schedule');
    }
  };

  const handleDeleteSchedule = async (schedule: MeetingSchedule) => {
    if (!window.confirm(`Delete "${schedule.name}"? This will also delete all associated bookings.`)) return;
    try {
      // Delete bookings first
      await supabase.from('crm_meeting_bookings').delete().eq('schedule_id', schedule.id);
      const { error } = await supabase.from('crm_meeting_schedules').delete().eq('id', schedule.id);
      if (error) throw error;
      toast.success('Schedule deleted');
      await loadSchedules();
    } catch {
      toast.error('Failed to delete schedule');
    }
  };

  const handleCopyLink = (schedule: MeetingSchedule) => {
    const url = `https://${BOOKING_DOMAIN}/book/${schedule.slug}`;
    navigator.clipboard.writeText(url).then(
      () => toast.success('Booking link copied to clipboard'),
      () => toast.error('Failed to copy link'),
    );
  };

  const handleViewBookings = (schedule: MeetingSchedule) => {
    setSelectedSchedule(schedule);
    setViewMode('bookings');
    loadBookings(schedule.id);
  };

  const handleBookingStatusChange = async (bookingId: string, status: BookingStatus, reason?: string) => {
    try {
      const update: Record<string, unknown> = { status };
      if (reason) update.cancellation_reason = reason;
      const { error } = await supabase.from('crm_meeting_bookings').update(update).eq('id', bookingId);
      if (error) throw error;
      toast.success(`Booking marked as ${BOOKING_STATUS_CONFIG[status].label.toLowerCase()}`);
      if (selectedSchedule) await loadBookings(selectedSchedule.id);
      await loadSchedules();
    } catch {
      toast.error('Failed to update booking status');
    }
  };

  // -------------------------------------------------------------------------
  // Filter schedules
  // -------------------------------------------------------------------------
  const filteredSchedules = useMemo(() => {
    if (!searchQuery) return schedules;
    const q = searchQuery.toLowerCase();
    return schedules.filter(
      (s) =>
        s.name.toLowerCase().includes(q) ||
        (s.description || '').toLowerCase().includes(q) ||
        s.slug.toLowerCase().includes(q),
    );
  }, [schedules, searchQuery]);

  // -------------------------------------------------------------------------
  // Render
  // -------------------------------------------------------------------------

  // Bookings view
  if (viewMode === 'bookings' && selectedSchedule) {
    return (
      <div className="p-6 max-w-7xl mx-auto">
        <BookingsView
          schedule={selectedSchedule}
          bookings={bookings}
          loading={bookingsLoading}
          onStatusChange={handleBookingStatusChange}
          onBack={() => {
            setViewMode('schedules');
            setSelectedSchedule(null);
          }}
        />
      </div>
    );
  }

  return (
    <div className="p-6 max-w-7xl mx-auto">
      {/* Header */}
      <div className="flex items-start justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Meeting Scheduler</h1>
          <p className="text-sm text-gray-500 mt-1">Create shareable booking links for leads</p>
        </div>
        <button
          onClick={handleCreateSchedule}
          className="inline-flex items-center gap-2 px-5 py-2.5 rounded-lg bg-th-accent-600 text-white text-sm font-medium hover:bg-th-accent-600/90 transition-colors shadow-sm"
        >
          <Plus className="w-4 h-4" />
          Create Schedule
        </button>
      </div>

      {/* Search bar */}
      {schedules.length > 0 && (
        <div className="relative max-w-md mb-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Search schedulesΓÇª"
            className="w-full pl-9 pr-3 py-2 rounded-lg border border-th-border bg-surface-primary text-sm text-th-text-primary placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-th-accent-600/30"
          />
        </div>
      )}

      {/* Content */}
      {loading ? (
        <div className="flex items-center justify-center py-20">
          <Loader2 className="w-7 h-7 animate-spin text-th-accent-600" />
        </div>
      ) : filteredSchedules.length === 0 && !searchQuery ? (
        <EmptyState onCreateClick={handleCreateSchedule} />
      ) : filteredSchedules.length === 0 ? (
        <div className="text-center py-16">
          <Search className="w-10 h-10 text-gray-300 mx-auto mb-3" />
          <p className="text-sm text-gray-500">No schedules match "{searchQuery}"</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
          {filteredSchedules.map((schedule) => (
            <ScheduleCard
              key={schedule.id}
              schedule={schedule}
              stats={scheduleStats[schedule.id] || { total: 0, upcoming: 0, completed: 0, no_shows: 0 }}
              onEdit={() => handleEditSchedule(schedule)}
              onCopyLink={() => handleCopyLink(schedule)}
              onViewBookings={() => handleViewBookings(schedule)}
              onToggleActive={() => handleToggleActive(schedule)}
              onDelete={() => handleDeleteSchedule(schedule)}
            />
          ))}
        </div>
      )}

      {/* Schedule Editor Modal */}
      {editorOpen && (
        <ScheduleEditorModal
          schedule={editingSchedule}
          templates={templates}
          onSave={handleSaveSchedule}
          onClose={() => {
            setEditorOpen(false);
            setEditingSchedule(null);
          }}
        />
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { RefreshCw, Filter } from 'lucide-react';
import toast from 'react-hot-toast';
import { useCRM } from '../contexts/CRMContext';
import { PipelineFilters } from '../components/PipelineFilters';
import type { Lead } from '@mpbhealth/crm-core';
import { formatTimeAgo } from '@mpbhealth/crm-core';

export default function Pipeline() {
  const { leadService, activityService, pipelineStages, refreshDashboard } = useCRM();
  const [leadsByStage, setLeadsByStage] = useState<Record<string, Lead[]>>({});
  const [loading, setLoading] = useState(true);
  const [draggedLead, setDraggedLead] = useState<Lead | null>(null);
  const [showFilters, setShowFilters] = useState(false);
  const [filterFn, setFilterFn] = useState<((lead: Lead) => boolean) | null>(null);

  const loadLeads = async () => {
    setLoading(true);
    const grouped = await leadService.getLeadsByStage();
    setLeadsByStage(grouped);
    setLoading(false);
  };

  useEffect(() => {
    loadLeads();
  }, []);

  const handleDragStart = (e: React.DragEvent, lead: Lead) => {
    setDraggedLead(lead);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = async (e: React.DragEvent, targetStage: string) => {
    e.preventDefault();

    if (!draggedLead || draggedLead.pipeline_stage === targetStage) {
      setDraggedLead(null);
      return;
    }

    const originalStage = draggedLead.pipeline_stage;

    // Optimistic update
    setLeadsByStage((prev) => {
      const newLeadsByStage = { ...prev };

      // Remove from original stage
      newLeadsByStage[originalStage] = (newLeadsByStage[originalStage] || []).filter(
        (l) => l.id !== draggedLead.id
      );

      // Add to target stage
      if (!newLeadsByStage[targetStage]) {
        newLeadsByStage[targetStage] = [];
      }
      newLeadsByStage[targetStage] = [
        { ...draggedLead, pipeline_stage: targetStage },
        ...newLeadsByStage[targetStage],
      ];

      return newLeadsByStage;
    });

    // Update in database
    const result = await leadService.updateLeadStage(draggedLead.id, targetStage);

    if (result.success) {
      await activityService.logStageChange(draggedLead.id, originalStage, targetStage);
      toast.success(`Moved to ${pipelineStages.find((s) => s.name === targetStage)?.display_name}`);
      refreshDashboard();
    } else {
      // Revert on failure
      loadLeads();
      toast.error('Failed to update stage');
    }

    setDraggedLead(null);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-th-accent-600" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-th-text-primary">Pipeline</h1>
          <p className="text-th-text-tertiary text-sm mt-1">
            Drag and drop leads between stages
          </p>
        </div>
        <div className="flex items-center space-x-3">
          <div className="relative">
            <button
              onClick={() => setShowFilters(!showFilters)}
              className={`flex items-center space-x-2 px-4 py-2 border rounded-lg text-sm font-medium transition-colors ${
                showFilters || filterFn
                  ? 'border-th-accent-500 text-th-accent-700 bg-th-accent-50'
                  : 'border-th-border text-th-text-secondary hover:bg-surface-secondary'
              }`}
            >
              <Filter className="w-4 h-4" />
              <span>Filter</span>
            </button>
            {showFilters && (
              <PipelineFilters onFilter={(fn) => setFilterFn(() => fn)} />
            )}
          </div>
          <button
            onClick={loadLeads}
            className="flex items-center space-x-2 px-4 py-2 bg-surface-primary border border-th-border rounded-lg text-sm font-medium text-th-text-secondary hover:bg-surface-secondary"
          >
            <RefreshCw className="w-4 h-4" />
            <span>Refresh</span>
          </button>
        </div>
      </div>

      {/* Pipeline board */}
      <div className="flex space-x-4 overflow-x-auto pb-4">
        {pipelineStages.map((stage) => {
          const rawStageLeads = leadsByStage[stage.name] || [];
          const stageLeads = filterFn ? rawStageLeads.filter(filterFn) : rawStageLeads;

          return (
            <div
              key={stage.id}
              className="pipeline-column flex-shrink-0 w-72"
              onDragOver={handleDragOver}
              onDrop={(e) => handleDrop(e, stage.name)}
            >
              {/* Stage header */}
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-2">
                  <div
                    className="w-3 h-3 rounded-full"
                    style={{ backgroundColor: stage.color }}
                  />
                  <h3 className="font-semibold text-th-text-primary">
                    {stage.display_name}
                  </h3>
                </div>
                <span className="text-sm text-th-text-tertiary bg-surface-primary px-2 py-0.5 rounded-full">
                  {stageLeads.length}
                </span>
              </div>

              {/* Lead cards */}
              <div className="space-y-3 min-h-[200px]">
                {stageLeads.map((lead) => (
                  <div
                    key={lead.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, lead)}
                    className={`lead-card ${
                      draggedLead?.id === lead.id ? 'dragging' : ''
                    }`}
                  >
                    <Link to={`/leads/${lead.id}`}>
                      <div className="flex items-start justify-between">
                        <div>
                          <p className="font-medium text-th-text-primary">
                            {lead.first_name} {lead.last_name}
                          </p>
                          <p className="text-sm text-th-text-tertiary mt-1">
                            {lead.email}
                          </p>
                        </div>
                        {lead.lead_score > 0 && (
                          <span className="text-xs bg-th-accent-100 text-th-accent-700 px-2 py-0.5 rounded-full">
                            {lead.lead_score}
                          </span>
                        )}
                      </div>
                      {lead.phone && (
                        <p className="text-sm text-th-text-tertiary mt-2">
                          {lead.phone}
                        </p>
                      )}
                      <div className="flex items-center justify-between mt-3 pt-3 border-t border-th-border-subtle">
                        <span className="text-xs text-th-text-tertiary">
                          {formatTimeAgo(lead.created_at)}
                        </span>
                        {lead.tags && lead.tags.length > 0 && (
                          <div className="flex space-x-1">
                            {lead.tags.slice(0, 2).map((tag) => (
                              <span
                                key={tag}
                                className="text-xs bg-surface-tertiary text-th-text-secondary px-2 py-0.5 rounded"
                              >
                                {tag}
                              </span>
                            ))}
                          </div>
                        )}
                      </div>
                    </Link>
                  </div>
                ))}
                {stageLeads.length === 0 && (
                  <div className="text-center py-8 text-th-text-tertiary text-sm">
                    No leads in this stage
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

