  const handleSubmitForApproval = async () => {
    if (!id) return;
    try {
      await purchaseOrderService.updatePurchaseOrder(id, {
        status: 'pending_approval',
        approval_status: 'pending',
      });
      toast.success('Purchase order submitted for approval');
      loadPurchaseOrder();
