                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 bg-th-accent-100 rounded-lg flex items-center justify-center">
                            <ClipboardList className="w-5 h-5 text-th-accent-700" />
                          </div>
                          <div>
                            <p className="text-sm font-medium text-th-text-primary hover:text-th-accent-600">
                              {po.po_number}
                            </p>
                            {po.name && (
                              <p className="text-xs text-th-text-tertiary">{po.name}</p>
                            )}
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {po.vendor?.name || '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${statusColors.bg} ${statusColors.text}`}
                        >
                          {formatStatusLabel(po.status)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        {po.approval_status && (
                          <span
                            className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${approvalColors.bg} ${approvalColors.text}`}
                          >
                            {formatStatusLabel(po.approval_status)}
                          </span>
                        )}
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="text-sm font-medium text-th-text-primary">
                          {formatCurrency(po.total)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-th-text-secondary">
                          {po.order_date
                            ? new Date(po.order_date).toLocaleDateString()
                            : '-'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-sm text-th-text-tertiary">
                        {formatTimeAgo(po.created_at)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex items-center justify-between px-6 py-4 border-t border-th-border">
                <p className="text-sm text-th-text-tertiary">
                  Showing {page * pageSize + 1} to {Math.min((page + 1) * pageSize, total)} of {total}
                </p>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page === 0}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Previous
                  </button>
                  <button
                    onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                    disabled={page >= totalPages - 1}
                    className="px-3 py-1 text-sm border border-th-border rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-surface-secondary"
                  >
                    Next
                  </button>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Calculator,
  Search,
  RefreshCw,
  CheckCircle,
  Clock,
  AlertCircle,
  ChevronLeft,
  ChevronRight,
  Download,
  Tag,
  Eye,
  Mail,
  Phone,
  MapPin,
  Calendar,
  ExternalLink,
} from 'lucide-react';
import { useCRM } from '../contexts/CRMContext';
import type { QuoteSubmission } from '@mpbhealth/crm-core';

const PAGE_SIZE = 20;
const zohoConfigured = !!import.meta.env.VITE_ZOHO_API_KEY;

export default function QuickRateEstimateLeads() {
  const navigate = useNavigate();
  const { importService } = useCRM();

  const [submissions, setSubmissions] = useState<QuoteSubmission[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  // Filters
  const [searchTerm, setSearchTerm] = useState('');
  const [syncFilter, setSyncFilter] = useState<string>('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Detail view
  const [selectedSubmission, setSelectedSubmission] = useState<QuoteSubmission | null>(null);

  const loadSubmissions = useCallback(async () => {
    setLoading(true);
    try {
      const { leads: data, total: count } = await importService.getQuickRateEstimateLeads(
        {
          search: searchTerm || undefined,
          syncStatus: syncFilter || undefined,
        },
        PAGE_SIZE,
        (page - 1) * PAGE_SIZE
      );
      setSubmissions(data);
      setTotal(count);
    } catch (error) {
      console.error('Failed to load quick rate estimate leads:', error);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [importService, searchTerm, syncFilter, page]);

  useEffect(() => {
    loadSubmissions();
  }, [loadSubmissions]);

  const handleRefresh = () => {
    setRefreshing(true);
    loadSubmissions();
  };

  const handleSelectAll = () => {
    if (selectedIds.size === submissions.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(submissions.map((s) => s.id)));
    }
  };

  const handleSelectRow = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) {
      next.delete(id);
    } else {
      next.add(id);
    }
    setSelectedIds(next);
  };

  const handleLabelAsQuickRateEstimate = async () => {
    if (selectedIds.size === 0) return;

    try {
      const result = await importService.importQuoteSubmissionsAsLeads(Array.from(selectedIds));
      if (result.success) {
        setSelectedIds(new Set());
        loadSubmissions();
      }
    } catch (error) {
      console.error('Failed to label leads:', error);
    }
  };

  const totalPages = Math.ceil(total / PAGE_SIZE);

  const getSyncStatusBadge = (status: string) => {
    switch (status) {
      case 'success':
        return (
          <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-700">
            <CheckCircle className="w-3 h-3" />
            Synced
          </span>
        );
      case 'pending':
        return (
          <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-700">
            <Clock className="w-3 h-3" />
            Pending
          </span>
        );
      case 'failed':
      case 'retrying':
        return (
          <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-700">
            <AlertCircle className="w-3 h-3" />
            {status === 'retrying' ? 'Retrying' : 'Failed'}
          </span>
        );
      default:
        return null;
    }
  };

  const formatDate = (date: string) => {
    return new Date(date).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
